def make_asset_canonical_front_contact_sheet(
    turntable_manifest: dict[str, Any],
    output_path: Path,
    thumb_size: int = 190,
) -> Path:
    views = turntable_manifest.get("views") if isinstance(turntable_manifest.get("views"), dict) else {}
    object_ids = sorted(views)
    axes = ["+x", "-x", "+y", "-y"]
    label_h = 34
    row_h = thumb_size + label_h
    width = thumb_size * len(axes)
    height = max(row_h * len(object_ids), row_h)
    canvas = Image.new("RGB", (width, height), (245, 242, 235))
    draw = ImageDraw.Draw(canvas)
    try:
        from PIL import ImageFont

        font = ImageFont.load_default()
    except Exception:
        font = None
    for row, object_id in enumerate(object_ids):
        row_y = row * row_h
        for col, axis in enumerate(axes):
            x = col * thumb_size
            image_path = Path(str(views.get(object_id, {}).get(axis, "")))
            draw.rectangle([x, row_y, x + thumb_size - 1, row_y + thumb_size - 1], outline=(160, 150, 135), width=1)
            if image_path.exists():
                with Image.open(image_path) as image:
                    image = image.convert("RGB")
                    image.thumbnail((thumb_size - 14, thumb_size - 14), Image.Resampling.LANCZOS)
                    canvas.paste(image, (x + (thumb_size - image.width) // 2, row_y + (thumb_size - image.height) // 2))
            label = f"{object_id} view {axis}"
            draw.rectangle([x, row_y + thumb_size, x + thumb_size - 1, row_y + row_h - 1], fill=(232, 226, 214))
            draw.text((x + 6, row_y + thumb_size + 9), label[:32], fill=(20, 20, 20), font=font)
    output_path.parent.mkdir(parents=True, exist_ok=True)
    canvas.save(output_path)
    return output_path


def build_asset_canonical_front_prompt(plan: dict[str, Any], object_ids: list[str]) -> str:
    compact_objects = [
        {
            "id": obj.get("id"),
            "category": obj.get("category"),
            "description": obj.get("description"),
            "current_front_yaw_offset_degrees": obj.get("front_yaw_offset_degrees", 0.0),
        }
        for obj in plan.get("objects", [])
        if isinstance(obj, dict) and str(obj.get("id")) in set(object_ids)
    ]
    return f"""
You are the asset canonical-front detector for TreeSAGE.
The attached contact sheet shows each 3D asset from four local-axis camera views: +x, -x, +y, -y.
For each listed object, decide which local axis is the asset's functional front direction.

Objects:
{json.dumps(compact_objects, ensure_ascii=False, indent=2)}

Return only JSON:
{{
  "schema": "tree_sage_asset_canonical_front_agent_v1",
  "objects": [
    {{
      "id": "existing_object_id",
      "canonical_front_axis": "+x|-x|+y|-y|unknown",
      "confidence": 0.0,
      "evidence": "short visual reason"
    }}
  ],
  "notes": ["short uncertainty notes"]
}}

Rules:
- For chairs, armchairs, sofas, and lounge seats, the front is the side a seated person faces out of; the backrest is behind.
- For beds, the canonical front used by TreeSAGE is the visible headboard/pillow-facing side, not the footboard/open foot end. Choose the local axis from which the pillows and the front face of the headboard are visible. The headboard geometry may sit against a wall, but its visible face points into the room.
- For cabinets/bookshelves, the front is the open/door/drawer side.
- For tables whose front is not meaningful, use unknown unless there is a clear asymmetric front.
- If the mesh is too fragmented or the front is visually ambiguous, use unknown with low confidence.
""".strip()


def run_asset_canonical_front_agent(
    plan: dict[str, Any],
    object_ids: list[str],
    contact_sheet: Path,
    output_dir: Path,
    model: str | None,
) -> dict[str, Any]:
    return run_codex_reference_json_agent(
        "asset_canonical_front",
        build_asset_canonical_front_prompt(plan, object_ids),
        contact_sheet,
        output_dir,
        model,
    )


def build_fallback_asset_canonical_front_report(plan: dict[str, Any], object_ids: list[str], reason: str) -> dict[str, Any]:
    objects = []
    by_id = {str(obj.get("id")): obj for obj in plan.get("objects", []) if isinstance(obj, dict)}
    for object_id in object_ids:
        obj = by_id.get(object_id)
        if not obj:
            continue
        axis = _default_canonical_front_axis(obj)
        confidence = _fallback_canonical_front_confidence(obj, axis)
        objects.append(
            {
                "id": object_id,
                "canonical_front_axis": axis,
                "confidence": confidence,
                "evidence": reason,
            }
        )
    return {
        "schema": "tree_sage_asset_canonical_front_agent_v1",
        "fallback": "local_directional_defaults",
        "objects": objects,
        "notes": [reason],
    }


def _canonical_front_axis_token(axis: Any) -> str:
    normalized = str(axis or "").strip().lower().replace(" ", "")
    aliases = {
        "x": "+x",
        "posx": "+x",
        "positive_x": "+x",
        "y": "+y",
        "posy": "+y",
        "positive_y": "+y",
        "negx": "-x",
        "negative_x": "-x",
        "negy": "-y",
        "negative_y": "-y",
    }
    return aliases.get(normalized, normalized)


def _opposite_canonical_front_axis(axis: str) -> str | None:
    return {
        "+x": "-x",
        "-x": "+x",
        "+y": "-y",
        "-y": "+y",
    }.get(axis)


def _is_bed_object(obj: dict[str, Any]) -> bool:
    if _is_soft_bedding_object(obj):
        return False
    semantic = _semantic_class(obj)
    category = str(obj.get("category") or "").lower()
    identity = f"{obj.get('id', '')} {category}".lower()
    if semantic == "bed" or category in {"bed", "queen bed", "king bed", "single bed", "twin bed"}:
        return True
    if any(keyword in identity for keyword in ("headboard", "footboard", "bedside")):
        return False
    return bool(re.search(r"\b(bed|queen bed|king bed|single bed|twin bed)\b", identity))


def _evidence_segment_for_axis(evidence: str, axis: str) -> str:
    if not evidence:
        return ""
    candidates = [axis]
    if axis.startswith("+"):
        candidates.append(f"plus {axis[1:]}")
        candidates.append(f"positive {axis[1:]}")
    elif axis.startswith("-"):
        candidates.append(f"minus {axis[1:]}")
        candidates.append(f"negative {axis[1:]}")
    lower = evidence.lower()
    positions = [lower.find(candidate) for candidate in candidates if lower.find(candidate) >= 0]
    if not positions:
        return ""
    start = min(positions)
    end_candidates = [idx for idx in (lower.find(";", start + 1), lower.find(".", start + 1), lower.find("\n", start + 1)) if idx >= 0]
    end = min(end_candidates) if end_candidates else min(len(lower), start + 160)
    return lower[start:end]


def _normalize_bed_canonical_front_axis(obj: dict[str, Any], axis: Any, evidence: str) -> tuple[str, str | None]:
    normalized = _canonical_front_axis_token(axis)
    if normalized not in {"+x", "-x", "+y", "-y"} or not _is_bed_object(obj):
        return normalized, None
    segment = _evidence_segment_for_axis(evidence, normalized)
    foot_terms = ("foot/open", "foot side", "foot end", "footboard", "open foot", "foot of")
    head_terms = ("headboard", "head board", "pillow", "pillows", "head side", "head end")
    if segment and any(term in segment for term in foot_terms) and not any(term in segment for term in head_terms):
        opposite = _opposite_canonical_front_axis(normalized)
        if opposite:
            return opposite, (
                "bed_front_axis_reinterpreted_from_foot_end: TreeSAGE bed front is the visible "
                "headboard/pillow-facing side, so an agent-selected foot/open side is inverted"
            )
    return normalized, None


def _bed_mesh_local_front_normalization(
    obj: dict[str, Any],
    canonical_axis: str,
    confidence: float,
) -> dict[str, Any] | None:
    if not _is_bed_object(obj):
        return None
    canonical_offset = _front_axis_to_offset(canonical_axis)
    target_axis = _canonical_front_axis_token(BED_ASSET_LOCAL_FRONT_AXIS)
    target_offset = _front_axis_to_offset(target_axis)
    if canonical_offset is None or target_offset is None:
        return None
    if confidence < BED_CANONICAL_FRONT_MESH_NORMALIZATION_MIN_CONFIDENCE:
        return None
    old_local = _round_yaw_90(float(obj.get("asset_local_yaw_offset_degrees", 0.0) or 0.0))
    new_local = _round_yaw_90(float(target_offset) - float(canonical_offset))
    return {
        "target_local_front_axis": target_axis,
        "target_local_front_yaw_offset_degrees": target_offset,
        "canonical_front_axis": canonical_axis,
        "canonical_front_yaw_offset_degrees": canonical_offset,
        "old_asset_local_yaw_offset_degrees": old_local,
        "new_asset_local_yaw_offset_degrees": new_local,
        "changed": abs(((new_local - old_local + 180.0) % 360.0) - 180.0) > 1e-4,
        "reason": (
            "Bed assets can have different raw local front axes even when their semantic wall pose is identical. "
            "Normalize the mesh-local front axis before layout/pose modules enforce back-to-wall footprint constraints."
        ),
    }


def apply_asset_canonical_front_report(plan: dict[str, Any], front_report: dict[str, Any]) -> dict[str, Any]:
    objects_by_id = {str(obj.get("id")): obj for obj in plan.get("objects", []) if isinstance(obj, dict)}
    applied: list[dict[str, Any]] = []
    skipped: list[dict[str, Any]] = []
    for item in front_report.get("objects", []) if isinstance(front_report.get("objects"), list) else []:
        if not isinstance(item, dict):
            continue
        object_id = str(item.get("id") or "")
        obj = objects_by_id.get(object_id)
        if not obj:
            skipped.append({"item": item, "reason": "unknown_object_id"})
            continue
        if _is_reused_asset_pose_prior_candidate(obj) and _has_reused_asset_local_pose_prior(obj):
            skipped.append(
                {
                    "id": object_id,
                    "canonical_front_axis": item.get("canonical_front_axis"),
                    "confidence": _clamp(_safe_float(item.get("confidence"), 0.0), 0.0, 1.0),
                    "reason": "protected_reused_asset_local_pose_metadata",
                    "pose_prior_source": obj.get("_reused_asset_pose_prior_source"),
                }
            )
            continue
        confidence = _clamp(_safe_float(item.get("confidence"), 0.0), 0.0, 1.0)
        raw_axis = item.get("canonical_front_axis")
        evidence = str(item.get("evidence") or "")
        canonical_axis, normalization_note = _normalize_bed_canonical_front_axis(obj, raw_axis, evidence)
        offset = _front_axis_to_offset(canonical_axis)
        if offset is None or confidence < ASSET_CANONICAL_FRONT_MIN_CONFIDENCE:
            skipped.append(
                {
                    "id": object_id,
                    "canonical_front_axis": raw_axis,
                    "normalized_canonical_front_axis": canonical_axis,
                    "confidence": confidence,
                    "reason": "unknown_or_low_confidence",
                }
            )
            continue
        old_offset = float(obj.get("front_yaw_offset_degrees", 0.0) or 0.0)
        old_asset_local_yaw = float(obj.get("asset_local_yaw_offset_degrees", 0.0) or 0.0)
        desired_effective = _effective_yaw(obj)
        mesh_local_normalization = _bed_mesh_local_front_normalization(obj, canonical_axis, confidence)
        if mesh_local_normalization:
            offset_to_apply = float(mesh_local_normalization["target_local_front_yaw_offset_degrees"])
            obj["asset_local_yaw_offset_degrees"] = float(
                mesh_local_normalization["new_asset_local_yaw_offset_degrees"]
            )
        else:
            offset_to_apply = offset
        obj["front_yaw_offset_degrees"] = offset_to_apply
        _set_effective_yaw(obj, desired_effective)
        obj["asset_canonical_front"] = {
            "axis": canonical_axis,
            "raw_axis": raw_axis,
            "confidence": confidence,
            "evidence": evidence,
            "front_yaw_offset_degrees": offset,
            "semantic_front_yaw_offset_degrees": offset_to_apply,
        }
        if mesh_local_normalization:
            obj["asset_canonical_front"]["mesh_local_normalization"] = mesh_local_normalization
        if normalization_note:
            obj["asset_canonical_front"]["normalization_note"] = normalization_note
        applied.append(
            {
                "id": object_id,
                "canonical_front_axis": canonical_axis,
                "raw_canonical_front_axis": raw_axis,
                "confidence": confidence,
                "old_front_yaw_offset_degrees": old_offset,
                "new_front_yaw_offset_degrees": offset_to_apply,
                "raw_canonical_front_yaw_offset_degrees": offset,
                "old_asset_local_yaw_offset_degrees": old_asset_local_yaw,
                "new_asset_local_yaw_offset_degrees": obj.get("asset_local_yaw_offset_degrees", 0.0),
                "mesh_local_normalization": mesh_local_normalization,
                "normalization_note": normalization_note,
            }
        )
    return {
        "schema": "tree_sage_asset_canonical_front_merge_v1",
        "enabled": True,
        "applied": applied,
        "applied_count": len(applied),
        "skipped": skipped,
        "ok": True,
        "raw_report": front_report,
    }


def render_labeled_topdown_pose_view(plan: dict[str, Any], output_path: Path) -> Path:
    room = plan["room"]
    margin = 90
    width_px = 1500
    scale = min((width_px - margin * 2) / float(room["width"]), 1500 / max(float(room["length"]), 1e-6))
    height_px = int(float(room["length"]) * scale + margin * 2)
    canvas = Image.new("RGB", (width_px, height_px), (241, 236, 225))
    draw = ImageDraw.Draw(canvas)
    try:
        from PIL import ImageFont

        font = ImageFont.load_default()
    except Exception:
        font = None

    def px(x: float, y: float) -> tuple[float, float]:
        return margin + x * scale, canvas.height - margin - y * scale

    x0, y0 = px(0, 0)
    x1, y1 = px(float(room["width"]), float(room["length"]))
    draw.rectangle([x0, y1, x1, y0], outline=(38, 38, 38), width=5, fill=(226, 219, 204))
    for obj in plan.get("objects", []):
        cx, cy = px(float(obj.get("x", 0.0)), float(obj.get("y", 0.0)))
        w, h = _rotated_footprint(obj)
        w *= scale
        h *= scale
        color = (112, 154, 190)
        if _is_seating_object(obj):
            color = (79, 151, 118)
        elif _is_table_anchor_object(obj):
            color = (85, 128, 202)
        elif _is_wall_attached_object(obj):
            color = (190, 128, 92)
        draw.rectangle([cx - w / 2, cy - h / 2, cx + w / 2, cy + h / 2], fill=color, outline=(20, 20, 20), width=2)
        yaw = math.radians(_effective_yaw(obj))
        arrow_len = max(22.0, min(w, h) * 0.55)
        draw.line([cx, cy, cx + math.cos(yaw) * arrow_len, cy - math.sin(yaw) * arrow_len], fill=(240, 205, 45), width=4)
        label = str(obj.get("id") or obj.get("category") or "")
        draw.rectangle([cx + 3, cy + 3, cx + 3 + min(len(label) * 6 + 8, 180), cy + 19], fill=(245, 242, 235))
        draw.text((cx + 7, cy + 6), label[:28], fill=(20, 20, 20), font=font)
    draw.text((margin, 25), "TreeSAGE top-down pose feedback view: yellow arrow = current effective front", fill=(20, 20, 20), font=font)
    output_path.parent.mkdir(parents=True, exist_ok=True)
    canvas.save(output_path)
    return output_path


def make_render_pose_feedback_sheet(reference_image: Path, rendered_pose_view: Path, output_path: Path) -> Path:
    with Image.open(reference_image) as ref, Image.open(rendered_pose_view) as pose:
        ref = ref.convert("RGB")
        pose = pose.convert("RGB")
        target_h = 760
        ref.thumbnail((760, target_h), Image.Resampling.LANCZOS)
        pose.thumbnail((980, target_h), Image.Resampling.LANCZOS)
        label_h = 42
        width = ref.width + pose.width
        height = max(ref.height, pose.height) + label_h
        canvas = Image.new("RGB", (width, height), (245, 242, 235))
        draw = ImageDraw.Draw(canvas)
        try:
            from PIL import ImageFont

            font = ImageFont.load_default()
        except Exception:
            font = None
        canvas.paste(ref, (0, label_h))
        canvas.paste(pose, (ref.width, label_h))
        draw.rectangle([0, 0, ref.width - 1, label_h - 1], fill=(232, 226, 214))
        draw.rectangle([ref.width, 0, width - 1, label_h - 1], fill=(232, 226, 214))
        draw.text((10, 14), "reference image", fill=(20, 20, 20), font=font)
        draw.text((ref.width + 10, 14), "current top-down render with ids and front arrows", fill=(20, 20, 20), font=font)
        output_path.parent.mkdir(parents=True, exist_ok=True)
        canvas.save(output_path)
    return output_path


def make_final_render_pose_feedback_sheet(
    reference_image: Path,
    estimated_render: Path,
    topdown_pose_view: Path,
    output_path: Path,
) -> Path:
    with Image.open(reference_image) as ref, Image.open(estimated_render) as render, Image.open(topdown_pose_view) as topdown:
        ref = ref.convert("RGB")
        render = render.convert("RGB")
        topdown = topdown.convert("RGB")
        target_h = 720
        ref.thumbnail((640, target_h), Image.Resampling.LANCZOS)
        render.thumbnail((760, target_h), Image.Resampling.LANCZOS)
        topdown.thumbnail((760, target_h), Image.Resampling.LANCZOS)
        label_h = 42
        width = ref.width + render.width + topdown.width
        height = max(ref.height, render.height, topdown.height) + label_h
        canvas = Image.new("RGB", (width, height), (245, 242, 235))
        draw = ImageDraw.Draw(canvas)
        try:
            from PIL import ImageFont

            font = ImageFont.load_default()
        except Exception:
            font = None
        x = 0
        for image, label in (
            (ref, "reference image"),
            (render, "current estimated-camera render"),
            (topdown, "top-down ids and effective front arrows"),
        ):
            canvas.paste(image, (x, label_h))
            draw.rectangle([x, 0, x + image.width - 1, label_h - 1], fill=(232, 226, 214))
            draw.text((x + 10, 14), label, fill=(20, 20, 20), font=font)
            x += image.width
        output_path.parent.mkdir(parents=True, exist_ok=True)
        canvas.save(output_path)
    return output_path


def _reference_bbox_for_pose_crop(obj: dict[str, Any]) -> list[float] | None:
    bbox = _normalized_bbox(obj.get("image_bbox"))
    if bbox:
        return bbox
    instance = obj.get("reference_instance")
    if isinstance(instance, dict):
        return _normalized_bbox(instance.get("bbox") or instance.get("image_bbox"))
    return None


def _reference_pose_matching_bbox(plan: dict[str, Any], obj: dict[str, Any]) -> tuple[list[float] | None, dict[str, Any]]:
    bbox = _reference_bbox_for_pose_crop(obj)
    if not bbox:
        return None, {"source": "none"}
    cleaned = list(bbox)
    notes: list[str] = []
    obj_id = str(obj.get("id") or "")
    obj_key = (
        str(obj.get("reference_instance", {}).get("duplicate_key") or "")
        if isinstance(obj.get("reference_instance"), dict)
        else ""
    )
    obj_category = str(obj.get("category") or "").lower()
    obj_h = bbox[3] - bbox[1]
    obj_w = bbox[2] - bbox[0]
    min_height = max(0.055, obj_h * 0.55)
    for other in plan.get("objects", []) if isinstance(plan.get("objects"), list) else []:
        if not isinstance(other, dict) or str(other.get("id") or "") == obj_id:
            continue
        other_bbox = _reference_bbox_for_pose_crop(other)
        if not other_bbox:
            continue
        other_key = (
            str(other.get("reference_instance", {}).get("duplicate_key") or "")
            if isinstance(other.get("reference_instance"), dict)
            else ""
        )
        other_category = str(other.get("category") or "").lower()
        obj_is_directional_seat = _is_seating_front_directional(obj) and ("chair" in obj_category or "seat" in obj_category)
        other_is_directional_seat = _is_seating_front_directional(other) and ("chair" in other_category or "seat" in other_category)
        same_repeated_kind = obj_is_directional_seat and other_is_directional_seat and (
            bool(obj_key and obj_key == other_key) or obj_category == other_category or "chair" in obj_category or "chair" in other_category
        )
        if not same_repeated_kind:
            continue
        overlap_x = min(cleaned[2], other_bbox[2]) - max(cleaned[0], other_bbox[0])
        overlap_y = min(cleaned[3], other_bbox[3]) - max(cleaned[1], other_bbox[1])
        if overlap_x <= 0.0 or overlap_y <= 0.0:
            continue
        x_overlap_ratio = overlap_x / max(obj_w, 1e-6)
        other_starts_below = other_bbox[1] > bbox[1] + obj_h * 0.42
        overlap_touches_lower_half = other_bbox[1] < cleaned[3] and other_bbox[1] > cleaned[1] + obj_h * 0.35
        if x_overlap_ratio >= 0.35 and other_starts_below and overlap_touches_lower_half:
            proposed_y2 = _clamp(other_bbox[1] + obj_h * 0.015, cleaned[1] + min_height, cleaned[3])
            if proposed_y2 < cleaned[3] - obj_h * 0.08:
                notes.append(
                    f"lower_foreground_overlap_removed:{other.get('id')} y2 {cleaned[3]:.3f}->{proposed_y2:.3f}"
                )
                cleaned[3] = proposed_y2
    if notes:
        tightened = list(cleaned)
        proposed_x1 = _clamp(tightened[0] + obj_w * 0.08, tightened[0], tightened[2] - obj_w * 0.55)
        proposed_y1 = _clamp(tightened[1] + obj_h * 0.12, tightened[1], tightened[3] - min_height)
        if proposed_x1 > tightened[0] + 1e-5:
            notes.append(f"foreground_clean_crop_tightened_x1 {tightened[0]:.3f}->{proposed_x1:.3f}")
            tightened[0] = proposed_x1
        if proposed_y1 > tightened[1] + 1e-5:
            notes.append(f"foreground_clean_crop_tightened_y1 {tightened[1]:.3f}->{proposed_y1:.3f}")
            tightened[1] = proposed_y1
        cleaned = tightened
        return cleaned, {"source": "foreground_overlap_cleaned", "original_bbox": bbox, "notes": notes}
    return bbox, {"source": "original_bbox"}


def _final_pose_instance_candidates(plan: dict[str, Any]) -> list[dict[str, Any]]:
    candidates = [
        obj
        for obj in plan.get("objects", [])
        if isinstance(obj, dict) and obj.get("id") and _is_seating_front_directional(obj) and _reference_bbox_for_pose_crop(obj)
    ]
    if len(candidates) <= 1:
        return []
    candidates.sort(key=lambda obj: (str(obj.get("category") or ""), float(obj.get("y", 0.0)), float(obj.get("x", 0.0)), str(obj.get("id"))))
    return candidates[:FINAL_POSE_INSTANCE_MAX_OBJECTS]


def _crop_normalized_instance(image: Image.Image, bbox: list[float], padding: float = 0.75) -> Image.Image:
    width, height = image.size
    x1, y1, x2, y2 = bbox
    bw = x2 - x1
    bh = y2 - y1
    x1 = _clamp(x1 - bw * padding, 0.0, 1.0)
    x2 = _clamp(x2 + bw * padding, 0.0, 1.0)
    y1 = _clamp(y1 - bh * padding, 0.0, 1.0)
    y2 = _clamp(y2 + bh * padding, 0.0, 1.0)
    return image.crop((int(x1 * width), int(y1 * height), int(x2 * width), int(y2 * height)))


def _draw_local_topdown_pose_crop(plan: dict[str, Any], focus: dict[str, Any], size: tuple[int, int] = (330, 230)) -> Image.Image:
    room = plan.get("room") if isinstance(plan.get("room"), dict) else {"width": 7.0, "length": 5.0}
    room_width = float(room.get("width", 7.0) or 7.0)
    room_length = float(room.get("length", 5.0) or 5.0)
    focus_x = float(focus.get("x", 0.0) or 0.0)
    focus_y = float(focus.get("y", 0.0) or 0.0)
    window = max(1.8, max(float(focus.get("dimensions", {}).get("width", 0.8)), float(focus.get("dimensions", {}).get("length", 0.8))) * 3.0)
    x_min = _clamp(focus_x - window / 2.0, 0.0, max(room_width - window, 0.0))
    y_min = _clamp(focus_y - window / 2.0, 0.0, max(room_length - window, 0.0))
    x_max = min(room_width, x_min + window)
    y_max = min(room_length, y_min + window)
    if x_max - x_min < 1e-4:
        x_min, x_max = 0.0, room_width
    if y_max - y_min < 1e-4:
        y_min, y_max = 0.0, room_length

    canvas = Image.new("RGB", size, (238, 234, 225))
    draw = ImageDraw.Draw(canvas)
    try:
        from PIL import ImageFont

        font = ImageFont.load_default()
    except Exception:
        font = None
    margin = 18
    scale = min((size[0] - margin * 2) / max(x_max - x_min, 1e-6), (size[1] - margin * 2) / max(y_max - y_min, 1e-6))

    def px(x: float, y: float) -> tuple[float, float]:
        return margin + (x - x_min) * scale, size[1] - margin - (y - y_min) * scale

    draw.rectangle([margin, margin, size[0] - margin, size[1] - margin], outline=(80, 80, 80), width=2)
    nearby: list[dict[str, Any]] = []
    for obj in plan.get("objects", []):
        if not isinstance(obj, dict) or not obj.get("id"):
            continue
        x = float(obj.get("x", 0.0) or 0.0)
        y = float(obj.get("y", 0.0) or 0.0)
        if x_min - 0.2 <= x <= x_max + 0.2 and y_min - 0.2 <= y <= y_max + 0.2:
            nearby.append(obj)
    for obj in nearby:
        cx, cy = px(float(obj.get("x", 0.0) or 0.0), float(obj.get("y", 0.0) or 0.0))
        fw, fl = _rotated_footprint(obj)
        w = max(6.0, fw * scale)
        h = max(6.0, fl * scale)
        focus_obj = str(obj.get("id")) == str(focus.get("id"))
        color = (48, 150, 92) if _is_seating_object(obj) else (92, 128, 184)
        if focus_obj:
            color = (216, 92, 58)
        draw.rectangle([cx - w / 2, cy - h / 2, cx + w / 2, cy + h / 2], fill=color, outline=(20, 20, 20), width=3 if focus_obj else 1)
        if _is_directional_front_object(obj):
            yaw = math.radians(_effective_yaw(obj))
            arrow_len = max(16.0, min(w, h) * 0.65)
            draw.line([cx, cy, cx + math.cos(yaw) * arrow_len, cy - math.sin(yaw) * arrow_len], fill=(245, 208, 45), width=4)
        label = str(obj.get("id") or "")[:18]
        draw.text((cx + 4, cy + 4), label, fill=(0, 0, 0), font=font)
    draw.text((8, 6), f"focus {focus.get('id')} yaw={_effective_yaw(focus):.0f}", fill=(0, 0, 0), font=font)
    return canvas


def make_instance_aware_final_render_pose_feedback_sheet(
    reference_image: Path,
    estimated_render: Path,
    topdown_pose_view: Path,
    plan: dict[str, Any],
    output_path: Path,
) -> Path:
    base_path = make_final_render_pose_feedback_sheet(reference_image, estimated_render, topdown_pose_view, output_path)
    candidates = _final_pose_instance_candidates(plan)
    if not candidates:
        return base_path
    with Image.open(base_path) as base, Image.open(reference_image) as ref, Image.open(estimated_render) as render:
        base = base.convert("RGB")
        ref = ref.convert("RGB")
        render = render.convert("RGB")
        row_h = 190
        label_w = 220
        ref_w = 230
        render_w = 260
        local_w = 360
        rows = min(len(candidates), FINAL_POSE_INSTANCE_MAX_OBJECTS)
        width = max(base.width, label_w + ref_w + render_w + local_w)
        height = base.height + 34 + rows * row_h
        canvas = Image.new("RGB", (width, height), (245, 242, 235))
        canvas.paste(base, (0, 0))
        draw = ImageDraw.Draw(canvas)
        try:
            from PIL import ImageFont

            font = ImageFont.load_default()
        except Exception:
            font = None
        y = base.height
        draw.rectangle([0, y, width, y + 33], fill=(220, 214, 202))
        draw.text(
            (10, y + 10),
            "repeated seating instance crops: reference crop + current render crop + current local top-down pose",
            fill=(0, 0, 0),
            font=font,
        )
        y += 34
        for obj in candidates:
            bbox = _reference_bbox_for_pose_crop(obj)
            if not bbox:
                continue
            draw.rectangle([0, y, width, y + row_h - 1], fill=(250, 248, 243), outline=(210, 205, 196))
            text = (
                f"{obj.get('id')}\n"
                f"{obj.get('category')}\n"
                f"x={float(obj.get('x', 0.0)):.2f} y={float(obj.get('y', 0.0)):.2f}\n"
                f"effective_yaw={_effective_yaw(obj):.0f}"
            )
            draw.text((10, y + 12), text, fill=(0, 0, 0), font=font)
            ref_crop = _crop_normalized_instance(ref, bbox)
            ref_crop.thumbnail((ref_w - 18, row_h - 24), Image.Resampling.LANCZOS)
            ref_x = label_w + (ref_w - ref_crop.width) // 2
            canvas.paste(ref_crop, (ref_x, y + (row_h - ref_crop.height) // 2))
            render_crop = _crop_normalized_instance(render, bbox)
            render_crop.thumbnail((render_w - 18, row_h - 24), Image.Resampling.LANCZOS)
            render_x = label_w + ref_w + (render_w - render_crop.width) // 2
            canvas.paste(render_crop, (render_x, y + (row_h - render_crop.height) // 2))
            local = _draw_local_topdown_pose_crop(plan, obj, (local_w - 20, row_h - 20))
            canvas.paste(local, (label_w + ref_w + render_w + 10, y + 10))
            y += row_h
        output_path.parent.mkdir(parents=True, exist_ok=True)
        canvas.save(output_path)
    return output_path


def make_reference_instance_pose_grounding_sheet(
    reference_image: Path,
    topdown_pose_view: Path,
    plan: dict[str, Any],
    output_path: Path,
) -> Path:
    candidates = _final_pose_instance_candidates(plan)
    with Image.open(reference_image) as ref, Image.open(topdown_pose_view) as topdown:
        ref = ref.convert("RGB")
        topdown = topdown.convert("RGB")
        overview_h = 560
        ref_overview = ref.copy()
        topdown_overview = topdown.copy()
        ref_overview.thumbnail((620, overview_h), Image.Resampling.LANCZOS)
        topdown_overview.thumbnail((760, overview_h), Image.Resampling.LANCZOS)
        label_h = 36
        row_h = 190
        label_w = 230
        ref_w = 260
        local_w = 420
        rows = min(len(candidates), FINAL_POSE_INSTANCE_MAX_OBJECTS)
        width = max(ref_overview.width + topdown_overview.width, label_w + ref_w + local_w)
        height = max(ref_overview.height, topdown_overview.height) + label_h + 34 + rows * row_h
        canvas = Image.new("RGB", (width, height), (245, 242, 235))
        draw = ImageDraw.Draw(canvas)
        try:
            from PIL import ImageFont

            font = ImageFont.load_default()
        except Exception:
            font = None
        x = 0
        for image, label in ((ref_overview, "reference image"), (topdown_overview, "current top-down ids and front arrows")):
            canvas.paste(image, (x, label_h))
            draw.rectangle([x, 0, x + image.width - 1, label_h - 1], fill=(232, 226, 214))
            draw.text((x + 10, 11), label, fill=(20, 20, 20), font=font)
            x += image.width
        y = max(ref_overview.height, topdown_overview.height) + label_h
        draw.rectangle([0, y, width, y + 33], fill=(220, 214, 202))
        draw.text(
            (10, y + 10),
            "reference pose grounding rows: target object reference crop + local top-down id/arrow crop",
            fill=(0, 0, 0),
            font=font,
        )
        y += 34
        for obj in candidates[:FINAL_POSE_INSTANCE_MAX_OBJECTS]:
            bbox = _reference_bbox_for_pose_crop(obj)
            if not bbox:
                continue
            draw.rectangle([0, y, width, y + row_h - 1], fill=(250, 248, 243), outline=(210, 205, 196))
            text = (
                f"{obj.get('id')}\n"
                f"{obj.get('category')}\n"
                f"bbox={','.join(f'{v:.3f}' for v in bbox)}\n"
                f"x={float(obj.get('x', 0.0)):.2f} y={float(obj.get('y', 0.0)):.2f}\n"
                f"effective_yaw={_effective_yaw(obj):.0f}"
            )
            draw.text((10, y + 12), text, fill=(0, 0, 0), font=font)
            ref_crop = _crop_normalized_instance(ref, bbox, padding=1.0)
            ref_crop.thumbnail((ref_w - 18, row_h - 24), Image.Resampling.LANCZOS)
            canvas.paste(ref_crop, (label_w + (ref_w - ref_crop.width) // 2, y + (row_h - ref_crop.height) // 2))
            local = _draw_local_topdown_pose_crop(plan, obj, (local_w - 20, row_h - 20))
            canvas.paste(local, (label_w + ref_w + 10, y + 10))
            y += row_h
        output_path.parent.mkdir(parents=True, exist_ok=True)
        canvas.save(output_path)
    return output_path


POSE_CANDIDATE_YAWS = (0, 45, 90, 135, 180, 225, 270, 315)


def _draw_reference_overview_with_pose_candidates(
    reference_image: Image.Image,
    objects: list[dict[str, Any]],
    *,
    size: tuple[int, int] = (760, 520),
) -> Image.Image:
    overview = reference_image.copy().convert("RGB")
    overview.thumbnail(size, Image.Resampling.LANCZOS)
    draw = ImageDraw.Draw(overview)
    width, height = reference_image.size
    scale_x = overview.width / max(width, 1)
    scale_y = overview.height / max(height, 1)
    palette = [(230, 64, 64), (48, 190, 70), (60, 130, 240), (230, 150, 40), (180, 70, 220)]
    for index, obj in enumerate(objects):
        bbox = _reference_bbox_for_pose_crop(obj)
        if not bbox:
            continue
        color = palette[index % len(palette)]
        x1 = bbox[0] * width * scale_x
        y1 = bbox[1] * height * scale_y
        x2 = bbox[2] * width * scale_x
        y2 = bbox[3] * height * scale_y
        draw.rectangle([x1, y1, x2, y2], outline=color, width=4)
        draw.ellipse([x1 - 8, y1 - 8, x2 + 8, y2 + 8], outline=color, width=3)
        label = str(obj.get("reference_instance", {}).get("reference_label") or obj.get("id") or "")
        draw.text((x1 + 3, max(0, y1 - 16)), f"{label} / {obj.get('id')}", fill=color)
    return overview


def _candidate_pose_topdown_grid(plan: dict[str, Any], obj: dict[str, Any], size: tuple[int, int] = (640, 220)) -> Image.Image:
    columns = len(POSE_CANDIDATE_YAWS)
    cell_w = max(72, size[0] // columns)
    cell_h = size[1]
    canvas = Image.new("RGB", (cell_w * columns, cell_h), (245, 242, 235))
    draw = ImageDraw.Draw(canvas)
    for index, yaw in enumerate(POSE_CANDIDATE_YAWS):
        candidate_plan = deepcopy(plan)
        candidate_obj = None
        for item in candidate_plan.get("objects", []):
            if isinstance(item, dict) and str(item.get("id")) == str(obj.get("id")):
                candidate_obj = item
                break
        if candidate_obj is None:
            continue
        _set_effective_yaw(candidate_obj, float(yaw), allow_fine_seating=True)
        crop = _draw_local_topdown_pose_crop(candidate_plan, candidate_obj, (cell_w, cell_h - 28))
        x = index * cell_w
        canvas.paste(crop, (x, 0))
        draw.rectangle([x, 0, x + cell_w - 1, cell_h - 1], outline=(150, 145, 135), width=1)
        draw.text((x + 8, cell_h - 22), f"yaw {yaw}", fill=(0, 0, 0))
    return canvas


def _render_candidate_thumbnail(image_path: Path, size: tuple[int, int]) -> Image.Image:
    canvas = Image.new("RGB", size, (246, 243, 236))
    if not image_path.exists():
        draw = ImageDraw.Draw(canvas)
        draw.rectangle([0, 0, size[0] - 1, size[1] - 1], outline=(180, 80, 80), width=2)
        draw.text((8, size[1] // 2 - 6), "missing render", fill=(120, 20, 20))
        return canvas
    with Image.open(image_path) as image:
        image = image.convert("RGBA")
        alpha = image.getchannel("A")
        bbox = alpha.getbbox()
        if bbox:
            image = image.crop(bbox)
        image.thumbnail((size[0] - 12, size[1] - 30), Image.Resampling.LANCZOS)
        background = Image.new("RGBA", image.size, (246, 243, 236, 255))
        background.alpha_composite(image)
        rgb = background.convert("RGB")
        canvas.paste(rgb, ((size[0] - rgb.width) // 2, max(4, (size[1] - 28 - rgb.height) // 2)))
    return canvas


def _candidate_pose_render_grid(
    render_manifest: dict[str, Any],
    obj: dict[str, Any],
    size: tuple[int, int] = (760, 240),
) -> Image.Image:
    columns = len(POSE_CANDIDATE_YAWS)
    cell_w = max(84, size[0] // columns)
    cell_h = size[1]
    canvas = Image.new("RGB", (cell_w * columns, cell_h), (245, 242, 235))
    draw = ImageDraw.Draw(canvas)
    renders = (
        render_manifest.get("objects", {})
        .get(str(obj.get("id")), {})
        .get("renders", {})
        if isinstance(render_manifest.get("objects"), dict)
        else {}
    )
    for index, yaw in enumerate(POSE_CANDIDATE_YAWS):
        label = str(int(yaw))
        x = index * cell_w
        thumb = _render_candidate_thumbnail(Path(str(renders.get(label, ""))), (cell_w, cell_h - 26))
        canvas.paste(thumb, (x, 0))
        draw.rectangle([x, 0, x + cell_w - 1, cell_h - 1], outline=(150, 145, 135), width=1)
        draw.text((x + 8, cell_h - 21), f"yaw {label}", fill=(0, 0, 0))
    return canvas


def make_reference_pose_candidate_matching_sheet(
    reference_image: Path,
    plan: dict[str, Any],
    output_path: Path,
    *,
    object_ids: list[str] | None = None,
) -> Path:
    candidates = _final_pose_instance_candidates(plan)
    if object_ids:
        wanted = set(object_ids)
        candidates = [obj for obj in candidates if str(obj.get("id")) in wanted]
    if not candidates:
        raise ValueError("no pose candidate matching objects")
    with Image.open(reference_image) as ref_image:
        ref = ref_image.convert("RGB")
        overview = _draw_reference_overview_with_pose_candidates(ref, candidates)
        row_h = 270
        label_w = 220
        exact_w = 190
        grid_w = 720
        width = max(overview.width, label_w + exact_w + grid_w + 40)
        height = 54 + overview.height + len(candidates) * row_h
        canvas = Image.new("RGB", (width, height), (245, 242, 235))
        draw = ImageDraw.Draw(canvas)
        draw.text((14, 12), "Reference pose candidate matching: choose the candidate yaw whose local pose best matches the circled reference instance.", fill=(0, 0, 0))
        canvas.paste(overview, (14, 44))
        y = 54 + overview.height
        ref_w, ref_h = ref.size
        for obj in candidates:
            bbox, bbox_report = _reference_pose_matching_bbox(plan, obj)
            if not bbox:
                continue
            draw.rectangle([0, y, width, y + row_h - 1], fill=(250, 248, 243), outline=(210, 205, 196))
            label = str(obj.get("reference_instance", {}).get("reference_label") or "")
            text = (
                f"{label} / {obj.get('id')}\n"
                f"{obj.get('category')}\n"
                f"bbox={','.join(f'{v:.3f}' for v in bbox)}\n"
                f"pose_bbox_source={bbox_report.get('source')}\n"
                f"current_eff={_effective_yaw(obj):.0f}"
            )
            draw.text((12, y + 16), text, fill=(0, 0, 0))
            exact = ref.crop((int(bbox[0] * ref_w), int(bbox[1] * ref_h), int(bbox[2] * ref_w), int(bbox[3] * ref_h)))
            exact = exact.resize((170, 170), Image.Resampling.LANCZOS)
            canvas.paste(exact, (label_w, y + 34))
            draw.rectangle([label_w, y + 34, label_w + exact.width, y + 34 + exact.height], outline=(160, 60, 60), width=2)
            draw.text((label_w, y + 210), "exact bbox crop", fill=(0, 0, 0))
            grid = _candidate_pose_topdown_grid(plan, obj, (grid_w, row_h - 34))
            canvas.paste(grid, (label_w + exact_w + 20, y + 10))
            draw.text((label_w + exact_w + 20, y + row_h - 22), "candidate yaw local top-down panels", fill=(0, 0, 0))
            y += row_h
        output_path.parent.mkdir(parents=True, exist_ok=True)
        canvas.save(output_path)
    return output_path


