def build_reference_pose_candidate_matching_prompt(scene_prompt: str, plan: dict[str, Any], object_ids: list[str] | None = None) -> str:
    candidates = _final_pose_instance_candidates(plan)
    if object_ids:
        wanted = set(object_ids)
        candidates = [obj for obj in candidates if str(obj.get("id")) in wanted]
    compact = []
    for obj in candidates:
        pose_bbox, bbox_report = _reference_pose_matching_bbox(plan, obj)
        compact.append(
            {
                "id": obj.get("id"),
                "reference_label": obj.get("reference_instance", {}).get("reference_label") if isinstance(obj.get("reference_instance"), dict) else None,
                "category": obj.get("category"),
                "description": obj.get("description"),
                "image_bbox": pose_bbox,
                "pose_bbox_report": bbox_report,
                "current_effective_yaw": _effective_yaw(obj),
            }
        )
    return f"""
You are the pose candidate matching agent for TreeSAGE.
The attached sheet contains a full reference image with target instances circled, each target's exact bbox crop, and eight candidate panels labeled yaw 0,45,90,135,180,225,270,315.
When real single-asset rendered candidates are shown, treat this as a visual retrieval task: compare the exact reference bbox crop on the left against the rendered candidate images on the right and choose the closest projected visual match.

Scene prompt:
{scene_prompt}

Yaw convention:
- 0 means front/right/east.
- 90 means front/up/north.
- 180 means front/left/west.
- 270 means front/down/south.
- Diagonal candidates are 45,135,225,315.

Objects:
{json.dumps(compact, ensure_ascii=False, indent=2)}

Return only JSON:
{{
  "schema": "tree_sage_reference_pose_candidate_matching_agent_v1",
  "objects": [
    {{
      "id": "existing_object_id",
      "chosen_effective_yaw": 0,
      "confidence": 0.0,
      "evidence": "short visual matching reason",
      "rejected_yaws": [90, 180],
      "ambiguity_notes": "short note or empty"
    }}
  ],
  "notes": ["short notes"]
}}

Rules:
- Use the colored/circled full-reference instance to avoid mixing repeated chairs.
- If rendered candidates are shown, do not infer the answer from functional front/open direction, table direction, pouf direction, room center, or cluster center. Use those only to identify which reference instance is being evaluated.
- Compare projection-level visual cues between the exact reference crop and each rendered candidate: visible back-panel side, armrest silhouette, cushion outline, base/leg line, left/right thickness, and whether the chair reads as a side view, front view, rear view, or diagonal view.
- Treat this as left-image versus right-panel image matching. For each row, compare the exact reference bbox crop against every rendered yaw panel in that same row; do not compare against other rows or other object ids.
- If the bbox crop contains another chair or foreground object, ignore the non-target pixels using the full-reference circled instance and the row label. Do not let a foreground/overlapping chair determine the target yaw.
- A slight slant of an armrest or cushion caused by perspective is not enough to choose a diagonal yaw. Choose a diagonal yaw only when the entire rendered candidate's projected silhouette is clearly closer than the nearest cardinal candidate.
- For 180 versus 225 specifically: if the crop mostly reads as a left-facing side view with the chair body extending left and the back/closed side on the right, choose 180. Choose 225 only if the whole chair silhouette, base line, back panel, and armrests are visibly diagonal, not merely because one armrest or cushion edge is slanted.
- If the reference crop and the generated asset shape do not match well, set confidence below 0.65 and mention asset-shape mismatch in ambiguity_notes instead of forcing a high-confidence yaw.
- If an asset-shape mismatch makes two yaw panels similarly plausible, prefer the nearest cardinal yaw and mark the result ambiguous/low confidence instead of choosing a diagonal.
- For chairs/seating without reliable rendered candidates, identify the back/closed side and arm structure in the exact crop; the functional front/open direction is the opposite side.
- Use the full-reference circled instance only to disambiguate repeated chairs and crop perspective. Never override the exact crop vs rendered-candidate visual match with a generic "faces inward" assumption.
- Select one of the displayed candidate yaw labels exactly.
- If two rendered candidates are close, choose the simpler cardinal yaw unless the rendered diagonal is plainly more similar in silhouette.
- In evidence, name the visual cue you used, such as "back/closed side is on the right, so front is left."
- Do not invent object ids.
""".strip()


def run_reference_pose_candidate_matching_agent(
    scene_prompt: str,
    plan: dict[str, Any],
    feedback_sheet: Path,
    output_dir: Path,
    model: str | None,
    *,
    object_ids: list[str] | None = None,
) -> dict[str, Any]:
    return run_codex_reference_json_agent(
        "reference_pose_candidate_matching",
        build_reference_pose_candidate_matching_prompt(scene_prompt, plan, object_ids),
        feedback_sheet,
        output_dir,
        model,
    )


def merge_reference_pose_candidate_matching(
    plan: dict[str, Any],
    matching_report: dict[str, Any],
    *,
    apply_now: bool = True,
) -> dict[str, Any]:
    converted = {"schema": "tree_sage_reference_instance_pose_grounding_agent_v1", "objects": [], "notes": matching_report.get("notes", [])}
    for item in matching_report.get("objects", []) if isinstance(matching_report.get("objects"), list) else []:
        if not isinstance(item, dict):
            continue
        converted["objects"].append(
            {
                "id": item.get("id"),
                "target_effective_yaw": item.get("chosen_effective_yaw"),
                "confidence": item.get("confidence", 0.0),
                "ambiguous": False,
                "reference_pose": f"candidate_yaw_{item.get('chosen_effective_yaw')}",
                "evidence": item.get("evidence") or item.get("ambiguity_notes") or "",
            }
        )
    if not apply_now:
        objects = {str(obj.get("id")): obj for obj in plan.get("objects", []) if isinstance(obj, dict)}
        matched: list[dict[str, Any]] = []
        skipped: list[dict[str, Any]] = []
        for item in converted["objects"]:
            object_id = str(item.get("id") or "")
            obj = objects.get(object_id)
            if not obj:
                skipped.append({"item": item, "reason": "unknown_object"})
                continue
            if not _is_seating_front_directional(obj):
                skipped.append({"item": item, "reason": "object_not_directional_seating"})
                continue
            if "target_effective_yaw" not in item:
                skipped.append({"item": item, "reason": "missing_target_effective_yaw"})
                continue
            confidence = _clamp(_safe_float(item.get("confidence"), 0.0), 0.0, 1.0)
            target = _round_yaw_for_object(obj, _safe_float(item.get("target_effective_yaw"), _effective_yaw(obj)))
            before_effective = _effective_yaw(obj)
            matched.append(
                {
                    "object_id": object_id,
                    "target_effective_yaw": target,
                    "current_effective_yaw": before_effective,
                    "confidence": confidence,
                    "would_change": abs((target - before_effective + 180.0) % 360.0 - 180.0) > 1e-3,
                    "reference_pose": str(item.get("reference_pose") or ""),
                    "evidence": str(item.get("evidence") or ""),
                }
            )
        return {
            "schema": "tree_sage_reference_pose_candidate_matching_merge_v1",
            "enabled": True,
            "ok": True,
            "apply_enabled": False,
            "matched": matched,
            "matched_count": len(matched),
            "applied": [],
            "applied_count": 0,
            "changed_count": 0,
            "skipped": skipped,
            "raw_matching_report": matching_report,
        }
    report = merge_reference_instance_pose_grounding(plan, converted, apply_now=apply_now)
    report["schema"] = "tree_sage_reference_pose_candidate_matching_merge_v1"
    report["apply_enabled"] = True
    report["matched_count"] = report.get("applied_count", 0)
    report["raw_matching_report"] = matching_report
    return report


def make_reference_vs_render_sheet(reference_image: Path, estimated_render: Path, output_path: Path, render_label: str) -> Path:
    with Image.open(reference_image) as ref, Image.open(estimated_render) as render:
        ref = ref.convert("RGB")
        render = render.convert("RGB")
        target_h = 900
        ref.thumbnail((900, target_h), Image.Resampling.LANCZOS)
        render.thumbnail((900, target_h), Image.Resampling.LANCZOS)
        label_h = 36
        width = ref.width + render.width
        height = max(ref.height, render.height) + label_h
        canvas = Image.new("RGB", (width, height), (255, 255, 255))
        draw = ImageDraw.Draw(canvas)
        try:
            from PIL import ImageFont

            font = ImageFont.load_default()
        except Exception:
            font = None
        canvas.paste(ref, (0, label_h))
        canvas.paste(render, (ref.width, label_h))
        draw.text((12, 10), "Reference", fill=(0, 0, 0), font=font)
        draw.text((ref.width + 12, 10), render_label, fill=(0, 0, 0), font=font)
        output_path.parent.mkdir(parents=True, exist_ok=True)
        canvas.save(output_path)
    return output_path


def build_render_pose_feedback_prompt(
    plan: dict[str, Any],
    scene_hypergraph: dict[str, Any],
    reference_grounding_report: dict[str, Any],
    *,
    final_render: bool = False,
) -> str:
    relevant = []
    for obj in plan.get("objects", []):
        if not isinstance(obj, dict) or not obj.get("id"):
            continue
        if not (_is_directional_front_object(obj) or _is_wall_attached_object(obj)):
            continue
        relevant.append(
            {
                "id": obj.get("id"),
                "category": obj.get("category"),
                "description": obj.get("description"),
                "x": round(float(obj.get("x", 0.0)), 4),
                "y": round(float(obj.get("y", 0.0)), 4),
                "yaw": float(obj.get("yaw", 0.0) or 0.0),
                "front_yaw_offset_degrees": float(obj.get("front_yaw_offset_degrees", 0.0) or 0.0),
                "footprint_yaw_offset_degrees": float(obj.get("footprint_yaw_offset_degrees", 0.0) or 0.0),
                "effective_yaw": _effective_yaw(obj),
                "asset_canonical_front": obj.get("asset_canonical_front"),
            }
        )
    compact_grounding = _compact_reference_grounding_for_agents(reference_grounding_report)
    compact_hypergraph = {
        "factor_count": scene_hypergraph.get("factor_count", 0),
        "factors": scene_hypergraph.get("factors", [])[:12],
    }
    if final_render:
        image_description = (
            "The attached image has scene-level panels plus repeated-object instance panels: the reference image, "
            "the current estimated-camera 3D render, a top-down ID map, and per-object reference/current-render/top-down crops. "
            "Yellow arrows show each object's current effective front direction."
        )
        precision_rule = (
            "- Use the estimated-camera render to find visual pose errors, then use the top-down labels to choose object ids.\n"
            "- For repeated chairs, match by the per-object reference crop, current-render crop, local neighborhood, wall side, and table side before editing.\n"
            "- For every repeated seating instance row, explicitly decide whether the current yellow arrow matches the reference crop. "
            "If it does not, output an edit for that object instead of relying on the whole-scene impression.\n"
            "- For a local cluster of repeated armchairs/lounge chairs beside a wall or cabinet, audit each visible instance separately. "
            "Do not assume same-cluster seats share one inward-facing direction; only group them when the reference visibly shows the same pose for every instance.\n"
            "- Treat scene-hypergraph face-anchor directions as proposals, not ground truth; override them when the rendered/reference cluster pose visibly disagrees.\n"
            "- For repeated seating, prefer operation=set_effective_yaw with an explicit target yaw; avoid set_facing unless the target-center direction is exactly the intended pose.\n"
            "- For chairs/armchairs/lounge seats/sofas, you may use 45-degree effective_yaw values: 0,45,90,135,180,225,270,315."
        )
    else:
        image_description = (
            "The attached image compares the reference image with the current top-down render. "
            "The right panel labels object ids; yellow arrows show each object's current effective front direction."
        )
        precision_rule = "- Prefer high precision over completeness."
    return f"""
You are the render-based pose correction agent for TreeSAGE.
{image_description}
Review only clear pose/orientation mistakes. Output bounded edits, not a new scene.

Current directional objects:
{json.dumps(relevant, ensure_ascii=False, indent=2)}

World effective yaw convention:
- 0 means the functional front points right/east (+x).
- 90 means the functional front points toward the back/north wall (+y).
- 180 means the functional front points left/west (-x).
- 270 means the functional front points toward the front/south side (-y).
- For beds, "functional front" means the visible headboard/pillow-facing side, not the footboard/open foot end. A bed with a headboard against wall_north/back wall normally has its headboard/pillow-facing side pointing into the room, effective_yaw=270, after the asset canonical-front axis is corrected.
- A drawer/cabinet front facing into the room from wall_north/back wall is 270, not 0.
- A drawer/cabinet front facing into the room from wall_south/front wall is 90.
- A drawer/cabinet front facing into the room from wall_east/right wall is 180.
- A drawer/cabinet front facing into the room from wall_west/left wall is 0.
- Bedside tables beside a bed with a wall_north headboard should use effective_yaw=270 when their drawers face the room/viewer.

Scene hypergraph:
{json.dumps(compact_hypergraph, ensure_ascii=False, indent=2)}

Reference instance map:
{json.dumps(compact_grounding, ensure_ascii=False, indent=2)}

Return only JSON:
{{
  "schema": "tree_sage_render_pose_feedback_agent_v1",
  "visual_score": 0.0,
  "instance_audits": [
    {{
      "object_id": "existing_object_id",
      "decision": "keep|edit|uncertain",
      "target_effective_yaw": 0,
      "observed_reference_pose": "short pose description",
      "current_pose_issue": "short issue or none"
    }}
  ],
  "edits": [
    {{
      "object_id": "existing_object_id",
      "operation": "set_facing|rotate_yaw|set_effective_yaw",
      "target_id": "existing_object_id|null",
      "delta_degree": 0,
      "effective_yaw": 0,
      "confidence": 0.0,
      "reason": "short visual reason"
    }}
  ],
  "notes": ["short uncertainty notes"]
}}

Rules:
- For chairs/armchairs/lounge seats around a table, prefer operation=set_facing with target_id set to the table if the arrow does not point toward the table.
- For nightstands, dressers, cabinets, wardrobes, and drawer chests, the functional front is the visible drawer/door face; when the reference shows the drawer/door face open to the room, use set_effective_yaw even if the object is beside a bed.
- For beds, judge whether the visible headboard/pillows are on the wall side and face into the room. Do not mark a bed correct just because the footboard/open foot end points toward the camera.
- Use rotate_yaw only for a clear 180-degree front/back flip, or a clear 90-degree table/cabinet long-axis correction.
- Use set_effective_yaw when the intended front direction is visually clear from the rendered scene and reference.
- For directional seating, set_effective_yaw may use 45-degree increments when the reference chair is diagonal.
- For repeated seating rows, include one instance_audit per row. If the decision is edit, include a matching edit.
- Do not move objects. Do not edit scale.
- If labels are ambiguous or the reference does not clearly determine the pose, omit the edit.
{precision_rule}
""".strip()


def _is_bedside_front_pose_feedback_edit(obj: dict[str, Any], applied_item: dict[str, Any]) -> bool:
    if not _is_bedside_table_object(obj):
        return False
    confidence = _safe_float(applied_item.get("confidence"), 0.0)
    if confidence < 0.80:
        return False
    reason = str(applied_item.get("reason") or "").lower()
    return any(keyword in reason for keyword in ("drawer", "front", "outward", "room"))


def _is_protected_bed_wall_pose_feedback_edit(
    obj: dict[str, Any] | None,
    applied_item: dict[str, Any],
    cross_constraints: list[dict[str, Any]],
    parent: dict[str, str],
) -> bool:
    if not obj or not _is_bed_or_sofa_object(obj):
        return False
    if _semantic_token(applied_item.get("operation")) != "set_effective_yaw":
        return False
    confidence = _safe_float(applied_item.get("confidence"), 0.0)
    if confidence < 0.80:
        return False
    wall_id = _back_to_wall_target_wall(obj, cross_constraints, parent)
    if wall_id not in VIRTUAL_WALLS:
        return False
    desired = _wall_semantic_yaw(wall_id)
    after = applied_item.get("after") if isinstance(applied_item.get("after"), dict) else {}
    effective_yaw = _safe_float(after.get("effective_yaw"), _effective_yaw(obj))
    delta = abs(((effective_yaw - desired + 180.0) % 360.0) - 180.0)
    return delta <= 1e-4


def _is_protected_wall_attached_pose_feedback_edit(obj: dict[str, Any] | None, applied_item: dict[str, Any]) -> bool:
    if not obj:
        return False
    if _semantic_token(applied_item.get("operation")) != "set_effective_yaw":
        return False
    confidence = _safe_float(applied_item.get("confidence"), 0.0)
    if confidence < 0.78:
        return False
    wall_id = str(obj.get("support_id") or "")
    if wall_id not in VIRTUAL_WALLS or str(obj.get("placement_type") or "") != "attached_to_wall":
        return False
    text = _object_identity_text(obj)
    if not any(keyword in text for keyword in ("window", "wall art", "painting", "picture", "poster", "print", "mirror", "door")):
        return False
    desired = _wall_semantic_yaw(wall_id)
    after = applied_item.get("after") if isinstance(applied_item.get("after"), dict) else {}
    effective_yaw = _safe_float(after.get("effective_yaw"), _effective_yaw(obj))
    delta = abs(((effective_yaw - desired + 180.0) % 360.0) - 180.0)
    return delta <= 1e-4


