def _axis_pair_violation_residual(violation: dict[str, Any]) -> float:
    scene_gap = _safe_float(violation.get("scene_gap"), 0.0)
    required = _safe_float(violation.get("required_gap_or_threshold"), 0.0)
    relation = str(violation.get("relation") or "")
    if relation in {"same_column", "same_depth"}:
        return max(0.0, scene_gap - required)
    return max(0.0, required - scene_gap)


def _axis_pair_constraint_score(
    constraints: list[dict[str, Any]],
    objects: dict[str, dict[str, Any]],
) -> tuple[int, float]:
    violations = _reference_axis_pair_constraint_violations(constraints, objects)
    residual = sum(_axis_pair_violation_residual(violation) for violation in violations)
    return len(violations), round(float(residual), 6)


def _gap_affinity_constraint_score(
    constraints: list[dict[str, Any]],
    objects: dict[str, dict[str, Any]],
) -> tuple[int, float]:
    violations = _reference_axis_gap_affinity_violations(constraints, objects)
    residual = sum(_gap_affinity_violation_residual(violation) for violation in violations)
    return len(violations), round(float(residual), 6)


def _gap_affinity_subject_delta(
    constraint: dict[str, Any],
    objects: dict[str, dict[str, Any]],
) -> tuple[str, float] | None:
    subject_id = str(constraint.get("subject") or "")
    near_id = str(constraint.get("near_object") or "")
    far_id = str(constraint.get("far_object") or "")
    axis = str(constraint.get("axis") or "")
    if axis not in {"x", "y"}:
        return None
    subject = objects.get(subject_id)
    near = objects.get(near_id)
    far = objects.get(far_id)
    if not subject or not near or not far:
        return None
    subject_value = float(subject.get(axis, 0.0))
    near_value = float(near.get(axis, 0.0))
    far_value = float(far.get(axis, 0.0))
    near_gap = abs(subject_value - near_value)
    far_gap = abs(subject_value - far_value)
    ratio_limit = _clamp(
        _safe_float(constraint.get("scene_gap_ratio_limit"), REFERENCE_GAP_AFFINITY_SCENE_RATIO),
        0.1,
        1.0,
    )
    allowed_near_gap = max(
        float(REFERENCE_GAP_AFFINITY_MIN_SCENE_MARGIN),
        float(far_gap) * float(ratio_limit),
    )
    if near_gap <= allowed_near_gap + 1e-6:
        return None
    direction = 1.0 if near_value > subject_value else -1.0
    return axis, direction * (near_gap - allowed_near_gap)


def _select_gap_affinity_repair_move(
    constraint: dict[str, Any],
    affinity_constraints: list[dict[str, Any]],
    pair_constraints: list[dict[str, Any]],
    objects: dict[str, dict[str, Any]],
    descendants: dict[str, set[str]],
    room: dict[str, Any],
    max_step: float,
) -> dict[str, Any] | None:
    subject_id = str(constraint.get("subject") or "")
    if not subject_id:
        return None
    mover = objects.get(subject_id)
    axis_delta = _gap_affinity_subject_delta(constraint, objects)
    if not axis_delta or not _hypergraph_object_movable(mover):
        return None
    axis, raw_delta_value = axis_delta
    delta_value = _limited_repair_delta(raw_delta_value, max_step=max_step)
    if abs(delta_value) <= 1e-6:
        return None
    current_affinity_score = _gap_affinity_constraint_score(affinity_constraints, objects)
    current_pair_score = _axis_pair_constraint_score(pair_constraints, objects) if pair_constraints else (0, 0.0)

    candidate_objects = deepcopy(objects)
    candidate_mover = candidate_objects.get(subject_id)
    if not candidate_mover:
        return None
    before = (
        float(candidate_mover.get("x", 0.0)),
        float(candidate_mover.get("y", 0.0)),
        float(candidate_mover.get("z", 0.0)),
    )
    delta = (delta_value, 0.0, 0.0) if axis == "x" else (0.0, delta_value, 0.0)
    moved_nodes = _move_spatial_relation_unit(candidate_objects, descendants, subject_id, delta, room)
    after = (
        float(candidate_mover.get("x", 0.0)),
        float(candidate_mover.get("y", 0.0)),
        float(candidate_mover.get("z", 0.0)),
    )
    key_index = 0 if axis == "x" else 1
    applied_delta = float(after[key_index] - before[key_index])
    if abs(applied_delta) <= 1e-6:
        return None
    candidate_affinity_score = _gap_affinity_constraint_score(affinity_constraints, candidate_objects)
    candidate_pair_score = _axis_pair_constraint_score(pair_constraints, candidate_objects) if pair_constraints else (0, 0.0)
    if tuple(candidate_affinity_score) >= tuple(current_affinity_score):
        return None
    if candidate_pair_score[0] > current_pair_score[0] + 1:
        return None
    return {
        "axis": axis,
        "raw_delta": float(raw_delta_value),
        "delta": float(delta_value),
        "applied_delta": applied_delta,
        "moved_root": subject_id,
        "moved_node_count": len(moved_nodes),
        "affinity_score_before": current_affinity_score,
        "affinity_score_after": candidate_affinity_score,
        "pair_score_before": current_pair_score,
        "pair_score_after": candidate_pair_score,
    }


def _cluster_anchor_constraint_score(
    constraints: list[dict[str, Any]],
    objects: dict[str, dict[str, Any]],
    room: dict[str, Any],
) -> tuple[int, float]:
    violations = _reference_cluster_anchor_violations(constraints, objects, room)
    residual = sum(_cluster_anchor_violation_residual(violation) for violation in violations)
    return len(violations), round(float(residual), 6)


def _cluster_anchor_delta(
    constraint: dict[str, Any],
    objects: dict[str, dict[str, Any]],
    room: dict[str, Any],
) -> tuple[str, float] | None:
    members = [str(item) for item in constraint.get("members", []) if str(item) in objects]
    anchor_id = str(constraint.get("anchor_object") or "")
    anchor = objects.get(anchor_id)
    centroid = _scene_cluster_centroid(objects, members)
    if not members or not anchor or not centroid:
        return None
    best: tuple[float, str, float] | None = None
    for axis, index in (("x", 0), ("y", 1)):
        cluster_value = float(centroid[index])
        anchor_value = float(anchor.get(axis, 0.0))
        gap = abs(cluster_value - anchor_value)
        allowed = _cluster_anchor_allowed_axis_distance(constraint, room, axis)
        excess = gap - allowed
        if excess <= 1e-6:
            continue
        direction = 1.0 if anchor_value > cluster_value else -1.0
        ranking = (excess, axis, direction * excess)
        if best is None or ranking[0] > best[0]:
            best = ranking
    if not best:
        return None
    return best[1], best[2]


def _move_cluster_members(
    objects: dict[str, dict[str, Any]],
    descendants: dict[str, set[str]],
    member_ids: list[str],
    delta: tuple[float, float, float],
    room: dict[str, Any],
) -> set[str]:
    moved_nodes: set[str] = set()
    for member_id in member_ids:
        if member_id not in objects:
            continue
        for node_id in _move_spatial_relation_unit(objects, descendants, member_id, delta, room):
            moved_nodes.add(node_id)
    return moved_nodes


def _select_cluster_anchor_repair_move(
    constraint: dict[str, Any],
    cluster_constraints: list[dict[str, Any]],
    pair_constraints: list[dict[str, Any]],
    affinity_constraints: list[dict[str, Any]],
    objects: dict[str, dict[str, Any]],
    descendants: dict[str, set[str]],
    room: dict[str, Any],
    max_step: float,
) -> dict[str, Any] | None:
    members = [str(item) for item in constraint.get("members", []) if str(item) in objects]
    if len(members) < 2:
        return None
    anchor_id = str(constraint.get("anchor_object") or "")
    axis_delta = _cluster_anchor_delta(constraint, objects, room)
    if not axis_delta:
        return None
    axis, raw_delta_value = axis_delta
    delta_value = _limited_repair_delta(raw_delta_value, max_step=max_step)
    if abs(delta_value) <= 1e-6:
        return None
    current_cluster_score = _cluster_anchor_constraint_score(cluster_constraints, objects, room)
    current_pair_score = _axis_pair_constraint_score(pair_constraints, objects) if pair_constraints else (0, 0.0)
    current_affinity_score = _gap_affinity_constraint_score(affinity_constraints, objects) if affinity_constraints else (0, 0.0)

    delta = (delta_value, 0.0, 0.0) if axis == "x" else (0.0, delta_value, 0.0)
    anchor_delta = (-delta_value, 0.0, 0.0) if axis == "x" else (0.0, -delta_value, 0.0)
    candidates: list[dict[str, Any]] = []

    if all(_hypergraph_object_movable(objects.get(member_id)) for member_id in members):
        candidate_objects = deepcopy(objects)
        moved_nodes = _move_cluster_members(candidate_objects, descendants, members, delta, room)
        if moved_nodes:
            candidates.append(
                {
                    "move_mode": "move_cluster",
                    "delta": float(delta_value),
                    "moved_members": members,
                    "moved_node_count": len(moved_nodes),
                    "objects": candidate_objects,
                    "preference": 0,
                }
            )

    if anchor_id in objects and _hypergraph_object_movable(objects.get(anchor_id)):
        candidate_objects = deepcopy(objects)
        moved_nodes = _move_spatial_relation_unit(candidate_objects, descendants, anchor_id, anchor_delta, room)
        if moved_nodes:
            candidates.append(
                {
                    "move_mode": "move_anchor",
                    "delta": float(-delta_value),
                    "moved_anchor": anchor_id,
                    "moved_node_count": len(moved_nodes),
                    "objects": candidate_objects,
                    "preference": 1,
                }
            )

    best: tuple[tuple[int, float, int, float, int], dict[str, Any]] | None = None
    for candidate in candidates:
        candidate_objects = candidate.pop("objects")
        candidate_cluster_score = _cluster_anchor_constraint_score(cluster_constraints, candidate_objects, room)
        candidate_pair_score = _axis_pair_constraint_score(pair_constraints, candidate_objects) if pair_constraints else (0, 0.0)
        candidate_affinity_score = _gap_affinity_constraint_score(affinity_constraints, candidate_objects) if affinity_constraints else (0, 0.0)
        if tuple(candidate_cluster_score) >= tuple(current_cluster_score):
            continue
        if candidate_pair_score[0] > current_pair_score[0] + 2:
            continue
        if candidate_affinity_score[0] > current_affinity_score[0] + 2:
            continue
        candidate.update(
            {
                "axis": axis,
                "raw_delta": float(raw_delta_value),
                "cluster_score_before": current_cluster_score,
                "cluster_score_after": candidate_cluster_score,
                "pair_score_before": current_pair_score,
                "pair_score_after": candidate_pair_score,
                "affinity_score_before": current_affinity_score,
                "affinity_score_after": candidate_affinity_score,
            }
        )
        ranking = (
            candidate_cluster_score[0],
            candidate_cluster_score[1],
            candidate_pair_score[0],
            candidate_pair_score[1],
            int(candidate.get("preference", 9)),
        )
        if best is None or ranking < best[0]:
            best = (ranking, candidate)
    return best[1] if best else None


def _select_axis_pair_repair_move(
    constraint: dict[str, Any],
    constraints: list[dict[str, Any]],
    objects: dict[str, dict[str, Any]],
    descendants: dict[str, set[str]],
    room: dict[str, Any],
    max_step: float,
) -> dict[str, Any] | None:
    subject_id = str(constraint.get("subject") or "")
    target_id = str(constraint.get("object") or "")
    if not subject_id or not target_id:
        return None

    current_score = _axis_pair_constraint_score(constraints, objects)
    # Score both move directions against the whole factor. This matters most
    # for same-axis clusters, where moving one large target can satisfy the
    # current pair while breaking another pair in the same reference group.
    move_options = [
        (subject_id, False, _axis_pair_constraint_subject_delta(constraint, objects)),
        (target_id, True, _axis_pair_constraint_target_delta(constraint, objects)),
    ]

    best: tuple[tuple[int, float, int, float], dict[str, Any]] | None = None
    for moved_root, fallback, axis_delta in move_options:
        mover = objects.get(moved_root)
        if not axis_delta or not _hypergraph_object_movable(mover):
            continue
        axis, raw_delta_value = axis_delta
        delta_value = _limited_repair_delta(raw_delta_value, max_step=max_step)
        if abs(delta_value) <= 1e-6:
            continue
        key_index = 0 if axis == "x" else 1
        candidate_objects = deepcopy(objects)
        candidate_mover = candidate_objects.get(moved_root)
        if not candidate_mover:
            continue
        before = (
            float(candidate_mover.get("x", 0.0)),
            float(candidate_mover.get("y", 0.0)),
            float(candidate_mover.get("z", 0.0)),
        )
        delta = (delta_value, 0.0, 0.0) if axis == "x" else (0.0, delta_value, 0.0)
        moved_nodes = _move_spatial_relation_unit(candidate_objects, descendants, moved_root, delta, room)
        after = (
            float(candidate_mover.get("x", 0.0)),
            float(candidate_mover.get("y", 0.0)),
            float(candidate_mover.get("z", 0.0)),
        )
        applied_delta = float(after[key_index] - before[key_index])
        if abs(applied_delta) <= 1e-6:
            continue
        candidate_score = _axis_pair_constraint_score(constraints, candidate_objects)
        preference = 0 if fallback else 1
        ranking = (candidate_score[0], candidate_score[1], preference, round(abs(applied_delta), 6))
        candidate = {
            "axis": axis,
            "raw_delta": float(raw_delta_value),
            "delta": float(delta_value),
            "applied_delta": applied_delta,
            "moved_root": moved_root,
            "fallback": bool(fallback),
            "moved_node_count": len(moved_nodes),
            "score_before": current_score,
            "score_after": candidate_score,
        }
        if best is None or ranking < best[0]:
            best = (ranking, candidate)

    if best is None:
        return None
    candidate = best[1]
    if tuple(candidate["score_after"]) >= tuple(candidate["score_before"]):
        return None
    return candidate


def _hypergraph_repair_constraints_from_validation(
    scene_hypergraph: dict[str, Any],
    validation_report: dict[str, Any],
    objects: dict[str, dict[str, Any]],
) -> list[dict[str, Any]]:
    constraints: list[dict[str, Any]] = []
    seen: set[tuple[str, str, str]] = set()

    def add_or_upgrade_constraint(constraint: dict[str, Any]) -> None:
        key = (
            str(constraint.get("subject") or ""),
            str(constraint.get("relation") or ""),
            str(constraint.get("object") or ""),
        )
        if "" in key:
            return
        if key in seen:
            if "required_scene_gap" in constraint:
                for existing in constraints:
                    existing_key = (
                        str(existing.get("subject") or ""),
                        str(existing.get("relation") or ""),
                        str(existing.get("object") or ""),
                    )
                    if existing_key == key:
                        existing["required_scene_gap"] = max(
                            _safe_float(existing.get("required_scene_gap"), SPATIAL_ORDER_MIN_AXIS_GAP),
                            _safe_float(constraint.get("required_scene_gap"), SPATIAL_ORDER_MIN_AXIS_GAP),
                        )
                        break
            return
        seen.add(key)
        constraints.append(constraint)

    for factor in scene_hypergraph.get("factors", []) if isinstance(scene_hypergraph.get("factors"), list) else []:
        if not isinstance(factor, dict) or factor.get("type") != "reference_axis_pair_constraints":
            continue
        confidence = _clamp(_safe_float(factor.get("confidence"), 0.0), 0.0, 1.0)
        if confidence < SPATIAL_ORDER_HARD_CONFIDENCE:
            continue
        for raw_constraint in factor.get("pair_constraints", []) if isinstance(factor.get("pair_constraints"), list) else []:
            if not isinstance(raw_constraint, dict):
                continue
            if _axis_pair_constraint_is_soft(raw_constraint, objects):
                continue
            key = (
                str(raw_constraint.get("subject") or ""),
                str(raw_constraint.get("relation") or ""),
                str(raw_constraint.get("object") or ""),
            )
            if "" in key or key in seen:
                continue
            seen.add(key)
            constraint = dict(raw_constraint)
            constraint["source_factor_id"] = factor.get("factor_id")
            constraint["source_factor_type"] = factor.get("type")
            constraint["confidence"] = confidence
            constraints.append(constraint)
    for check in validation_report.get("factor_checks", []) if isinstance(validation_report.get("factor_checks"), list) else []:
        if not isinstance(check, dict) or not check.get("hard"):
            continue
        axis_name = str(check.get("axis") or "")
        if axis_name in {"front_to_back", "y"}:
            repair_relation = "in_front_of"
            repair_axis = "y"
        elif axis_name in {"left_to_right", "x"}:
            repair_relation = "left_of"
            repair_axis = "x"
        else:
            repair_relation = ""
            repair_axis = ""
        if repair_relation:
            order_violation_items: list[dict[str, Any]] = []
            for key_name in ("order_violations", "pairwise_order_violations"):
                raw_items = check.get(key_name) if isinstance(check.get(key_name), list) else []
                order_violation_items.extend([item for item in raw_items if isinstance(item, dict)])
            for violation in order_violation_items:
                subject = str(violation.get("before") or "")
                target = str(violation.get("after") or "")
                if not subject or not target:
                    continue
                add_or_upgrade_constraint(
                    {
                        "subject": subject,
                        "relation": repair_relation,
                        "object": target,
                        "axis": repair_axis,
                        "source_factor_id": check.get("factor_id"),
                        "source_factor_type": check.get("factor_type"),
                        "confidence": _safe_float(check.get("confidence"), 0.86),
                        "required_scene_gap": SPATIAL_ORDER_MIN_AXIS_GAP,
                        "repair_reason": "reference_order_violation",
                        "ref_gap": violation.get("ref_gap"),
                    }
                )
        for violation in check.get("same_axis_violations", []) if isinstance(check.get("same_axis_violations"), list) else []:
            if not isinstance(violation, dict):
                continue
            relation = str(violation.get("relation") or "")
            if relation not in {"same_depth", "same_column"}:
                continue
            subject = str(violation.get("a") or "")
            target = str(violation.get("b") or "")
            key = (subject, relation, target)
            if "" in key or key in seen:
                continue
            seen.add(key)
            constraints.append(
                {
                    "subject": subject,
                    "relation": relation,
                    "object": target,
                    "axis": "y" if relation == "same_depth" else "x",
                    "source_factor_id": check.get("factor_id"),
                    "source_factor_type": check.get("factor_type"),
                    "confidence": _safe_float(check.get("confidence"), 0.86),
                    "ref_gap": violation.get("ref_gap"),
                    "same_axis_threshold": violation.get("ref_threshold"),
                }
            )
        for violation in check.get("gap_violations", []) if isinstance(check.get("gap_violations"), list) else []:
            if not isinstance(violation, dict):
                continue
            axis = str(violation.get("axis") or "")
            relation = "left_of" if axis == "x" else "in_front_of" if axis == "y" else ""
            subject = str(violation.get("before") or "")
            target = str(violation.get("after") or "")
            if not relation:
                continue
            add_or_upgrade_constraint(
                {
                    "subject": subject,
                    "relation": relation,
                    "object": target,
                    "axis": axis,
                    "source_factor_id": check.get("factor_id"),
                    "source_factor_type": check.get("factor_type"),
                    "confidence": _safe_float(check.get("confidence"), 0.86),
                    "required_scene_gap": max(
                        SPATIAL_ORDER_MIN_AXIS_GAP,
                        _safe_float(violation.get("min_gap"), SPATIAL_ORDER_MIN_AXIS_GAP),
                    ),
                    "repair_reason": "reference_order_gap_violation",
                }
            )
        if not check.get("depth_profile_hard", check.get("hard")):
            continue
        for violation in check.get("depth_profile_violations", []) if isinstance(check.get("depth_profile_violations"), list) else []:
            if not isinstance(violation, dict):
                continue
            subject = str(violation.get("before") or "")
            target = str(violation.get("after") or "")
            scene_gap = _safe_float(violation.get("scene_gap"), SPATIAL_ORDER_MIN_AXIS_GAP)
            actual_ratio = max(1e-6, _safe_float(violation.get("actual_ratio"), 1.0))
            allowed = violation.get("allowed_ratio_range") if isinstance(violation.get("allowed_ratio_range"), list) else []
            min_ratio = _safe_float(allowed[0] if allowed else 0.0, 0.0)
            required_gap = scene_gap
            if min_ratio > 0.0 and actual_ratio < min_ratio:
                required_gap = scene_gap * (min_ratio / actual_ratio)
            add_or_upgrade_constraint(
                {
                    "subject": subject,
                    "relation": "in_front_of",
                    "object": target,
                    "axis": "y",
                    "source_factor_id": check.get("factor_id"),
                    "source_factor_type": check.get("factor_type"),
                    "confidence": _safe_float(check.get("confidence"), 0.86),
                    "required_scene_gap": max(SPATIAL_ORDER_MIN_AXIS_GAP, required_gap),
                    "repair_reason": "reference_depth_profile_violation",
                    "expected_ratio": violation.get("expected_ratio"),
                    "actual_ratio": violation.get("actual_ratio"),
                }
            )
    return constraints


def _hypergraph_gap_affinity_constraints_from_validation(
    scene_hypergraph: dict[str, Any],
    validation_report: dict[str, Any],
) -> list[dict[str, Any]]:
    constraints_by_key: dict[tuple[str, str, str, str], dict[str, Any]] = {}
    for factor in scene_hypergraph.get("factors", []) if isinstance(scene_hypergraph.get("factors"), list) else []:
        if not isinstance(factor, dict) or factor.get("type") != "reference_axis_gap_affinity":
            continue
        confidence = _clamp(_safe_float(factor.get("confidence"), 0.0), 0.0, 1.0)
        if confidence < SPATIAL_ORDER_HARD_CONFIDENCE:
            continue
        for raw_constraint in factor.get("gap_affinity_constraints", []) if isinstance(factor.get("gap_affinity_constraints"), list) else []:
            if not isinstance(raw_constraint, dict) or _gap_affinity_constraint_is_soft(raw_constraint):
                continue
            key = (
                str(raw_constraint.get("subject") or ""),
                str(raw_constraint.get("near_object") or ""),
                str(raw_constraint.get("far_object") or ""),
                str(raw_constraint.get("axis") or ""),
            )
            if "" in key or key in constraints_by_key:
                continue
            constraint = dict(raw_constraint)
            constraint["source_factor_id"] = factor.get("factor_id")
            constraint["source_factor_type"] = factor.get("type")
            constraint["confidence"] = confidence
            constraints_by_key[key] = constraint

    violation_keys: set[tuple[str, str, str, str]] = set()
    for check in validation_report.get("factor_checks", []) if isinstance(validation_report.get("factor_checks"), list) else []:
        if not isinstance(check, dict) or not check.get("hard") or check.get("factor_type") != "reference_axis_gap_affinity":
            continue
        for violation in check.get("violations", []) if isinstance(check.get("violations"), list) else []:
            if not isinstance(violation, dict):
                continue
            key = (
                str(violation.get("subject") or ""),
                str(violation.get("near_object") or ""),
                str(violation.get("far_object") or ""),
                str(violation.get("axis") or ""),
            )
            if "" not in key:
                violation_keys.add(key)

    if not violation_keys:
        return []
    return [constraint for key, constraint in constraints_by_key.items() if key in violation_keys]


def _hypergraph_cluster_anchor_constraints_from_validation(
    scene_hypergraph: dict[str, Any],
    validation_report: dict[str, Any],
) -> list[dict[str, Any]]:
    constraints_by_key: dict[str, dict[str, Any]] = {}
    for factor in scene_hypergraph.get("factors", []) if isinstance(scene_hypergraph.get("factors"), list) else []:
        if not isinstance(factor, dict) or factor.get("type") != "reference_cluster_anchor_affinity":
            continue
        confidence = _clamp(_safe_float(factor.get("confidence"), 0.0), 0.0, 1.0)
        if confidence < SPATIAL_ORDER_HARD_CONFIDENCE:
            continue
        for raw_constraint in factor.get("cluster_constraints", []) if isinstance(factor.get("cluster_constraints"), list) else []:
            if not isinstance(raw_constraint, dict):
                continue
            cluster_id = str(raw_constraint.get("cluster_id") or "")
            if not cluster_id or cluster_id in constraints_by_key:
                continue
            constraint = dict(raw_constraint)
            constraint["source_factor_id"] = factor.get("factor_id")
            constraint["source_factor_type"] = factor.get("type")
            constraint["confidence"] = confidence
            constraints_by_key[cluster_id] = constraint

    violation_keys: set[str] = set()
    for check in validation_report.get("factor_checks", []) if isinstance(validation_report.get("factor_checks"), list) else []:
        if not isinstance(check, dict) or not check.get("hard") or check.get("factor_type") != "reference_cluster_anchor_affinity":
            continue
        for violation in check.get("violations", []) if isinstance(check.get("violations"), list) else []:
            if not isinstance(violation, dict):
                continue
            cluster_id = str(violation.get("cluster_id") or "")
            if cluster_id:
                violation_keys.add(cluster_id)
    if not violation_keys:
        return []
    return [constraint for key, constraint in constraints_by_key.items() if key in violation_keys]


def repair_scene_hypergraph_spatial_constraints(
    plan: dict[str, Any],
    scene_hypergraph: dict[str, Any],
    support_tree: dict[str, Any],
    parent: dict[str, str],
    max_iterations: int = SCENE_HYPERGRAPH_REPAIR_MAX_ITERATIONS,
    max_step: float = SCENE_HYPERGRAPH_REPAIR_MAX_STEP,
) -> dict[str, Any]:
    objects = {str(obj.get("id")): obj for obj in plan.get("objects", []) if isinstance(obj, dict)}
    descendants = _descendant_map(support_tree)
    room = plan.get("room") if isinstance(plan.get("room"), dict) else {}
    before_validation = validate_scene_hypergraph_constraints(plan, scene_hypergraph, parent)
    constraints = _hypergraph_repair_constraints_from_validation(scene_hypergraph, before_validation, objects)
    gap_affinity_constraints = _hypergraph_gap_affinity_constraints_from_validation(scene_hypergraph, before_validation)
    cluster_anchor_constraints = _hypergraph_cluster_anchor_constraints_from_validation(scene_hypergraph, before_validation)
    report: dict[str, Any] = {
        "schema": "tree_sage_scene_hypergraph_spatial_repair_v1",
        "enabled": bool(scene_hypergraph.get("enabled"))
        and (bool(constraints) or bool(gap_affinity_constraints) or bool(cluster_anchor_constraints)),
        "strategy": "repair high-confidence hypergraph cluster-anchor, reference-axis pair, reference-depth-profile, and adjacent gap-affinity constraints with bounded center-coordinate moves",
        "max_iterations": int(max_iterations),
        "max_step": float(max_step),
        "before_validation_ok": bool(before_validation.get("ok")),
        "before_warning_count": len(before_validation.get("warnings", [])),
        "constraint_count": len(constraints),
        "gap_affinity_constraint_count": len(gap_affinity_constraints),
        "cluster_anchor_constraint_count": len(cluster_anchor_constraints),
        "iterations": [],
        "fixes": [],
        "warnings": [],
        "soft_warnings": [],
        "ok": True,
    }
    if not scene_hypergraph.get("enabled"):
        report["reason"] = "scene_hypergraph_disabled"
        return report
    if not constraints and not gap_affinity_constraints and not cluster_anchor_constraints:
        report["reason"] = "no_high_confidence_repairable_hypergraph_constraints"
        report["fix_count"] = 0
        report["after_validation"] = before_validation
        report["ok"] = bool(before_validation.get("ok"))
        return report

    for iteration in range(max(1, int(max_iterations))):
        iteration_actions: list[dict[str, Any]] = []
        for constraint in cluster_anchor_constraints:
            violations = _reference_cluster_anchor_violations([constraint], objects, room)
            if not violations:
                continue
            selected_move = _select_cluster_anchor_repair_move(
                constraint,
                cluster_anchor_constraints,
                constraints,
                gap_affinity_constraints,
                objects,
                descendants,
                room,
                max_step=max_step,
            )
            if not selected_move:
                continue
            axis = str(selected_move["axis"])
            delta_value = float(selected_move["delta"])
            raw_delta_value = float(selected_move["raw_delta"])
            delta = (delta_value, 0.0, 0.0) if axis == "x" else (0.0, delta_value, 0.0)
            move_mode = str(selected_move.get("move_mode") or "move_cluster")
            if move_mode == "move_anchor":
                moved_nodes = _move_spatial_relation_unit(
                    objects,
                    descendants,
                    str(selected_move.get("moved_anchor") or constraint.get("anchor_object") or ""),
                    delta,
                    room,
                )
            else:
                moved_nodes = _move_cluster_members(
                    objects,
                    descendants,
                    [str(item) for item in selected_move.get("moved_members", [])],
                    delta,
                    room,
                )
            status_after = _reference_cluster_anchor_violations([constraint], objects, room)
            action = {
                "iteration": iteration + 1,
                "source_factor_id": constraint.get("source_factor_id"),
                "source_factor_type": constraint.get("source_factor_type"),
                "repair_type": "reference_cluster_anchor_affinity",
                "cluster_id": constraint.get("cluster_id"),
                "members": constraint.get("members", []),
                "anchor_object": constraint.get("anchor_object"),
                "move_mode": move_mode,
                "moved_anchor": selected_move.get("moved_anchor"),
                "relation": "cluster_near_anchor",
                "axis": axis,
                "requested_delta": round(float(raw_delta_value), 6),
                "applied_delta": round(float(delta_value), 6),
                "moved_node_count": len(moved_nodes),
                "violations_before": violations,
                "violations_after": status_after,
                "ok_after": not status_after,
                "cluster_score_before": selected_move.get("cluster_score_before"),
                "cluster_score_after": selected_move.get("cluster_score_after"),
                "pair_score_before": selected_move.get("pair_score_before"),
                "pair_score_after": selected_move.get("pair_score_after"),
                "affinity_score_before": selected_move.get("affinity_score_before"),
                "affinity_score_after": selected_move.get("affinity_score_after"),
            }
            iteration_actions.append(action)
            report["fixes"].append(action)
        for constraint in gap_affinity_constraints:
            violations = _reference_axis_gap_affinity_violations([constraint], objects)
            if not violations:
                continue
            selected_move = _select_gap_affinity_repair_move(
                constraint,
                gap_affinity_constraints,
                constraints,
                objects,
                descendants,
                room,
                max_step=max_step,
            )
            if not selected_move:
                continue
            moved_root = str(selected_move["moved_root"])
            mover = objects.get(moved_root)
            if not _hypergraph_object_movable(mover):
                report["soft_warnings"].append(
                    f"skipped non-movable gap-affinity constraint {constraint.get('subject')} closer_to {constraint.get('near_object')}"
                )
                continue
            axis = str(selected_move["axis"])
            raw_delta_value = float(selected_move["raw_delta"])
            delta_value = float(selected_move["delta"])
            if abs(delta_value) <= 1e-6:
                continue
            key_index = 0 if axis == "x" else 1
            before = (float(mover.get("x", 0.0)), float(mover.get("y", 0.0)), float(mover.get("z", 0.0)))
            delta = (delta_value, 0.0, 0.0) if axis == "x" else (0.0, delta_value, 0.0)
            moved_nodes = _move_spatial_relation_unit(objects, descendants, moved_root, delta, room)
            after = (float(mover.get("x", 0.0)), float(mover.get("y", 0.0)), float(mover.get("z", 0.0)))
            status_after = _reference_axis_gap_affinity_violations([constraint], objects)
            action = {
                "iteration": iteration + 1,
                "source_factor_id": constraint.get("source_factor_id"),
                "source_factor_type": constraint.get("source_factor_type"),
                "repair_type": "reference_axis_gap_affinity",
                "subject": constraint.get("subject"),
                "relation": "closer_to_neighbor",
                "near_object": constraint.get("near_object"),
                "far_object": constraint.get("far_object"),
                "moved_root": moved_root,
                "axis": axis,
                "requested_delta": round(float(raw_delta_value), 6),
                "applied_delta": round(float(after[key_index] - before[key_index]), 6),
                "moved_node_count": len(moved_nodes),
                "violations_before": violations,
                "violations_after": status_after,
                "ok_after": not status_after,
                "affinity_score_before": selected_move.get("affinity_score_before"),
                "affinity_score_after": selected_move.get("affinity_score_after"),
                "pair_score_before": selected_move.get("pair_score_before"),
                "pair_score_after": selected_move.get("pair_score_after"),
            }
            iteration_actions.append(action)
            report["fixes"].append(action)
        for constraint in constraints:
            violations = _reference_axis_pair_constraint_violations([constraint], objects)
            if not violations:
                continue
            subject_id = str(constraint.get("subject") or "")
            target_id = str(constraint.get("object") or "")
            subject = objects.get(subject_id)
            target = objects.get(target_id)
            if not subject or not target:
                continue
            selected_move = _select_axis_pair_repair_move(
                constraint,
                constraints,
                objects,
                descendants,
                room,
                max_step=max_step,
            )
            if not selected_move:
                continue
            moved_root = str(selected_move["moved_root"])
            fallback = bool(selected_move.get("fallback"))
            mover = objects.get(moved_root)
            if not _hypergraph_object_movable(mover):
                report["soft_warnings"].append(
                    f"skipped non-movable hypergraph constraint {subject_id} {constraint.get('relation')} {target_id}"
                )
                continue
            axis = str(selected_move["axis"])
            raw_delta_value = float(selected_move["raw_delta"])
            delta_value = float(selected_move["delta"])
            if abs(delta_value) <= 1e-6:
                continue
            key_index = 0 if axis == "x" else 1
            before = (float(mover.get("x", 0.0)), float(mover.get("y", 0.0)), float(mover.get("z", 0.0)))
            delta = (delta_value, 0.0, 0.0) if axis == "x" else (0.0, delta_value, 0.0)
            moved_nodes = _move_spatial_relation_unit(objects, descendants, moved_root, delta, room)
            after = (float(mover.get("x", 0.0)), float(mover.get("y", 0.0)), float(mover.get("z", 0.0)))
            action = {
                "iteration": iteration + 1,
                "source_factor_id": constraint.get("source_factor_id"),
                "source_factor_type": constraint.get("source_factor_type"),
                "subject": subject_id,
                "relation": constraint.get("relation"),
                "object": target_id,
                "moved_root": moved_root,
                "fallback_moved_target": bool(fallback),
                "axis": axis,
                "requested_delta": round(float(raw_delta_value), 6),
                "applied_delta": round(float(after[key_index] - before[key_index]), 6),
                "moved_node_count": len(moved_nodes),
                "violations_before": violations,
                "constraint_score_before": selected_move.get("score_before"),
                "constraint_score_after": selected_move.get("score_after"),
            }
            status_after = _reference_axis_pair_constraint_violations([constraint], objects)
            action["ok_after"] = not status_after
            action["violations_after"] = status_after
            iteration_actions.append(action)
            report["fixes"].append(action)
            if (
                status_after
                and not fallback
                and str(constraint.get("relation") or "") not in {"same_depth", "same_column"}
                and _hypergraph_object_movable(target)
            ):
                target_axis_delta = _axis_pair_constraint_target_delta(constraint, objects)
                if target_axis_delta:
                    target_axis, target_raw_delta = target_axis_delta
                    target_delta_value = _limited_repair_delta(target_raw_delta, max_step=max_step)
                    if abs(target_delta_value) > 1e-6:
                        target_before = (float(target.get("x", 0.0)), float(target.get("y", 0.0)), float(target.get("z", 0.0)))
                        target_delta = (target_delta_value, 0.0, 0.0) if target_axis == "x" else (0.0, target_delta_value, 0.0)
                        target_moved_nodes = _move_spatial_relation_unit(objects, descendants, target_id, target_delta, room)
                        target_after = (float(target.get("x", 0.0)), float(target.get("y", 0.0)), float(target.get("z", 0.0)))
                        fallback_action = {
                            "iteration": iteration + 1,
                            "source_factor_id": constraint.get("source_factor_id"),
                            "source_factor_type": constraint.get("source_factor_type"),
                            "subject": subject_id,
                            "relation": constraint.get("relation"),
                            "object": target_id,
                            "moved_root": target_id,
                            "fallback_moved_target": True,
                            "axis": target_axis,
                            "requested_delta": round(float(target_raw_delta), 6),
                            "applied_delta": round(float(target_after[0 if target_axis == "x" else 1] - target_before[0 if target_axis == "x" else 1]), 6),
                            "moved_node_count": len(target_moved_nodes),
                            "violations_before": status_after,
                            "violations_after": _reference_axis_pair_constraint_violations([constraint], objects),
                        }
                        fallback_action["ok_after"] = not fallback_action["violations_after"]
                        iteration_actions.append(fallback_action)
                        report["fixes"].append(fallback_action)
        report["iterations"].append(
            {"iteration": iteration + 1, "action_count": len(iteration_actions), "actions": iteration_actions}
        )
        if not iteration_actions:
            break
        if (
            not _reference_axis_pair_constraint_violations(constraints, objects)
            and not _reference_axis_gap_affinity_violations(gap_affinity_constraints, objects)
            and not _reference_cluster_anchor_violations(cluster_anchor_constraints, objects, room)
        ):
            break

    after_validation = validate_scene_hypergraph_constraints(plan, scene_hypergraph, parent)
    remaining = _reference_axis_pair_constraint_violations(constraints, objects)
    remaining_gap_affinity = _reference_axis_gap_affinity_violations(gap_affinity_constraints, objects)
    remaining_cluster_anchor = _reference_cluster_anchor_violations(cluster_anchor_constraints, objects, room)
    report["after_validation"] = after_validation
    report["remaining_violations"] = remaining
    report["remaining_gap_affinity_violations"] = remaining_gap_affinity
    report["remaining_cluster_anchor_violations"] = remaining_cluster_anchor
    report["fix_count"] = len(report["fixes"])
    report["after_warning_count"] = len(after_validation.get("warnings", []))
    if remaining:
        for violation in remaining[:20]:
            report["warnings"].append(
                f"{violation.get('subject')} {violation.get('relation')} {violation.get('object')}: "
                f"scene_gap={violation.get('scene_gap')}, required={violation.get('required_gap_or_threshold')}"
            )
    if remaining_gap_affinity:
        for violation in remaining_gap_affinity[:20]:
            report["warnings"].append(
                f"{violation.get('subject')} closer_to {violation.get('near_object')} than {violation.get('far_object')}: "
                f"near_gap={violation.get('scene_near_gap')}, allowed={violation.get('allowed_near_gap')}"
            )
    if remaining_cluster_anchor:
        for violation in remaining_cluster_anchor[:20]:
            report["warnings"].append(
                f"{violation.get('cluster_id')} near {violation.get('anchor_object')} on {violation.get('axis')}: "
                f"scene_gap={violation.get('scene_gap')}, allowed={violation.get('allowed_gap')}"
            )
    report["ok"] = not report["warnings"] and bool(after_validation.get("ok"))
    return report


def _monotonic_axis_targets(values: list[float], min_gap: float = SPATIAL_ORDER_MIN_AXIS_GAP) -> list[float]:
    if not values:
        return []
    targets = sorted(float(value) for value in values)
    for index in range(1, len(targets)):
        if targets[index] <= targets[index - 1] + min_gap:
            targets[index] = targets[index - 1] + min_gap
    original_center = sum(values) / float(len(values))
    target_center = sum(targets) / float(len(targets))
    shift = target_center - original_center
    return [value - shift for value in targets]


def _clamp_spatial_order_moved_nodes(
    objects: dict[str, dict[str, Any]],
    node_ids: list[str],
    room: dict[str, float],
) -> None:
    for node_id in node_ids:
        obj = objects.get(node_id)
        if not obj:
            continue
        support_id = str(obj.get("support_id") or "")
        if str(obj.get("placement_type")) == "attached_to_wall" and support_id in VIRTUAL_WALLS:
            _clamp_wall_attached_object(obj, room, support_id)
        elif str(obj.get("placement_type", "floor")) in {"floor", "hanging", "on_top", "inside"}:
            _clamp_object_to_room(obj, room)


def _fine_spatial_order_scene_span(obj: dict[str, Any], axis: str) -> tuple[float, float, float, float]:
    axis_index = {"x": 0, "y": 1, "z": 2}[axis]
    min_v, max_v = _bbox_for_object(obj)
    low = float(min_v[axis_index])
    high = float(max_v[axis_index])
    return low, (low + high) / 2.0, high, max(0.0, high - low)


def _fine_spatial_order_wall_tangent_axis(wall_id: str) -> str | None:
    if wall_id in {"wall_east", "wall_west"}:
        return "y"
    if wall_id in {"wall_north", "wall_south"}:
        return "x"
    return None


def _fine_spatial_order_is_protected_assembly_member(obj: dict[str, Any]) -> bool:
    return (
        _functional_cluster_is_window_object(obj)
        or _is_curtain_panel_object(obj)
        or _is_curtain_rod_object(obj)
    )


def _fine_spatial_order_can_move_root(
    objects: dict[str, dict[str, Any]],
    object_id: str,
    axis: str,
    parent: dict[str, str],
) -> tuple[bool, str | None]:
    obj = objects.get(str(object_id))
    if not obj:
        return False, "missing_object"
    if _fine_spatial_order_is_protected_assembly_member(obj):
        return False, "protected_window_curtain_assembly"
    if _is_floor_covering(obj) or _is_hanging_object(obj):
        return False, "non_movable_floor_covering_or_hanging"
    placement = str(obj.get("placement_type") or "floor")
    support_id = str(obj.get("support_id") or "")
    wall_id = _object_attached_wall_id(objects, str(object_id), parent)
    if placement == "attached_to_wall" or support_id in VIRTUAL_WALLS or _is_wall_attached_object(obj):
        if wall_id not in VIRTUAL_WALLS:
            return False, "wall_attached_without_wall"
        if axis != _fine_spatial_order_wall_tangent_axis(wall_id):
            return False, "wall_attached_normal_axis_locked"
        return True, None
    if placement in {"on_top", "inside"} or (support_id and support_id in objects):
        return False, "supported_child_not_root_movable"
    if _is_bed_or_sofa_object(obj):
        return False, "major_anchor_locked"
    if _is_wall_anchored_floor_object(obj, parent) and wall_id in VIRTUAL_WALLS:
        tangent_axis = _fine_spatial_order_wall_tangent_axis(wall_id)
        if tangent_axis and axis != tangent_axis:
            return False, "wall_anchored_floor_normal_axis_locked"
    return placement in {"floor", "", "against_wall"}, None if placement in {"floor", "", "against_wall"} else "unsupported_placement"


def _fine_spatial_order_reference_edge_gap(
    ref_bboxes: dict[str, list[float]],
    before_id: str,
    after_id: str,
    axis_name: str,
) -> float | None:
    before_bbox = ref_bboxes.get(str(before_id))
    after_bbox = ref_bboxes.get(str(after_id))
    if not before_bbox or not after_bbox:
        return None
    if axis_name == "x":
        return float(after_bbox[0]) - float(before_bbox[2])
    if axis_name == "front_to_back":
        # Larger reference image-y usually means visually closer/front.  For a
        # front-to-back sequence, the front object's top edge should remain
        # lower than the back object's bottom edge only when the boxes are well
        # separated; otherwise depth/frontness profile is the safer cue.
        return float(before_bbox[1]) - float(after_bbox[3])
    return None


def _fine_spatial_order_pair_violation(
    objects: dict[str, dict[str, Any]],
    before_id: str,
    after_id: str,
    scene_axis: str,
    clearance: float,
) -> dict[str, Any] | None:
    before = objects.get(str(before_id))
    after = objects.get(str(after_id))
    if not before or not after:
        return None
    before_low, _before_center, before_high, before_span = _fine_spatial_order_scene_span(before, scene_axis)
    after_low, _after_center, after_high, after_span = _fine_spatial_order_scene_span(after, scene_axis)
    edge_gap = float(after_low) - float(before_high)
    deficit = float(clearance) - edge_gap
    if deficit <= 1e-6:
        return None
    return {
        "before": before_id,
        "after": after_id,
        "axis": scene_axis,
        "before_span": [round(float(before_low), 6), round(float(before_high), 6)],
        "after_span": [round(float(after_low), 6), round(float(after_high), 6)],
        "before_size": round(float(before_span), 6),
        "after_size": round(float(after_span), 6),
        "edge_gap": round(float(edge_gap), 6),
        "required_edge_gap": round(float(clearance), 6),
        "deficit": round(float(deficit), 6),
    }


def _fine_spatial_order_axis_refinement(
    plan: dict[str, Any],
    scene_graph: dict[str, Any],
    support_tree: dict[str, Any],
    parent: dict[str, str],
    cross_constraints: list[dict[str, Any]],
    group: dict[str, Any],
    axis_name: str,
    order_key: str,
    ref_bboxes: dict[str, list[float]],
    ref_depths: dict[str, dict[str, Any]],
    lateral_side_wall_group_ids: set[str],
    report: dict[str, Any],
    max_step: float,
) -> None:
    objects = {str(obj.get("id")): obj for obj in plan.get("objects", []) if isinstance(obj, dict) and obj.get("id")}
    raw_order = group.get(order_key) if isinstance(group.get(order_key), list) else []
    expected = _spatial_order_units([str(value) for value in raw_order], objects, parent)
    if len(expected) < 2:
        return
    confidence = _safe_float(group.get("confidence"), 0.0)
    if str(group.get("scope") or "") == "global_anchor" and confidence < 0.8:
        report["checks"].append(
            {
                "group_id": group.get("group_id"),
                "scope": group.get("scope"),
                "axis": "left_to_right" if axis_name == "x" else "front_to_back",
                "expected_order": expected,
                "skipped": True,
                "reason": "global_anchor_order_below_repair_confidence",
                "confidence": confidence,
            }
        )
        return
    side_wall_lateral_axis = axis_name == "x" and str(group.get("group_id") or "") in lateral_side_wall_group_ids
    scene_axis = "x" if side_wall_lateral_axis else _scene_axis_for_reference_order(axis_name, objects, expected, parent)
    group_wall_id = _common_attached_wall_id(objects, expected, parent) or str(group.get("anchor_id") or "")
    side_wall_image_tangent_order = (
        axis_name == "x"
        and not side_wall_lateral_axis
        and scene_axis == "y"
        and str(group.get("scope") or "") == "wall"
        and group_wall_id in {"wall_east", "wall_west"}
    )
    reference_profile = _reference_axis_profile(
        expected,
        ref_bboxes,
        "x" if axis_name == "x" else "front_to_back",
        ref_depths,
    )
    gap_required = _spatial_order_axis_gap_required(expected, scene_axis, cross_constraints, parent)
    check: dict[str, Any] = {
        "group_id": group.get("group_id"),
        "scope": group.get("scope"),
        "axis": "left_to_right" if axis_name == "x" else "front_to_back",
        "scene_axis": scene_axis,
        "expected_order": expected,
        "current_order_before": _axis_order(objects, expected, scene_axis),
        "gap_required": bool(gap_required),
        "edge_checks": [],
        "fixes": [],
        "skipped": False,
    }
    if side_wall_image_tangent_order:
        check.update({"skipped": True, "reason": "side_wall_image_left_right_is_perspective_tangent_cue"})
        report["checks"].append(check)
        return
    if not gap_required:
        check.update({"skipped": True, "reason": "axis_gap_not_required_for_this_wall_plane"})
        report["checks"].append(check)
        return
    descendants = _descendant_map(support_tree)
    room = plan["room"]
    clearance = max(float(SPATIAL_ORDER_MIN_AXIS_GAP), float(FINE_SPATIAL_ORDER_SCENE_CLEARANCE))
    effective_max_step = max(0.0, min(float(max_step), float(FINE_SPATIAL_ORDER_MAX_STEP)))
    for iteration in range(2):
        iteration_actions: list[dict[str, Any]] = []
        objects = {str(obj.get("id")): obj for obj in plan.get("objects", []) if isinstance(obj, dict) and obj.get("id")}
        for before_id, after_id in zip(expected, expected[1:]):
            if _reference_pair_is_same_axis(reference_profile, before_id, after_id):
                check["edge_checks"].append(
                    {
                        "before": before_id,
                        "after": after_id,
                        "skipped": True,
                        "reason": "reference_same_axis_pair",
                    }
                )
                continue
            ref_gap = _reference_profile_expected_gap(reference_profile, before_id, after_id)
            ref_edge_gap = _fine_spatial_order_reference_edge_gap(ref_bboxes, before_id, after_id, "x" if axis_name == "x" else "front_to_back")
            threshold = _reference_same_axis_threshold(reference_profile, before_id, after_id)
            min_ref_gap = max(float(REFERENCE_DEPTH_PROFILE_MIN_IMAGE_GAP), float(threshold or 0.0))
            if axis_name == "x":
                if ref_edge_gap is not None and ref_edge_gap < float(FINE_SPATIAL_ORDER_MIN_REF_EDGE_GAP):
                    check["edge_checks"].append(
                        {
                            "before": before_id,
                            "after": after_id,
                            "skipped": True,
                            "reason": "reference_bboxes_overlap_on_axis",
                            "ref_edge_gap": round(float(ref_edge_gap), 6),
                            "min_ref_edge_gap": round(float(FINE_SPATIAL_ORDER_MIN_REF_EDGE_GAP), 6),
                        }
                    )
                    continue
                if ref_gap is not None and ref_gap <= min_ref_gap:
                    continue
            else:
                if ref_gap is None or ref_gap <= min_ref_gap:
                    check["edge_checks"].append(
                        {
                            "before": before_id,
                            "after": after_id,
                            "skipped": True,
                            "reason": "weak_front_back_reference_gap",
                            "ref_gap": round(float(ref_gap), 6) if ref_gap is not None else None,
                            "min_ref_gap": round(float(min_ref_gap), 6),
                        }
                    )
                    continue
            violation = _fine_spatial_order_pair_violation(objects, before_id, after_id, scene_axis, clearance)
            if not violation:
                check["edge_checks"].append(
                    {
                        "before": before_id,
                        "after": after_id,
                        "ok": True,
                        "ref_gap": round(float(ref_gap), 6) if ref_gap is not None else None,
                        "ref_edge_gap": round(float(ref_edge_gap), 6) if ref_edge_gap is not None else None,
                    }
                )
                continue
            after_movable, after_reason = _fine_spatial_order_can_move_root(objects, after_id, scene_axis, parent)
            before_movable, before_reason = _fine_spatial_order_can_move_root(objects, before_id, scene_axis, parent)
            moved_root = after_id if after_movable else before_id if before_movable else None
            if not moved_root:
                violation.update(
                    {
                        "skipped": True,
                        "reason": "no_movable_adjacent_root",
                        "before_skip_reason": before_reason,
                        "after_skip_reason": after_reason,
                    }
                )
                check["edge_checks"].append(violation)
                continue
            raw_delta = float(violation["deficit"]) if moved_root == after_id else -float(violation["deficit"])
            delta_value = _limited_repair_delta(raw_delta, max_step=effective_max_step)
            if abs(delta_value) <= 1e-6:
                continue
            mover = objects[moved_root]
            before_position = (float(mover.get("x", 0.0)), float(mover.get("y", 0.0)), float(mover.get("z", 0.0)))
            delta = (delta_value, 0.0, 0.0) if scene_axis == "x" else (0.0, delta_value, 0.0)
            moved_nodes = _move_spatial_relation_unit(objects, descendants, moved_root, delta, room)
            after_position = (float(mover.get("x", 0.0)), float(mover.get("y", 0.0)), float(mover.get("z", 0.0)))
            applied_delta = after_position[0] - before_position[0] if scene_axis == "x" else after_position[1] - before_position[1]
            action = {
                "iteration": iteration + 1,
                "type": "fine_edge_order_move",
                "before": before_id,
                "after": after_id,
                "axis": scene_axis,
                "moved_root": moved_root,
                "requested_delta": round(float(raw_delta), 6),
                "applied_delta": round(float(applied_delta), 6),
                "moved_node_count": len(moved_nodes),
                "violation_before": violation,
            }
            objects = {str(obj.get("id")): obj for obj in plan.get("objects", []) if isinstance(obj, dict) and obj.get("id")}
            action["violation_after"] = _fine_spatial_order_pair_violation(objects, before_id, after_id, scene_axis, clearance)
            iteration_actions.append(action)
            check["fixes"].append(action)
            report["fixes"].append(action)
        if not iteration_actions:
            break
    objects = {str(obj.get("id")): obj for obj in plan.get("objects", []) if isinstance(obj, dict) and obj.get("id")}
    check["current_order_after"] = _axis_order(objects, expected, scene_axis)
    check["fixed"] = bool(check["fixes"])
    report["checks"].append(check)


def _fine_spatial_order_wall_vertical_refinement(
    plan: dict[str, Any],
    scene_graph: dict[str, Any],
    parent: dict[str, str],
    report: dict[str, Any],
    max_step: float,
) -> None:
    room = plan.get("room") if isinstance(plan.get("room"), dict) else {}
    room_height = float(room.get("height", 0.0) or 0.0)
    if room_height <= 0.0:
        return
    objects = {str(obj.get("id")): obj for obj in plan.get("objects", []) if isinstance(obj, dict) and obj.get("id")}
    ref_bboxes = _reference_bboxes_by_object(scene_graph)
    vertical_checks: list[dict[str, Any]] = []
    effective_max_step = max(0.0, min(float(max_step), float(FINE_SPATIAL_ORDER_VERTICAL_MAX_STEP)))
    for object_id, obj in sorted(objects.items()):
        placement = str(obj.get("placement_type") or "")
        support_id = str(obj.get("support_id") or "")
        if placement in {"on_top", "inside"} or support_id in objects:
            continue
        if placement != "attached_to_wall":
            continue
        wall_id = support_id if support_id in VIRTUAL_WALLS else _object_attached_wall_id(objects, object_id, parent)
        if wall_id not in VIRTUAL_WALLS:
            continue
        if _fine_spatial_order_is_protected_assembly_member(obj) or _is_floor_grounded_wall_door(obj):
            continue
        bbox = ref_bboxes.get(object_id)
        if not bbox:
            continue
        y1 = _clamp(float(bbox[1]), 0.0, 1.0)
        y2 = _clamp(float(bbox[3]), 0.0, 1.0)
        if y2 <= y1 or y2 - y1 < 0.025:
            continue
        dims = obj.setdefault("dimensions", {})
        height = max(0.01, float(dims.get("height", 0.0) or 0.0))
        ref_center_y = (y1 + y2) / 2.0
        target_center_z = room_height * (1.0 - ref_center_y)
        target_center_z = _clamp(target_center_z, height / 2.0 + 0.04, room_height - height / 2.0 - 0.04)
        current_center_z = float(obj.get("z", 0.0) or 0.0) + height / 2.0
        raw_delta = float(target_center_z) - float(current_center_z)
        check = {
            "id": object_id,
            "wall_id": wall_id,
            "reference_bbox": [round(float(value), 6) for value in bbox],
            "current_center_z": round(float(current_center_z), 6),
            "target_center_z": round(float(target_center_z), 6),
            "raw_delta_z": round(float(raw_delta), 6),
        }
        if abs(raw_delta) < 0.04:
            check["ok"] = True
            vertical_checks.append(check)
            continue
        delta_z = _limited_repair_delta(raw_delta, max_step=effective_max_step)
        if abs(delta_z) <= 1e-6:
            check.update({"ok": False, "skipped": True, "reason": "zero_limited_delta"})
            vertical_checks.append(check)
            continue
        before = _plan_object_snapshot(obj)
        obj["z"] = float(obj.get("z", 0.0) or 0.0) + float(delta_z)
        obj["z"] = _clamp(float(obj["z"]), 0.02, max(0.02, room_height - height - 0.04))
        _clamp_wall_attached_object(obj, room, wall_id)
        after = _plan_object_snapshot(obj)
        check.update(
            {
                "ok": True,
                "changed": before != after,
                "applied_delta_z": round(float(after.get("z", 0.0) - before.get("z", 0.0)), 6),
                "before": before,
                "after": after,
            }
        )
        vertical_checks.append(check)
        if before != after:
            fix = {
                "type": "fine_wall_vertical_reference_center",
                "id": object_id,
                "wall_id": wall_id,
                "reference_bbox": check["reference_bbox"],
                "requested_delta_z": check["raw_delta_z"],
                "applied_delta_z": check["applied_delta_z"],
                "before": before,
                "after": after,
            }
            report["fixes"].append(fix)
            report.setdefault("vertical_fixes", []).append(fix)
    report["vertical_checks"] = vertical_checks


def _fine_layout_unit_scene_bounds(
    objects: dict[str, dict[str, Any]],
    member_ids: list[str],
) -> dict[str, list[float]] | None:
    lows = {"x": [], "y": [], "z": []}
    highs = {"x": [], "y": [], "z": []}
    for object_id in member_ids:
        obj = objects.get(str(object_id))
        if not obj:
            continue
        min_v, max_v = _bbox_for_object(obj)
        for axis, index in (("x", 0), ("y", 1), ("z", 2)):
            lows[axis].append(float(min_v[index]))
            highs[axis].append(float(max_v[index]))
    if not any(lows.values()):
        return None
    bounds: dict[str, list[float]] = {}
    for axis in ("x", "y", "z"):
        low = min(lows[axis])
        high = max(highs[axis])
        bounds[axis] = [low, (low + high) / 2.0, high, max(0.0, high - low)]
    return bounds


def _fine_layout_unit_reference_bbox(
    ref_bboxes: dict[str, list[float]],
    member_ids: list[str],
) -> list[float] | None:
    boxes = [ref_bboxes[str(object_id)] for object_id in member_ids if str(object_id) in ref_bboxes]
    if not boxes:
        return None
    return [
        min(float(bbox[0]) for bbox in boxes),
        min(float(bbox[1]) for bbox in boxes),
        max(float(bbox[2]) for bbox in boxes),
        max(float(bbox[3]) for bbox in boxes),
    ]


def _fine_layout_unit_wall_id(
    objects: dict[str, dict[str, Any]],
    member_ids: list[str],
    parent: dict[str, str],
) -> str | None:
    votes: dict[str, int] = {}
    for object_id in member_ids:
        wall_id = _object_attached_wall_id(objects, str(object_id), parent)
        if wall_id in VIRTUAL_WALLS:
            votes[wall_id] = votes.get(wall_id, 0) + 1
    return max(votes.items(), key=lambda item: item[1])[0] if votes else None


def _fine_window_curtain_cluster_member_ids(
    objects: dict[str, dict[str, Any]],
    ref_bboxes: dict[str, list[float]],
    parent: dict[str, str],
) -> list[list[str]]:
    windows = [
        obj
        for obj in objects.values()
        if _functional_cluster_is_window_object(obj)
        and not _is_curtain_panel_object(obj)
        and not _is_curtain_rod_object(obj)
    ]
    clusters: list[list[str]] = []
    assigned: set[str] = set()

    def near_window(window_id: str, object_id: str) -> bool:
        window_bbox = ref_bboxes.get(window_id)
        object_bbox = ref_bboxes.get(object_id)
        if not window_bbox or not object_bbox:
            return len(windows) == 1
        wx = (float(window_bbox[0]) + float(window_bbox[2])) / 2.0
        wy = (float(window_bbox[1]) + float(window_bbox[3])) / 2.0
        ox = (float(object_bbox[0]) + float(object_bbox[2])) / 2.0
        oy = (float(object_bbox[1]) + float(object_bbox[3])) / 2.0
        return abs(wx - ox) <= 0.46 and abs(wy - oy) <= 0.50

    for window in windows:
        window_id = str(window.get("id") or "")
        if not window_id:
            continue
        window_wall = _object_attached_wall_id(objects, window_id, parent)
        members = [window_id]
        for object_id, obj in sorted(objects.items()):
            if object_id == window_id:
                continue
            if not (_is_curtain_panel_object(obj) or _is_curtain_rod_object(obj)):
                continue
            object_wall = _object_attached_wall_id(objects, object_id, parent)
            if window_wall in VIRTUAL_WALLS and object_wall in VIRTUAL_WALLS and object_wall != window_wall:
                continue
            if near_window(window_id, object_id):
                members.append(object_id)
        if len(members) < 2:
            continue
        member_set = set(members)
        if assigned & member_set:
            continue
        assigned.update(member_set)
        clusters.append(sorted(member_set))
    return clusters


def _fine_spatial_order_layout_units(
    plan: dict[str, Any],
    scene_graph: dict[str, Any],
    parent: dict[str, str],
) -> list[dict[str, Any]]:
    objects = {str(obj.get("id")): obj for obj in plan.get("objects", []) if isinstance(obj, dict) and obj.get("id")}
    ref_bboxes = _reference_bboxes_by_object(scene_graph)
    units: list[dict[str, Any]] = []
    clustered_members: set[str] = set()
    for member_ids in _fine_window_curtain_cluster_member_ids(objects, ref_bboxes, parent):
        clustered_members.update(member_ids)
        window_id = next((object_id for object_id in member_ids if _functional_cluster_is_window_object(objects.get(object_id, {}))), member_ids[0])
        units.append(
            _fine_make_layout_unit(
                f"window_curtain_cluster:{window_id}",
                "window_curtain_cluster",
                member_ids,
                objects,
                ref_bboxes,
                parent,
                locked_internal_order=True,
            )
        )
    for object_id in sorted(objects):
        if object_id in clustered_members:
            continue
        units.append(
            _fine_make_layout_unit(
                object_id,
                "object",
                [object_id],
                objects,
                ref_bboxes,
                parent,
                locked_internal_order=False,
            )
        )
    return [unit for unit in units if unit]


def _fine_make_layout_unit(
    unit_id: str,
    unit_type: str,
    member_ids: list[str],
    objects: dict[str, dict[str, Any]],
    ref_bboxes: dict[str, list[float]],
    parent: dict[str, str],
    *,
    locked_internal_order: bool,
) -> dict[str, Any]:
    scene_bounds = _fine_layout_unit_scene_bounds(objects, member_ids)
    ref_bbox = _fine_layout_unit_reference_bbox(ref_bboxes, member_ids)
    if not scene_bounds:
        return {}
    first_obj = objects.get(member_ids[0], {})
    wall_id = _fine_layout_unit_wall_id(objects, member_ids, parent)
    unit = {
        "unit_id": unit_id,
        "unit_type": unit_type,
        "object_id": member_ids[0] if len(member_ids) == 1 else None,
        "member_ids": list(member_ids),
        "locked_internal_order": bool(locked_internal_order),
        "category": first_obj.get("category"),
        "description": first_obj.get("description"),
        "wall_id": wall_id,
        "scene_bounds": {
            axis: [round(float(value), 6) for value in values]
            for axis, values in scene_bounds.items()
        },
        "scene_top": round(float(scene_bounds["z"][2]), 6),
        "scene_bottom": round(float(scene_bounds["z"][0]), 6),
    }
    if ref_bbox:
        unit["reference_bbox"] = [round(float(value), 6) for value in ref_bbox]
        unit["reference_top_y"] = round(float(ref_bbox[1]), 6)
        unit["reference_bottom_y"] = round(float(ref_bbox[3]), 6)
    return unit


def _fine_vertical_top_relevant_unit(unit: dict[str, Any], objects: dict[str, dict[str, Any]]) -> bool:
    if unit.get("unit_type") == "window_curtain_cluster":
        return True
    object_id = str(unit.get("object_id") or "")
    obj = objects.get(object_id)
    if not obj:
        return False
    text = _object_identity_text(obj)
    if _is_floor_covering(obj) or _is_hanging_object(obj):
        return False
    if any(
        keyword in text
        for keyword in (
            "wardrobe",
            "armoire",
            "closet",
            "door",
            "window",
            "curtain",
            "dresser",
            "cabinet",
            "wall art",
            "painting",
            "picture",
            "poster",
            "mirror",
        )
    ):
        return True
    return str(obj.get("placement_type") or "") == "attached_to_wall"


def _fine_vertical_scale_candidate_object(obj: dict[str, Any] | None) -> bool:
    if not obj:
        return False
    if _is_floor_covering(obj) or _is_hanging_object(obj):
        return False
    placement = str(obj.get("placement_type") or "floor")
    support_id = str(obj.get("support_id") or "")
    if placement not in {"floor", "against_wall", ""}:
        return False
    if support_id and support_id not in {"floor", "None", "none", "null"} and support_id not in VIRTUAL_WALLS:
        return False
    text = _object_identity_text(obj)
    return any(keyword in text for keyword in ("wardrobe", "armoire", "closet", "door", "dresser", "cabinet", "bookcase", "bookshelf"))


def _fine_spatial_order_vertical_edge_residuals(
    plan: dict[str, Any],
    layout_units: list[dict[str, Any]],
) -> list[dict[str, Any]]:
    objects = {str(obj.get("id")): obj for obj in plan.get("objects", []) if isinstance(obj, dict) and obj.get("id")}
    relevant = [
        unit
        for unit in layout_units
        if "reference_top_y" in unit and _fine_vertical_top_relevant_unit(unit, objects)
    ]
    residuals: list[dict[str, Any]] = []
    for index, a in enumerate(relevant):
        for b in relevant[index + 1 :]:
            a_ref_top = float(a["reference_top_y"])
            b_ref_top = float(b["reference_top_y"])
            if abs(a_ref_top - b_ref_top) > 0.28:
                continue
            a_top = float(a.get("scene_top", 0.0) or 0.0)
            b_top = float(b.get("scene_top", 0.0) or 0.0)
            ref_gap = b_ref_top - a_ref_top
            scene_gap = a_top - b_top
            if abs(ref_gap) <= float(FINE_SPATIAL_ORDER_VERTICAL_TOP_REF_GAP):
                if ref_gap > 0.012 and scene_gap < float(FINE_SPATIAL_ORDER_VERTICAL_TOP_MIN_GAP):
                    target_top = b_top + float(FINE_SPATIAL_ORDER_VERTICAL_TOP_MIN_GAP)
                    residual_type = "top_order_violation_with_near_reference_tops"
                    raise_unit = a
                    against_unit = b
                elif ref_gap < -0.012 and -scene_gap < float(FINE_SPATIAL_ORDER_VERTICAL_TOP_MIN_GAP):
                    target_top = a_top + float(FINE_SPATIAL_ORDER_VERTICAL_TOP_MIN_GAP)
                    residual_type = "top_order_violation_with_near_reference_tops"
                    raise_unit = b
                    against_unit = a
                elif abs(scene_gap) > float(FINE_SPATIAL_ORDER_VERTICAL_TOP_SCENE_TOLERANCE):
                    if scene_gap < 0.0:
                        target_top = b_top - float(FINE_SPATIAL_ORDER_VERTICAL_TOP_SCENE_TOLERANCE)
                        raise_unit = a
                        against_unit = b
                    else:
                        target_top = a_top - float(FINE_SPATIAL_ORDER_VERTICAL_TOP_SCENE_TOLERANCE)
                        raise_unit = b
                        against_unit = a
                    residual_type = "top_alignment_gap_too_large"
                else:
                    continue
            elif ref_gap > 0.0 and scene_gap < float(FINE_SPATIAL_ORDER_VERTICAL_TOP_MIN_GAP):
                target_top = b_top + float(FINE_SPATIAL_ORDER_VERTICAL_TOP_MIN_GAP)
                residual_type = "top_order_violation"
                raise_unit = a
                against_unit = b
            elif ref_gap < 0.0 and -scene_gap < float(FINE_SPATIAL_ORDER_VERTICAL_TOP_MIN_GAP):
                target_top = a_top + float(FINE_SPATIAL_ORDER_VERTICAL_TOP_MIN_GAP)
                residual_type = "top_order_violation"
                raise_unit = b
                against_unit = a
            else:
                continue
            room_height = _safe_float(plan.get("room", {}).get("height"), 0.0)
            ref_target_top = room_height * (1.0 - float(raise_unit.get("reference_top_y", 0.0))) if room_height > 0.0 else target_top
            target_top = max(float(target_top), float(ref_target_top))
            residuals.append(
                {
                    "type": residual_type,
                    "raise_unit_id": raise_unit.get("unit_id"),
                    "against_unit_id": against_unit.get("unit_id"),
                    "raise_member_ids": raise_unit.get("member_ids", []),
                    "against_member_ids": against_unit.get("member_ids", []),
                    "raise_locked_internal_order": bool(raise_unit.get("locked_internal_order")),
                    "against_locked_internal_order": bool(against_unit.get("locked_internal_order")),
                    "reference_top_gap": round(float(ref_gap), 6),
                    "scene_top_gap": round(float(scene_gap), 6),
                    "raise_scene_top": raise_unit.get("scene_top"),
                    "against_scene_top": against_unit.get("scene_top"),
                    "target_scene_top": round(float(target_top), 6),
                    "deficit": round(max(0.0, float(target_top) - float(raise_unit.get("scene_top", 0.0) or 0.0)), 6),
                    "evidence": (
                        "Reference vertical top edges imply a higher or similar top edge, but the rendered scene top edge is too low. "
                        "If the raise unit is a floor/root object, translation cannot repair this without floating; scale-height repair is a candidate."
                    ),
                }
            )
    residuals.sort(key=lambda item: (-float(item.get("deficit", 0.0) or 0.0), str(item.get("raise_unit_id") or "")))
    return residuals[:24]


def _fine_scale_candidates_from_vertical_residuals(
    plan: dict[str, Any],
    layout_units: list[dict[str, Any]],
    residuals: list[dict[str, Any]],
) -> list[dict[str, Any]]:
    objects = {str(obj.get("id")): obj for obj in plan.get("objects", []) if isinstance(obj, dict) and obj.get("id")}
    units = {str(unit.get("unit_id")): unit for unit in layout_units}
    room = plan.get("room", {}) if isinstance(plan.get("room"), dict) else {}
    by_object: dict[str, dict[str, Any]] = {}
    for residual in residuals:
        unit = units.get(str(residual.get("raise_unit_id") or ""))
        if not unit or unit.get("unit_type") != "object":
            continue
        object_id = str(unit.get("object_id") or "")
        obj = objects.get(object_id)
        if not _fine_vertical_scale_candidate_object(obj):
            continue
        dims = obj.get("dimensions") if isinstance(obj.get("dimensions"), dict) else {}
        current_height = _safe_float(dims.get("height"), 0.0)
        if current_height <= 0.0:
            continue
        bottom_z = _safe_float(obj.get("z"), 0.0)
        target_height = float(residual.get("target_scene_top", 0.0) or 0.0) - bottom_z
        bounds = _scale_prior_bounds_for_object(obj, room)
        min_height, max_height = bounds.get("height", (current_height, current_height))
        target_height = _clamp(target_height, float(min_height), float(max_height))
        target_height = min(target_height, current_height * float(FINE_SPATIAL_ORDER_SCALE_MAX_RATIO))
        if target_height <= current_height * 1.015:
            continue
        existing = by_object.get(object_id)
        candidate = {
            "target_object_id": object_id,
            "unit_id": unit.get("unit_id"),
            "scale_axis": "height",
            "operation": "increase",
            "current_height": round(float(current_height), 6),
            "target_height": round(float(target_height), 6),
            "target_ratio": round(float(target_height / current_height), 6),
            "bounds": {"height": [round(float(min_height), 6), round(float(max_height), 6)]},
            "anchored_edge": "bottom_on_floor",
            "residual": residual,
        }
        if existing is None or float(candidate["target_height"]) > float(existing["target_height"]):
            by_object[object_id] = candidate
    return sorted(by_object.values(), key=lambda item: (-float(item["target_height"]), str(item["target_object_id"])))


def _fine_detailed_layout_snapshot(
    plan: dict[str, Any],
    scene_graph: dict[str, Any],
    parent: dict[str, str],
) -> dict[str, Any]:
    objects = {str(obj.get("id")): obj for obj in plan.get("objects", []) if isinstance(obj, dict) and obj.get("id")}
    units = _fine_spatial_order_layout_units(plan, scene_graph, parent)
    compact_units: list[dict[str, Any]] = []
    for unit in units:
        if not isinstance(unit, dict):
            continue
        unit_id = str(unit.get("unit_id") or "")
        member_ids = [str(value) for value in unit.get("member_ids", []) if value]
        first_obj = objects.get(member_ids[0], {}) if member_ids else {}
        dims = first_obj.get("dimensions") if isinstance(first_obj.get("dimensions"), dict) else {}
        compact = {
            "unit_id": unit_id,
            "unit_type": unit.get("unit_type"),
            "object_id": unit.get("object_id"),
            "member_ids": member_ids,
            "locked_internal_order": bool(unit.get("locked_internal_order")),
            "category": unit.get("category") or first_obj.get("category"),
            "placement_type": first_obj.get("placement_type"),
            "support_id": first_obj.get("support_id"),
            "wall_id": unit.get("wall_id") or _object_attached_wall_id(objects, str(unit.get("object_id") or ""), parent),
            "scene_bounds": unit.get("scene_bounds", {}),
            "reference_bbox": unit.get("reference_bbox"),
        }
        compact_units.append({key: value for key, value in compact.items() if value not in (None, "", [], {})})
    return {
        "room": plan.get("room", {}),
        "layout_units": compact_units,
    }


def build_fine_spatial_order_detailed_prompt(
    scene_prompt: str,
    plan: dict[str, Any],
    scene_graph: dict[str, Any],
    parent: dict[str, str],
) -> str:
    snapshot = _fine_detailed_layout_snapshot(plan, scene_graph, parent)
    snapshot_json = json.dumps(snapshot, ensure_ascii=False, separators=(",", ":"))
    scene_prompt_short = str(scene_prompt or "")
    if len(scene_prompt_short) > 240:
        scene_prompt_short = scene_prompt_short[:237].rstrip() + "..."
    return f"""
You are the third-stage detailed spatial-order reader for TreeSAGE Flow 2.
The attached image may be a side-by-side comparison: the left side is the reference image and the right side is the current render.
If it is not side-by-side, treat it as the reference image only and rely on the JSON scene snapshot for current scene coordinates.

Scene prompt:
{scene_prompt_short}

Current scene/layout snapshot:
{snapshot_json}

Your task is to infer fine, endpoint-level axis relationships from the reference, not just object-center order.
Output constraints that the deterministic third-stage solver can check against the current scene.

Use this coordinate schema:
- axis="x": left/right scene axis. edge values are low, center, high.
- axis="y": front/back or outer/inner depth axis. low is the front/outer/camera side; high is the back/inner wall side for this room layout.
- axis="z": vertical axis. low is bottom; high is top.

Important:
- Emit endpoint relations such as "a.high <= b.high" or "a.low approximately equals b.low".
- For depth containment/overlap, describe the endpoint order explicitly. Example: if A spans around B on the y axis, output A.low <= B.low and B.high <= A.high. If the visual order is A_back < B_back < B_front < A_front, express it with low/high endpoint constraints using the provided y convention.
- Window/curtain/rod clusters are locked layout units. Judge them as a single unit unless the visible error is explicitly about their internal assembly order.
- Do not emit support-surface constraints between a child object and its support, such as lamp/book/plant-on-nightstand alignment or tabletop z contact. The support registry and tabletop packer handle those relations.
- For rugs/floor coverings, be exact about endpoint direction. If a rug extends left/front beyond a bed, output rug.low <= bed.low. If a rug extends right/back beyond a bed, output bed.high <= rug.high. Do not reverse these containment endpoints.
- Do not emit required same-wall normal-axis equality between a wall-attached object and floor furniture anchored to the same wall; wall contact validators handle the wall plane. If the visual issue is along-wall depth/order, use the wall tangent axis endpoint relation instead.
- Do not emit y-axis full-containment constraints between side-wall floor storage and a window_curtain_cluster. The deterministic fixture-depth solver owns storage-vs-window/curtain front-edge and compactness relations.
- Prefer high-confidence required constraints for large visible objects and wall clusters. Use soft constraints for uncertain or occluded cases.
- Do not invent objects. Use only unit_id or object_id values from layout_units/object_metadata.
- Do not propose absolute coordinates; only endpoint relationships.

Return only JSON:
{{
  "schema": "tree_sage_fine_spatial_order_detailed_agent_v1",
  "axis_relations": [
    {{
      "axis": "x|y|z",
      "relation": "less_than_or_equal|approximately_equal",
      "left": {{"unit_id": "existing_unit_or_object_id", "edge": "low|center|high"}},
      "right": {{"unit_id": "existing_unit_or_object_id", "edge": "low|center|high"}},
      "target_gap": 0.0,
      "importance": "required|soft",
      "confidence": 0.0,
      "evidence": "short visual evidence",
      "expected_effect": "move_or_scale_goal"
    }}
  ],
  "cluster_notes": [
    {{
      "unit_id": "existing_unit_id",
      "note": "short note about locked cluster interpretation"
    }}
  ],
  "notes": ["short uncertainty notes"]
}}

Rules:
- relation="less_than_or_equal" means left endpoint should be <= right endpoint - target_gap.
- relation="approximately_equal" means the two endpoints should align within local tolerance.
- Use target_gap=0.0 for containment or edge alignment unless a visible clearance is clearly required.
- Keep axis_relations to the most important {FINE_SPATIAL_ORDER_DETAILED_MAX_CONSTRAINTS} constraints.
- If the current render already satisfies a relation, you may still output it; the solver will record it as ok.
""".strip()


def run_fine_spatial_order_detailed_agent(
    scene_prompt: str,
    plan: dict[str, Any],
    scene_graph: dict[str, Any],
    parent: dict[str, str],
    comparison_or_reference_image: Path,
    output_dir: Path,
    model: str | None,
) -> dict[str, Any]:
    return run_codex_reference_json_agent(
        "fine_spatial_order_detailed",
        build_fine_spatial_order_detailed_prompt(scene_prompt, plan, scene_graph, parent),
        comparison_or_reference_image,
        output_dir,
        model,
    )


def _fine_detailed_normalize_axis(raw_axis: Any) -> str | None:
    text = str(raw_axis or "").strip().lower().replace("-", "_").replace(" ", "_")
    if text in {"x", "left_right", "left_to_right", "horizontal"}:
        return "x"
    if text in {"y", "front_back", "front_to_back", "depth", "inner_outer", "outer_inner"}:
        return "y"
    if text in {"z", "vertical", "height", "up_down", "top_bottom"}:
        return "z"
    return None


def _fine_detailed_normalize_edge(raw_edge: Any) -> str | None:
    text = str(raw_edge or "").strip().lower().replace("-", "_").replace(" ", "_")
    mapping = {
        "low": "low",
        "min": "low",
        "minimum": "low",
        "left": "low",
        "front": "low",
        "outer": "low",
        "near": "low",
        "bottom": "low",
        "lower": "low",
        "center": "center",
        "centre": "center",
        "middle": "center",
        "mid": "center",
        "high": "high",
        "max": "high",
        "maximum": "high",
        "right": "high",
        "back": "high",
        "rear": "high",
        "inner": "high",
        "far": "high",
        "top": "high",
        "upper": "high",
    }
    return mapping.get(text)


def _fine_detailed_normalize_relation(raw_relation: Any) -> str | None:
    text = str(raw_relation or "").strip().lower().replace("-", "_").replace(" ", "_")
    if text in {"less_than_or_equal", "less_than", "before", "ordered_before", "lte", "<=", "<"}:
        return "less_than_or_equal"
    if text in {"approximately_equal", "approx_equal", "near_equal", "aligned", "align", "same", "=", "=="}:
        return "approximately_equal"
    return None


def _fine_detailed_endpoint_from_raw(raw_endpoint: Any) -> dict[str, str] | None:
    if isinstance(raw_endpoint, str):
        return {"unit_id": raw_endpoint, "edge": "center"}
    if not isinstance(raw_endpoint, dict):
        return None
    unit_id = (
        raw_endpoint.get("unit_id")
        or raw_endpoint.get("object_id")
        or raw_endpoint.get("id")
        or raw_endpoint.get("target")
    )
    edge = _fine_detailed_normalize_edge(raw_endpoint.get("edge") or raw_endpoint.get("endpoint") or raw_endpoint.get("side"))
    if not unit_id or not edge:
        return None
    return {"unit_id": str(unit_id), "edge": edge}


def _fine_detailed_unit_is_side_wall_storage(unit: dict[str, Any]) -> bool:
    if unit.get("unit_type") != "object":
        return False
    wall_id = str(unit.get("wall_id") or "")
    if wall_id not in {"wall_west", "wall_east"}:
        return False
    text = f"{unit.get('category') or ''} {unit.get('description') or ''} {unit.get('unit_id') or ''}".lower()
    return any(keyword in text for keyword in ("dresser", "cabinet", "storage", "sideboard", "console", "wardrobe"))


def _fine_detailed_relation_owned_by_fixture_depth(
    axis: str,
    relation: str,
    left: dict[str, str],
    right: dict[str, str],
    left_unit: dict[str, Any],
    right_unit: dict[str, Any],
) -> bool:
    if axis != "y" or relation != "less_than_or_equal":
        return False
    left_cluster = left_unit.get("unit_type") == "window_curtain_cluster"
    right_cluster = right_unit.get("unit_type") == "window_curtain_cluster"
    if left_cluster == right_cluster:
        return False
    storage_unit = right_unit if left_cluster else left_unit
    if not _fine_detailed_unit_is_side_wall_storage(storage_unit):
        return False
    left_edge = str(left.get("edge") or "")
    right_edge = str(right.get("edge") or "")
    return left_edge == right_edge and left_edge in {"low", "high"}


def _fine_detailed_normalized_relations(
    raw_report: dict[str, Any] | None,
    unit_by_id: dict[str, dict[str, Any]],
) -> tuple[list[dict[str, Any]], list[dict[str, Any]]]:
    relations: list[dict[str, Any]] = []
    skipped: list[dict[str, Any]] = []
    raw_items = raw_report.get("axis_relations", []) if isinstance(raw_report, dict) else []
    if not isinstance(raw_items, list):
        return relations, [{"reason": "axis_relations_not_list"}]
    for index, item in enumerate(raw_items[: max(0, int(FINE_SPATIAL_ORDER_DETAILED_MAX_CONSTRAINTS))]):
        if not isinstance(item, dict):
            skipped.append({"index": index, "reason": "relation_not_object"})
            continue
        axis = _fine_detailed_normalize_axis(item.get("axis"))
        relation = _fine_detailed_normalize_relation(item.get("relation") or item.get("type"))
        left = _fine_detailed_endpoint_from_raw(
            item.get("left")
            or item.get("before")
            or item.get("lesser")
            or item.get("from")
            or item.get("a")
        )
        right = _fine_detailed_endpoint_from_raw(
            item.get("right")
            or item.get("after")
            or item.get("greater")
            or item.get("to")
            or item.get("b")
        )
        confidence = _safe_float(item.get("confidence"), 0.0)
        if not axis or not relation or not left or not right:
            skipped.append({"index": index, "reason": "invalid_axis_relation_or_endpoint", "raw": item})
            continue
        left_unit = unit_by_id.get(str(left["unit_id"]))
        right_unit = unit_by_id.get(str(right["unit_id"]))
        if not left_unit or not right_unit:
            skipped.append(
                {
                    "index": index,
                    "reason": "unknown_unit_id",
                    "left_unit_id": left["unit_id"],
                    "right_unit_id": right["unit_id"],
                }
            )
            continue
        if confidence < float(FINE_SPATIAL_ORDER_DETAILED_MIN_CONFIDENCE):
            skipped.append({"index": index, "reason": "low_confidence", "confidence": confidence, "raw": item})
            continue
        importance = str(item.get("importance") or "soft").strip().lower()
        if importance not in {"required", "soft"}:
            importance = "soft"
        target_gap = max(0.0, _safe_float(item.get("target_gap"), 0.0))
        if _fine_detailed_relation_owned_by_fixture_depth(axis, relation, left, right, left_unit, right_unit):
            skipped.append(
                {
                    "index": index,
                    "reason": "side_wall_storage_window_cluster_y_endpoint_owned_by_fixture_depth",
                    "left_unit_id": left["unit_id"],
                    "right_unit_id": right["unit_id"],
                    "left_edge": left.get("edge"),
                    "right_edge": right.get("edge"),
                    "raw": item,
                }
            )
            continue
        relations.append(
            {
                "index": index,
                "axis": axis,
                "relation": relation,
                "left": left,
                "right": right,
                "target_gap": round(float(target_gap), 6),
                "importance": importance,
                "confidence": round(float(confidence), 6),
                "evidence": item.get("evidence"),
                "expected_effect": item.get("expected_effect"),
            }
        )
    return relations, skipped


def _fine_detailed_endpoint_value(unit: dict[str, Any], axis: str, edge: str) -> float | None:
    values = unit.get("scene_bounds", {}).get(axis) if isinstance(unit.get("scene_bounds"), dict) else None
    if not isinstance(values, list) or len(values) < 3:
        return None
    index = {"low": 0, "center": 1, "high": 2}.get(edge)
    if index is None:
        return None
    return _safe_float(values[index], 0.0)


def _fine_detailed_unit_member_ids(unit: dict[str, Any]) -> set[str]:
    member_ids = unit.get("member_ids") if isinstance(unit.get("member_ids"), list) else []
    ids = {str(value) for value in member_ids if value}
    object_id = str(unit.get("object_id") or "")
    if object_id:
        ids.add(object_id)
    unit_id = str(unit.get("unit_id") or "")
    if unit.get("unit_type") == "object" and unit_id:
        ids.add(unit_id)
    return ids


def _fine_detailed_units_have_support_relation(
    objects: dict[str, dict[str, Any]],
    parent: dict[str, str],
    a_unit: dict[str, Any],
    b_unit: dict[str, Any],
) -> bool:
    a_ids = _fine_detailed_unit_member_ids(a_unit)
    b_ids = _fine_detailed_unit_member_ids(b_unit)
    if not a_ids or not b_ids:
        return False

    def support_id_for(object_id: str) -> str:
        obj = objects.get(str(object_id), {})
        return str(parent.get(str(object_id)) or obj.get("support_id") or "")

    for object_id in a_ids:
        if support_id_for(object_id) in b_ids:
            return True
    for object_id in b_ids:
        if support_id_for(object_id) in a_ids:
            return True
    return False


def _fine_detailed_unit_objects(
    objects: dict[str, dict[str, Any]],
    unit: dict[str, Any],
) -> list[dict[str, Any]]:
    return [objects[object_id] for object_id in _fine_detailed_unit_member_ids(unit) if object_id in objects]


def _fine_detailed_relation_involves_floor_covering(
    objects: dict[str, dict[str, Any]],
    left_unit: dict[str, Any],
    right_unit: dict[str, Any],
) -> bool:
    return any(
        _is_floor_covering(obj)
        for obj in (
            _fine_detailed_unit_objects(objects, left_unit)
            + _fine_detailed_unit_objects(objects, right_unit)
        )
    )


def _fine_detailed_unit_is_floor_covering(
    objects: dict[str, dict[str, Any]],
    unit: dict[str, Any],
) -> bool:
    return any(_is_floor_covering(obj) for obj in _fine_detailed_unit_objects(objects, unit))


def _fine_detailed_unit_wall_id(
    objects: dict[str, dict[str, Any]],
    parent: dict[str, str],
    unit: dict[str, Any],
) -> str:
    wall_id = str(unit.get("wall_id") or "")
    if wall_id in VIRTUAL_WALLS:
        return wall_id
    for object_id in _fine_detailed_unit_member_ids(unit):
        if object_id in objects:
            wall_id = _object_attached_wall_id(objects, object_id, parent)
            if wall_id in VIRTUAL_WALLS:
                return wall_id
    return ""


def _fine_detailed_wall_normal_axis(wall_id: str) -> str | None:
    tangent_axis = _fine_spatial_order_wall_tangent_axis(wall_id)
    if tangent_axis == "x":
        return "y"
    if tangent_axis == "y":
        return "x"
    return None


def _fine_detailed_unit_has_wall_attached_member(
    objects: dict[str, dict[str, Any]],
    unit: dict[str, Any],
) -> bool:
    return any(_is_wall_attached_object(obj) or _is_hanging_object(obj) for obj in _fine_detailed_unit_objects(objects, unit))


def _fine_detailed_unit_has_wall_anchored_floor_member(
    objects: dict[str, dict[str, Any]],
    parent: dict[str, str],
    unit: dict[str, Any],
) -> bool:
    for obj in _fine_detailed_unit_objects(objects, unit):
        if _is_wall_anchored_floor_object(obj, parent) or _is_bed_or_sofa_object(obj):
            wall_id = _fine_detailed_unit_wall_id(objects, parent, unit)
            if wall_id in VIRTUAL_WALLS:
                return True
    return False


def _fine_detailed_is_same_wall_normal_contact_relation(
    objects: dict[str, dict[str, Any]],
    parent: dict[str, str],
    left_unit: dict[str, Any],
    right_unit: dict[str, Any],
    axis: str,
    relation_type: str,
) -> bool:
    if relation_type != "approximately_equal":
        return False
    left_wall = _fine_detailed_unit_wall_id(objects, parent, left_unit)
    right_wall = _fine_detailed_unit_wall_id(objects, parent, right_unit)
    if not left_wall or left_wall != right_wall:
        return False
    if axis != _fine_detailed_wall_normal_axis(left_wall):
        return False
    left_attached = _fine_detailed_unit_has_wall_attached_member(objects, left_unit)
    right_attached = _fine_detailed_unit_has_wall_attached_member(objects, right_unit)
    left_floor = _fine_detailed_unit_has_wall_anchored_floor_member(objects, parent, left_unit)
    right_floor = _fine_detailed_unit_has_wall_anchored_floor_member(objects, parent, right_unit)
    return (left_attached and right_floor) or (right_attached and left_floor)


def _fine_detailed_floor_covering_extends_low_text(text: str) -> bool:
    lowered = text.lower().replace("_", " ")
    phrases = (
        "extends farther left",
        "extends left",
        "farther left",
        "left beyond",
        "beyond bed left",
        "beyond the bed left",
        "projects clearly in front",
        "projects in front",
        "extends farther front",
        "farther front",
        "toward camera",
        "in front of the bed",
    )
    return any(phrase in lowered for phrase in phrases)


def _fine_detailed_floor_covering_extends_high_text(text: str) -> bool:
    lowered = text.lower().replace("_", " ")
    phrases = (
        "extends farther right",
        "extends right",
        "farther right",
        "right beyond",
        "beyond bed right",
        "beyond the bed right",
        "extends farther back",
        "farther back",
        "back beyond",
        "toward headboard",
        "continues under bed",
        "continues beneath",
    )
    return any(phrase in lowered for phrase in phrases)


def _fine_detailed_repair_floor_covering_endpoint_relation(
    relation: dict[str, Any],
    objects: dict[str, dict[str, Any]],
    unit_by_id: dict[str, dict[str, Any]],
) -> tuple[dict[str, Any], dict[str, Any] | None]:
    if str(relation.get("relation") or "") != "less_than_or_equal":
        return relation, None
    left_ref = relation.get("left") if isinstance(relation.get("left"), dict) else {}
    right_ref = relation.get("right") if isinstance(relation.get("right"), dict) else {}
    edge = str(left_ref.get("edge") or "")
    if edge not in {"low", "high"} or edge != str(right_ref.get("edge") or ""):
        return relation, None
    left_unit = unit_by_id.get(str(left_ref.get("unit_id") or ""))
    right_unit = unit_by_id.get(str(right_ref.get("unit_id") or ""))
    if not left_unit or not right_unit:
        return relation, None
    left_is_floor = _fine_detailed_unit_is_floor_covering(objects, left_unit)
    right_is_floor = _fine_detailed_unit_is_floor_covering(objects, right_unit)
    if left_is_floor == right_is_floor:
        return relation, None
    evidence_text = f"{relation.get('evidence') or ''} {relation.get('expected_effect') or ''}"
    should_swap = False
    reason = ""
    if edge == "low" and right_is_floor and _fine_detailed_floor_covering_extends_low_text(evidence_text):
        should_swap = True
        reason = "floor_covering_low_endpoint_extension_direction"
    elif edge == "high" and left_is_floor and _fine_detailed_floor_covering_extends_high_text(evidence_text):
        should_swap = True
        reason = "floor_covering_high_endpoint_extension_direction"
    if not should_swap:
        return relation, None
    repaired = deepcopy(relation)
    repaired["left"] = dict(right_ref)
    repaired["right"] = dict(left_ref)
    repair = {
        "relation_index": relation.get("index"),
        "reason": reason,
        "before": {"left": relation.get("left"), "right": relation.get("right")},
        "after": {"left": repaired.get("left"), "right": repaired.get("right")},
        "evidence": relation.get("evidence"),
        "expected_effect": relation.get("expected_effect"),
    }
    return repaired, repair


def _fine_detailed_unit_map(
    plan: dict[str, Any],
    scene_graph: dict[str, Any],
    parent: dict[str, str],
) -> tuple[list[dict[str, Any]], dict[str, dict[str, Any]]]:
    layout_units = _fine_spatial_order_layout_units(plan, scene_graph, parent)
    unit_by_id = {str(unit.get("unit_id")): unit for unit in layout_units if isinstance(unit, dict) and unit.get("unit_id")}
    for unit in layout_units:
        if not isinstance(unit, dict):
            continue
        object_id = str(unit.get("object_id") or "")
        if object_id:
            unit_by_id.setdefault(object_id, unit)
        for member_id in unit.get("member_ids", []) if isinstance(unit.get("member_ids"), list) else []:
            unit_by_id.setdefault(str(member_id), unit)
    return layout_units, unit_by_id


def _fine_detailed_relation_state(
    plan: dict[str, Any],
    scene_graph: dict[str, Any],
    parent: dict[str, str],
    relation: dict[str, Any],
    tolerance: float,
) -> dict[str, Any] | None:
    _layout_units, unit_by_id = _fine_detailed_unit_map(plan, scene_graph, parent)
    objects = {str(obj.get("id")): obj for obj in plan.get("objects", []) if isinstance(obj, dict) and obj.get("id")}
    axis = str(relation.get("axis") or "")
    left_ref = relation.get("left") if isinstance(relation.get("left"), dict) else {}
    right_ref = relation.get("right") if isinstance(relation.get("right"), dict) else {}
    left_unit = unit_by_id.get(str(left_ref.get("unit_id") or ""))
    right_unit = unit_by_id.get(str(right_ref.get("unit_id") or ""))
    if not left_unit or not right_unit:
        return None
    if _fine_detailed_units_have_support_relation(objects, parent, left_unit, right_unit):
        return {
            "relation_index": relation.get("index"),
            "ok": True,
            "skipped": True,
            "reason": "support_child_parent_relation_not_fine_order",
        }
    left_value = _fine_detailed_endpoint_value(left_unit, axis, str(left_ref.get("edge") or ""))
    right_value = _fine_detailed_endpoint_value(right_unit, axis, str(right_ref.get("edge") or ""))
    if left_value is None or right_value is None:
        return None
    target_gap = _safe_float(relation.get("target_gap"), 0.0)
    relation_type = str(relation.get("relation") or "")
    if _fine_detailed_is_same_wall_normal_contact_relation(objects, parent, left_unit, right_unit, axis, relation_type):
        return {
            "relation_index": relation.get("index"),
            "ok": True,
            "skipped": True,
            "reason": "same_wall_normal_contact_not_fine_order",
        }
    if relation_type == "less_than_or_equal":
        residual = float(left_value) + float(target_gap) - float(right_value)
        ok = residual <= tolerance
        violation = max(0.0, residual)
    elif relation_type == "approximately_equal":
        residual = abs(float(left_value) - float(right_value))
        ok = residual <= tolerance
        violation = residual
    else:
        return None
    return {
        "relation_index": relation.get("index"),
        "axis": axis,
        "relation": relation_type,
        "left": relation.get("left"),
        "right": relation.get("right"),
        "importance": relation.get("importance"),
        "residual": round(float(residual), 6),
        "violation": round(float(violation), 6),
        "tolerance": round(float(tolerance), 6),
        "ok": bool(ok),
    }


def _fine_detailed_required_guard_violations(
    plan: dict[str, Any],
    scene_graph: dict[str, Any],
    parent: dict[str, str],
    relations: list[dict[str, Any]],
    tolerance: float,
) -> dict[str, dict[str, Any]]:
    violations: dict[str, dict[str, Any]] = {}
    for relation in relations:
        if str(relation.get("importance") or "") != "required":
            continue
        state = _fine_detailed_relation_state(plan, scene_graph, parent, relation, tolerance)
        if not state or state.get("ok"):
            continue
        violations[str(relation.get("index"))] = state
    return violations


def _fine_detailed_is_vertical_scale_candidate(obj: dict[str, Any] | None) -> bool:
    if not obj:
        return False
    if _is_floor_covering(obj) or _is_hanging_object(obj):
        return False
    placement = str(obj.get("placement_type") or "floor")
    support_id = str(obj.get("support_id") or "")
    if placement != "floor":
        return False
    if support_id and support_id not in {"floor", "None", "none", "null"} and support_id not in VIRTUAL_WALLS:
        return False
    text = _object_identity_text(obj)
    return any(
        keyword in text
        for keyword in (
            "bed",
            "sofa",
            "wardrobe",
            "armoire",
            "closet",
            "door",
            "dresser",
            "cabinet",
            "bookcase",
            "bookshelf",
            "nightstand",
            "bedside",
            "side table",
            "table",
            "desk",
        )
    )


def _fine_apply_detailed_height_scale(
    plan: dict[str, Any],
    objects: dict[str, dict[str, Any]],
    parent: dict[str, str],
    unit: dict[str, Any],
    target_top: float,
    relation: dict[str, Any],
    report: dict[str, Any],
) -> bool:
    if unit.get("unit_type") != "object":
        return False
    object_id = str(unit.get("object_id") or "")
    obj = objects.get(object_id)
    if not _fine_detailed_is_vertical_scale_candidate(obj):
        return False
    assert obj is not None
    dims = obj.get("dimensions") if isinstance(obj.get("dimensions"), dict) else {}
    current_height = _safe_float(dims.get("height"), 0.0)
    if current_height <= 0.0:
        return False
    min_v, max_v = _bbox_for_object(obj)
    current_top = float(max_v[2])
    if float(target_top) <= current_top + max(0.02, float(FINE_SPATIAL_ORDER_DETAILED_TOLERANCE) * 0.5):
        return False
    room = plan.get("room", {}) if isinstance(plan.get("room"), dict) else {}
    bounds = _scale_prior_bounds_for_object(obj, room)
    min_height, max_height = bounds.get("height", (current_height, current_height))
    target_height = float(target_top) - float(min_v[2])
    target_height = _clamp(target_height, float(min_height), float(max_height))
    target_height = min(target_height, current_height * float(FINE_SPATIAL_ORDER_SCALE_MAX_RATIO))
    if target_height <= current_height * 1.015:
        return False
    before = _plan_object_snapshot(obj)
    before_dimensions = dict(dims)
    dims["height"] = float(target_height)
    obj["dimensions"] = dims
    if str(obj.get("placement_type") or "floor") == "floor":
        obj["z"] = 0.0
    _clamp_object_to_room_rotated(obj, room, margin=0.0)
    for child in objects.values():
        child_id = str(child.get("id") or "")
        if child_id == object_id:
            continue
        child_support = str(child.get("support_id") or parent.get(child_id) or "")
        if child_support == object_id and str(child.get("placement_type") or "") == "on_top":
            child["z"] = _supported_child_surface_z(obj, child)
    after = _plan_object_snapshot(obj)
    if before == after and before_dimensions == dict(dims):
        return False
    fix = {
        "type": "fine_detailed_agent_top_height_scale",
        "id": object_id,
        "axis": "height",
        "anchored_edge": "bottom_on_floor",
        "target_scene_top": round(float(target_top), 6),
        "before": before,
        "after": after,
        "before_dimensions": before_dimensions,
        "after_dimensions": dict(dims),
        "applied_ratio": round(float(target_height / current_height), 6),
        "agent_relation": relation,
    }
    report.setdefault("fixes", []).append(fix)
    report.setdefault("vertical_fixes", []).append(fix)
    return True


def _fine_detailed_attempt_xy_move(
    plan: dict[str, Any],
    scene_graph: dict[str, Any],
    support_tree: dict[str, Any],
    parent: dict[str, str],
    relation: dict[str, Any],
    guard_relations: list[dict[str, Any]],
    left_unit: dict[str, Any],
    right_unit: dict[str, Any],
    delta_left: float | None,
    delta_right: float | None,
    report: dict[str, Any],
    max_step: float,
    tolerance: float,
) -> bool:
    axis = str(relation.get("axis") or "")
    if axis not in {"x", "y"}:
        return False
    descendants = _descendant_map(support_tree)
    room = plan.get("room", {}) if isinstance(plan.get("room"), dict) else {}
    candidates: list[tuple[str, dict[str, Any], float | None]] = [
        ("right", right_unit, delta_right),
        ("left", left_unit, delta_left),
    ]
    effective_max_step = max(0.0, min(float(max_step), float(FINE_SPATIAL_ORDER_MAX_STEP)))
    for side, unit, raw_delta in candidates:
        if raw_delta is None or abs(float(raw_delta)) <= 1e-6:
            continue
        if unit.get("unit_type") != "object":
            continue
        objects = {str(obj.get("id")): obj for obj in plan.get("objects", []) if isinstance(obj, dict) and obj.get("id")}
        object_id = str(unit.get("object_id") or "")
        movable, reason = _fine_spatial_order_can_move_root(objects, object_id, axis, parent)
        if not movable:
            report.setdefault("detailed_order_skipped_moves", []).append(
                {
                    "relation_index": relation.get("index"),
                    "side": side,
                    "unit_id": unit.get("unit_id"),
                    "reason": reason,
                }
            )
            continue
        delta_value = _limited_repair_delta(float(raw_delta), max_step=effective_max_step)
        if abs(delta_value) <= 1e-6:
            continue
        mover = objects[object_id]
        before_objects = deepcopy(plan.get("objects", []))
        before_required = (
            _fine_detailed_required_guard_violations(plan, scene_graph, parent, guard_relations, tolerance)
            if str(relation.get("importance") or "") != "required"
            else {}
        )
        before_position = (float(mover.get("x", 0.0)), float(mover.get("y", 0.0)), float(mover.get("z", 0.0)))
        delta = (delta_value, 0.0, 0.0) if axis == "x" else (0.0, delta_value, 0.0)
        moved_nodes = _move_spatial_relation_unit(objects, descendants, object_id, delta, room)
        after_position = (float(mover.get("x", 0.0)), float(mover.get("y", 0.0)), float(mover.get("z", 0.0)))
        applied_delta = after_position[0] - before_position[0] if axis == "x" else after_position[1] - before_position[1]
        if abs(applied_delta) <= 1e-6:
            continue
        if str(relation.get("importance") or "") != "required":
            after_required = _fine_detailed_required_guard_violations(plan, scene_graph, parent, guard_relations, tolerance)
            worsened_required = []
            for key, after_state in after_required.items():
                before_state = before_required.get(key, {})
                before_violation = _safe_float(before_state.get("violation"), 0.0)
                after_violation = _safe_float(after_state.get("violation"), 0.0)
                if after_violation > before_violation + max(1e-4, float(tolerance) * 0.25):
                    worsened_required.append(after_state)
            if worsened_required:
                plan["objects"] = before_objects
                report.setdefault("detailed_order_skipped_moves", []).append(
                    {
                        "relation_index": relation.get("index"),
                        "side": side,
                        "unit_id": unit.get("unit_id"),
                        "moved_root": object_id,
                        "reason": "soft_move_would_worsen_required_relation",
                        "worsened_required": worsened_required[:5],
                    }
                )
                continue
        fix = {
            "type": "fine_detailed_agent_edge_move",
            "relation_index": relation.get("index"),
            "axis": axis,
            "moved_side": side,
            "moved_root": object_id,
            "requested_delta": round(float(raw_delta), 6),
            "applied_delta": round(float(applied_delta), 6),
            "moved_node_count": len(moved_nodes),
            "agent_relation": relation,
        }
        report.setdefault("fixes", []).append(fix)
        report.setdefault("detailed_order_fixes", []).append(fix)
        return True
    return False


def _fine_spatial_order_detailed_agent_refinement(
    plan: dict[str, Any],
    scene_graph: dict[str, Any],
    support_tree: dict[str, Any],
    parent: dict[str, str],
    raw_agent_report: dict[str, Any] | None,
    report: dict[str, Any],
    max_step: float,
) -> None:
    agent_section: dict[str, Any] = {
        "schema": "tree_sage_fine_spatial_order_detailed_apply_v1",
        "enabled": bool(raw_agent_report),
        "raw_agent_report": raw_agent_report or {},
        "relations": [],
        "skipped": [],
        "checks": [],
        "fixes": [],
        "unresolved": [],
        "unresolved_required_count": 0,
    }
    if not raw_agent_report:
        agent_section["reason"] = "no_agent_report"
        report["detailed_order_agent"] = agent_section
        report["detailed_order_unresolved_required_count"] = 0
        return
    layout_units = _fine_spatial_order_layout_units(plan, scene_graph, parent)
    unit_by_id = {str(unit.get("unit_id")): unit for unit in layout_units if isinstance(unit, dict) and unit.get("unit_id")}
    for unit in layout_units:
        if not isinstance(unit, dict):
            continue
        object_id = str(unit.get("object_id") or "")
        if object_id:
            unit_by_id.setdefault(object_id, unit)
        for member_id in unit.get("member_ids", []) if isinstance(unit.get("member_ids"), list) else []:
            unit_by_id.setdefault(str(member_id), unit)
    relations, skipped = _fine_detailed_normalized_relations(raw_agent_report, unit_by_id)
    objects = {str(obj.get("id")): obj for obj in plan.get("objects", []) if isinstance(obj, dict) and obj.get("id")}
    relation_repairs: list[dict[str, Any]] = []
    repaired_relations: list[dict[str, Any]] = []
    for relation in relations:
        repaired, repair = _fine_detailed_repair_floor_covering_endpoint_relation(relation, objects, unit_by_id)
        repaired_relations.append(repaired)
        if repair:
            relation_repairs.append(repair)
    relations = repaired_relations
    agent_section["relations"] = relations
    agent_section["skipped"] = skipped
    agent_section["relation_repairs"] = relation_repairs
    tolerance = max(0.0, float(FINE_SPATIAL_ORDER_DETAILED_TOLERANCE))
    for relation in relations:
        for iteration in range(2):
            layout_units = _fine_spatial_order_layout_units(plan, scene_graph, parent)
            unit_by_id = {str(unit.get("unit_id")): unit for unit in layout_units if isinstance(unit, dict) and unit.get("unit_id")}
            for unit in layout_units:
                if not isinstance(unit, dict):
                    continue
                object_id = str(unit.get("object_id") or "")
                if object_id:
                    unit_by_id.setdefault(object_id, unit)
                for member_id in unit.get("member_ids", []) if isinstance(unit.get("member_ids"), list) else []:
                    unit_by_id.setdefault(str(member_id), unit)
            axis = str(relation.get("axis") or "")
            left_ref = relation.get("left") if isinstance(relation.get("left"), dict) else {}
            right_ref = relation.get("right") if isinstance(relation.get("right"), dict) else {}
            left_unit = unit_by_id.get(str(left_ref.get("unit_id") or ""))
            right_unit = unit_by_id.get(str(right_ref.get("unit_id") or ""))
            if not left_unit or not right_unit:
                break
            left_value = _fine_detailed_endpoint_value(left_unit, axis, str(left_ref.get("edge") or ""))
            right_value = _fine_detailed_endpoint_value(right_unit, axis, str(right_ref.get("edge") or ""))
            if left_value is None or right_value is None:
                break
            objects = {str(obj.get("id")): obj for obj in plan.get("objects", []) if isinstance(obj, dict) and obj.get("id")}
            target_gap = _safe_float(relation.get("target_gap"), 0.0)
            relation_type = str(relation.get("relation") or "")
            check = {
                "relation_index": relation.get("index"),
                "iteration": iteration + 1,
                "axis": axis,
                "relation": relation_type,
                "left_unit_id": left_unit.get("unit_id"),
                "right_unit_id": right_unit.get("unit_id"),
                "left_edge": left_ref.get("edge"),
                "right_edge": right_ref.get("edge"),
                "left_value": round(float(left_value), 6),
                "right_value": round(float(right_value), 6),
                "target_gap": round(float(target_gap), 6),
                "importance": relation.get("importance"),
            }
            if _fine_detailed_units_have_support_relation(objects, parent, left_unit, right_unit):
                check.update({"skipped": True, "reason": "support_child_parent_relation_not_fine_order"})
                agent_section["checks"].append(check)
                break
            if _fine_detailed_is_same_wall_normal_contact_relation(objects, parent, left_unit, right_unit, axis, relation_type):
                check.update({"skipped": True, "reason": "same_wall_normal_contact_not_fine_order"})
                agent_section["checks"].append(check)
                break
            if (
                str(relation.get("importance") or "") != "required"
                and _fine_detailed_relation_involves_floor_covering(objects, left_unit, right_unit)
            ):
                check.update({"skipped": True, "reason": "soft_floor_covering_relation_not_motion_constraint"})
                agent_section["checks"].append(check)
                break
            if relation_type == "less_than_or_equal":
                violation = float(left_value) + float(target_gap) - float(right_value)
                check["violation"] = round(float(violation), 6)
                if violation <= tolerance:
                    check["ok"] = True
                    agent_section["checks"].append(check)
                    break
                applied = False
                if axis in {"x", "y"}:
                    applied = _fine_detailed_attempt_xy_move(
                        plan,
                        scene_graph,
                        support_tree,
                        parent,
                        relation,
                        relations,
                        left_unit,
                        right_unit,
                        delta_left=-float(violation),
                        delta_right=float(violation),
                        report=agent_section,
                        max_step=max_step,
                        tolerance=tolerance,
                    )
                elif axis == "z" and str(right_ref.get("edge")) == "high":
                    applied = _fine_apply_detailed_height_scale(
                        plan,
                        objects,
                        parent,
                        right_unit,
                        float(left_value) + float(target_gap),
                        relation,
                        agent_section,
                    )
                check["fixed"] = bool(applied)
                agent_section["checks"].append(check)
                if not applied:
                    break
                continue
            if relation_type == "approximately_equal":
                diff = float(left_value) - float(right_value)
                check["difference"] = round(float(diff), 6)
                if abs(diff) <= tolerance:
                    check["ok"] = True
                    agent_section["checks"].append(check)
                    break
                applied = False
                if axis in {"x", "y"}:
                    applied = _fine_detailed_attempt_xy_move(
                        plan,
                        scene_graph,
                        support_tree,
                        parent,
                        relation,
                        relations,
                        left_unit,
                        right_unit,
                        delta_left=-float(diff),
                        delta_right=float(diff),
                        report=agent_section,
                        max_step=max_step,
                        tolerance=tolerance,
                    )
                elif axis == "z" and str(left_ref.get("edge")) == "high" and str(right_ref.get("edge")) == "high":
                    if left_value < right_value:
                        applied = _fine_apply_detailed_height_scale(plan, objects, parent, left_unit, float(right_value), relation, agent_section)
                    else:
                        applied = _fine_apply_detailed_height_scale(plan, objects, parent, right_unit, float(left_value), relation, agent_section)
                check["fixed"] = bool(applied)
                agent_section["checks"].append(check)
                if not applied:
                    break
                continue
            agent_section["checks"].append({**check, "skipped": True, "reason": "unsupported_relation_type"})
            break
    # Final pass: unresolved required constraints are hard failures. Soft misses
    # are diagnostic only, because the visual evidence can be ambiguous.
    final_units = _fine_spatial_order_layout_units(plan, scene_graph, parent)
    final_unit_by_id = {str(unit.get("unit_id")): unit for unit in final_units if isinstance(unit, dict) and unit.get("unit_id")}
    for unit in final_units:
        if not isinstance(unit, dict):
            continue
        object_id = str(unit.get("object_id") or "")
        if object_id:
            final_unit_by_id.setdefault(object_id, unit)
        for member_id in unit.get("member_ids", []) if isinstance(unit.get("member_ids"), list) else []:
            final_unit_by_id.setdefault(str(member_id), unit)
    unresolved: list[dict[str, Any]] = []
    final_objects = {str(obj.get("id")): obj for obj in plan.get("objects", []) if isinstance(obj, dict) and obj.get("id")}
    for relation in relations:
        axis = str(relation.get("axis") or "")
        left_ref = relation.get("left") if isinstance(relation.get("left"), dict) else {}
        right_ref = relation.get("right") if isinstance(relation.get("right"), dict) else {}
        left_unit = final_unit_by_id.get(str(left_ref.get("unit_id") or ""))
        right_unit = final_unit_by_id.get(str(right_ref.get("unit_id") or ""))
        if not left_unit or not right_unit:
            continue
        if _fine_detailed_units_have_support_relation(final_objects, parent, left_unit, right_unit):
            continue
        left_value = _fine_detailed_endpoint_value(left_unit, axis, str(left_ref.get("edge") or ""))
        right_value = _fine_detailed_endpoint_value(right_unit, axis, str(right_ref.get("edge") or ""))
        if left_value is None or right_value is None:
            continue
        target_gap = _safe_float(relation.get("target_gap"), 0.0)
        relation_type = str(relation.get("relation") or "")
        if _fine_detailed_is_same_wall_normal_contact_relation(final_objects, parent, left_unit, right_unit, axis, relation_type):
            continue
        if relation_type == "less_than_or_equal":
            residual = float(left_value) + float(target_gap) - float(right_value)
            ok = residual <= tolerance
        elif relation_type == "approximately_equal":
            residual = abs(float(left_value) - float(right_value))
            ok = residual <= tolerance
        else:
            continue
        if ok:
            continue
        unresolved.append(
            {
                "relation_index": relation.get("index"),
                "axis": axis,
                "relation": relation_type,
                "left": relation.get("left"),
                "right": relation.get("right"),
                "importance": relation.get("importance"),
                "confidence": relation.get("confidence"),
                "residual": round(float(residual), 6),
                "tolerance": round(float(tolerance), 6),
                "evidence": relation.get("evidence"),
            }
        )
    agent_section["fixes"] = agent_section.get("fixes", [])
    agent_section["fix_count"] = len(agent_section["fixes"])
    agent_section["unresolved"] = unresolved
    agent_section["unresolved_required_count"] = len(
        [item for item in unresolved if str(item.get("importance") or "") == "required"]
    )
    report.setdefault("fixes", []).extend(agent_section["fixes"])
    report.setdefault("detailed_order_fixes", []).extend(agent_section["fixes"])
    report["detailed_order_agent"] = agent_section
    report["detailed_order_unresolved"] = unresolved
    report["detailed_order_unresolved_required_count"] = int(agent_section["unresolved_required_count"])


def _fine_bbox_projection_ref_interval(ref_bbox: list[float], ref_axis: str) -> tuple[float, float] | None:
    if len(ref_bbox) < 4:
        return None
    if ref_axis == "image_x":
        return float(ref_bbox[0]), float(ref_bbox[2])
    if ref_axis == "image_y":
        return float(ref_bbox[1]), float(ref_bbox[3])
    return None


def _fine_bbox_projection_unit_wall_id(
    objects: dict[str, dict[str, Any]],
    parent: dict[str, str],
    unit: dict[str, Any],
) -> str:
    wall_id = str(unit.get("wall_id") or "")
    if wall_id in VIRTUAL_WALLS:
        return wall_id
    return _fine_detailed_unit_wall_id(objects, parent, unit)


def _fine_bbox_projection_unit_has_wall_fixture(
    objects: dict[str, dict[str, Any]],
    unit: dict[str, Any],
) -> bool:
    if unit.get("unit_type") == "window_curtain_cluster":
        return True
    for obj in _fine_detailed_unit_objects(objects, unit):
        if (
            _is_wall_attached_object(obj)
            or str(obj.get("placement_type") or "") == "attached_to_wall"
            or str(obj.get("support_id") or "") in VIRTUAL_WALLS
        ):
            return True
    return False


def _fine_bbox_projection_unit_has_floor_anchor(
    objects: dict[str, dict[str, Any]],
    parent: dict[str, str],
    unit: dict[str, Any],
) -> bool:
    for obj in _fine_detailed_unit_objects(objects, unit):
        if _is_floor_covering(obj) or _is_hanging_object(obj):
            continue
        object_id = str(obj.get("id") or "")
        support_id = str(obj.get("support_id") or parent.get(object_id) or "")
        if support_id in objects or str(obj.get("placement_type") or "floor") not in {"floor", "against_wall", ""}:
            continue
        text = _object_identity_text(obj)
        if (
            _is_bed_or_sofa_object(obj)
            or _is_floor_storage_or_table_branch_object(obj)
            or any(keyword in text for keyword in ("wardrobe", "armoire", "closet", "dresser", "cabinet", "nightstand"))
        ):
            return True
    return False


def _fine_bbox_projection_unit_is_supported_child(
    objects: dict[str, dict[str, Any]],
    parent: dict[str, str],
    unit: dict[str, Any],
) -> bool:
    if unit.get("unit_type") != "object":
        return False
    for obj in _fine_detailed_unit_objects(objects, unit):
        object_id = str(obj.get("id") or "")
        support_id = str(obj.get("support_id") or parent.get(object_id) or "")
        if str(obj.get("placement_type") or "") in {"on_top", "inside"}:
            return True
        if support_id in objects:
            return True
    return False


def _fine_bbox_projection_unit_is_wall_decor(
    objects: dict[str, dict[str, Any]],
    unit: dict[str, Any],
) -> bool:
    if unit.get("unit_type") != "object":
        return False
    for obj in _fine_detailed_unit_objects(objects, unit):
        if not (
            _is_wall_attached_object(obj)
            or str(obj.get("placement_type") or "") == "attached_to_wall"
            or str(obj.get("support_id") or "") in VIRTUAL_WALLS
        ):
            continue
        if _is_wall_door_object(obj) or _functional_cluster_is_window_object(obj) or _is_curtain_panel_object(obj) or _is_curtain_rod_object(obj):
            continue
        text = _object_identity_text(obj)
        if any(keyword in text for keyword in ("art", "painting", "picture", "poster", "photo", "mirror", "frame")):
            return True
    return False


def _fine_bbox_projection_unit_move_preference(
    objects: dict[str, dict[str, Any]],
    parent: dict[str, str],
    unit: dict[str, Any],
) -> int:
    if _fine_bbox_projection_unit_is_wall_decor(objects, unit):
        return 0
    if unit.get("unit_type") == "window_curtain_cluster":
        return 99
    unit_objects = _fine_detailed_unit_objects(objects, unit)
    if any(_is_wall_door_object(obj) for obj in unit_objects):
        return 7
    if _fine_bbox_projection_unit_has_wall_fixture(objects, unit):
        return 2
    if any(_is_bed_or_sofa_object(obj) for obj in unit_objects):
        return 9
    if _fine_bbox_projection_unit_has_floor_anchor(objects, parent, unit):
        return 4
    return 6


def _fine_bbox_projection_side_wall_decor_storage_pair(
    objects: dict[str, dict[str, Any]],
    parent: dict[str, str],
    left_unit: dict[str, Any],
    right_unit: dict[str, Any],
    axis: str,
) -> tuple[str, str, str] | None:
    if axis != "y":
        return None
    left_wall = _fine_bbox_projection_unit_wall_id(objects, parent, left_unit)
    right_wall = _fine_bbox_projection_unit_wall_id(objects, parent, right_unit)
    if left_wall != right_wall or left_wall not in {"wall_west", "wall_east"}:
        return None

    def storage_id_for(unit: dict[str, Any]) -> str | None:
        if unit.get("unit_type") != "object":
            return None
        object_id = str(unit.get("object_id") or unit.get("unit_id") or "")
        obj = objects.get(object_id)
        if not obj or str(obj.get("placement_type") or "floor") not in {"floor", "against_wall", ""}:
            return None
        if _is_bedside_table_object(obj) or not _is_floor_storage_or_table_branch_object(obj):
            return None
        return object_id

    left_decor = _fine_bbox_projection_unit_is_wall_decor(objects, left_unit)
    right_decor = _fine_bbox_projection_unit_is_wall_decor(objects, right_unit)
    left_storage = storage_id_for(left_unit)
    right_storage = storage_id_for(right_unit)
    if left_decor and right_storage:
        return str(left_unit.get("object_id") or left_unit.get("unit_id")), right_storage, left_wall
    if right_decor and left_storage:
        return str(right_unit.get("object_id") or right_unit.get("unit_id")), left_storage, left_wall
    return None


def _fine_bbox_projection_overlap_candidates(
    plan: dict[str, Any],
    scene_graph: dict[str, Any],
    parent: dict[str, str],
) -> list[dict[str, Any]]:
    layout_units = _fine_spatial_order_layout_units(plan, scene_graph, parent)
    objects = {str(obj.get("id")): obj for obj in plan.get("objects", []) if isinstance(obj, dict) and obj.get("id")}
    candidates: list[dict[str, Any]] = []
    min_ref_span = max(1e-6, float(FINE_BBOX_PROJECTION_OVERLAP_MIN_REF_SPAN))
    min_ref_overlap = max(0.0, float(FINE_BBOX_PROJECTION_OVERLAP_MIN_REF_OVERLAP))
    min_ratio = max(0.0, float(FINE_BBOX_PROJECTION_OVERLAP_MIN_RATIO))
    for left_index, left_unit in enumerate(layout_units):
        if not isinstance(left_unit, dict) or not left_unit.get("reference_bbox"):
            continue
        if _fine_bbox_projection_unit_is_supported_child(objects, parent, left_unit):
            continue
        left_wall = _fine_bbox_projection_unit_wall_id(objects, parent, left_unit)
        if left_wall not in VIRTUAL_WALLS:
            continue
        for right_unit in layout_units[left_index + 1 :]:
            if not isinstance(right_unit, dict) or not right_unit.get("reference_bbox"):
                continue
            if _fine_bbox_projection_unit_is_supported_child(objects, parent, right_unit):
                continue
            right_wall = _fine_bbox_projection_unit_wall_id(objects, parent, right_unit)
            if left_wall != right_wall:
                continue
            scene_axis = _fine_spatial_order_wall_tangent_axis(left_wall)
            if scene_axis not in {"x", "y"}:
                continue
            if _fine_detailed_units_have_support_relation(objects, parent, left_unit, right_unit):
                continue
            left_wall_fixture = _fine_bbox_projection_unit_has_wall_fixture(objects, left_unit)
            right_wall_fixture = _fine_bbox_projection_unit_has_wall_fixture(objects, right_unit)
            left_floor_anchor = _fine_bbox_projection_unit_has_floor_anchor(objects, parent, left_unit)
            right_floor_anchor = _fine_bbox_projection_unit_has_floor_anchor(objects, parent, right_unit)
            if not ((left_wall_fixture and right_floor_anchor) or (right_wall_fixture and left_floor_anchor)):
                continue
            ref_axis = "image_x"
            left_interval = _fine_bbox_projection_ref_interval(left_unit.get("reference_bbox", []), ref_axis)
            right_interval = _fine_bbox_projection_ref_interval(right_unit.get("reference_bbox", []), ref_axis)
            if not left_interval or not right_interval:
                continue
            left_span = max(0.0, left_interval[1] - left_interval[0])
            right_span = max(0.0, right_interval[1] - right_interval[0])
            if left_span < min_ref_span or right_span < min_ref_span:
                continue
            ref_overlap = min(left_interval[1], right_interval[1]) - max(left_interval[0], right_interval[0])
            if ref_overlap < min_ref_overlap:
                continue
            overlap_ratio = float(ref_overlap) / max(1e-6, min(left_span, right_span))
            if overlap_ratio < min_ratio:
                continue
            left_id = str(left_unit.get("unit_id") or "")
            right_id = str(right_unit.get("unit_id") or "")
            candidates.append(
                {
                    "constraint_id": f"bbox_projection_overlap:{left_id}:{right_id}:{scene_axis}",
                    "left_unit_id": left_id,
                    "right_unit_id": right_id,
                    "axis": scene_axis,
                    "wall_id": left_wall,
                    "reference_projection_axis": ref_axis,
                    "reference_interval_left": [round(float(value), 6) for value in left_interval],
                    "reference_interval_right": [round(float(value), 6) for value in right_interval],
                    "reference_overlap": round(float(ref_overlap), 6),
                    "reference_overlap_ratio": round(float(overlap_ratio), 6),
                    "target_scene_overlap": round(max(0.0, float(FINE_BBOX_PROJECTION_OVERLAP_TARGET_SCENE_OVERLAP)), 6),
                    "importance": "required",
                    "solver_constraints": [
                        f"{left_id}.{scene_axis}.low <= {right_id}.{scene_axis}.high",
                        f"{right_id}.{scene_axis}.low <= {left_id}.{scene_axis}.high",
                    ],
                    "evidence": "reference_bbox projections overlap on the wall-tangent image axis; enforce scene bbox interval intersection instead of center-only order",
                }
            )
    candidates.sort(
        key=lambda item: (
            -float(item.get("reference_overlap_ratio", 0.0) or 0.0),
            -float(item.get("reference_overlap", 0.0) or 0.0),
            str(item.get("left_unit_id") or ""),
            str(item.get("right_unit_id") or ""),
        )
    )
    auto_candidates = candidates[: max(0, int(FINE_BBOX_PROJECTION_OVERLAP_MAX_CONSTRAINTS))]
    unit_by_id: dict[str, dict[str, Any]] = {}
    for unit in layout_units:
        if not isinstance(unit, dict):
            continue
        unit_id = str(unit.get("unit_id") or "")
        if unit_id:
            unit_by_id.setdefault(unit_id, unit)
        object_id = str(unit.get("object_id") or "")
        if object_id:
            unit_by_id.setdefault(object_id, unit)
        for member_id in unit.get("member_ids", []) if isinstance(unit.get("member_ids"), list) else []:
            unit_by_id.setdefault(str(member_id), unit)
    seen = {
        (
            str(item.get("left_unit_id") or ""),
            str(item.get("right_unit_id") or ""),
            str(item.get("axis") or ""),
        )
        for item in auto_candidates
    }
    human_candidates: list[dict[str, Any]] = []
    raw_human = (
        scene_graph.get("_human_bbox_projection_overlap_constraints")
        if isinstance(scene_graph.get("_human_bbox_projection_overlap_constraints"), list)
        else []
    )
    for index, item in enumerate(raw_human):
        if not isinstance(item, dict):
            continue
        left_unit = unit_by_id.get(str(item.get("left_unit_id") or ""))
        right_unit = unit_by_id.get(str(item.get("right_unit_id") or ""))
        if not left_unit or not right_unit:
            continue
        axis = _fine_detailed_normalize_axis(item.get("axis"))
        if axis not in {"x", "y"}:
            left_wall = _fine_bbox_projection_unit_wall_id(objects, parent, left_unit)
            right_wall = _fine_bbox_projection_unit_wall_id(objects, parent, right_unit)
            axis = _fine_spatial_order_wall_tangent_axis(left_wall) if left_wall == right_wall else None
        if axis not in {"x", "y"}:
            continue
        key = (str(left_unit.get("unit_id") or ""), str(right_unit.get("unit_id") or ""), axis)
        if key in seen:
            continue
        seen.add(key)
        target_scene_overlap = max(
            0.0,
            _safe_float(item.get("target_scene_overlap"), FINE_BBOX_PROJECTION_OVERLAP_TARGET_SCENE_OVERLAP),
        )
        human_candidates.append(
            {
                "constraint_id": str(item.get("constraint_id") or f"human_bbox_projection_overlap:{index:03d}:{key[0]}:{key[1]}:{axis}"),
                "left_unit_id": key[0],
                "right_unit_id": key[1],
                "axis": axis,
                "wall_id": _fine_bbox_projection_unit_wall_id(objects, parent, left_unit),
                "reference_projection_axis": item.get("reference_projection_axis"),
                "reference_interval_left": item.get("reference_interval_left"),
                "reference_interval_right": item.get("reference_interval_right"),
                "reference_overlap": item.get("reference_overlap"),
                "reference_overlap_ratio": item.get("reference_overlap_ratio"),
                "target_scene_overlap": round(float(target_scene_overlap), 6),
                "importance": str(item.get("importance") or "required"),
                "source": "human_constraints",
                "human_constraint_index": item.get("human_constraint_index", index),
                "solver_constraints": [
                    f"{key[0]}.{axis}.low <= {key[1]}.{axis}.high",
                    f"{key[1]}.{axis}.low <= {key[0]}.{axis}.high",
                ],
                "evidence": str(item.get("evidence") or "Human-specified scene bbox interval intersection."),
            }
        )
    return [*auto_candidates, *human_candidates]


def _fine_bbox_projection_current_state(
    unit_by_id: dict[str, dict[str, Any]],
    constraint: dict[str, Any],
    tolerance: float,
) -> dict[str, Any] | None:
    axis = str(constraint.get("axis") or "")
    left_unit = unit_by_id.get(str(constraint.get("left_unit_id") or ""))
    right_unit = unit_by_id.get(str(constraint.get("right_unit_id") or ""))
    if axis not in {"x", "y"} or not left_unit or not right_unit:
        return None
    left_bounds = left_unit.get("scene_bounds", {}).get(axis) if isinstance(left_unit.get("scene_bounds"), dict) else None
    right_bounds = right_unit.get("scene_bounds", {}).get(axis) if isinstance(right_unit.get("scene_bounds"), dict) else None
    if not isinstance(left_bounds, list) or len(left_bounds) < 3 or not isinstance(right_bounds, list) or len(right_bounds) < 3:
        return None
    left_low, left_center, left_high = float(left_bounds[0]), float(left_bounds[1]), float(left_bounds[2])
    right_low, right_center, right_high = float(right_bounds[0]), float(right_bounds[1]), float(right_bounds[2])
    overlap = min(left_high, right_high) - max(left_low, right_low)
    target_overlap = max(0.0, _safe_float(constraint.get("target_scene_overlap"), 0.0))
    residual = max(0.0, target_overlap - overlap)
    return {
        "constraint_id": constraint.get("constraint_id"),
        "left_unit_id": left_unit.get("unit_id"),
        "right_unit_id": right_unit.get("unit_id"),
        "axis": axis,
        "left_interval": [round(float(left_low), 6), round(float(left_high), 6)],
        "right_interval": [round(float(right_low), 6), round(float(right_high), 6)],
        "left_center": round(float(left_center), 6),
        "right_center": round(float(right_center), 6),
        "scene_overlap": round(float(overlap), 6),
        "target_scene_overlap": round(float(target_overlap), 6),
        "residual": round(float(residual), 6),
        "tolerance": round(float(tolerance), 6),
        "ok": bool(residual <= tolerance),
    }


def _fine_bbox_projection_apply_side_wall_decor_storage_overlap(
    plan: dict[str, Any],
    scene_graph: dict[str, Any],
    parent: dict[str, str],
    cross_constraints: list[dict[str, Any]] | None,
    constraint: dict[str, Any],
    left_unit: dict[str, Any],
    right_unit: dict[str, Any],
    state: dict[str, Any],
) -> dict[str, Any] | None:
    objects = {str(obj.get("id")): obj for obj in plan.get("objects", []) if isinstance(obj, dict) and obj.get("id")}
    pair = _fine_bbox_projection_side_wall_decor_storage_pair(
        objects,
        parent,
        left_unit,
        right_unit,
        str(constraint.get("axis") or ""),
    )
    if not pair:
        return None
    decor_id, storage_id, wall_id = pair
    residuals = _fine_side_wall_edge_residuals(plan, scene_graph, parent, cross_constraints or [])
    scoped: list[dict[str, Any]] = []
    for residual in residuals:
        residual_type = str(residual.get("type") or "")
        residual_storage = str(residual.get("storage_id") or "")
        if residual_storage != storage_id:
            continue
        if residual_type == "side_wall_wall_decor_storage_tangent_misalignment" and str(residual.get("object_id") or "") == decor_id:
            scoped.append(residual)
        elif residual_type == "side_wall_storage_extend_for_wall_decor" and str(residual.get("object_id") or "") == decor_id:
            scoped.append(residual)
        elif residual_type == "side_wall_curtain_slot_for_wall_decor" and str(residual.get("decor_id") or "") == decor_id:
            scoped.append(residual)
    if not scoped:
        return {
            "type": "fine_bbox_projection_overlap_protected_side_wall_skipped",
            "constraint_id": constraint.get("constraint_id"),
            "decor_id": decor_id,
            "storage_id": storage_id,
            "wall_id": wall_id,
            "state_before": state,
            "reason": "no_scoped_side_wall_residual",
        }
    fixes = _fine_apply_side_wall_edge_residuals(plan, scoped)
    if not fixes:
        return {
            "type": "fine_bbox_projection_overlap_protected_side_wall_skipped",
            "constraint_id": constraint.get("constraint_id"),
            "decor_id": decor_id,
            "storage_id": storage_id,
            "wall_id": wall_id,
            "state_before": state,
            "scoped_residuals": scoped,
            "reason": "scoped_side_wall_residual_not_applied",
        }
    for fix in fixes:
        fix["constraint_family"] = "bbox_projection_overlap"
        fix["constraint_id"] = constraint.get("constraint_id")
        fix["protected_side_wall_decor_id"] = decor_id
        fix["protected_side_wall_storage_id"] = storage_id
    return {
        "type": "fine_bbox_projection_overlap_protected_side_wall_fixes",
        "constraint_id": constraint.get("constraint_id"),
        "decor_id": decor_id,
        "storage_id": storage_id,
        "wall_id": wall_id,
        "state_before": state,
        "scoped_residuals": scoped,
        "fixes": fixes,
    }


def _fine_bbox_projection_apply_overlap_move(
    plan: dict[str, Any],
    scene_graph: dict[str, Any],
    support_tree: dict[str, Any],
    parent: dict[str, str],
    constraint: dict[str, Any],
    state: dict[str, Any],
    max_step: float,
) -> dict[str, Any] | None:
    axis = str(constraint.get("axis") or "")
    if axis not in {"x", "y"}:
        return None
    layout_units, unit_by_id = _fine_detailed_unit_map(plan, scene_graph, parent)
    del layout_units
    left_unit = unit_by_id.get(str(constraint.get("left_unit_id") or ""))
    right_unit = unit_by_id.get(str(constraint.get("right_unit_id") or ""))
    if not left_unit or not right_unit:
        return None
    objects = {str(obj.get("id")): obj for obj in plan.get("objects", []) if isinstance(obj, dict) and obj.get("id")}
    room = plan.get("room", {}) if isinstance(plan.get("room"), dict) else {}
    descendants = _descendant_map(support_tree)
    target_overlap = max(0.0, _safe_float(constraint.get("target_scene_overlap"), 0.0))
    current_overlap = _safe_float(state.get("scene_overlap"), 0.0)
    needed_delta = max(0.0, target_overlap - current_overlap)
    if needed_delta <= 1e-6:
        return None
    left_center = _safe_float(state.get("left_center"), 0.0)
    right_center = _safe_float(state.get("right_center"), 0.0)
    if left_center <= right_center:
        raw_options = [(left_unit, needed_delta), (right_unit, -needed_delta)]
    else:
        raw_options = [(left_unit, -needed_delta), (right_unit, needed_delta)]
    options: list[dict[str, Any]] = []
    for unit, delta_value in raw_options:
        if unit.get("unit_type") != "object":
            continue
        object_id = str(unit.get("object_id") or unit.get("unit_id") or "")
        movable, reason = _fine_spatial_order_can_move_root(objects, object_id, axis, parent)
        if not movable:
            options.append(
                {
                    "unit_id": unit.get("unit_id"),
                    "object_id": object_id,
                    "delta": round(float(delta_value), 6),
                    "skipped": True,
                    "reason": reason,
                }
            )
            continue
        options.append(
            {
                "unit": unit,
                "unit_id": unit.get("unit_id"),
                "object_id": object_id,
                "delta": float(delta_value),
                "preference": _fine_bbox_projection_unit_move_preference(objects, parent, unit),
            }
        )
    movable_options = [option for option in options if not option.get("skipped")]
    if not movable_options:
        return {
            "type": "fine_bbox_projection_overlap_move_skipped",
            "constraint": constraint,
            "state_before": state,
            "move_options": options,
            "reason": "no_movable_unit",
        }
    movable_options.sort(
        key=lambda item: (
            int(item.get("preference", 99)),
            abs(float(item.get("delta", 0.0) or 0.0)),
            str(item.get("object_id") or ""),
        )
    )
    chosen = movable_options[0]
    object_id = str(chosen.get("object_id") or "")
    mover = objects.get(object_id)
    if not mover:
        return None
    effective_max_step = max(0.0, min(float(max_step), float(FINE_BBOX_PROJECTION_OVERLAP_MAX_STEP)))
    delta_value = _limited_repair_delta(float(chosen.get("delta", 0.0) or 0.0), max_step=effective_max_step)
    if abs(delta_value) <= 1e-6:
        return None
    before = _plan_object_snapshot(mover)
    before_position = (float(mover.get("x", 0.0)), float(mover.get("y", 0.0)), float(mover.get("z", 0.0)))
    delta = (delta_value, 0.0, 0.0) if axis == "x" else (0.0, delta_value, 0.0)
    moved_nodes = _move_spatial_relation_unit(objects, descendants, object_id, delta, room)
    after_position = (float(mover.get("x", 0.0)), float(mover.get("y", 0.0)), float(mover.get("z", 0.0)))
    applied_delta = after_position[0] - before_position[0] if axis == "x" else after_position[1] - before_position[1]
    if abs(applied_delta) <= 1e-6:
        return None
    after = _plan_object_snapshot(mover)
    return {
        "type": "fine_bbox_projection_overlap_move",
        "constraint_id": constraint.get("constraint_id"),
        "axis": axis,
        "moved_root": object_id,
        "moved_unit_id": chosen.get("unit_id"),
        "requested_delta": round(float(chosen.get("delta", 0.0) or 0.0), 6),
        "applied_delta": round(float(applied_delta), 6),
        "moved_node_count": len(moved_nodes),
        "before": before,
        "after": after,
        "state_before": state,
        "constraint": constraint,
        "move_options": [
            {key: value for key, value in option.items() if key != "unit"}
            for option in options
        ],
    }


def _fine_spatial_order_bbox_projection_overlap_refinement(
    plan: dict[str, Any],
    scene_graph: dict[str, Any],
    support_tree: dict[str, Any],
    parent: dict[str, str],
    cross_constraints: list[dict[str, Any]] | None,
    report: dict[str, Any],
    *,
    enabled: bool,
    max_step: float,
) -> None:
    section: dict[str, Any] = {
        "schema": "tree_sage_bbox_projection_overlap_refinement_v1",
        "enabled": bool(enabled),
        "candidates": [],
        "checks": [],
        "fixes": [],
        "unresolved": [],
        "constraint_count": 0,
        "fix_count": 0,
        "unresolved_required_count": 0,
    }
    if not enabled:
        section["reason"] = "disabled"
        report["bbox_projection_overlap"] = section
        report["bbox_projection_overlap_constraint_count"] = 0
        report["bbox_projection_overlap_fix_count"] = 0
        report["bbox_projection_overlap_unresolved_required_count"] = 0
        return
    constraints = _fine_bbox_projection_overlap_candidates(plan, scene_graph, parent)
    section["candidates"] = constraints
    section["constraint_count"] = len(constraints)
    tolerance = max(0.0, float(FINE_SPATIAL_ORDER_DETAILED_TOLERANCE))
    for iteration in range(3):
        iteration_fix_count = 0
        layout_units, unit_by_id = _fine_detailed_unit_map(plan, scene_graph, parent)
        del layout_units
        for constraint in constraints:
            state = _fine_bbox_projection_current_state(unit_by_id, constraint, tolerance)
            if not state:
                continue
            check = {
                "iteration": iteration + 1,
                "constraint_id": constraint.get("constraint_id"),
                "state": state,
                "ok": bool(state.get("ok")),
            }
            if state.get("ok"):
                section["checks"].append(check)
                continue
            left_unit = unit_by_id.get(str(constraint.get("left_unit_id") or ""))
            right_unit = unit_by_id.get(str(constraint.get("right_unit_id") or ""))
            protected_fix = (
                _fine_bbox_projection_apply_side_wall_decor_storage_overlap(
                    plan,
                    scene_graph,
                    parent,
                    cross_constraints,
                    constraint,
                    left_unit,
                    right_unit,
                    state,
                )
                if left_unit and right_unit
                else None
            )
            if protected_fix and protected_fix.get("type") == "fine_bbox_projection_overlap_protected_side_wall_fixes":
                section["fixes"].extend(protected_fix.get("fixes", []))
                section.setdefault("protected_side_wall_fixes", []).append(protected_fix)
                check["fixed"] = True
                check["fix_mode"] = "protected_side_wall_decor_storage"
                iteration_fix_count += len(protected_fix.get("fixes", []))
                section["checks"].append(check)
                continue
            if protected_fix:
                section.setdefault("skipped_fixes", []).append(protected_fix)
            fix = _fine_bbox_projection_apply_overlap_move(
                plan,
                scene_graph,
                support_tree,
                parent,
                constraint,
                state,
                max_step=max_step,
            )
            if fix and fix.get("type") == "fine_bbox_projection_overlap_move":
                section["fixes"].append(fix)
                check["fixed"] = True
                iteration_fix_count += 1
            elif fix:
                section.setdefault("skipped_fixes", []).append(fix)
                check["fixed"] = False
                check["skip_reason"] = fix.get("reason")
            else:
                check["fixed"] = False
            section["checks"].append(check)
        if iteration_fix_count == 0:
            break
    final_units, final_unit_by_id = _fine_detailed_unit_map(plan, scene_graph, parent)
    del final_units
    unresolved: list[dict[str, Any]] = []
    for constraint in constraints:
        state = _fine_bbox_projection_current_state(final_unit_by_id, constraint, tolerance)
        if not state or state.get("ok"):
            continue
        unresolved.append(
            {
                "constraint_id": constraint.get("constraint_id"),
                "left_unit_id": constraint.get("left_unit_id"),
                "right_unit_id": constraint.get("right_unit_id"),
                "axis": constraint.get("axis"),
                "importance": constraint.get("importance"),
                "state": state,
                "reference_overlap_ratio": constraint.get("reference_overlap_ratio"),
                "reference_overlap": constraint.get("reference_overlap"),
                "solver_constraints": constraint.get("solver_constraints"),
                "evidence": constraint.get("evidence"),
            }
        )
    section["fix_count"] = len(section["fixes"])
    section["unresolved"] = unresolved
    section["unresolved_required_count"] = len(
        [item for item in unresolved if str(item.get("importance") or "") == "required"]
    )
    report.setdefault("fixes", []).extend(section["fixes"])
    report.setdefault("bbox_projection_overlap_fixes", []).extend(section["fixes"])
    report["bbox_projection_overlap"] = section
    report["bbox_projection_overlap_constraint_count"] = int(section["constraint_count"])
    report["bbox_projection_overlap_fix_count"] = int(section["fix_count"])
    report["bbox_projection_overlap_unresolved_required_count"] = int(section["unresolved_required_count"])


def _fine_scene_axis_dimension_key(obj: dict[str, Any], scene_axis: str) -> str | None:
    if scene_axis not in {"x", "y"}:
        return None
    base_width, base_length = _rotated_footprint(obj)
    base_span = base_width if scene_axis == "x" else base_length
    best_key: str | None = None
    best_delta = 0.0
    for key in ("width", "length"):
        probe = deepcopy(obj)
        dims = probe.get("dimensions") if isinstance(probe.get("dimensions"), dict) else {}
        current = _safe_float(dims.get(key), 0.0)
        if current <= 0.0:
            continue
        dims[key] = current + 0.1
        probe["dimensions"] = dims
        width, length = _rotated_footprint(probe)
        span = width if scene_axis == "x" else length
        delta = abs(float(span) - float(base_span))
        if delta > best_delta:
            best_delta = delta
            best_key = key
    return best_key if best_delta > 1e-5 else None


def _fine_reference_x_overlap_ratio(ref_bboxes: dict[str, list[float]], a_id: str, b_id: str) -> float:
    a = ref_bboxes.get(str(a_id))
    b = ref_bboxes.get(str(b_id))
    if not a or not b:
        return 0.0
    a_width = max(1e-6, float(a[2]) - float(a[0]))
    b_width = max(1e-6, float(b[2]) - float(b[0]))
    overlap = max(0.0, min(float(a[2]), float(b[2])) - max(float(a[0]), float(b[0])))
    return float(overlap) / max(1e-6, min(a_width, b_width))


def _fine_side_wall_curtain_slot_target_span(current_span: float) -> float:
    if current_span <= 0.0:
        return 0.0
    min_slot = max(0.0, float(FINE_SPATIAL_ORDER_SIDE_WALL_CURTAIN_MIN_SLOT))
    max_slot = max(min_slot, float(FINE_SPATIAL_ORDER_SIDE_WALL_CURTAIN_SLOT_MAX))
    if float(current_span) <= max_slot + 0.015:
        return float(current_span)
    ratio = _clamp(float(FINE_SPATIAL_ORDER_SIDE_WALL_CURTAIN_SLOT_RATIO), 0.05, 1.0)
    return float(_clamp(float(current_span) * ratio, min_slot, max_slot))


def _fine_reference_frontness_signal(
    object_id: str,
    ref_bboxes: dict[str, list[float]],
    ref_depths: dict[str, dict[str, Any]],
) -> dict[str, Any] | None:
    depth_item = ref_depths.get(str(object_id))
    if isinstance(depth_item, dict):
        confidence = _safe_float(depth_item.get("confidence"), 0.0)
        if confidence > 0.0:
            return {
                "object_id": str(object_id),
                "frontness": _clamp(_safe_float(depth_item.get("frontness"), 0.0), 0.0, 1.0),
                "confidence": confidence,
                "source": "depth_frontness",
            }
    bbox = ref_bboxes.get(str(object_id))
    if bbox:
        return {
            "object_id": str(object_id),
            "frontness": _clamp(float(bbox[3]), 0.0, 1.0),
            "confidence": 0.42,
            "source": "bbox_bottom",
        }
    return None


def _fine_side_wall_window_cluster_records(
    objects: dict[str, dict[str, Any]],
    ref_bboxes: dict[str, list[float]],
    ref_depths: dict[str, dict[str, Any]],
    parent: dict[str, str],
) -> list[dict[str, Any]]:
    records: list[dict[str, Any]] = []
    for member_ids in _fine_window_curtain_cluster_member_ids(objects, ref_bboxes, parent):
        window_id = next(
            (
                object_id
                for object_id in member_ids
                if _functional_cluster_is_window_object(objects.get(object_id, {}))
                and not _is_curtain_panel_object(objects.get(object_id, {}))
                and not _is_curtain_rod_object(objects.get(object_id, {}))
            ),
            member_ids[0] if member_ids else "",
        )
        window = objects.get(str(window_id))
        if not window:
            continue
        wall_id = _object_attached_wall_id(objects, str(window_id), parent)
        if wall_id not in {"wall_west", "wall_east"}:
            continue
        member_records: list[dict[str, Any]] = []
        for member_id in sorted(set(str(value) for value in member_ids if value)):
            member = objects.get(member_id)
            if not member:
                continue
            member_min, member_max = _bbox_for_object(member)
            signal = _fine_reference_frontness_signal(member_id, ref_bboxes, ref_depths)
            member_records.append(
                {
                    "id": member_id,
                    "is_window": _functional_cluster_is_window_object(member),
                    "is_curtain": _is_curtain_panel_object(member),
                    "is_rod": _is_curtain_rod_object(member),
                    "center_y": round(float(member.get("y", 0.0) or 0.0), 6),
                    "span_y": [round(float(member_min[1]), 6), round(float(member_max[1]), 6)],
                    "reference_frontness": signal,
                }
            )
        if not member_records:
            continue
        signals = [item["reference_frontness"] for item in member_records if isinstance(item.get("reference_frontness"), dict)]
        cluster_signal = max(signals, key=lambda item: float(item.get("frontness", 0.0)), default=None)
        depth_members = [item for item in member_records if not bool(item.get("is_rod"))]
        if not depth_members:
            depth_members = member_records
        cluster_low = min(float(item["span_y"][0]) for item in depth_members)
        cluster_high = max(float(item["span_y"][1]) for item in depth_members)
        window_min, window_max = _bbox_for_object(window)
        records.append(
            {
                "unit_id": f"window_curtain_cluster:{window_id}",
                "window_id": str(window_id),
                "wall_id": wall_id,
                "member_ids": [str(item["id"]) for item in member_records],
                "members": member_records,
                "span_y": [round(float(cluster_low), 6), round(float(cluster_high), 6)],
                "window_span_y": [round(float(window_min[1]), 6), round(float(window_max[1]), 6)],
                "window_center_y": round((float(window_min[1]) + float(window_max[1])) / 2.0, 6),
                "reference_frontness": cluster_signal,
            }
        )
    return records


def _fine_side_wall_fixture_depth_residuals(
    plan: dict[str, Any],
    scene_graph: dict[str, Any],
    parent: dict[str, str],
    cross_constraints: list[dict[str, Any]] | None,
) -> list[dict[str, Any]]:
    room = plan.get("room") if isinstance(plan.get("room"), dict) else {}
    if not room:
        return []
    objects = {str(obj.get("id")): obj for obj in plan.get("objects", []) if isinstance(obj, dict) and obj.get("id")}
    ref_bboxes = _reference_bboxes_by_object(scene_graph)
    ref_depths = _reference_depths_by_object(scene_graph)
    clusters = _fine_side_wall_window_cluster_records(objects, ref_bboxes, ref_depths, parent)
    clusters_by_wall: dict[str, list[dict[str, Any]]] = {}
    for cluster in clusters:
        clusters_by_wall.setdefault(str(cluster.get("wall_id") or ""), []).append(cluster)

    storage_by_wall: dict[str, list[str]] = {"wall_west": [], "wall_east": []}
    for object_id, obj in objects.items():
        if str(obj.get("placement_type") or "") != "floor":
            continue
        if not _is_floor_storage_or_table_branch_object(obj) or _is_bedside_table_object(obj):
            continue
        wall_id = _wall_relation_for_object(object_id, cross_constraints or [], parent)
        if wall_id in {"wall_west", "wall_east"}:
            storage_by_wall.setdefault(wall_id, []).append(object_id)

    residuals: list[dict[str, Any]] = []
    tolerance = float(FINE_SPATIAL_ORDER_SIDE_WALL_EDGE_TOLERANCE)
    clearance = max(float(FINE_SPATIAL_ORDER_SCENE_CLEARANCE), 0.04)
    for wall_id, storage_ids in sorted(storage_by_wall.items()):
        for storage_id in sorted(storage_ids):
            storage = objects.get(storage_id)
            storage_signal = _fine_reference_frontness_signal(storage_id, ref_bboxes, ref_depths)
            storage_bbox = ref_bboxes.get(storage_id)
            if not storage or not storage_signal:
                continue
            storage_min, storage_max = _bbox_for_object(storage)
            storage_span = max(0.0, float(storage_max[1]) - float(storage_min[1]))
            if storage_span <= 0.0:
                continue
            for cluster in clusters_by_wall.get(wall_id, []):
                cluster_signal = cluster.get("reference_frontness") if isinstance(cluster.get("reference_frontness"), dict) else None
                if not cluster_signal:
                    continue
                frontness_gap = float(storage_signal["frontness"]) - float(cluster_signal.get("frontness", 0.0))
                cluster_bottom_values = [
                    float(ref_bboxes[member_id][3])
                    for member_id in cluster.get("member_ids", [])
                    if member_id in ref_bboxes
                ]
                bbox_bottom_gap = (
                    float(storage_bbox[3]) - max(cluster_bottom_values)
                    if storage_bbox and cluster_bottom_values
                    else 0.0
                )
                if frontness_gap < 0.12 and bbox_bottom_gap < 0.08:
                    continue
                cluster_span = cluster.get("span_y") if isinstance(cluster.get("span_y"), list) else []
                if len(cluster_span) < 2:
                    continue
                cluster_low = float(cluster_span[0])
                target_storage_front_y = cluster_low - clearance
                if float(storage_min[1]) <= target_storage_front_y + tolerance:
                    continue

                front_member = min(
                    (
                        item
                        for item in cluster.get("members", [])
                        if isinstance(item, dict) and isinstance(item.get("span_y"), list) and len(item["span_y"]) >= 2
                        and not bool(item.get("is_rod"))
                    ),
                    key=lambda item: (float(item["span_y"][0]), str(item.get("id") or "")),
                    default=None,
                )
                if front_member and bool(front_member.get("is_curtain")):
                    current_span = float(front_member["span_y"][1]) - float(front_member["span_y"][0])
                    target_span = _fine_side_wall_curtain_slot_target_span(current_span)
                    window_span = cluster.get("window_span_y") if isinstance(cluster.get("window_span_y"), list) else []
                    if target_span > 0.0 and len(window_span) >= 2:
                        member_center = (float(front_member["span_y"][0]) + float(front_member["span_y"][1])) / 2.0
                        window_center = _safe_float(cluster.get("window_center_y"), member_center)
                        if member_center <= window_center:
                            target_y = float(window_span[0]) - clearance - target_span / 2.0
                            side = "before"
                            anchored_edge = "window_left_edge"
                        else:
                            target_y = float(window_span[1]) + clearance + target_span / 2.0
                            side = "after"
                            anchored_edge = "window_right_edge"
                        if current_span > target_span + 0.015 or abs(target_y - member_center) > tolerance:
                            residuals.append(
                                {
                                    "type": "side_wall_curtain_slot_for_storage_depth_order",
                                    "object_id": str(front_member.get("id") or ""),
                                    "storage_id": storage_id,
                                    "window_id": cluster.get("window_id"),
                                    "cluster_unit_id": cluster.get("unit_id"),
                                    "wall_id": wall_id,
                                    "axis": "y",
                                    "side": side,
                                    "target_scene_span": round(float(target_span), 6),
                                    "current_scene_span": round(float(current_span), 6),
                                    "target_y": round(float(target_y), 6),
                                    "anchored_edge": anchored_edge,
                                    "window_span_y": [round(float(value), 6) for value in window_span],
                                    "storage_scene_span_y": [round(float(storage_min[1]), 6), round(float(storage_max[1]), 6)],
                                    "cluster_scene_span_y": [round(float(value), 6) for value in cluster_span],
                                    "reference_frontness_gap": round(float(frontness_gap), 6),
                                    "reference_bbox_bottom_gap": round(float(bbox_bottom_gap), 6),
                                    "reference_frontness": {
                                        storage_id: storage_signal,
                                        str(cluster.get("unit_id") or ""): cluster_signal,
                                    },
                                    "evidence": (
                                        "Reference depth shows the side-wall storage is closer/outer than the window-curtain "
                                        "fixture; compact the protruding curtain panel before forcing a large storage-depth scale."
                                    ),
                                }
                            )
                            continue

                target_scene_span = float(storage_max[1]) - target_storage_front_y
                if target_scene_span <= storage_span + 0.015:
                    continue
                residuals.append(
                    {
                        "type": "side_wall_storage_window_cluster_front_edge_gap",
                        "storage_id": storage_id,
                        "window_id": cluster.get("window_id"),
                        "cluster_unit_id": cluster.get("unit_id"),
                        "wall_id": wall_id,
                        "axis": "y",
                        "target_object_id": storage_id,
                        "anchored_edge": "back_edge",
                        "target_scene_span": round(float(target_scene_span), 6),
                        "current_scene_span": round(float(storage_span), 6),
                        "target_front_y": round(float(target_storage_front_y), 6),
                        "storage_scene_span_y": [round(float(storage_min[1]), 6), round(float(storage_max[1]), 6)],
                        "cluster_scene_span_y": [round(float(value), 6) for value in cluster_span],
                        "reference_frontness_gap": round(float(frontness_gap), 6),
                        "reference_bbox_bottom_gap": round(float(bbox_bottom_gap), 6),
                        "reference_frontness": {
                            storage_id: storage_signal,
                            str(cluster.get("unit_id") or ""): cluster_signal,
                        },
                        "evidence": (
                            "A same-side-wall floor storage unit that is visibly closer/outer than a window-curtain "
                            "fixture must have its front/outer depth edge outside the fixture, not only a center-order match."
                        ),
                    }
                )
    return residuals


def _fine_side_wall_protected_window_intervals(
    objects: dict[str, dict[str, Any]],
    parent: dict[str, str],
    cross_constraints: list[dict[str, Any]] | None,
    wall_id: str,
    decor_id: str,
) -> list[dict[str, Any]]:
    decor = objects.get(str(decor_id))
    if not decor:
        return []
    decor_min, decor_max = _bbox_for_object(decor)
    same_wall_curtains: list[dict[str, Any]] = []
    for object_id, obj in objects.items():
        if object_id == decor_id:
            continue
        other_wall = _object_attached_wall_id(objects, object_id, parent) or _wall_relation_for_object(
            object_id,
            cross_constraints or [],
            parent,
        )
        if other_wall != wall_id or not _is_curtain_panel_object(obj):
            continue
        other_min, other_max = _bbox_for_object(obj)
        z_overlap = min(float(decor_max[2]), float(other_max[2])) - max(float(decor_min[2]), float(other_min[2]))
        if z_overlap <= 0.02:
            continue
        span_y = max(0.0, float(other_max[1]) - float(other_min[1]))
        if span_y <= 0.0:
            continue
        same_wall_curtains.append(
            {
                "object_id": object_id,
                "center_y": (float(other_min[1]) + float(other_max[1])) / 2.0,
                "span_y": span_y,
            }
        )
    intervals: list[dict[str, Any]] = []
    for object_id, obj in objects.items():
        if object_id == decor_id:
            continue
        other_wall = _object_attached_wall_id(objects, object_id, parent) or _wall_relation_for_object(
            object_id,
            cross_constraints or [],
            parent,
        )
        if other_wall != wall_id:
            continue
        # Window panels are hard blockers for wall art. Curtain panels remain
        # governed by the fixed window/curtain assembly step; treating every
        # curtain width as a hard blocker can make this reference impossible
        # without a separate curtain-width scale decision.
        if _is_curtain_panel_object(obj) or _is_curtain_rod_object(obj):
            continue
        if not _functional_cluster_is_window_object(obj):
            continue
        other_min, other_max = _bbox_for_object(obj)
        z_overlap = min(float(decor_max[2]), float(other_max[2])) - max(float(decor_min[2]), float(other_min[2]))
        if z_overlap <= 0.02:
            continue
        interval_low = float(other_min[1])
        interval_high = float(other_max[1])
        if interval_high <= interval_low:
            continue
        window_center = (interval_low + interval_high) / 2.0
        before_curtains = [curtain for curtain in same_wall_curtains if float(curtain["center_y"]) < window_center]
        after_curtains = [curtain for curtain in same_wall_curtains if float(curtain["center_y"]) > window_center]
        curtain_before = max(before_curtains, key=lambda item: float(item["center_y"]), default=None)
        curtain_after = min(after_curtains, key=lambda item: float(item["center_y"]), default=None)
        assembly_gap = max(float(FINE_SPATIAL_ORDER_SCENE_CLEARANCE), 0.04)
        before_target_span = (
            _fine_side_wall_curtain_slot_target_span(float(curtain_before.get("span_y", 0.0) or 0.0))
            if curtain_before
            else None
        )
        after_target_span = (
            _fine_side_wall_curtain_slot_target_span(float(curtain_after.get("span_y", 0.0) or 0.0))
            if curtain_after
            else None
        )
        intervals.append(
            {
                "object_id": object_id,
                "span_y": [round(float(interval_low), 6), round(float(interval_high), 6)],
                "z_overlap": round(float(z_overlap), 6),
                "curtain_before_id": str(curtain_before.get("object_id") or "") if curtain_before else None,
                "curtain_after_id": str(curtain_after.get("object_id") or "") if curtain_after else None,
                "curtain_before_target_span": round(float(before_target_span), 6)
                if before_target_span is not None
                else None,
                "curtain_after_target_span": round(float(after_target_span), 6)
                if after_target_span is not None
                else None,
                "reserve_before": round(
                    float(before_target_span + assembly_gap),
                    6,
                )
                if before_target_span is not None
                else 0.0,
                "reserve_after": round(
                    float(after_target_span + assembly_gap),
                    6,
                )
                if after_target_span is not None
                else 0.0,
            }
        )
    intervals.sort(key=lambda item: (float(item["span_y"][0]), str(item.get("object_id") or "")))
    return intervals


def _fine_side_wall_interval_clear(
    low: float,
    high: float,
    protected_intervals: list[dict[str, Any]],
    clearance: float,
) -> bool:
    for interval in protected_intervals:
        span = interval.get("span_y") if isinstance(interval.get("span_y"), list) else []
        if len(span) < 2:
            continue
        protected_low = float(span[0]) - float(clearance)
        protected_high = float(span[1]) + float(clearance)
        if min(float(high), protected_high) - max(float(low), protected_low) > 1e-6:
            return False
    return True


def _fine_side_wall_target_avoiding_intervals(
    *,
    current_center: float,
    decor_span: float,
    storage_low: float,
    storage_high: float,
    protected_intervals: list[dict[str, Any]],
    room_length: float,
) -> dict[str, Any]:
    half_span = max(0.0, float(decor_span)) / 2.0
    room_margin = max(float(FLOOR_WALL_AGAINST_GAP), 0.02)
    room_low = half_span + room_margin
    room_high = max(room_low, float(room_length) - half_span - room_margin)
    inside_low = float(storage_low) + half_span + 0.015
    inside_high = float(storage_high) - half_span - 0.015
    if inside_high < inside_low:
        storage_center = (float(storage_low) + float(storage_high)) / 2.0
        inside_low = inside_high = storage_center
    preferred_center = _clamp(float(current_center), inside_low, inside_high)
    clearance = max(float(FINE_SPATIAL_ORDER_SCENE_CLEARANCE), 0.045)

    candidates: list[dict[str, Any]] = []

    def add_candidate(center: float, source: str, interval_object_id: str | None = None) -> None:
        center = _clamp(float(center), room_low, room_high)
        low = center - half_span
        high = center + half_span
        if not _fine_side_wall_interval_clear(low, high, protected_intervals, clearance):
            return
        storage_extension = max(0.0, float(storage_low) - low) + max(0.0, high - float(storage_high))
        candidates.append(
            {
                "target_y": center,
                "target_span_y": [low, high],
                "source": source,
                "interval_object_id": interval_object_id,
                "storage_extension": storage_extension,
                "distance_to_current": abs(center - float(current_center)),
                "distance_to_preferred": abs(center - float(preferred_center)),
            }
        )

    add_candidate(preferred_center, "inside_storage_preferred")
    for interval in protected_intervals:
        span = interval.get("span_y") if isinstance(interval.get("span_y"), list) else []
        if len(span) < 2:
            continue
        object_id = str(interval.get("object_id") or "")
        reserve_before = max(0.0, _safe_float(interval.get("reserve_before"), 0.0))
        reserve_after = max(0.0, _safe_float(interval.get("reserve_after"), 0.0))
        add_candidate(float(span[0]) - reserve_before - clearance - half_span, "before_protected_window", object_id)
        add_candidate(float(span[1]) + reserve_after + clearance + half_span, "after_protected_window", object_id)

    if not candidates:
        fallback = _clamp(preferred_center, room_low, room_high)
        return {
            "target_y": fallback,
            "target_span_y": [fallback - half_span, fallback + half_span],
            "source": "blocked_fallback",
            "blocked": True,
            "protected_intervals": protected_intervals,
        }

    candidates.sort(
        key=lambda item: (
            float(item.get("distance_to_current", 0.0) or 0.0),
            float(item.get("storage_extension", 0.0) or 0.0),
            float(item.get("distance_to_preferred", 0.0) or 0.0),
            str(item.get("source") or ""),
        )
    )
    chosen = dict(candidates[0])
    chosen["target_span_y"] = [round(float(v), 6) for v in chosen.get("target_span_y", [])]
    chosen["target_y"] = round(float(chosen.get("target_y", 0.0) or 0.0), 6)
    chosen["storage_extension"] = round(float(chosen.get("storage_extension", 0.0) or 0.0), 6)
    chosen["distance_to_current"] = round(float(chosen.get("distance_to_current", 0.0) or 0.0), 6)
    chosen["distance_to_preferred"] = round(float(chosen.get("distance_to_preferred", 0.0) or 0.0), 6)
    chosen["protected_intervals"] = protected_intervals
    return chosen


def _fine_side_wall_edge_residuals(
    plan: dict[str, Any],
    scene_graph: dict[str, Any],
    parent: dict[str, str],
    cross_constraints: list[dict[str, Any]] | None,
) -> list[dict[str, Any]]:
    room = plan.get("room") if isinstance(plan.get("room"), dict) else {}
    if not room:
        return []
    objects = {str(obj.get("id")): obj for obj in plan.get("objects", []) if isinstance(obj, dict) and obj.get("id")}
    ref_bboxes = _reference_bboxes_by_object(scene_graph)
    ref_depths = _reference_depths_by_object(scene_graph)
    residuals: list[dict[str, Any]] = []

    storage_by_wall: dict[str, list[str]] = {"wall_west": [], "wall_east": []}
    wall_decor_by_wall: dict[str, list[str]] = {"wall_west": [], "wall_east": []}
    door_by_wall: dict[str, list[str]] = {"wall_west": [], "wall_east": []}
    for object_id, obj in objects.items():
        placement = str(obj.get("placement_type") or "")
        support_id = str(obj.get("support_id") or "")
        wall_id = _object_attached_wall_id(objects, object_id, parent) or _wall_relation_for_object(object_id, cross_constraints or [], parent)
        if wall_id not in {"wall_west", "wall_east"}:
            continue
        if placement == "floor" and _is_floor_storage_or_table_branch_object(obj) and not _is_bedside_table_object(obj):
            storage_by_wall.setdefault(wall_id, []).append(object_id)
            continue
        if placement == "attached_to_wall" and support_id == wall_id:
            if _is_wall_door_object(obj):
                door_by_wall.setdefault(wall_id, []).append(object_id)
                continue
            if _fine_spatial_order_is_protected_assembly_member(obj) or _functional_cluster_is_window_object(obj):
                continue
            if not ref_bboxes.get(object_id):
                continue
            wall_decor_by_wall.setdefault(wall_id, []).append(object_id)

    tolerance = float(FINE_SPATIAL_ORDER_SIDE_WALL_EDGE_TOLERANCE)
    for wall_id, decor_ids in sorted(wall_decor_by_wall.items()):
        for decor_id in sorted(decor_ids):
            decor = objects.get(decor_id)
            if not decor:
                continue
            decor_min, decor_max = _bbox_for_object(decor)
            decor_span = max(0.0, float(decor_max[1]) - float(decor_min[1]))
            best: tuple[float, str] | None = None
            for storage_id in storage_by_wall.get(wall_id, []):
                score = _fine_reference_x_overlap_ratio(ref_bboxes, decor_id, storage_id)
                if score <= 0.18:
                    decor_bbox = ref_bboxes.get(decor_id)
                    storage_bbox = ref_bboxes.get(storage_id)
                    if not decor_bbox or not storage_bbox:
                        continue
                    same_side_edge = (
                        wall_id == "wall_west"
                        and float(decor_bbox[0]) <= 0.055
                        and float(storage_bbox[0]) <= 0.055
                    ) or (
                        wall_id == "wall_east"
                        and float(decor_bbox[2]) >= 0.945
                        and float(storage_bbox[2]) >= 0.945
                    )
                    if not same_side_edge:
                        continue
                    score = 0.19
                if best is None or score > best[0]:
                    best = (score, storage_id)
            if not best:
                continue
            storage_id = best[1]
            storage = objects.get(storage_id)
            if not storage:
                continue
            storage_min, storage_max = _bbox_for_object(storage)
            protected_intervals = _fine_side_wall_protected_window_intervals(
                objects,
                parent,
                cross_constraints,
                wall_id,
                decor_id,
            )
            target = _fine_side_wall_target_avoiding_intervals(
                current_center=float(decor.get("y", 0.0) or 0.0),
                decor_span=decor_span,
                storage_low=float(storage_min[1]),
                storage_high=float(storage_max[1]),
                protected_intervals=protected_intervals,
                room_length=float(room.get("length", 0.0) or 0.0),
            )
            target_span = target.get("target_span_y") if isinstance(target.get("target_span_y"), list) else []
            target_low = float(target_span[0]) - 0.015 if len(target_span) >= 2 else float(storage_min[1])
            target_high = float(target_span[1]) + 0.015 if len(target_span) >= 2 else float(storage_max[1])
            if target_low < float(storage_min[1]) - tolerance:
                target_scene_span = float(storage_max[1]) - target_low
                current_scene_span = float(storage_max[1]) - float(storage_min[1])
                if target_scene_span > current_scene_span + 0.015:
                    residuals.append(
                        {
                            "type": "side_wall_storage_extend_for_wall_decor",
                            "object_id": decor_id,
                            "storage_id": storage_id,
                            "wall_id": wall_id,
                            "axis": "y",
                            "target_object_id": storage_id,
                            "anchored_edge": "back_edge",
                            "target_scene_span": round(float(target_scene_span), 6),
                            "current_scene_span": round(float(current_scene_span), 6),
                            "target_decor_span_y": [round(float(target_low), 6), round(float(target_high), 6)],
                            "storage_scene_span_y": [round(float(storage_min[1]), 6), round(float(storage_max[1]), 6)],
                            "protected_intervals": protected_intervals,
                            "placement_target": target,
                            "reference_x_overlap_ratio": round(float(best[0]), 6),
                            "evidence": "A side-wall wall object must align with a same-wall storage tangent/depth span; when the only non-window slot lies outside current storage bounds, extend storage depth before moving the wall object.",
                        }
                    )
            elif target_high > float(storage_max[1]) + tolerance:
                target_scene_span = target_high - float(storage_min[1])
                current_scene_span = float(storage_max[1]) - float(storage_min[1])
                if target_scene_span > current_scene_span + 0.015:
                    residuals.append(
                        {
                            "type": "side_wall_storage_extend_for_wall_decor",
                            "object_id": decor_id,
                            "storage_id": storage_id,
                            "wall_id": wall_id,
                            "axis": "y",
                            "target_object_id": storage_id,
                            "anchored_edge": "front_edge",
                            "target_scene_span": round(float(target_scene_span), 6),
                            "current_scene_span": round(float(current_scene_span), 6),
                            "target_decor_span_y": [round(float(target_low), 6), round(float(target_high), 6)],
                            "storage_scene_span_y": [round(float(storage_min[1]), 6), round(float(storage_max[1]), 6)],
                            "protected_intervals": protected_intervals,
                            "placement_target": target,
                            "reference_x_overlap_ratio": round(float(best[0]), 6),
                            "evidence": "A side-wall wall object must align with a same-wall storage tangent/depth span; when the only non-window slot lies outside current storage bounds, extend storage depth before moving the wall object.",
                        }
                    )
            target_source = str(target.get("source") or "")
            target_interval_object = str(target.get("interval_object_id") or "")
            target_interval = next(
                (
                    interval
                    for interval in protected_intervals
                    if str(interval.get("object_id") or "") == target_interval_object
                ),
                None,
            )
            if target_interval and target_source in {"before_protected_window", "after_protected_window"}:
                window_span = target_interval.get("span_y") if isinstance(target_interval.get("span_y"), list) else []
                assembly_gap = max(float(FINE_SPATIAL_ORDER_SCENE_CLEARANCE), 0.04)
                for side in ("before", "after"):
                    curtain_id = str(target_interval.get(f"curtain_{side}_id") or "")
                    curtain = objects.get(curtain_id)
                    curtain_target_span = _safe_float(target_interval.get(f"curtain_{side}_target_span"), 0.0)
                    if not curtain or curtain_target_span <= 0.0 or len(window_span) < 2:
                        continue
                    curtain_min, curtain_max = _bbox_for_object(curtain)
                    curtain_current_span = max(0.0, float(curtain_max[1]) - float(curtain_min[1]))
                    if side == "before":
                        curtain_target_y = float(window_span[0]) - assembly_gap - curtain_target_span / 2.0
                        anchored_edge = "window_left_edge"
                    else:
                        curtain_target_y = float(window_span[1]) + assembly_gap + curtain_target_span / 2.0
                        anchored_edge = "window_right_edge"
                    if curtain_current_span > curtain_target_span + 0.015 or abs(float(curtain.get("y", 0.0) or 0.0) - curtain_target_y) > tolerance:
                        residuals.append(
                            {
                                "type": "side_wall_curtain_slot_for_wall_decor",
                                "object_id": curtain_id,
                                "decor_id": decor_id,
                                "window_id": target_interval_object,
                                "storage_id": storage_id,
                                "wall_id": wall_id,
                                "axis": "y",
                                "side": side,
                                "target_scene_span": round(float(curtain_target_span), 6),
                                "current_scene_span": round(float(curtain_current_span), 6),
                                "target_y": round(float(curtain_target_y), 6),
                                "anchored_edge": anchored_edge,
                                "window_span_y": [round(float(value), 6) for value in window_span],
                                "decor_target": target,
                                "evidence": "The window/curtain assembly must keep half-curtains tightly beside the window while leaving a clear slot for same-wall decor aligned to the dresser.",
                            }
                        )
            allowed_low = float(storage_min[1]) + decor_span / 2.0 + 0.015
            allowed_high = float(storage_max[1]) - decor_span / 2.0 - 0.015
            if allowed_high < allowed_low:
                center = (float(storage_min[1]) + float(storage_max[1])) / 2.0
                allowed_low = allowed_high = center
            current_center = float(decor.get("y", 0.0) or 0.0)
            target_y = _safe_float(target.get("target_y"), _clamp(current_center, allowed_low, allowed_high))
            delta = target_y - current_center
            if abs(delta) <= tolerance:
                continue
            residuals.append(
                {
                    "type": "side_wall_wall_decor_storage_tangent_misalignment",
                    "object_id": decor_id,
                    "storage_id": storage_id,
                    "wall_id": wall_id,
                    "axis": "y",
                    "current_y": round(float(current_center), 6),
                    "target_y": round(float(target_y), 6),
                    "required_span": [round(float(allowed_low), 6), round(float(allowed_high), 6)],
                    "target_span_y": [round(float(value), 6) for value in target_span] if len(target_span) >= 2 else None,
                    "decor_scene_span_y": [round(float(decor_min[1]), 6), round(float(decor_max[1]), 6)],
                    "storage_scene_span_y": [round(float(storage_min[1]), 6), round(float(storage_max[1]), 6)],
                    "delta": round(float(delta), 6),
                    "protected_intervals": protected_intervals,
                    "placement_target": target,
                    "reference_x_overlap_ratio": round(float(best[0]), 6),
                    "reference_bbox": {
                        decor_id: [round(float(value), 6) for value in ref_bboxes.get(decor_id, [])],
                        storage_id: [round(float(value), 6) for value in ref_bboxes.get(storage_id, [])],
                    },
                    "evidence": "A same-side-wall wall object visually shares the side-wall column with a floor storage unit; compare wall-tangent edges, not only image-center order.",
                }
            )

    beds = [obj for obj in objects.values() if _is_bed_or_sofa_object(obj)]
    if len(beds) == 1:
        bed = beds[0]
        bed_id = str(bed.get("id") or "")
        bed_bbox = ref_bboxes.get(bed_id)
        bed_min, bed_max = _bbox_for_object(bed)
        bed_front_y = float(bed_min[1])
        for wall_id, storage_ids in sorted(storage_by_wall.items()):
            for storage_id in sorted(storage_ids):
                storage = objects.get(storage_id)
                storage_bbox = ref_bboxes.get(storage_id)
                if not storage or not bed_bbox or not storage_bbox:
                    continue
                storage_dims = storage.get("dimensions") if isinstance(storage.get("dimensions"), dict) else {}
                if _safe_float(storage_dims.get("height"), 0.0) > 1.25 or _is_book_storage(storage):
                    continue
                bbox_bottom_gap = abs(float(bed_bbox[3]) - float(storage_bbox[3]))
                bed_depth = ref_depths.get(bed_id, {})
                storage_depth = ref_depths.get(storage_id, {})
                depth_gap = (
                    abs(_safe_float(bed_depth.get("frontness"), 0.0) - _safe_float(storage_depth.get("frontness"), 0.0))
                    if isinstance(bed_depth, dict) and isinstance(storage_depth, dict)
                    else 1.0
                )
                if bbox_bottom_gap > 0.055 and depth_gap > 0.35:
                    continue
                storage_min, storage_max = _bbox_for_object(storage)
                storage_front_y = float(storage_min[1])
                front_gap = storage_front_y - bed_front_y
                if abs(front_gap) <= float(FINE_SPATIAL_ORDER_SIDE_WALL_STORAGE_BED_FRONT_TOLERANCE):
                    continue
                target_front_y = bed_front_y + (0.02 if front_gap > 0.0 else -0.02)
                if front_gap > 0.0:
                    target_span = float(storage_max[1]) - target_front_y
                    target_object_id = storage_id
                    current_span = float(storage_max[1]) - float(storage_min[1])
                else:
                    target_span = float(bed_max[1]) - float(storage_front_y)
                    target_object_id = bed_id
                    current_span = float(bed_max[1]) - float(bed_min[1])
                if target_span <= current_span + 0.015:
                    continue
                residuals.append(
                    {
                        "type": "side_wall_storage_bed_front_edge_gap",
                        "storage_id": storage_id,
                        "bed_id": bed_id,
                        "wall_id": wall_id,
                        "axis": "y",
                        "target_object_id": target_object_id,
                        "anchored_edge": "back_edge",
                        "current_front_gap": round(float(front_gap), 6),
                        "target_scene_span": round(float(target_span), 6),
                        "current_scene_span": round(float(current_span), 6),
                        "bed_front_y": round(float(bed_front_y), 6),
                        "storage_front_y": round(float(storage_front_y), 6),
                        "reference_bbox_bottom_gap": round(float(bbox_bottom_gap), 6),
                        "reference_depth_frontness_gap": round(float(depth_gap), 6),
                        "evidence": "The side-wall storage outer/front depth should stay close to the bed outer/front depth; if translation cannot satisfy it, extend the relevant depth-axis scale while preserving the back edge.",
                    }
                )
        for wall_id, door_ids in sorted(door_by_wall.items()):
            for door_id in sorted(door_ids):
                door = objects.get(door_id)
                door_bbox = ref_bboxes.get(door_id)
                if not door or not bed_bbox or not door_bbox:
                    continue
                bbox_bottom_gap = abs(float(bed_bbox[3]) - float(door_bbox[3]))
                bed_depth = ref_depths.get(bed_id, {})
                door_depth = ref_depths.get(door_id, {})
                depth_gap = (
                    abs(_safe_float(bed_depth.get("frontness"), 0.0) - _safe_float(door_depth.get("frontness"), 0.0))
                    if isinstance(bed_depth, dict) and isinstance(door_depth, dict)
                    else 1.0
                )
                if bbox_bottom_gap > 0.065 and depth_gap > 0.42:
                    continue
                door_min, door_max = _bbox_for_object(door)
                door_front_y = float(door_min[1])
                door_span_y = max(0.0, float(door_max[1]) - float(door_min[1]))
                if door_span_y <= 0.0:
                    continue
                front_gap = door_front_y - bed_front_y
                if abs(front_gap) <= float(FINE_SPATIAL_ORDER_SIDE_WALL_STORAGE_BED_FRONT_TOLERANCE):
                    continue
                target_y = float(bed_front_y) + door_span_y / 2.0
                residuals.append(
                    {
                        "type": "side_wall_door_bed_front_edge_gap",
                        "door_id": door_id,
                        "bed_id": bed_id,
                        "wall_id": wall_id,
                        "axis": "y",
                        "current_front_gap": round(float(front_gap), 6),
                        "target_y": round(float(target_y), 6),
                        "door_front_y": round(float(door_front_y), 6),
                        "bed_front_y": round(float(bed_front_y), 6),
                        "door_scene_span_y": [round(float(door_min[1]), 6), round(float(door_max[1]), 6)],
                        "bed_scene_span_y": [round(float(bed_min[1]), 6), round(float(bed_max[1]), 6)],
                        "reference_bbox_bottom_gap": round(float(bbox_bottom_gap), 6),
                        "reference_depth_frontness_gap": round(float(depth_gap), 6),
                        "evidence": "A side-wall door whose reference bottom/front edge is close to the bed must align its room-depth outer/front edge with the bed; compare edges, not only object centers.",
                    }
                )
    return residuals


def _fine_apply_side_wall_edge_residuals(
    plan: dict[str, Any],
    residuals: list[dict[str, Any]],
) -> list[dict[str, Any]]:
    objects = {str(obj.get("id")): obj for obj in plan.get("objects", []) if isinstance(obj, dict) and obj.get("id")}
    room = plan.get("room") if isinstance(plan.get("room"), dict) else {}
    fixes: list[dict[str, Any]] = []
    for residual in residuals:
        residual_type = str(residual.get("type") or "")
        if residual_type == "side_wall_wall_decor_storage_tangent_misalignment":
            object_id = str(residual.get("object_id") or "")
            obj = objects.get(object_id)
            wall_id = str(residual.get("wall_id") or "")
            if not obj or wall_id not in VIRTUAL_WALLS:
                continue
            current_y = float(obj.get("y", 0.0) or 0.0)
            target_y = _safe_float(residual.get("target_y"), current_y)
            delta = _clamp(
                target_y - current_y,
                -float(FINE_SPATIAL_ORDER_SIDE_WALL_EDGE_MAX_MOVE),
                float(FINE_SPATIAL_ORDER_SIDE_WALL_EDGE_MAX_MOVE),
            )
            if abs(delta) <= 1e-6:
                continue
            before = _plan_object_snapshot(obj)
            obj["y"] = current_y + delta
            _clamp_wall_attached_object(obj, room, wall_id)
            after = _plan_object_snapshot(obj)
            if before != after:
                fixes.append(
                    {
                        "type": "fine_side_wall_edge_move",
                        "id": object_id,
                        "wall_id": wall_id,
                        "axis": "y",
                        "before": before,
                        "after": after,
                        "residual": residual,
                    }
                )
            continue
        if residual_type == "side_wall_door_bed_front_edge_gap":
            object_id = str(residual.get("door_id") or "")
            obj = objects.get(object_id)
            wall_id = str(residual.get("wall_id") or "")
            if not obj or wall_id not in {"wall_west", "wall_east"}:
                continue
            current_y = float(obj.get("y", 0.0) or 0.0)
            target_y = _safe_float(residual.get("target_y"), current_y)
            delta = _clamp(
                target_y - current_y,
                -float(FINE_SPATIAL_ORDER_SIDE_WALL_EDGE_MAX_MOVE),
                float(FINE_SPATIAL_ORDER_SIDE_WALL_EDGE_MAX_MOVE),
            )
            if abs(delta) <= 1e-6:
                continue
            before = _plan_object_snapshot(obj)
            obj["y"] = current_y + delta
            _clamp_wall_attached_object(obj, room, wall_id)
            after = _plan_object_snapshot(obj)
            if before != after:
                fixes.append(
                    {
                        "type": "fine_side_wall_door_bed_front_edge_move",
                        "id": object_id,
                        "wall_id": wall_id,
                        "axis": "y",
                        "before": before,
                        "after": after,
                        "residual": residual,
                    }
                )
            continue
        if residual_type in {"side_wall_curtain_slot_for_wall_decor", "side_wall_curtain_slot_for_storage_depth_order"}:
            object_id = str(residual.get("object_id") or "")
            obj = objects.get(object_id)
            wall_id = str(residual.get("wall_id") or "")
            if not obj or wall_id not in {"wall_west", "wall_east"}:
                continue
            dims = obj.get("dimensions") if isinstance(obj.get("dimensions"), dict) else {}
            current_width = _safe_float(dims.get("width"), 0.0)
            target_scene_span = _safe_float(residual.get("target_scene_span"), current_width)
            if current_width <= 0.0 or target_scene_span <= 0.0:
                continue
            before = _plan_object_snapshot(obj)
            dims["width"] = min(current_width, target_scene_span)
            dims["length"] = min(
                _safe_float(dims.get("length"), WINDOW_CURTAIN_CLUSTER_PANEL_THICKNESS),
                float(WINDOW_CURTAIN_CLUSTER_PANEL_THICKNESS),
            )
            obj["dimensions"] = dims
            _new_width, new_length = _rotated_footprint(obj)
            obj["y"] = _safe_float(residual.get("target_y"), float(obj.get("y", 0.0) or 0.0))
            _clamp_wall_attached_object(obj, room, wall_id)
            after = _plan_object_snapshot(obj)
            if before != after:
                fixes.append(
                    {
                        "type": "fine_side_wall_curtain_slot_scale",
                        "id": object_id,
                        "wall_id": wall_id,
                        "axis": "y",
                        "dimension_key": "width",
                        "before": before,
                        "after": after,
                        "target_scene_span": round(float(new_length), 6),
                        "residual": residual,
                    }
                )
            continue
        if residual_type in {
            "side_wall_storage_bed_front_edge_gap",
            "side_wall_storage_extend_for_wall_decor",
            "side_wall_storage_window_cluster_front_edge_gap",
        }:
            object_id = str(residual.get("target_object_id") or "")
            obj = objects.get(object_id)
            if not obj:
                continue
            dim_key = _fine_scene_axis_dimension_key(obj, "y")
            dims = obj.get("dimensions") if isinstance(obj.get("dimensions"), dict) else {}
            if not dim_key or dim_key not in dims:
                continue
            current_dim = _safe_float(dims.get(dim_key), 0.0)
            _current_width, current_length = _rotated_footprint(obj)
            target_scene_span = _safe_float(residual.get("target_scene_span"), current_length)
            if current_dim <= 0.0 or current_length <= 0.0 or target_scene_span <= current_length + 0.015:
                continue
            ratio = min(float(FINE_SPATIAL_ORDER_SIDE_WALL_STORAGE_MAX_RATIO), target_scene_span / current_length)
            before = _plan_object_snapshot(obj)
            before_dimensions = dict(dims)
            old_min, old_max = _bbox_for_object(obj)
            dims[dim_key] = current_dim * ratio
            obj["dimensions"] = dims
            _new_width, new_length = _rotated_footprint(obj)
            anchored_edge = str(residual.get("anchored_edge") or "")
            if anchored_edge == "back_edge":
                obj["y"] = float(old_max[1]) - new_length / 2.0
            elif anchored_edge == "front_edge":
                obj["y"] = float(old_min[1]) + new_length / 2.0
            _clamp_object_to_room_rotated(obj, room, margin=0.0)
            after = _plan_object_snapshot(obj)
            if before != after:
                fixes.append(
                    {
                        "type": "fine_side_wall_depth_scale",
                        "id": object_id,
                        "axis": "y",
                        "dimension_key": dim_key,
                        "anchored_edge": anchored_edge,
                        "before": before,
                        "after": after,
                        "before_dimensions": before_dimensions,
                        "after_dimensions": dict(dims),
                        "applied_ratio": round(float(ratio), 6),
                        "residual": residual,
                    }
                )
    return fixes


def _fine_spatial_order_side_wall_fixture_depth_refinement(
    plan: dict[str, Any],
    scene_graph: dict[str, Any],
    parent: dict[str, str],
    cross_constraints: list[dict[str, Any]] | None,
    report: dict[str, Any],
) -> None:
    before = _fine_side_wall_fixture_depth_residuals(plan, scene_graph, parent, cross_constraints)
    all_fixes: list[dict[str, Any]] = []
    passes: list[dict[str, Any]] = []
    for iteration in range(3):
        iteration_residuals = _fine_side_wall_fixture_depth_residuals(plan, scene_graph, parent, cross_constraints)
        iteration_fixes = _fine_apply_side_wall_edge_residuals(plan, iteration_residuals)
        for fix in iteration_fixes:
            fix["iteration"] = iteration + 1
            fix["constraint_family"] = "side_wall_fixture_depth"
        all_fixes.extend(iteration_fixes)
        passes.append(
            {
                "iteration": iteration + 1,
                "residual_count": len(iteration_residuals),
                "fix_count": len(iteration_fixes),
                "residual_types": sorted({str(item.get("type") or "") for item in iteration_residuals}),
            }
        )
        if not iteration_fixes:
            break
    after = _fine_side_wall_fixture_depth_residuals(plan, scene_graph, parent, cross_constraints)
    report["side_wall_fixture_depth_residuals_before"] = before
    report["side_wall_fixture_depth_residuals"] = after
    report["side_wall_fixture_depth_residual_count"] = len(after)
    report["side_wall_fixture_depth_unresolved_required_count"] = len(after)
    report["side_wall_fixture_depth_passes"] = passes
    if all_fixes:
        report.setdefault("side_wall_fixture_depth_fixes", []).extend(all_fixes)
        report.setdefault("fixes", []).extend(all_fixes)


def _fine_spatial_order_side_wall_edge_refinement(
    plan: dict[str, Any],
    scene_graph: dict[str, Any],
    parent: dict[str, str],
    cross_constraints: list[dict[str, Any]] | None,
    report: dict[str, Any],
) -> None:
    before = _fine_side_wall_edge_residuals(plan, scene_graph, parent, cross_constraints)
    all_fixes: list[dict[str, Any]] = []
    passes: list[dict[str, Any]] = []
    for iteration in range(3):
        iteration_residuals = _fine_side_wall_edge_residuals(plan, scene_graph, parent, cross_constraints)
        iteration_fixes = _fine_apply_side_wall_edge_residuals(plan, iteration_residuals)
        for fix in iteration_fixes:
            fix["iteration"] = iteration + 1
        all_fixes.extend(iteration_fixes)
        passes.append(
            {
                "iteration": iteration + 1,
                "residual_count": len(iteration_residuals),
                "fix_count": len(iteration_fixes),
                "residual_types": sorted({str(item.get("type") or "") for item in iteration_residuals}),
            }
        )
        if not iteration_fixes:
            break
    after = _fine_side_wall_edge_residuals(plan, scene_graph, parent, cross_constraints)
    report["side_wall_edge_residuals_before"] = before
    report["side_wall_edge_residuals"] = after
    report["side_wall_edge_residual_count"] = len(after)
    report["side_wall_edge_unresolved_required_count"] = len(after)
    report["side_wall_edge_passes"] = passes
    if all_fixes:
        report.setdefault("side_wall_edge_fixes", []).extend(all_fixes)
        report.setdefault("fixes", []).extend(all_fixes)


def _fine_spatial_order_bed_lamp_top_refinement(
    plan: dict[str, Any],
    scene_graph: dict[str, Any],
    parent: dict[str, str],
    report: dict[str, Any],
) -> None:
    room = plan.get("room") if isinstance(plan.get("room"), dict) else {}
    objects = {str(obj.get("id")): obj for obj in plan.get("objects", []) if isinstance(obj, dict) and obj.get("id")}
    ref_bboxes = _reference_bboxes_by_object(scene_graph)
    beds = [
        obj
        for obj in objects.values()
        if _is_bed_or_sofa_object(obj) and str(obj.get("placement_type") or "floor") == "floor"
    ]
    alignment: dict[str, Any] = {
        "enabled": True,
        "fixes": [],
        "residuals": [],
        "unresolved_required_count": 0,
    }
    if len(beds) != 1:
        alignment["reason"] = "expected_single_floor_bed"
        report["bed_lamp_top_alignment"] = alignment
        report["bed_lamp_top_unresolved_required_count"] = 0
        return
    bed = beds[0]
    bed_id = str(bed.get("id") or "")
    bed_ref = ref_bboxes.get(bed_id)
    if not bed_ref:
        alignment["reason"] = "missing_bed_reference_bbox"
        report["bed_lamp_top_alignment"] = alignment
        report["bed_lamp_top_unresolved_required_count"] = 0
        return
    bed_ref_top = float(bed_ref[1])
    lamps: list[dict[str, Any]] = []
    for object_id, obj in sorted(objects.items()):
        if object_id == bed_id:
            continue
        text = _object_identity_text(obj)
        if "floor lamp" in text or ("floor" in text and "lamp" in text):
            continue
        if _scale_kind(obj) not in {"table_lamp", "lamp"} and "lamp" not in text:
            continue
        placement = str(obj.get("placement_type") or "")
        support_id = str(obj.get("support_id") or parent.get(object_id) or "")
        if placement != "on_top" and support_id not in objects:
            continue
        bbox = ref_bboxes.get(object_id)
        if not bbox:
            continue
        ref_top_gap = abs(float(bbox[1]) - bed_ref_top)
        if ref_top_gap > float(FINE_SPATIAL_ORDER_BED_LAMP_TOP_REF_TOLERANCE):
            continue
        obj_min, obj_max = _bbox_for_object(obj)
        lamps.append(
            {
                "id": object_id,
                "reference_top_y": round(float(bbox[1]), 6),
                "reference_top_gap": round(float(ref_top_gap), 6),
                "scene_top": round(float(obj_max[2]), 6),
                "scene_bottom": round(float(obj_min[2]), 6),
                "support_id": support_id,
            }
        )
    if not lamps:
        alignment["reason"] = "no_reference_top_aligned_table_lamps"
        report["bed_lamp_top_alignment"] = alignment
        report["bed_lamp_top_unresolved_required_count"] = 0
        return

    bed_min, bed_max = _bbox_for_object(bed)
    bed_scene_top = float(bed_max[2])
    lamp_tops = sorted(float(item["scene_top"]) for item in lamps)
    target_top = lamp_tops[len(lamp_tops) // 2]
    if len(lamp_tops) % 2 == 0:
        target_top = (lamp_tops[len(lamp_tops) // 2 - 1] + lamp_tops[len(lamp_tops) // 2]) / 2.0
    residual = {
        "type": "bed_lamp_top_alignment_gap",
        "bed_id": bed_id,
        "lamp_ids": [str(item["id"]) for item in lamps],
        "bed_reference_top_y": round(float(bed_ref_top), 6),
        "lamp_reference_tops_y": [round(float(item["reference_top_y"]), 6) for item in lamps],
        "bed_scene_top": round(float(bed_scene_top), 6),
        "target_scene_top": round(float(target_top), 6),
        "scene_top_gap": round(float(target_top - bed_scene_top), 6),
        "evidence": "The reference bed top edge and bedside table-lamp top edge are nearly level, so the bed height can be increased while keeping it grounded.",
    }
    if target_top - bed_scene_top <= float(FINE_SPATIAL_ORDER_BED_LAMP_TOP_SCENE_TOLERANCE):
        alignment["residuals"] = []
        alignment["reason"] = "already_within_scene_tolerance"
        alignment["bed_scene_top"] = round(float(bed_scene_top), 6)
        alignment["target_scene_top"] = round(float(target_top), 6)
        alignment["lamp_evidence"] = lamps
        report["bed_lamp_top_alignment"] = alignment
        report["bed_lamp_top_unresolved_required_count"] = 0
        return

    dims = bed.get("dimensions") if isinstance(bed.get("dimensions"), dict) else {}
    current_height = _safe_float(dims.get("height"), 0.0)
    if current_height <= 0.0:
        alignment["residuals"] = [residual]
        alignment["reason"] = "invalid_bed_height"
        alignment["unresolved_required_count"] = 1
        report["bed_lamp_top_alignment"] = alignment
        report["bed_lamp_top_unresolved_required_count"] = 1
        return
    bounds = _scale_prior_bounds_for_object(bed, room)
    min_height, max_height = bounds.get("height", (current_height, current_height))
    target_height = float(target_top) - float(bed_min[2])
    target_height = _clamp(target_height, float(min_height), float(max_height))
    target_height = min(target_height, current_height * float(FINE_SPATIAL_ORDER_BED_LAMP_TOP_MAX_RATIO))
    if target_height > current_height * 1.015:
        before = _plan_object_snapshot(bed)
        before_dimensions = dict(dims)
        dims["height"] = float(target_height)
        bed["dimensions"] = dims
        if str(bed.get("placement_type") or "floor") == "floor":
            bed["z"] = 0.0
        _clamp_object_to_room_rotated(bed, room, margin=0.0)
        for child in objects.values():
            child_id = str(child.get("id") or "")
            if child_id == bed_id:
                continue
            child_support = str(child.get("support_id") or parent.get(child_id) or "")
            if child_support == bed_id and str(child.get("placement_type") or "") == "on_top":
                child["z"] = _supported_child_surface_z(bed, child)
        after = _plan_object_snapshot(bed)
        fix = {
            "type": "fine_bed_lamp_top_height_scale",
            "id": bed_id,
            "axis": "height",
            "anchored_edge": "bottom_on_floor",
            "before": before,
            "after": after,
            "before_dimensions": before_dimensions,
            "after_dimensions": dict(dims),
            "target_scene_top": round(float(target_top), 6),
            "applied_ratio": round(float(target_height / current_height), 6),
            "residual": residual,
        }
        alignment["fixes"].append(fix)
        report.setdefault("vertical_fixes", []).append(fix)
        report.setdefault("fixes", []).append(fix)
    after_min, after_max = _bbox_for_object(bed)
    after_gap = float(target_top) - float(after_max[2])
    alignment["residuals"] = [] if after_gap <= float(FINE_SPATIAL_ORDER_BED_LAMP_TOP_SCENE_TOLERANCE) else [residual]
    alignment["unresolved_required_count"] = len(alignment["residuals"])
    alignment["bed_scene_top_before"] = round(float(bed_scene_top), 6)
    alignment["bed_scene_top_after"] = round(float(after_max[2]), 6)
    alignment["target_scene_top"] = round(float(target_top), 6)
    alignment["scene_top_gap_after"] = round(float(after_gap), 6)
    alignment["lamp_evidence"] = lamps
    report["bed_lamp_top_alignment"] = alignment
    report["bed_lamp_top_unresolved_required_count"] = int(alignment["unresolved_required_count"])


def build_fine_scale_residual_refiner_prompt(
    plan: dict[str, Any],
    layout_units: list[dict[str, Any]],
    residuals: list[dict[str, Any]],
    candidates: list[dict[str, Any]],
) -> str:
    snapshot = {
        "room": plan.get("room", {}),
        "layout_units": layout_units,
        "vertical_edge_residuals": residuals,
        "scale_candidates": candidates,
    }
    return f"""
You are the third-stage vertical edge and scale residual refiner for TreeSAGE Flow 2.
The attached image is a side-by-side comparison: left is the reference image, right is the current TreeSAGE render.

Your task is to judge whether any listed scale candidate should be applied to make vertical top-edge relationships match the reference.
Do not redesign the scene. Do not split locked layout units. Window/curtain/rod clusters are fixed assemblies and should only be used as comparison units.

Current residual snapshot:
{json.dumps(snapshot, ensure_ascii=False, indent=2)}

Return only JSON:
{{
  "schema": "tree_sage_fine_scale_residual_refiner_agent_v1",
  "scale_changes": [
    {{
      "target_object_id": "existing_object_id",
      "scale_axis": "height",
      "operation": "increase|decrease|keep",
      "target_ratio_range": [1.0, 1.0],
      "target_value": 0.0,
      "anchored_edge": "bottom_on_floor|wall_center|keep_current",
      "confidence": 0.0,
      "evidence": "short visual evidence from the reference and render",
      "expected_effect": "short expected geometric effect"
    }}
  ],
  "rejected_candidates": [
    {{
      "target_object_id": "existing_object_id",
      "reason": "short reason"
    }}
  ],
  "notes": ["short uncertainty notes"]
}}

Rules:
- Only choose target_object_id values that appear in scale_candidates.
- Prefer height changes for floor/root furniture whose bottom stays on the floor.
- If a top edge is too low but the object is a fixed assembly, do not scale it; recommend scaling a compatible single floor object instead.
- If the render already matches the reference well enough, return operation="keep".
- Keep changes conservative. A ratio range like [1.08, 1.18] is preferred over an exact aggressive value.
- The downstream deterministic solver will clamp target_value to object bounds and reject changes that cause collisions or physics regressions.
""".strip()


def run_fine_scale_residual_refiner_agent(
    plan: dict[str, Any],
    layout_units: list[dict[str, Any]],
    residuals: list[dict[str, Any]],
    candidates: list[dict[str, Any]],
    comparison_sheet: Path,
    output_dir: Path,
    model: str | None,
) -> dict[str, Any]:
    return run_codex_reference_json_agent(
        "fine_scale_residual_refiner",
        build_fine_scale_residual_refiner_prompt(plan, layout_units, residuals, candidates),
        comparison_sheet,
        output_dir,
        model,
    )


def apply_fine_scale_residual_refiner_report(
    plan: dict[str, Any],
    raw_report: dict[str, Any] | None,
    candidates: list[dict[str, Any]],
    *,
    enabled: bool,
    min_confidence: float = FINE_SPATIAL_ORDER_SCALE_MIN_CONFIDENCE,
) -> dict[str, Any]:
    report: dict[str, Any] = {
        "schema": "tree_sage_fine_scale_residual_refiner_apply_v1",
        "enabled": bool(enabled),
        "raw_agent_report": raw_report or {},
        "candidate_count": len(candidates),
        "applied": [],
        "skipped": [],
        "fixes": [],
        "fix_count": 0,
        "ok": True,
    }
    if not enabled:
        report["reason"] = "disabled"
        return report
    if not candidates:
        report["reason"] = "no_scale_candidates"
        return report
    objects = {str(obj.get("id")): obj for obj in plan.get("objects", []) if isinstance(obj, dict) and obj.get("id")}
    candidate_by_id = {str(candidate.get("target_object_id")): candidate for candidate in candidates}
    requested: dict[str, dict[str, Any]] = {}
    for item in raw_report.get("scale_changes", []) if isinstance(raw_report, dict) and isinstance(raw_report.get("scale_changes"), list) else []:
        if not isinstance(item, dict):
            continue
        object_id = str(item.get("target_object_id") or "")
        candidate = candidate_by_id.get(object_id)
        if not candidate:
            report["skipped"].append({"id": object_id, "reason": "agent_target_not_in_candidates"})
            continue
        operation = str(item.get("operation") or "").strip().lower()
        confidence = _safe_float(item.get("confidence"), 0.0)
        if operation not in {"increase", "decrease"}:
            report["skipped"].append({"id": object_id, "reason": f"agent_operation_{operation or 'missing'}"})
            continue
        if confidence < float(min_confidence):
            report["skipped"].append({"id": object_id, "reason": "low_confidence", "confidence": confidence})
            continue
        requested[object_id] = item
    if not requested:
        best = candidates[0]
        requested[str(best["target_object_id"])] = {
            "target_object_id": best["target_object_id"],
            "scale_axis": "height",
            "operation": "increase",
            "target_value": best.get("target_height"),
            "confidence": float(min_confidence),
            "evidence": "deterministic_fallback_from_vertical_edge_residual",
            "expected_effect": "raise floor furniture top edge while keeping bottom on floor",
        }
        report["fallback_used"] = True
    for object_id, request in requested.items():
        candidate = candidate_by_id.get(object_id)
        obj = objects.get(object_id)
        if not candidate or not obj:
            continue
        dims = obj.get("dimensions") if isinstance(obj.get("dimensions"), dict) else {}
        current_height = _safe_float(dims.get("height"), 0.0)
        if current_height <= 0.0:
            report["skipped"].append({"id": object_id, "reason": "invalid_current_height"})
            continue
        target_height = _safe_float(request.get("target_value"), 0.0)
        if target_height <= 0.0:
            ratio_range = request.get("target_ratio_range") if isinstance(request.get("target_ratio_range"), list) else []
            ratio_values = [_safe_float(value, 0.0) for value in ratio_range]
            ratio_values = [value for value in ratio_values if value > 0.0]
            target_ratio = min(max(ratio_values) if ratio_values else _safe_float(candidate.get("target_ratio"), 1.0), _safe_float(candidate.get("target_ratio"), 1.0))
            target_height = current_height * target_ratio
        target_height = min(float(target_height), float(candidate.get("target_height", target_height)))
        bounds = candidate.get("bounds", {}).get("height") if isinstance(candidate.get("bounds"), dict) else None
        if isinstance(bounds, list) and len(bounds) >= 2:
            target_height = _clamp(target_height, float(bounds[0]), float(bounds[1]))
        target_height = min(target_height, current_height * float(FINE_SPATIAL_ORDER_SCALE_MAX_RATIO))
        if target_height <= current_height * 1.015:
            report["skipped"].append({"id": object_id, "reason": "target_height_too_close", "target_height": target_height})
            continue
        before = _plan_object_snapshot(obj)
        before_dimensions = dict(dims)
        dims["height"] = float(target_height)
        obj["dimensions"] = dims
        if str(obj.get("placement_type") or "floor") == "floor":
            obj["z"] = 0.0
        after = _plan_object_snapshot(obj)
        fix = {
            "type": "fine_scale_height_repair",
            "id": object_id,
            "axis": "height",
            "anchored_edge": request.get("anchored_edge") or candidate.get("anchored_edge"),
            "before": before,
            "after": after,
            "before_dimensions": before_dimensions,
            "after_dimensions": dict(dims),
            "candidate": candidate,
            "agent_request": request,
        }
        report["applied"].append(fix)
        report["fixes"].append(fix)
    report["fix_count"] = len(report["fixes"])
    if report["fix_count"] == 0 and not report.get("reason"):
        report["reason"] = "no_applicable_agent_or_fallback_change"
    return report


def apply_fine_spatial_order_refinement(
    plan: dict[str, Any],
    scene_graph: dict[str, Any],
    support_tree: dict[str, Any],
    parent: dict[str, str],
    cross_constraints: list[dict[str, Any]] | None = None,
    *,
    enabled: bool = True,
    stage: str = "post_density_refiner",
    max_step: float = FINE_SPATIAL_ORDER_MAX_STEP,
    detailed_order_report: dict[str, Any] | None = None,
    agent_only_ablation: bool = False,
    bbox_projection_overlap_enabled: bool = True,
) -> dict[str, Any]:
    groups = scene_graph.get("_reference_spatial_order_groups") if isinstance(scene_graph.get("_reference_spatial_order_groups"), list) else []
    report: dict[str, Any] = {
        "schema": "tree_sage_fine_spatial_order_refinement_v1",
        "enabled": bool(enabled),
        "stage": stage,
        "checks": [],
        "vertical_checks": [],
        "fixes": [],
        "vertical_fixes": [],
        "warnings": [],
        "soft_warnings": [],
        "agent_only_ablation": bool(agent_only_ablation),
        "accepted": False,
        "ok": True,
    }
    if not enabled:
        report["reason"] = "disabled"
        return report
    if not groups:
        report["reason"] = "no_reference_spatial_order_groups"
    cross_constraints = cross_constraints or []
    ref_bboxes = _reference_bboxes_by_object(scene_graph)
    ref_depths = _reference_depths_by_object(scene_graph)
    consistency = scene_graph.get("_reference_consistency_refiner") if isinstance(scene_graph.get("_reference_consistency_refiner"), dict) else {}
    lateral_side_wall_group_ids = {
        str(branch.get("group_id") or "")
        for branch in consistency.get("side_wall_branches", [])
        if isinstance(branch, dict)
        and str(branch.get("layout_mode") or "") in {"same_depth_lateral", "mixed_depth_lateral"}
        and str(branch.get("group_id") or "")
    }
    if agent_only_ablation:
        report["disabled_modules"] = [
            "wall_vertical_reference_refinement",
            "side_wall_edge_residual_refinement",
            "bed_lamp_top_residual_refinement",
            "vertical_scale_residual_candidates",
        ]
    for group in groups:
        if not isinstance(group, dict):
            continue
        _fine_spatial_order_axis_refinement(
            plan,
            scene_graph,
            support_tree,
            parent,
            cross_constraints,
            group,
            "x",
            "left_to_right",
            ref_bboxes,
            ref_depths,
            lateral_side_wall_group_ids,
            report,
            max_step,
        )
        _fine_spatial_order_axis_refinement(
            plan,
            scene_graph,
            support_tree,
            parent,
            cross_constraints,
            group,
            "y",
            "front_to_back",
            ref_bboxes,
            ref_depths,
            lateral_side_wall_group_ids,
            report,
            max_step,
        )
    if not agent_only_ablation:
        _fine_spatial_order_wall_vertical_refinement(
            plan,
            scene_graph,
            parent,
            report,
            max_step=float(FINE_SPATIAL_ORDER_VERTICAL_MAX_STEP),
        )
    _fine_spatial_order_detailed_agent_refinement(
        plan,
        scene_graph,
        support_tree,
        parent,
        detailed_order_report,
        report,
        max_step,
    )
    _fine_spatial_order_side_wall_fixture_depth_refinement(
        plan,
        scene_graph,
        parent,
        cross_constraints,
        report,
    )
    _fine_spatial_order_bbox_projection_overlap_refinement(
        plan,
        scene_graph,
        support_tree,
        parent,
        cross_constraints,
        report,
        enabled=bool(bbox_projection_overlap_enabled),
        max_step=max(max_step, float(FINE_BBOX_PROJECTION_OVERLAP_MAX_STEP)),
    )
    if agent_only_ablation:
        report["side_wall_edge_residuals_before"] = []
        report["side_wall_edge_residuals"] = []
        report["side_wall_edge_residual_count"] = 0
        report["side_wall_edge_unresolved_required_count"] = 0
        report["side_wall_edge_passes"] = []
        report["bed_lamp_top_alignment"] = {"enabled": False, "reason": "agent_only_ablation"}
        report["bed_lamp_top_unresolved_required_count"] = 0
    else:
        _fine_spatial_order_side_wall_edge_refinement(
            plan,
            scene_graph,
            parent,
            cross_constraints,
            report,
        )
        _fine_spatial_order_bed_lamp_top_refinement(
            plan,
            scene_graph,
            parent,
            report,
        )
    layout_units = _fine_spatial_order_layout_units(plan, scene_graph, parent)
    vertical_edge_residuals = _fine_spatial_order_vertical_edge_residuals(plan, layout_units)
    scale_candidates = (
        []
        if agent_only_ablation
        else _fine_scale_candidates_from_vertical_residuals(plan, layout_units, vertical_edge_residuals)
    )
    report["layout_units"] = layout_units
    report["vertical_edge_residuals"] = vertical_edge_residuals
    report["vertical_edge_residual_count"] = len(vertical_edge_residuals)
    report["scale_candidates"] = scale_candidates
    report["scale_candidate_count"] = len(scale_candidates)
    report["fix_count"] = len(report.get("fixes", []))
    report["detailed_order_fix_count"] = len(report.get("detailed_order_fixes", []))
    report["check_count"] = len(report.get("checks", []))
    report["vertical_fix_count"] = len(report.get("vertical_fixes", []))
    report["vertical_check_count"] = len(report.get("vertical_checks", []))
    report["ok"] = not report.get("warnings")
    return report


def audit_and_repair_reference_spatial_order(
    plan: dict[str, Any],
    scene_graph: dict[str, Any],
    support_tree: dict[str, Any],
    parent: dict[str, str],
    cross_constraints: list[dict[str, Any]] | None = None,
    repair: bool = True,
) -> dict[str, Any]:
    groups = scene_graph.get("_reference_spatial_order_groups") if isinstance(scene_graph.get("_reference_spatial_order_groups"), list) else []
    report: dict[str, Any] = {
        "schema": "tree_sage_reference_spatial_order_repair_v1",
        "enabled": bool(groups),
        "stage": "after_layout_before_pose",
        "group_checks": [],
        "fixes": [],
        "warnings": [],
        "soft_warnings": [],
        "repair_enabled": bool(repair),
        "ok": True,
    }
    if not groups:
        report["reason"] = "no_reference_spatial_order_groups"
        return report

    objects = {str(obj["id"]): obj for obj in plan.get("objects", [])}
    descendants = _descendant_map(support_tree)
    room = plan["room"]
    cross_constraints = cross_constraints or []
    reference_bboxes = _reference_bboxes_by_object(scene_graph)
    reference_depths = _reference_depths_by_object(scene_graph)
    view_condition = scene_graph.get("_view_condition_report") if isinstance(scene_graph.get("_view_condition_report"), dict) else {}
    branch_relation_mode = bool(view_condition.get("branch_relation_mode_enabled"))
    consistency = scene_graph.get("_reference_consistency_refiner") if isinstance(scene_graph.get("_reference_consistency_refiner"), dict) else {}
    lateral_side_wall_group_ids = {
        str(branch.get("group_id") or "")
        for branch in consistency.get("side_wall_branches", [])
        if isinstance(branch, dict)
        and str(branch.get("layout_mode") or "") in {"same_depth_lateral", "mixed_depth_lateral"}
        and str(branch.get("group_id") or "")
    }

    def apply_axis(group: dict[str, Any], axis_name: str, order_key: str) -> None:
        raw_order = group.get(order_key) if isinstance(group.get(order_key), list) else []
        expected = _spatial_order_units([str(value) for value in raw_order], objects, parent)
        if len(expected) < 2:
            return
        confidence = _safe_float(group.get("confidence"), 0.0)
        if str(group.get("scope") or "") == "global_anchor" and confidence < 0.8:
            report["group_checks"].append(
                {
                    "group_id": group.get("group_id"),
                    "scope": group.get("scope"),
                    "axis": "left_to_right" if axis_name == "x" else "front_to_back",
                    "expected_order": expected,
                    "fixed": False,
                    "skipped": True,
                    "reason": "global_anchor_order_below_repair_confidence",
                    "confidence": confidence,
                }
            )
            return
        soft_tabletop_cross_support = branch_relation_mode and _view_condition_soft_tabletop_order_group(group, parent)
        soft_wall_plane_order = branch_relation_mode and bool(group.get("view_condition_soft_wall_plane_order"))
        side_wall_lateral_axis = (
            axis_name == "x" and str(group.get("group_id") or "") in lateral_side_wall_group_ids
        )
        scene_axis = "x" if side_wall_lateral_axis else _scene_axis_for_reference_order(axis_name, objects, expected, parent)
        group_wall_id = _common_attached_wall_id(objects, expected, parent) or str(group.get("anchor_id") or "")
        side_wall_image_tangent_order = (
            axis_name == "x"
            and not side_wall_lateral_axis
            and scene_axis == "y"
            and str(group.get("scope") or "") == "wall"
            and group_wall_id in {"wall_east", "wall_west"}
        )
        current_before = _axis_order(objects, expected, scene_axis)
        reference_profile = _reference_axis_profile(
            expected,
            reference_bboxes,
            "x" if axis_name == "x" else "front_to_back",
            reference_depths,
        )
        violations_before = _adjacent_reference_order_violations(expected, current_before, reference_profile)
        pairwise_violations_before = _pairwise_reference_order_violations(expected, current_before, reference_profile)
        gap_required = _spatial_order_axis_gap_required(expected, scene_axis, cross_constraints, parent)
        gap_violations_before = (
            _adjacent_axis_gap_violations(expected, objects, scene_axis, profile=reference_profile) if gap_required else []
        )
        check: dict[str, Any] = {
            "group_id": group.get("group_id"),
            "scope": group.get("scope"),
            "axis": "left_to_right" if axis_name == "x" else "front_to_back",
            "scene_axis": scene_axis,
            "expected_order": expected,
            "current_order_before": current_before,
            "violations_before": violations_before,
            "pairwise_violations_before": pairwise_violations_before,
            "gap_violations_before": gap_violations_before,
            "gap_required": bool(gap_required),
            "fixed": False,
        }
        if side_wall_image_tangent_order:
            check["soft_reason"] = "side_wall_image_left_right_is_perspective_tangent_cue"
        if (violations_before or pairwise_violations_before or gap_violations_before) and (not repair or soft_wall_plane_order):
            check.update(
                {
                    "fixed": False,
                    "repair_skipped": True,
                    "repair_skip_reason": "soft_wall_plane_order" if soft_wall_plane_order and repair else None,
                    "current_order_after": current_before,
                    "violations_after": violations_before,
                    "pairwise_violations_after": pairwise_violations_before,
                    "gap_violations_after": gap_violations_before,
                }
            )
            message = f"{group.get('group_id')}: {check['axis']} order violations in final plan"
            if confidence >= SPATIAL_ORDER_HARD_CONFIDENCE and not soft_tabletop_cross_support and not soft_wall_plane_order and not side_wall_image_tangent_order:
                report["warnings"].append(message)
            else:
                report["soft_warnings"].append(message)
        elif violations_before or pairwise_violations_before or gap_violations_before:
            if side_wall_image_tangent_order:
                check.update(
                    {
                        "fixed": False,
                        "repair_skipped": True,
                        "repair_skip_reason": "side_wall_image_left_right_is_perspective_tangent_cue",
                        "current_order_after": current_before,
                        "violations_after": violations_before,
                        "pairwise_violations_after": pairwise_violations_before,
                        "gap_violations_after": gap_violations_before,
                    }
                )
                report["soft_warnings"].append(f"{group.get('group_id')}: {check['axis']} side-wall image order kept soft")
                report["group_checks"].append(check)
                return
            key = "x" if scene_axis == "x" else "y"
            sorted_values = _monotonic_axis_targets([float(objects[object_id].get(key, 0.0)) for object_id in expected])
            moves: list[tuple[str, tuple[float, float, float]]] = []
            for index, object_id in enumerate(expected):
                delta_value = sorted_values[index] - float(objects[object_id].get(key, 0.0))
                if abs(delta_value) <= 1e-5:
                    continue
                delta = (delta_value, 0.0, 0.0) if scene_axis == "x" else (0.0, delta_value, 0.0)
                moves.append((object_id, delta))
            moved_nodes: set[str] = set()
            for object_id, delta in moves:
                for node_id in descendants.get(object_id, [object_id]):
                    if node_id in moved_nodes:
                        continue
                    obj = objects.get(node_id)
                    if not obj:
                        continue
                    obj["x"] = float(obj["x"]) + delta[0]
                    obj["y"] = float(obj["y"]) + delta[1]
                    obj["z"] = float(obj.get("z", 0.0)) + delta[2]
                    moved_nodes.add(node_id)
            _clamp_spatial_order_moved_nodes(objects, sorted(moved_nodes), room)
            current_after = _axis_order(objects, expected, scene_axis)
            violations_after = _adjacent_reference_order_violations(expected, current_after, reference_profile)
            pairwise_violations_after = _pairwise_reference_order_violations(expected, current_after, reference_profile)
            gap_violations_after = (
                _adjacent_axis_gap_violations(expected, objects, scene_axis, profile=reference_profile) if gap_required else []
            )
            extra_moved_roots: list[str] = []
            for _pass in range(2):
                if not violations_after and not pairwise_violations_after and not gap_violations_after:
                    break
                pass_moved: set[str] = set()
                for previous_id, current_id in zip(expected, expected[1:]):
                    previous_value = float(objects[previous_id].get(key, 0.0))
                    current_value = float(objects[current_id].get(key, 0.0))
                    required_value = previous_value + SPATIAL_ORDER_MIN_AXIS_GAP
                    if current_value >= required_value:
                        continue
                    delta_value = required_value - current_value
                    delta = (delta_value, 0.0, 0.0) if scene_axis == "x" else (0.0, delta_value, 0.0)
                    extra_moved_roots.append(current_id)
                    for node_id in descendants.get(current_id, [current_id]):
                        obj = objects.get(node_id)
                        if not obj:
                            continue
                        obj["x"] = float(obj["x"]) + delta[0]
                        obj["y"] = float(obj["y"]) + delta[1]
                        obj["z"] = float(obj.get("z", 0.0)) + delta[2]
                        moved_nodes.add(node_id)
                        pass_moved.add(node_id)
                if pass_moved:
                    _clamp_spatial_order_moved_nodes(objects, sorted(pass_moved), room)
                current_after = _axis_order(objects, expected, scene_axis)
                violations_after = _adjacent_reference_order_violations(expected, current_after, reference_profile)
                pairwise_violations_after = _pairwise_reference_order_violations(expected, current_after, reference_profile)
                gap_violations_after = (
                    _adjacent_axis_gap_violations(expected, objects, scene_axis, profile=reference_profile) if gap_required else []
                )
            check.update(
                {
                    "fixed": True,
                    "current_order_after": current_after,
                    "violations_after": violations_after,
                    "pairwise_violations_after": pairwise_violations_after,
                    "gap_violations_after": gap_violations_after,
                    "moved_roots": [object_id for object_id, _delta in moves],
                    "extra_moved_roots": sorted(set(extra_moved_roots)),
                    "moved_node_count": len(moved_nodes),
                }
            )
            report["fixes"].append(
                f"{group.get('group_id')}: repaired {check['axis']} order; moved {len(moves)} roots"
            )
            if check.get("violations_after") or check.get("pairwise_violations_after") or check.get("gap_violations_after"):
                message = f"{group.get('group_id')}: remaining {check['axis']} order violations"
                if confidence >= SPATIAL_ORDER_HARD_CONFIDENCE and not soft_tabletop_cross_support and not soft_wall_plane_order:
                    report["warnings"].append(message)
                else:
                    report["soft_warnings"].append(message)
        report["group_checks"].append(check)

    for group in groups:
        if not isinstance(group, dict):
            continue
        apply_axis(group, "x", "left_to_right")
        apply_axis(group, "y", "front_to_back")

    report["check_count"] = len(report["group_checks"])
    report["fix_count"] = len(report["fixes"])
    report["ok"] = not report["warnings"]
    return report


def build_reference_alignment_report(
    scene_graph: dict[str, Any],
    plan: dict[str, Any],
    support_tree: dict[str, Any],
    cross_constraints: list[dict[str, Any]],
    parent: dict[str, str],
) -> dict[str, Any]:
    objects = {obj["id"]: obj for obj in plan.get("objects", [])}
    room = plan["room"]
    checks: list[dict[str, Any]] = []
    warnings: list[str] = []

    def add_check(name: str, ok: bool, detail: str, hard: bool = True) -> None:
        checks.append({"name": name, "ok": bool(ok), "detail": detail, "hard": bool(hard)})
        if not ok and hard:
            warnings.append(detail)

    for obj in objects.values():
        if _is_ambient_or_empty_object(obj):
            add_check("no_ambient_objects", False, f"ambient object remained in plan: {obj['id']}")

        if _is_book_storage(obj):
            width, length = _rotated_footprint(obj)
            min_v, max_v = _bbox_for_object(obj)
            x = float(obj["x"])
            y = float(obj["y"])
            room_width = float(room["width"])
            room_length = float(room["length"])
            near_wall = min_v[0] <= 0.18 or min_v[1] <= 0.18 or max_v[0] >= room_width - 0.18 or max_v[1] >= room_length - 0.18
            large_enough = max(width, length) >= min(room_width, room_length) * 0.22
            add_check(
                f"{obj['id']}_large_wall_book_storage",
                near_wall and large_enough,
                f"{obj['id']} footprint=({width:.2f},{length:.2f}), center=({x:.2f},{y:.2f}), near_wall={near_wall}",
            )
            expected_wall_id = _wall_relation_for_object(str(obj.get("id") or ""), cross_constraints, parent)
            if expected_wall_id in VIRTUAL_WALLS:
                wall_status = _wall_relation_status(obj, expected_wall_id, room)
                add_check(
                    f"{obj['id']}_specified_wall_contact",
                    bool(wall_status.get("ok")),
                    (
                        f"{obj['id']} expected_wall={expected_wall_id}, "
                        f"distance={wall_status.get('distance_to_wall')}, yaw_ok={wall_status.get('yaw_ok')}"
                    ),
                )

        support_id = obj.get("support_id")
        if support_id and support_id in objects:
            support = objects[support_id]
            expected_z = _supported_child_surface_z(support, obj)
            z_ok = abs(float(obj.get("z", 0.0)) - expected_z) <= 0.08
            add_check(
                f"{obj['id']}_support_height",
                z_ok,
                f"{obj['id']} z={float(obj.get('z', 0.0)):.2f}, expected_support_z={expected_z:.2f}",
            )

    for wall_id in VIRTUAL_WALLS:
        for child in support_tree.get("children", []):
            if str(child.get("id")) != wall_id:
                continue
            for node in child.get("children", []):
                obj = objects.get(str(node.get("id")))
                if obj:
                    if _is_grounded_wall_against_furniture(obj):
                        wall_status = _wall_relation_status(obj, wall_id, room)
                        add_check(
                            f"{obj['id']}_wall_against",
                            bool(wall_status.get("ok")),
                            (
                                f"{obj['id']} expected_against={wall_id}, support={obj.get('support_id')}, "
                                f"distance={wall_status.get('distance_to_wall')}, yaw_ok={wall_status.get('yaw_ok')}"
                            ),
                        )
                    else:
                        add_check(f"{obj['id']}_wall_attached", str(obj.get("support_id")) == wall_id, f"{obj['id']} support={obj.get('support_id')}")

    for rel in cross_constraints:
        rel_type = str(rel.get("type", ""))
        a = objects.get(str(rel.get("subject")))
        b = objects.get(str(rel.get("object")))
        if not a or not b:
            continue
        if rel_type == "left_of":
            axis, sign = _spatial_relation_axis_sign(rel_type, objects, str(rel.get("subject")), str(rel.get("object")))
            ok = float(a[axis]) * sign > float(b[axis]) * sign
        elif rel_type == "right_of":
            axis, sign = _spatial_relation_axis_sign(rel_type, objects, str(rel.get("subject")), str(rel.get("object")))
            ok = float(a[axis]) * sign > float(b[axis]) * sign
        elif rel_type == "in_front_of":
            ok = float(a["y"]) < float(b["y"])
        elif rel_type == "behind":
            ok = float(a["y"]) > float(b["y"])
        else:
            continue
        try:
            confidence = float(rel.get("confidence", 0.75))
        except (TypeError, ValueError):
            confidence = 0.75
        is_spatial_order_agent_relation = str(rel.get("id", "")).startswith("agent_spatial_order_")
        branch_mode_suppression = _branch_mode_ambiguous_agent_sidewall_relation(scene_graph, rel, objects)
        if branch_mode_suppression:
            add_check(
                rel_type,
                True,
                (
                    f"{rel['subject']} {rel_type} {rel['object']} suppressed by branch mode "
                    f"expected={branch_mode_suppression.get('expected_relation')}"
                ),
                hard=False,
            )
            continue
        suppression = _agent_spatial_relation_suppressed_by_reference(scene_graph, rel)
        if suppression:
            add_check(
                rel_type,
                True,
                (
                    f"{rel['subject']} {rel_type} {rel['object']} suppressed by reference "
                    f"{suppression.get('reference_status')} expected={suppression.get('expected_relation')}"
                ),
                hard=False,
            )
            continue
        view_condition = scene_graph.get("_view_condition_report") if isinstance(scene_graph.get("_view_condition_report"), dict) else {}
        if view_condition.get("branch_relation_mode_enabled") and rel_type in SPATIAL_ORDER_RELATIONS:
            stable_pair = (
                _reference_grounding_global_candidate(a)
                and _reference_grounding_global_candidate(b)
                and not _has_text(a, ("plant", "lamp", "pillow", "cushion"))
                and not _has_text(b, ("plant", "lamp", "pillow", "cushion"))
            )
            hard = bool(stable_pair and confidence >= SPATIAL_ORDER_HARD_CONFIDENCE)
        else:
            hard = not is_spatial_order_agent_relation or confidence >= SPATIAL_ORDER_HARD_CONFIDENCE
        add_check(rel_type, ok, f"{rel['subject']} {rel_type} {rel['object']}", hard=hard)

    consistency = scene_graph.get("_reference_consistency_refiner") if isinstance(scene_graph.get("_reference_consistency_refiner"), dict) else {}
    for branch in consistency.get("side_wall_branches", []) if isinstance(consistency.get("side_wall_branches"), list) else []:
        if not isinstance(branch, dict):
            continue
        branch_ids = [str(object_id) for object_id in branch.get("object_ids", []) if str(object_id) in objects]
        floor_ids = _right_side_branch_floor_layout_ids(objects, branch_ids)
        if len(floor_ids) < 2:
            continue
        layout_mode = str(branch.get("layout_mode") or "")
        if layout_mode in {"same_depth_lateral", "mixed_depth_lateral"}:
            order = _side_wall_lateral_order_for_branch(scene_graph, branch, objects, floor_ids)
            y_values = [float(objects[object_id].get("y", 0.0) or 0.0) for object_id in order if object_id in objects]
            if layout_mode == "same_depth_lateral":
                y_spread = max(y_values) - min(y_values) if y_values else 0.0
                max_spread = 0.42
                add_check(
                    f"{branch.get('group_id') or branch.get('trigger')}_same_depth_lateral_y",
                    y_spread <= max_spread,
                    f"{order} side-wall same-depth y_spread={y_spread:.2f}, max_spread={max_spread:.2f}",
                )
            wall_id = str(branch.get("wall_id") or "")
            x_values = [float(objects[object_id].get("x", 0.0) or 0.0) for object_id in order if object_id in objects]
            if len(x_values) >= 2:
                if wall_id == "wall_east":
                    monotonic_ok = all(a >= b - 0.03 for a, b in zip(x_values, x_values[1:]))
                    direction = "wall-to-room decreasing x"
                else:
                    monotonic_ok = all(a <= b + 0.03 for a, b in zip(x_values, x_values[1:]))
                    direction = "wall-to-room increasing x"
                add_check(
                    f"{branch.get('group_id') or branch.get('trigger')}_{layout_mode}_x_order",
                    monotonic_ok,
                    f"{order} side-wall {layout_mode} order expected {direction}, x_values={[round(v, 3) for v in x_values]}",
                )
            if layout_mode == "mixed_depth_lateral":
                pair_checks = 0
                pair_ok = True
                pair_messages: list[str] = []
                for a_id, b_id in zip(order, order[1:]):
                    a = objects.get(a_id)
                    b = objects.get(b_id)
                    if not a or not b:
                        continue
                    a_bbox = _reference_bbox_from_sources(a)
                    b_bbox = _reference_bbox_from_sources(b)
                    if not a_bbox or not b_bbox:
                        continue
                    bottom_delta = float(a_bbox[3]) - float(b_bbox[3])
                    if abs(bottom_delta) < 0.055:
                        continue
                    pair_checks += 1
                    a_y = float(a.get("y", 0.0) or 0.0)
                    b_y = float(b.get("y", 0.0) or 0.0)
                    # Larger image bottom means visually closer/front; in room coordinates that is smaller y.
                    ok_pair = (a_y <= b_y + 0.08) if bottom_delta > 0.0 else (a_y >= b_y - 0.08)
                    pair_ok = pair_ok and ok_pair
                    pair_messages.append(
                        f"{a_id}->{b_id}: ref_bottom_delta={bottom_delta:.3f}, y=({a_y:.2f},{b_y:.2f}), ok={ok_pair}"
                    )
                if pair_checks:
                    add_check(
                        f"{branch.get('group_id') or branch.get('trigger')}_mixed_depth_lateral_y_profile",
                        pair_ok,
                        "; ".join(pair_messages[:4]),
                    )
            continue
        order = _front_to_back_order_for_branch(scene_graph, objects, floor_ids)
        for front_id, back_id in zip(order, order[1:]):
            front = objects.get(front_id)
            back = objects.get(back_id)
            if not front or not back:
                continue
            _front_min, front_max = _bbox_for_object(front)
            back_min, _back_max = _bbox_for_object(back)
            gap = float(back_min[1]) - float(front_max[1])
            max_gap = 0.38
            add_check(
                f"{branch.get('group_id') or branch.get('trigger')}_cluster_gap",
                gap <= max_gap,
                f"{front_id}->{back_id} side-wall cluster y_gap={gap:.2f}, max_gap={max_gap:.2f}",
            )

    return {
        "object_count": len(objects),
        "reference_object_count": len(scene_graph.get("objects", [])),
        "checks": checks,
        "warnings": warnings,
        "ok": not warnings,
        "parent_map": parent,
    }


def _flow2_mujoco_point(x: float, y: float, z: float = 0.0) -> dict[str, float]:
    return {"x": round(float(x), 6), "y": round(float(y), 6), "z": round(float(z), 6)}


def _flow2_plan_to_mujoco_room(plan: dict[str, Any], parent: dict[str, str]) -> dict[str, Any]:
    room = plan["room"]
    room_id = "room_tree_sage_flow2"
    width = float(room["width"])
    length = float(room["length"])
    height = float(room.get("height", room.get("ceiling_height", 2.7)))
    walls = [
        {"id": f"wall_{room_id}_north", "start_point": _flow2_mujoco_point(0, length), "end_point": _flow2_mujoco_point(width, length), "height": height, "thickness": 0.1, "material": "flow2_wall"},
        {"id": f"wall_{room_id}_south", "start_point": _flow2_mujoco_point(0, 0), "end_point": _flow2_mujoco_point(width, 0), "height": height, "thickness": 0.1, "material": "flow2_wall"},
        {"id": f"wall_{room_id}_east", "start_point": _flow2_mujoco_point(width, 0), "end_point": _flow2_mujoco_point(width, length), "height": height, "thickness": 0.1, "material": "flow2_wall"},
        {"id": f"wall_{room_id}_west", "start_point": _flow2_mujoco_point(0, 0), "end_point": _flow2_mujoco_point(0, length), "height": height, "thickness": 0.1, "material": "flow2_wall"},
    ]
    objects: list[dict[str, Any]] = []
    for obj in plan.get("objects", []):
        dims = obj.get("dimensions") if isinstance(obj.get("dimensions"), dict) else {}
        obj_width = max(float(dims.get("width", 0.05) or 0.05), 0.01)
        obj_length = max(float(dims.get("length", 0.05) or 0.05), 0.01)
        obj_height = max(float(dims.get("height", 0.05) or 0.05), 0.01)
        support_id = str(obj.get("support_id") or parent.get(str(obj.get("id")), "floor"))
        placement_type = str(obj.get("placement_type", "floor"))
        if placement_type == "attached_to_wall" or _is_wall_attached_object(obj) or _is_hanging_object(obj):
            place_id = "wall"
        elif support_id and support_id not in {"", "None"} | VIRTUAL_WALLS:
            place_id = support_id
        else:
            place_id = "floor"
        volume = obj_width * obj_length * obj_height
        objects.append(
            {
                "id": str(obj["id"]),
                "room_id": room_id,
                "type": str(obj.get("category", "object")),
                "description": str(obj.get("description", obj.get("category", ""))),
                "position": _flow2_mujoco_point(float(obj.get("x", 0.0)), float(obj.get("y", 0.0)), float(obj.get("z", 0.0))),
                "rotation": {"x": 0.0, "y": 0.0, "z": round(float(_footprint_yaw(obj)), 6)},
                "dimensions": {"width": obj_width, "length": obj_length, "height": obj_height},
                "place_id": place_id,
                "placement_constraints": [],
                "mass": max(float(obj.get("mass", volume * 80.0) or volume * 80.0), 0.05),
            }
        )
    return {
        "id": room_id,
        "room_type": str(plan.get("room_type", "tree_sage_flow2_room")),
        "position": _flow2_mujoco_point(0, 0, 0),
        "dimensions": {"width": width, "length": length, "height": height},
        "walls": walls,
        "doors": [],
        "windows": [],
        "objects": objects,
        "floor_material": "flow2_floor",
        "ceiling_height": height,
    }


def _flow2_soft_visual_mujoco_exempt_ids(plan: dict[str, Any], parent: dict[str, str]) -> set[str]:
    objects = {str(obj.get("id")): obj for obj in plan.get("objects", []) if isinstance(obj, dict) and obj.get("id")}
    exempt: set[str] = set()
    for object_id, obj in objects.items():
        if not _has_text(obj, ("pillow", "cushion", "blanket", "duvet", "comforter", "quilt")):
            continue
        support_id = str(obj.get("support_id") or parent.get(object_id) or "")
        support = objects.get(support_id)
        if support and _is_bed_or_sofa_object(support):
            exempt.add(object_id)
    return exempt


def _parse_flow2_mujoco_stdout(stdout: str) -> dict[str, Any] | None:
    for line in reversed(stdout.splitlines()):
        line = line.strip()
        if not line:
            continue
        try:
            parsed = json.loads(line)
        except Exception:
            continue
        if isinstance(parsed, dict):
            return parsed
    return None


def run_flow2_mujoco_check(
    plan: dict[str, Any],
    output_dir: Path,
    parent: dict[str, str],
    python_bin: str = DEFAULT_MUJOCO_PY,
    max_displacement: float = FLOW2_MUJOCO_MAX_DISPLACEMENT,
) -> dict[str, Any]:
    room = _flow2_plan_to_mujoco_room(plan, parent)
    room_path = output_dir / "mujoco_room.json"
    write_json(room_path, room)
    code = f"""
import json
from isaacsim.isaac_mcp.server import create_single_room_layout_scene_from_room, simulate_the_scene
create_result = create_single_room_layout_scene_from_room({str(output_dir)!r}, {str(room_path)!r})
simulate_result = simulate_the_scene()
print(json.dumps({{"create": create_result, "simulate": simulate_result}}, default=str))
"""
    env = os.environ.copy()
    env["SAGE_SIM_BACKEND"] = "mujoco"
    default_server_path = Path(__file__).resolve().parents[1] / "server"
    server_pythonpath = os.environ.get("SAGE_SERVER_PYTHONPATH", str(default_server_path))
    existing_pythonpath = env.get("PYTHONPATH", "")
    env["PYTHONPATH"] = (
        server_pythonpath
        if not existing_pythonpath
        else os.pathsep.join([server_pythonpath, existing_pythonpath])
    )
    try:
        proc = subprocess.run(
            [python_bin, "-c", code],
            env=env,
            text=True,
            stdout=subprocess.PIPE,
            stderr=subprocess.PIPE,
            check=False,
            timeout=float(os.environ.get("SAGE_FLOW2_MUJOCO_TIMEOUT", "180")),
        )
    except Exception as exc:
        return {
            "schema": "tree_sage_flow2_mujoco_check_v1",
            "enabled": True,
            "proxy_model": "axis_aligned_box_room",
            "python": python_bin,
            "room_path": str(room_path),
            "ok": False,
            "error": f"{type(exc).__name__}: {exc}",
        }
    parsed = _parse_flow2_mujoco_stdout(proc.stdout) or {}
    simulate = parsed.get("simulate") if isinstance(parsed.get("simulate"), dict) else {}
    mujoco_reports = simulate.get("mujoco_reports", []) if isinstance(simulate, dict) else []
    exempt_ids = _flow2_soft_visual_mujoco_exempt_ids(plan, parent)
    max_disp_raw = 0.0
    max_disp_filtered = 0.0
    if isinstance(mujoco_reports, list):
        for item in mujoco_reports:
            if isinstance(item, dict):
                max_disp_raw = max(max_disp_raw, float(item.get("max_displacement", 0.0) or 0.0))
                top_displacements = item.get("top_displacements") if isinstance(item.get("top_displacements"), list) else []
                for entry in top_displacements:
                    if not isinstance(entry, dict):
                        continue
                    if str(entry.get("body") or "") in exempt_ids:
                        continue
                    max_disp_filtered = max(max_disp_filtered, float(entry.get("displacement", 0.0) or 0.0))
    unstable_objects_raw = simulate.get("unstable_objects", []) if isinstance(simulate, dict) else []
    unstable_objects = [str(object_id) for object_id in unstable_objects_raw if str(object_id) not in exempt_ids]
    simulate_ok = str(simulate.get("status", "")).lower() == "success" if isinstance(simulate, dict) else False
    displacement_warning = max_disp_filtered > float(max_displacement)
    ok = proc.returncode == 0 and simulate_ok and not unstable_objects
    return {
        "schema": "tree_sage_flow2_mujoco_check_v1",
        "enabled": True,
        "proxy_model": "axis_aligned_box_room",
        "python": python_bin,
        "room_path": str(room_path),
        "returncode": int(proc.returncode),
        "max_displacement": round(float(max_disp_filtered), 6),
        "raw_max_displacement": round(float(max_disp_raw), 6),
        "max_displacement_threshold": float(max_displacement),
        "displacement_warning": bool(displacement_warning),
        "unstable_objects": unstable_objects,
        "raw_unstable_objects": unstable_objects_raw,
        "soft_visual_exemptions": sorted(exempt_ids),
        "create": parsed.get("create"),
        "simulate": simulate,
        "stdout_tail": proc.stdout.splitlines()[-20:],
        "stderr_tail": proc.stderr.splitlines()[-20:],
        "ok": bool(ok),
    }


def _layout_validation_score(
    aggregate_collision_report: dict[str, Any],
    reference_alignment_report: dict[str, Any],
    scene_hypergraph_validation_report: dict[str, Any] | None = None,
    branch_audit_report: dict[str, Any] | None = None,
) -> float:
    aggregate_conflicts = int(aggregate_collision_report.get("conflict_count", 0) or 0)
    reference_warnings = len(reference_alignment_report.get("warnings", []))
    hypergraph_warnings = 0
    hypergraph_soft_warnings = 0
    hard_pair_violations = 0
    hard_pair_residual = 0.0
    soft_pair_violations = 0
    if isinstance(scene_hypergraph_validation_report, dict) and scene_hypergraph_validation_report.get("enabled"):
        hypergraph_warnings = len(scene_hypergraph_validation_report.get("warnings", []))
        hypergraph_soft_warnings = len(scene_hypergraph_validation_report.get("soft_warnings", []))
        for check in scene_hypergraph_validation_report.get("factor_checks", []) if isinstance(scene_hypergraph_validation_report.get("factor_checks"), list) else []:
            if not isinstance(check, dict):
                continue
            if check.get("factor_type") not in {"reference_axis_gap_affinity", "reference_cluster_anchor_affinity"}:
                for violation in check.get("violations", []) if isinstance(check.get("violations"), list) else []:
                    if not isinstance(violation, dict):
                        continue
                    hard_pair_violations += 1
                    hard_pair_residual += _axis_pair_violation_residual(violation)
            for violation in check.get("soft_violations", []) if isinstance(check.get("soft_violations"), list) else []:
                if isinstance(violation, dict):
                    soft_pair_violations += 1
            for violation in check.get("same_axis_violations", []) if isinstance(check.get("same_axis_violations"), list) else []:
                if isinstance(violation, dict):
                    hard_pair_violations += 1
                    hard_pair_residual += _axis_pair_violation_residual(
                        {
                            "scene_gap": violation.get("scene_gap"),
                            "required_gap_or_threshold": violation.get("scene_threshold"),
                            "relation": violation.get("relation"),
                        }
                    )
            if check.get("factor_type") == "reference_axis_gap_affinity":
                for violation in check.get("violations", []) if isinstance(check.get("violations"), list) else []:
                    if isinstance(violation, dict):
                        hard_pair_violations += 1
                        hard_pair_residual += _gap_affinity_violation_residual(violation)
                for violation in check.get("soft_violations", []) if isinstance(check.get("soft_violations"), list) else []:
                    if isinstance(violation, dict):
                        soft_pair_violations += 1
            if check.get("factor_type") == "reference_cluster_anchor_affinity":
                for violation in check.get("violations", []) if isinstance(check.get("violations"), list) else []:
                    if isinstance(violation, dict):
                        hard_pair_violations += 1
                        hard_pair_residual += _cluster_anchor_violation_residual(violation)
    branch_failed_count = 0
    branch_conflict_count = 0
    if isinstance(branch_audit_report, dict) and branch_audit_report.get("enabled"):
        branch_failed_count = int(branch_audit_report.get("failed_branch_count", 0) or 0)
        for branch_result in branch_audit_report.get("branch_results", []) if isinstance(branch_audit_report.get("branch_results"), list) else []:
            if not isinstance(branch_result, dict):
                continue
            validation = branch_result.get("validation") if isinstance(branch_result.get("validation"), dict) else {}
            branch_conflict_count += int(validation.get("conflict_count", 0) or 0)
    return float(
        aggregate_conflicts * 100
        + branch_failed_count * 80
        + branch_conflict_count * 30
        + reference_warnings * 10
        + hypergraph_warnings * 20
        + hard_pair_violations * 8
        + hard_pair_residual * 12
        + hypergraph_soft_warnings * 2
        + soft_pair_violations * 0.5
    )


def _layout_state_after_changes(
    plan: dict[str, Any],
    scene_graph: dict[str, Any],
    support_tree: dict[str, Any],
    parent: dict[str, str],
    relation_to_parent: dict[str, str],
    cross_constraints: list[dict[str, Any]],
    asset_registry: dict[str, Any] | None,
    margin: float,
    branch_candidate_k: int,
    branch_execution_plan: dict[str, Any] | None = None,
) -> dict[str, Any]:
    support_surface_registry = build_support_surface_registry(plan, asset_registry)
    branch_summaries = build_branch_summaries(plan, support_tree, parent, relation_to_parent)
    reference_alignment_report = build_reference_alignment_report(scene_graph, plan, support_tree, cross_constraints, parent)
    branch_candidates = build_branch_candidates(
        plan,
        support_tree,
        parent,
        relation_to_parent,
        cross_constraints,
        support_surface_registry,
        k=branch_candidate_k,
    )
    aggregate_collision_report = build_aggregate_collision_report(
        plan,
        support_tree,
        parent,
        relation_to_parent,
        support_surface_registry,
        margin=margin,
    )
    scene_hypergraph = build_scene_hypergraph(
        plan,
        support_tree,
        parent,
        relation_to_parent,
        cross_constraints,
        scene_graph=scene_graph,
    )
    scene_hypergraph_validation_report = validate_scene_hypergraph_constraints(plan, scene_hypergraph, parent)
    branch_audit_report: dict[str, Any] = {"enabled": False, "reason": "no_branch_execution_plan", "ok": True}
    if isinstance(branch_execution_plan, dict) and branch_execution_plan.get("branches"):
        branch_audit_report = audit_incremental_branch_execution(
            plan,
            support_tree,
            parent,
            relation_to_parent,
            cross_constraints,
            support_surface_registry,
            branch_execution_plan,
            margin=margin,
        )
    return {
        "support_surface_registry": support_surface_registry,
        "branch_summaries": branch_summaries,
        "reference_alignment_report": reference_alignment_report,
        "branch_candidates": branch_candidates,
        "aggregate_collision_report": aggregate_collision_report,
        "scene_hypergraph": scene_hypergraph,
        "scene_hypergraph_validation_report": scene_hypergraph_validation_report,
        "branch_audit_report": branch_audit_report,
        "score": _layout_validation_score(
            aggregate_collision_report,
            reference_alignment_report,
            scene_hypergraph_validation_report,
            branch_audit_report,
        ),
    }


def run_joint_order_collision_repair(
    plan: dict[str, Any],
    scene_graph: dict[str, Any],
    support_tree: dict[str, Any],
    parent: dict[str, str],
    relation_to_parent: dict[str, str],
    cross_constraints: list[dict[str, Any]],
    asset_registry: dict[str, Any] | None,
    aggregate_collision_report: dict[str, Any],
    reference_alignment_report: dict[str, Any],
    margin: float,
    branch_candidate_k: int,
    branch_execution_plan: dict[str, Any] | None = None,
    max_iterations: int = 3,
) -> dict[str, Any]:
    base_scene_hypergraph = build_scene_hypergraph(
        plan,
        support_tree,
        parent,
        relation_to_parent,
        cross_constraints,
        scene_graph=scene_graph,
    )
    base_scene_hypergraph_validation_report = validate_scene_hypergraph_constraints(plan, base_scene_hypergraph, parent)
    base_branch_audit_report: dict[str, Any] = {"enabled": False, "reason": "no_branch_execution_plan", "ok": True}
    if isinstance(branch_execution_plan, dict) and branch_execution_plan.get("branches"):
        base_branch_audit_report = audit_incremental_branch_execution(
            plan,
            support_tree,
            parent,
            relation_to_parent,
            cross_constraints,
            build_support_surface_registry(plan, asset_registry),
            branch_execution_plan,
            margin=margin,
        )
    base_score = _layout_validation_score(
        aggregate_collision_report,
        reference_alignment_report,
        base_scene_hypergraph_validation_report,
        base_branch_audit_report,
    )
    report: dict[str, Any] = {
        "schema": "tree_sage_joint_order_collision_repair_v1",
        "enabled": True,
        "strategy": "alternate reference order, scene-hypergraph spatial, and relation-aware collision repair; accept only non-colliding lower-score layouts",
        "base_score": base_score,
        "base_conflict_count": int(aggregate_collision_report.get("conflict_count", 0) or 0),
        "base_reference_warning_count": len(reference_alignment_report.get("warnings", [])),
        "base_hypergraph_warning_count": len(base_scene_hypergraph_validation_report.get("warnings", [])),
        "base_branch_failed_count": int(base_branch_audit_report.get("failed_branch_count", 0) or 0),
        "attempts": [],
        "scene_hypergraph_repair_passes": [],
        "accepted": False,
        "accepted_iteration": None,
        "ok": (
            bool(aggregate_collision_report.get("ok"))
            and bool(reference_alignment_report.get("ok"))
            and bool(base_scene_hypergraph_validation_report.get("ok"))
            and bool(base_branch_audit_report.get("ok"))
        ),
    }
    base_score = float(base_score)
    best_score = base_score
    best_plan: dict[str, Any] | None = None
    best_state: dict[str, Any] | None = None
    best_attempt: dict[str, Any] | None = None
    candidate_plan = deepcopy(plan)

    for iteration in range(max(0, int(max_iterations))):
        order_report = audit_and_repair_reference_spatial_order(candidate_plan, scene_graph, support_tree, parent, cross_constraints)
        relation_report = repair_spatial_relation_constraints(candidate_plan, cross_constraints, support_tree, parent, scene_graph=scene_graph)
        post_relation_order_report = audit_and_repair_reference_spatial_order(
            candidate_plan,
            scene_graph,
            support_tree,
            parent,
            cross_constraints,
        )
        scene_hypergraph = build_scene_hypergraph(
            candidate_plan,
            support_tree,
            parent,
            relation_to_parent,
            cross_constraints,
            scene_graph=scene_graph,
        )
        hypergraph_repair_report = repair_scene_hypergraph_spatial_constraints(
            candidate_plan,
            scene_hypergraph,
            support_tree,
            parent,
        )
        if hypergraph_repair_report.get("fixes"):
            relation_report = merge_spatial_relation_repair_report(
                relation_report,
                repair_spatial_relation_constraints(candidate_plan, cross_constraints, support_tree, parent, scene_graph=scene_graph),
                "post_hypergraph_repair",
            )
            post_relation_order_report = audit_and_repair_reference_spatial_order(
                candidate_plan,
                scene_graph,
                support_tree,
                parent,
                cross_constraints,
            )
        state = _layout_state_after_changes(
            candidate_plan,
            scene_graph,
            support_tree,
            parent,
            relation_to_parent,
            cross_constraints,
            asset_registry,
            margin,
            branch_candidate_k,
            branch_execution_plan=branch_execution_plan,
        )
        collision_repair_report: dict[str, Any] = {"enabled": False, "reason": "aggregate_already_ok", "ok": True}
        if not state["aggregate_collision_report"].get("ok"):
            collision_repair_report = run_repair_agent(
                candidate_plan,
                support_tree,
                parent,
                relation_to_parent,
                state["support_surface_registry"],
                state["aggregate_collision_report"],
                max_iterations=2,
                cross_constraints=cross_constraints,
                scene_graph=scene_graph,
                margin=margin,
            )
            state = _layout_state_after_changes(
                candidate_plan,
                scene_graph,
                support_tree,
                parent,
                relation_to_parent,
                cross_constraints,
                asset_registry,
                margin,
                branch_candidate_k,
                branch_execution_plan=branch_execution_plan,
            )
            order_report = audit_and_repair_reference_spatial_order(
                candidate_plan,
                scene_graph,
                support_tree,
                parent,
                cross_constraints,
            )
            relation_report = repair_spatial_relation_constraints(candidate_plan, cross_constraints, support_tree, parent, scene_graph=scene_graph)
            scene_hypergraph = build_scene_hypergraph(
                candidate_plan,
                support_tree,
                parent,
                relation_to_parent,
                cross_constraints,
                scene_graph=scene_graph,
            )
            post_collision_hypergraph_repair_report = repair_scene_hypergraph_spatial_constraints(
                candidate_plan,
                scene_hypergraph,
                support_tree,
                parent,
            )
            if post_collision_hypergraph_repair_report.get("fixes"):
                hypergraph_repair_report = merge_scene_hypergraph_repair_report(
                    hypergraph_repair_report,
                    post_collision_hypergraph_repair_report,
                    "post_collision_repair",
                )
            _clamp_layout_objects_to_room(candidate_plan, cross_constraints, parent)
            state = _layout_state_after_changes(
                candidate_plan,
                scene_graph,
                support_tree,
                parent,
                relation_to_parent,
                cross_constraints,
                asset_registry,
                margin,
                branch_candidate_k,
                branch_execution_plan=branch_execution_plan,
            )
        same_wall_report: dict[str, Any] = {"enabled": False, "reason": "not_needed", "ok": True, "fix_count": 0}
        if not state["aggregate_collision_report"].get("ok"):
            same_wall_report = repair_same_wall_floor_branch_collisions(
                candidate_plan,
                support_tree,
                parent,
                relation_to_parent,
                cross_constraints,
                state["support_surface_registry"],
                margin=margin,
            )
            state = _layout_state_after_changes(
                candidate_plan,
                scene_graph,
                support_tree,
                parent,
                relation_to_parent,
                cross_constraints,
                asset_registry,
                margin,
                branch_candidate_k,
                branch_execution_plan=branch_execution_plan,
            )
        attempt = {
            "iteration": iteration + 1,
            "spatial_order_fix_count": int(order_report.get("fix_count", 0)) + int(post_relation_order_report.get("fix_count", 0)),
            "spatial_order_ok": bool(order_report.get("ok")) and bool(post_relation_order_report.get("ok")),
            "spatial_relation_fix_count": int(relation_report.get("fix_count", 0)),
            "spatial_relation_ok": bool(relation_report.get("ok")),
            "scene_hypergraph_repair_fix_count": int(hypergraph_repair_report.get("fix_count", 0) or 0),
            "scene_hypergraph_repair_ok": bool(state["scene_hypergraph_validation_report"].get("ok")),
            "collision_repair_action_count": len(collision_repair_report.get("actions", [])),
            "collision_repair_ok": bool(state["aggregate_collision_report"].get("ok")),
            "same_wall_fix_count": int(same_wall_report.get("fix_count", 0) or 0),
            "aggregate_conflict_count": int(state["aggregate_collision_report"].get("conflict_count", 0) or 0),
            "reference_warning_count": len(state["reference_alignment_report"].get("warnings", [])),
            "scene_hypergraph_warning_count": len(state["scene_hypergraph_validation_report"].get("warnings", [])),
            "branch_failed_count": int(state.get("branch_audit_report", {}).get("failed_branch_count", 0) or 0),
            "score": float(state["score"]),
            "accepted_candidate": False,
        }
        report["scene_hypergraph_repair_passes"].append(
            {
                "iteration": iteration + 1,
                "fix_count": int(hypergraph_repair_report.get("fix_count", 0) or 0),
                "before_warning_count": int(hypergraph_repair_report.get("before_warning_count", 0) or 0),
                "after_warning_count": int(hypergraph_repair_report.get("after_warning_count", 0) or 0),
                "final_warning_count": len(state["scene_hypergraph_validation_report"].get("warnings", [])),
                "final_ok": bool(state["scene_hypergraph_validation_report"].get("ok")),
                "remaining_violation_count": len(hypergraph_repair_report.get("remaining_violations", [])),
                "fixes": hypergraph_repair_report.get("fixes", [])[:40],
            }
        )
        report["attempts"].append(attempt)
        branch_ok = bool(state.get("branch_audit_report", {}).get("ok", True))
        if state["aggregate_collision_report"].get("ok") and branch_ok and float(state["score"]) < best_score:
            best_score = float(state["score"])
            best_plan = deepcopy(candidate_plan)
            best_state = state
            best_attempt = attempt
            attempt["accepted_candidate"] = True
        if (
            state["aggregate_collision_report"].get("ok")
            and state["reference_alignment_report"].get("ok")
            and state["scene_hypergraph_validation_report"].get("ok")
            and branch_ok
        ):
            break
        if (
            int(order_report.get("fix_count", 0)) == 0
            and int(post_relation_order_report.get("fix_count", 0)) == 0
            and int(relation_report.get("fix_count", 0)) == 0
            and int(hypergraph_repair_report.get("fix_count", 0) or 0) == 0
            and len(collision_repair_report.get("actions", [])) == 0
            and int(same_wall_report.get("fix_count", 0) or 0) == 0
        ):
            break

    if best_plan is not None and best_state is not None:
        _set_plan_objects_from_map(best_plan, _copy_object_map(best_plan))
        plan["objects"] = best_plan.get("objects", plan.get("objects", []))
        report["accepted"] = True
        report["accepted_iteration"] = best_attempt.get("iteration") if best_attempt else None
        report["accepted_score"] = best_score
        report["accepted_conflict_count"] = int(best_state["aggregate_collision_report"].get("conflict_count", 0) or 0)
        report["accepted_reference_warning_count"] = len(best_state["reference_alignment_report"].get("warnings", []))
        report["accepted_hypergraph_warning_count"] = len(best_state["scene_hypergraph_validation_report"].get("warnings", []))
        report["accepted_branch_failed_count"] = int(best_state["branch_audit_report"].get("failed_branch_count", 0) or 0)
        report["ok"] = (
            bool(best_state["aggregate_collision_report"].get("ok"))
            and bool(best_state["reference_alignment_report"].get("ok"))
            and bool(best_state["scene_hypergraph_validation_report"].get("ok"))
            and bool(best_state["branch_audit_report"].get("ok"))
        )
    else:
        report["accepted_score"] = base_score
        report["accepted_conflict_count"] = int(aggregate_collision_report.get("conflict_count", 0) or 0)
        report["accepted_reference_warning_count"] = len(reference_alignment_report.get("warnings", []))
        report["accepted_hypergraph_warning_count"] = len(base_scene_hypergraph_validation_report.get("warnings", []))
        report["accepted_branch_failed_count"] = int(base_branch_audit_report.get("failed_branch_count", 0) or 0)
    return report


def merge_reference_consistency_layout_report(
    aggregate: dict[str, Any],
    pass_report: dict[str, Any],
) -> dict[str, Any]:
    aggregate.setdefault("schema", "tree_sage_reference_consistency_layout_refiner_v1")
    aggregate.setdefault("enabled", bool(pass_report.get("enabled")))
    aggregate.setdefault("passes", [])
    aggregate.setdefault("fixes", [])
    aggregate.setdefault("warnings", [])
    aggregate["passes"].append(pass_report)
    aggregate["fixes"].extend(pass_report.get("fixes", []))
    aggregate["warnings"].extend(pass_report.get("warnings", []))
    aggregate["fix_count"] = len(aggregate.get("fixes", []))
    aggregate["ok"] = bool(aggregate.get("ok", True)) and bool(pass_report.get("ok", True))
    return aggregate


def _relation_front_to_back_edges(
    scene_graph: dict[str, Any],
    candidate_ids: set[str],
) -> list[tuple[str, str, str]]:
    edges: list[tuple[str, str, str]] = []
    for rel in scene_graph.get("relations", []) if isinstance(scene_graph.get("relations"), list) else []:
        if not isinstance(rel, dict):
            continue
        subject = str(rel.get("subject") or "")
        target = str(rel.get("object") or "")
        if subject not in candidate_ids or target not in candidate_ids:
            continue
        rel_type = str(rel.get("type") or "")
        if rel_type == "in_front_of":
            edges.append((subject, target, str(rel.get("evidence") or "")))
        elif rel_type == "behind":
            edges.append((target, subject, str(rel.get("evidence") or "")))
    return edges


def _front_to_back_order_for_branch(
    scene_graph: dict[str, Any],
    plan_objects: dict[str, dict[str, Any]],
    candidate_ids: list[str],
) -> list[str]:
    candidate_set = set(candidate_ids)
    edges = _relation_front_to_back_edges(scene_graph, candidate_set)
    reference_depths = _reference_depths_by_object(scene_graph)
    outgoing: dict[str, set[str]] = {object_id: set() for object_id in candidate_ids}
    incoming_count: dict[str, int] = {object_id: 0 for object_id in candidate_ids}
    for front_id, back_id, _evidence in edges:
        if back_id not in outgoing.get(front_id, set()):
            outgoing.setdefault(front_id, set()).add(back_id)
            incoming_count[back_id] = incoming_count.get(back_id, 0) + 1

    def fallback_key(object_id: str) -> tuple[float, float]:
        obj = plan_objects.get(object_id, {})
        depth = _reference_depth_for_profile(reference_depths, object_id)
        if depth:
            cx = _reference_bbox_center_x(obj)
            return (-float(depth["frontness"]), cx if cx is not None else 0.0)
        bottom = _reference_bbox_bottom(obj)
        cx = _reference_bbox_center_x(obj)
        return (-(bottom if bottom is not None else 0.0), cx if cx is not None else 0.0)

    ready = sorted([object_id for object_id in candidate_ids if incoming_count.get(object_id, 0) == 0], key=fallback_key)
    ordered: list[str] = []
    while ready:
        object_id = ready.pop(0)
        if object_id in ordered:
            continue
        ordered.append(object_id)
        for next_id in sorted(outgoing.get(object_id, set()), key=fallback_key):
            incoming_count[next_id] = incoming_count.get(next_id, 0) - 1
            if incoming_count[next_id] <= 0:
                ready.append(next_id)
        ready.sort(key=fallback_key)
    for object_id in sorted(candidate_ids, key=fallback_key):
        if object_id not in ordered:
            ordered.append(object_id)
    return ordered


def _reference_group_for_side_wall_branch(scene_graph: dict[str, Any], branch: dict[str, Any]) -> dict[str, Any] | None:
    groups = scene_graph.get("_reference_spatial_order_groups") if isinstance(scene_graph.get("_reference_spatial_order_groups"), list) else []
    group_id = str(branch.get("group_id") or "")
    if group_id:
        for group in groups:
            if isinstance(group, dict) and str(group.get("group_id") or "") == group_id:
                return group
    branch_ids = {str(object_id) for object_id in branch.get("object_ids", [])}
    best: tuple[int, dict[str, Any]] | None = None
    for group in groups:
        if not isinstance(group, dict):
            continue
        group_ids = {str(object_id) for object_id in group.get("objects", []) if str(object_id)}
        score = len(branch_ids & group_ids)
        if score and (best is None or score > best[0]):
            best = (score, group)
    return best[1] if best else None


def _side_wall_lateral_order_for_branch(
    scene_graph: dict[str, Any],
    branch: dict[str, Any],
    plan_objects: dict[str, dict[str, Any]],
    floor_ids: list[str],
) -> list[str]:
    group = _reference_group_for_side_wall_branch(scene_graph, branch)
    order: list[str] = []
    floor_set = set(floor_ids)
    for object_id in branch.get("lateral_order", []) if isinstance(branch.get("lateral_order"), list) else []:
        object_id = str(object_id)
        if object_id in floor_set and object_id not in order:
            order.append(object_id)
    if group:
        for object_id in group.get("left_to_right", []) if isinstance(group.get("left_to_right"), list) else []:
            object_id = str(object_id)
            if object_id in floor_set and object_id not in order:
                order.append(object_id)

    def fallback_key(object_id: str) -> tuple[float, float]:
        obj = plan_objects.get(object_id, {})
        cx = _reference_bbox_center_x(obj)
        y = float(obj.get("y", 0.0) or 0.0)
        return (cx if cx is not None else float(obj.get("x", 0.0) or 0.0), y)

    for object_id in sorted(floor_ids, key=fallback_key):
        if object_id not in order:
            order.append(object_id)
    return order


def _side_wall_same_depth_target_y(
    branch: dict[str, Any],
    plan_objects: dict[str, dict[str, Any]],
    order: list[str],
    room: dict[str, Any],
) -> float:
    anchor_id = str(branch.get("anchor_id") or "")
    group_anchor = branch.get("group_anchor_id")
    if group_anchor:
        anchor_id = str(group_anchor)
    if not anchor_id:
        group_id = str(branch.get("group_id") or "")
        # Local-branch ids are often named after the visual anchor; use the table/storage member if present.
        for object_id in order:
            obj = plan_objects.get(object_id, {})
            if _is_table_anchor_object(obj):
                anchor_id = object_id
                break
    if anchor_id in plan_objects and anchor_id in order:
        return _clamp(
            float(plan_objects[anchor_id].get("y", 0.0) or 0.0),
            0.2,
            float(room.get("length", 0.0) or 0.0) - 0.2,
        )
    values = [float(plan_objects[object_id].get("y", 0.0) or 0.0) for object_id in order if object_id in plan_objects]
    median = _median(values)
    return _clamp(float(median if median is not None else float(room.get("length", 0.0) or 0.0) * 0.5), 0.2, float(room.get("length", 0.0) or 0.0) - 0.2)


def _side_wall_same_depth_target_y_before_adjacent_large_anchor(
    scene_graph: dict[str, Any],
    plan_objects: dict[str, dict[str, Any]],
    order: list[str],
    target_y: float,
) -> float:
    order_set = set(order)
    groups = scene_graph.get("_reference_spatial_order_groups") if isinstance(scene_graph.get("_reference_spatial_order_groups"), list) else []
    best_limit: float | None = None
    for group in groups:
        if not isinstance(group, dict) or str(group.get("scope") or "") != "global_anchor":
            continue
        global_order = [str(object_id) for object_id in group.get("left_to_right", []) if str(object_id) in plan_objects]
        positions = [index for index, object_id in enumerate(global_order) if object_id in order_set]
        if not positions:
            continue
        for object_id in global_order[max(positions) + 1 :]:
            obj = plan_objects.get(object_id)
            if not obj:
                continue
            if _is_floor_covering(obj) or _is_hanging_object(obj):
                continue
            if not _is_bed_or_sofa_object(obj):
                break
            bed_min, _bed_max = _bbox_for_object(obj)
            member_lengths = [
                _rotated_footprint(plan_objects[member_id])[1]
                for member_id in order
                if member_id in plan_objects
            ]
            max_member_length = max(member_lengths) if member_lengths else 0.0
            limit = float(bed_min[1]) - max_member_length / 2.0 - 0.08
            best_limit = limit if best_limit is None else min(best_limit, limit)
            break
    if best_limit is None:
        return target_y
    return min(float(target_y), float(best_limit))


def _side_wall_same_depth_target_y_avoid_bed_overlap(
    plan_objects: dict[str, dict[str, Any]],
    order: list[str],
    target_y: float,
    room: dict[str, Any],
) -> float:
    if not order:
        return float(target_y)
    room_length = float(room.get("length", 0.0) or 0.0)
    if room_length <= 0.0:
        return float(target_y)
    member_lengths = [
        _rotated_footprint(plan_objects[object_id])[1]
        for object_id in order
        if object_id in plan_objects
    ]
    if not member_lengths:
        return float(target_y)
    half_extent = max(member_lengths) / 2.0
    margin = FLOOR_WALL_AGAINST_GAP
    clearance = 0.10
    min_target = half_extent + margin
    max_target = room_length - half_extent - margin
    if max_target <= min_target:
        return _clamp(float(target_y), margin, room_length - margin)

    branch_ref_cys = []
    for object_id in order:
        obj = plan_objects.get(object_id)
        bbox = _reference_bbox_from_sources(obj) if obj else None
        if bbox:
            branch_ref_cys.append((float(bbox[1]) + float(bbox[3])) / 2.0)
    branch_ref_cy = _median(branch_ref_cys)
    adjusted = _clamp(float(target_y), min_target, max_target)
    order_set = set(order)
    for bed in plan_objects.values():
        if str(bed.get("id") or "") in order_set or not _is_bed_or_sofa_object(bed):
            continue
        bed_min, bed_max = _bbox_for_object(bed)
        target_min = adjusted - half_extent
        target_max = adjusted + half_extent
        if target_max <= float(bed_min[1]) - clearance or target_min >= float(bed_max[1]) + clearance:
            continue
        bed_bbox = _reference_bbox_from_sources(bed)
        bed_ref_cy = ((float(bed_bbox[1]) + float(bed_bbox[3])) / 2.0) if bed_bbox else None
        front_candidate = float(bed_min[1]) - half_extent - clearance
        back_candidate = float(bed_max[1]) + half_extent + clearance
        front_valid = front_candidate >= min_target
        back_valid = back_candidate <= max_target
        prefer_front = bool(branch_ref_cy is not None and bed_ref_cy is not None and branch_ref_cy >= bed_ref_cy + 0.035)
        prefer_back = bool(branch_ref_cy is not None and bed_ref_cy is not None and branch_ref_cy <= bed_ref_cy - 0.035)
        if prefer_front and front_valid:
            adjusted = front_candidate
        elif prefer_back and back_valid:
            adjusted = back_candidate
        elif front_valid and back_valid:
            adjusted = front_candidate if abs(front_candidate - adjusted) <= abs(back_candidate - adjusted) else back_candidate
        elif front_valid:
            adjusted = front_candidate
        elif back_valid:
            adjusted = back_candidate
        else:
            adjusted = _clamp(adjusted, min_target, max_target)
    return _clamp(adjusted, min_target, max_target)


def _side_wall_mixed_depth_lateral_target_y(
    branch: dict[str, Any],
    plan_objects: dict[str, dict[str, Any]],
    object_id: str,
    order: list[str],
    base_target_y: float,
    room: dict[str, Any],
) -> float:
    obj = plan_objects.get(object_id)
    if not obj:
        return float(base_target_y)
    anchor_id = str(branch.get("group_anchor_id") or branch.get("anchor_id") or "")
    if not anchor_id or anchor_id not in plan_objects:
        anchor_id = next((candidate_id for candidate_id in order if _is_table_anchor_object(plan_objects.get(candidate_id, {}))), "")
    if not anchor_id or anchor_id == object_id or anchor_id not in plan_objects:
        return float(base_target_y)

    anchor_bbox = _reference_bbox_from_sources(plan_objects[anchor_id])
    obj_bbox = _reference_bbox_from_sources(obj)
    if not anchor_bbox or not obj_bbox:
        return float(base_target_y)

    # Image-space bbox bottom is a stable weak depth cue for oblique room references:
    # a smaller bottom usually means farther/back in the room. Keep tiny differences as same-depth.
    bottom_delta = float(anchor_bbox[3]) - float(obj_bbox[3])
    if abs(bottom_delta) < 0.045:
        bottom_delta = 0.0
    room_length = float(room.get("length", 0.0) or 0.0)
    depth_scale = _clamp(room_length * 0.22, 0.70, 1.20)
    target_y = float(base_target_y) + bottom_delta * depth_scale
    _width, length = _rotated_footprint(obj)
    margin = FLOOR_WALL_AGAINST_GAP
    return _clamp(target_y, length / 2.0 + margin, room_length - length / 2.0 - margin)


def _side_wall_anchor_long_axis_world(obj: dict[str, Any], wall_id: str) -> str | None:
    constraints = _semantic_pose_constraints(obj)
    long_axis = _semantic_token(constraints.get("long_axis_world")) if constraints else ""
    if _is_floor_storage_or_table_branch_object(obj):
        # A side-wall floor anchor is not always back-to-wall. If its drawer/door
        # front is tangent to the wall, the contact face is a side face and the
        # long axis may run along the wall normal. Use the same contact-face rule
        # as the final floor-storage repair so branch packing does not undo it.
        return _floor_storage_wall_target_long_axis(obj, wall_id)
    if long_axis in {"x", "y"}:
        return long_axis
    return None


def _orient_side_wall_floor_anchor(obj: dict[str, Any], wall_id: str) -> bool:
    desired_yaw = _floor_against_wall_yaw(wall_id, obj)
    long_axis = _side_wall_anchor_long_axis_world(obj, wall_id)
    if long_axis in {"x", "y"}:
        return _set_effective_yaw_with_long_axis(obj, desired_yaw, long_axis)
    return _set_effective_yaw(obj, desired_yaw, allow_fine_seating=False)


def _pack_side_wall_same_depth_lateral_branch(
    plan: dict[str, Any],
    scene_graph: dict[str, Any],
    branch: dict[str, Any],
    report: dict[str, Any],
    plan_objects: dict[str, dict[str, Any]],
    branch_ids: list[str],
    floor_ids: list[str],
) -> None:
    wall_id = str(branch.get("wall_id") or "")
    room = plan.get("room") if isinstance(plan.get("room"), dict) else {}
    order = _side_wall_lateral_order_for_branch(scene_graph, branch, plan_objects, floor_ids)
    if len(order) < 2:
        return
    layout_mode = str(branch.get("layout_mode") or "")
    mixed_depth = layout_mode == "mixed_depth_lateral"
    gap = FLOOR_WALL_AGAINST_GAP
    clearance = 0.08
    target_y = _side_wall_same_depth_target_y(branch, plan_objects, order, room)
    target_y = _side_wall_same_depth_target_y_before_adjacent_large_anchor(scene_graph, plan_objects, order, target_y)
    if not mixed_depth:
        target_y = _side_wall_same_depth_target_y_avoid_bed_overlap(plan_objects, order, target_y, room)
    current_edge = gap if wall_id == "wall_west" else float(room.get("width", 0.0) or 0.0) - gap
    placed_ids: list[str] = []
    for index, object_id in enumerate(order):
        obj = plan_objects[object_id]
        before = _plan_object_snapshot(obj)
        obj["placement_type"] = "floor"
        is_wall_anchor = _is_floor_storage_or_table_branch_object(obj)
        is_seat = _is_seating_object(obj) and not is_wall_anchor
        if is_wall_anchor:
            _orient_side_wall_floor_anchor(obj, wall_id)
            relation = _semantic_wall_relation(obj)
            mode = str(relation.get("mode") or "").strip().lower()
            obj["support_id"] = wall_id if index == 0 else None
        else:
            obj["support_id"] = None
        width, _length = _rotated_footprint(obj)
        if wall_id == "wall_west":
            obj["x"] = current_edge + width / 2.0
            current_edge = float(obj["x"]) + width / 2.0 + clearance
        else:
            obj["x"] = current_edge - width / 2.0
            current_edge = float(obj["x"]) - width / 2.0 - clearance
        object_target_y = (
            _side_wall_mixed_depth_lateral_target_y(branch, plan_objects, object_id, order, target_y, room)
            if mixed_depth
            else target_y
        )
        obj["y"] = object_target_y
        tuck_fix: dict[str, Any] | None = None
        if is_seat:
            target_id = str(_semantic_pose_constraints(obj).get("facing_target") or "")
            if target_id in plan_objects:
                target = plan_objects[target_id]
                if _is_desk_chair_tuck_pair(target, obj):
                    tuck_fix = _tuck_workstation_chair_under_table(
                        target,
                        obj,
                        room,
                        stage=str(report.get("stage") or "side_wall_lateral_pack"),
                    )
                else:
                    _set_object_facing_target(obj, target, allow_fine_seating=True)
        _clamp_object_to_room(obj, room)
        dx = float(obj.get("x", 0.0) or 0.0) - float(before["x"])
        dy = float(obj.get("y", 0.0) or 0.0) - float(before["y"])
        moved_children = _move_direct_supported_children(plan_objects, object_id, dx, dy, room)
        placed_ids.append(object_id)
        after = _plan_object_snapshot(obj)
        if before != after:
            report["fixes"].append(
                {
                    "stage": report.get("stage"),
                    "type": "side_wall_branch_mixed_depth_lateral_pack" if mixed_depth else "side_wall_branch_same_depth_lateral_pack",
                    "id": object_id,
                    "wall_id": wall_id,
                    "lateral_order": order,
                    "target_y": round(float(target_y), 6),
                    "object_target_y": round(float(object_target_y), 6),
                    "moved_children": moved_children,
                    "tuck_fix": tuck_fix,
                    "before": before,
                    "after": after,
                    "evidence": (
                        "Side-wall group is a mixed-depth lateral cluster; keep lateral order while preserving reference depth."
                        if mixed_depth
                        else "Side-wall group is a same-depth lateral cluster, not a wall-depth queue."
                    ),
                }
            )

    for object_id in branch_ids:
        obj = plan_objects.get(object_id)
        if not obj or not _is_wall_attached_object(obj):
            continue
        before = _plan_object_snapshot(obj)
        support = _nearest_floor_anchor_for_wall_object(obj, placed_ids, plan_objects, scene_graph)
        obj["placement_type"] = "attached_to_wall"
        obj["support_id"] = wall_id
        obj["yaw"] = _wall_semantic_yaw(wall_id)
        obj["footprint_yaw_offset_degrees"] = _wall_footprint_offset_for_object(wall_id, obj)
        obj["dimensions"]["length"] = min(float(obj["dimensions"]["length"]), WALL_ASSET_AXIS_REPAIR_MAX_DEPTH)
        if support:
            obj["y"] = float(support.get("y", target_y) or target_y)
        _clamp_wall_attached_object(obj, room, wall_id)
        after = _plan_object_snapshot(obj)
        if before != after:
            report["fixes"].append(
                {
                    "stage": report.get("stage"),
                    "type": "side_wall_same_depth_attached_object_alignment",
                    "id": object_id,
                    "wall_id": wall_id,
                    "support_anchor": support.get("id") if support else None,
                    "before": before,
                    "after": after,
                }
            )


def _plan_object_snapshot(obj: dict[str, Any]) -> dict[str, Any]:
    return {
        "x": round(float(obj.get("x", 0.0) or 0.0), 6),
        "y": round(float(obj.get("y", 0.0) or 0.0), 6),
        "z": round(float(obj.get("z", 0.0) or 0.0), 6),
        "yaw": round(float(obj.get("yaw", 0.0) or 0.0), 6),
        "placement_type": obj.get("placement_type"),
        "support_id": obj.get("support_id"),
        "asset_local_yaw_offset_degrees": round(float(obj.get("asset_local_yaw_offset_degrees", 0.0) or 0.0), 6),
        "front_yaw_offset_degrees": round(float(obj.get("front_yaw_offset_degrees", 0.0) or 0.0), 6),
        "footprint_yaw_offset_degrees": round(float(obj.get("footprint_yaw_offset_degrees", 0.0) or 0.0), 6),
    }


def _move_direct_supported_children(
    objects: dict[str, dict[str, Any]],
    support_id: str,
    dx: float,
    dy: float,
    room: dict[str, Any],
) -> list[str]:
    moved: list[str] = []
    if abs(dx) < 1e-6 and abs(dy) < 1e-6:
        return moved
    queue = [str(support_id)]
    seen_supports = set(queue)
    moved_set: set[str] = set()
    while queue:
        current_support_id = queue.pop(0)
        support_surface_registry = build_support_surface_registry({"objects": list(objects.values()), "room": room}, None)
        direct_children = [
            child
            for child in objects.values()
            if str(child.get("support_id") or "") == current_support_id and str(child.get("id") or "") not in moved_set
        ]
        for child in direct_children:
            child_id = str(child.get("id") or "")
            if not child_id:
                continue
            child["x"] = float(child.get("x", 0.0) or 0.0) + dx
            child["y"] = float(child.get("y", 0.0) or 0.0) + dy
            relation = "inside" if str(child.get("placement_type") or "") == "inside" else "on"
            _snap_object_to_registered_support_surface(child, current_support_id, support_surface_registry, relation)
            _clamp_object_to_room(child, room)
            moved.append(child_id)
            moved_set.add(child_id)
            if child_id not in seen_supports:
                queue.append(child_id)
                seen_supports.add(child_id)
    return moved


def _reference_bbox_overlap_ratio_x(a: list[float], b: list[float]) -> float:
    a_width = max(0.0, float(a[2]) - float(a[0]))
    b_width = max(0.0, float(b[2]) - float(b[0]))
    if min(a_width, b_width) <= 1e-6:
        return 0.0
    overlap = min(float(a[2]), float(b[2])) - max(float(a[0]), float(b[0]))
    return max(0.0, overlap) / min(a_width, b_width)


def _reference_bbox_rear_contact_score(large_bbox: list[float], anchor_bbox: list[float]) -> float:
    large_top = float(large_bbox[1])
    large_center_y = (float(large_bbox[1]) + float(large_bbox[3])) / 2.0
    anchor_center_y = (float(anchor_bbox[1]) + float(anchor_bbox[3])) / 2.0
    if anchor_center_y >= large_center_y:
        return 0.0
    overlap_ratio = _reference_bbox_overlap_ratio_x(large_bbox, anchor_bbox)
    if overlap_ratio < 0.10:
        return 0.0
    signed_gap = large_top - float(anchor_bbox[3])
    large_height = max(0.0, float(large_bbox[3]) - float(large_bbox[1]))
    if signed_gap > max(0.06, large_height * 0.18):
        return 0.0
    if signed_gap < -max(0.08, large_height * 0.24):
        return 0.0
    gap_score = 1.0 - min(1.0, abs(signed_gap) / max(0.10, large_height * 0.25))
    return round(float(overlap_ratio * 0.7 + gap_score * 0.3), 6)


def _reference_depth_slice_fix_large_object_rear_contact(
    plan: dict[str, Any],
    scene_graph: dict[str, Any],
    cross_constraints: list[dict[str, Any]],
    parent: dict[str, str],
    report: dict[str, Any],
) -> None:
    room = plan.get("room") if isinstance(plan.get("room"), dict) else {}
    if not room:
        return
    room_length = float(room.get("length", 0.0) or 0.0)
    if room_length <= 0.0:
        return
    objects = {str(obj.get("id")): obj for obj in plan.get("objects", []) if isinstance(obj, dict) and obj.get("id")}
    if not objects:
        return
    ref_bboxes = _reference_bboxes_by_object(scene_graph)
    ref_depths = _reference_depths_by_object(scene_graph)
    clearance = max(FLOOR_WALL_AGAINST_GAP, 0.025)

    for large in objects.values():
        if not _is_bed_or_sofa_object(large):
            continue
        large_id = str(large.get("id") or "")
        large_bbox = ref_bboxes.get(large_id)
        if not large_bbox:
            continue
        large_width, large_length = _rotated_footprint(large)
        if large_length <= 0.0:
            continue
        large_left = float(large.get("x", 0.0) or 0.0) - large_width / 2.0
        large_right = float(large.get("x", 0.0) or 0.0) + large_width / 2.0
        large_y = float(large.get("y", 0.0) or 0.0)
        candidates: list[dict[str, Any]] = []
        for anchor in objects.values():
            anchor_id = str(anchor.get("id") or "")
            if anchor_id == large_id or _is_bed_or_sofa_object(anchor):
                continue
            if str(anchor.get("placement_type", "floor")) != "floor":
                continue
            if not _is_floor_storage_or_table_branch_object(anchor):
                continue
            anchor_bbox = ref_bboxes.get(anchor_id)
            if not anchor_bbox:
                continue
            score = _reference_bbox_rear_contact_score(large_bbox, anchor_bbox)
            if score <= 0.0:
                continue
            anchor_width, anchor_length = _rotated_footprint(anchor)
            anchor_left = float(anchor.get("x", 0.0) or 0.0) - anchor_width / 2.0
            anchor_right = float(anchor.get("x", 0.0) or 0.0) + anchor_width / 2.0
            scene_overlap = min(large_right, anchor_right) - max(large_left, anchor_left)
            if scene_overlap <= min(large_width, anchor_width) * 0.05:
                continue
            anchor_y = float(anchor.get("y", 0.0) or 0.0)
            if anchor_y <= large_y:
                continue
            anchor_front = anchor_y - anchor_length / 2.0
            candidates.append(
                {
                    "id": anchor_id,
                    "score": score,
                    "front_y": anchor_front,
                    "bbox": [round(float(value), 6) for value in anchor_bbox],
                    "scene_overlap_x": round(float(scene_overlap), 6),
                }
            )
        if not candidates:
            continue

        candidates.sort(key=lambda item: (-float(item["score"]), float(item["front_y"]), str(item["id"])))
        front_y = min(float(candidate["front_y"]) for candidate in candidates)
        target_rear_y = front_y - clearance
        target_y = target_rear_y - large_length / 2.0
        target_y = _clamp(target_y, large_length / 2.0 + FLOOR_WALL_AGAINST_GAP, room_length - large_length / 2.0 - FLOOR_WALL_AGAINST_GAP)
        before = _plan_object_snapshot(large)
        old_x = float(large.get("x", 0.0) or 0.0)
        old_y = float(large.get("y", 0.0) or 0.0)

        if _has_word_text(large, ("bed",)):
            target_wall = _back_to_wall_target_wall(large, cross_constraints, parent)
            if target_wall in VIRTUAL_WALLS:
                _apply_bed_or_sofa_wall_pose_constraint(large, target_wall)
        if abs(target_y - old_y) >= 0.08:
            large["y"] = target_y
        _clamp_object_to_room(large, room)
        moved_children = _move_direct_supported_children(
            objects,
            large_id,
            float(large.get("x", old_x) or old_x) - old_x,
            float(large.get("y", old_y) or old_y) - old_y,
            room,
        )
        after = _plan_object_snapshot(large)
        if before != after:
            depth_item = ref_depths.get(large_id, {})
            slice_depths = depth_item.get("slice_depths") if isinstance(depth_item, dict) else None
            report["fixes"].append(
                {
                    "stage": report.get("stage"),
                    "type": "large_object_depth_slice_rear_contact",
                    "id": large_id,
                    "anchor_ids": [candidate["id"] for candidate in candidates],
                    "before": before,
                    "after": after,
                    "target_rear_y": round(float(target_rear_y), 6),
                    "anchor_front_y": round(float(front_y), 6),
                    "clearance": round(float(clearance), 6),
                    "reference_bbox": [round(float(value), 6) for value in large_bbox],
                    "anchor_evidence": candidates,
                    "reference_vertical_depth_slices": slice_depths,
                    "moved_children": moved_children,
                    "evidence": "Large bed/sofa depth is evaluated by rear/top image slice and visual contact with rear furniture, not by the whole-object crop median.",
                }
            )


def _reference_consistency_fix_bed_against_back_wall(
    plan: dict[str, Any],
    cross_constraints: list[dict[str, Any]],
    parent: dict[str, str],
    report: dict[str, Any],
) -> None:
    room = plan.get("room") if isinstance(plan.get("room"), dict) else {}
    if not room:
        return
    objects = {str(obj.get("id")): obj for obj in plan.get("objects", []) if isinstance(obj, dict) and obj.get("id")}
    north_wall_bed_ids = [
        str(obj.get("id") or "")
        for obj in objects.values()
        if _is_bed_or_sofa_object(obj) and _back_to_wall_target_wall(obj, cross_constraints, parent) == "wall_north"
    ]
    has_north_wall_bed_row = len(north_wall_bed_ids) >= 2
    north_wall_anchors = [
        obj
        for obj in objects.values()
        if not _is_bed_or_sofa_object(obj)
        and _is_floor_storage_or_table_branch_object(obj)
        and (
            _wall_relation_for_object(str(obj.get("id") or ""), cross_constraints, parent) == "wall_north"
            or float(obj.get("y", 0.0) or 0.0) >= float(room.get("length", 0.0) or 0.0) * 0.78
        )
    ]
    for bed in objects.values():
        if not _is_bed_or_sofa_object(bed):
            continue
        target_wall = _back_to_wall_target_wall(bed, cross_constraints, parent)
        if target_wall != "wall_north":
            continue
        before = _plan_object_snapshot(bed)
        old_x = float(bed.get("x", 0.0) or 0.0)
        old_y = float(bed.get("y", 0.0) or 0.0)
        _apply_bed_or_sofa_wall_pose_constraint(bed, target_wall)
        bed_width, bed_length = _rotated_footprint(bed)
        bed_left = float(bed.get("x", 0.0) or 0.0) - bed_width / 2.0
        bed_right = float(bed.get("x", 0.0) or 0.0) + bed_width / 2.0
        clearance = 0.02
        candidate_front_edges: list[float] = []
        for anchor in north_wall_anchors:
            anchor_width, anchor_length = _rotated_footprint(anchor)
            anchor_left = float(anchor.get("x", 0.0) or 0.0) - anchor_width / 2.0
            anchor_right = float(anchor.get("x", 0.0) or 0.0) + anchor_width / 2.0
            overlaps_x = min(bed_right, anchor_right) - max(bed_left, anchor_left)
            if overlaps_x <= min(bed_width, anchor_width) * 0.08:
                continue
            candidate_front_edges.append(float(anchor.get("y", 0.0) or 0.0) - anchor_length / 2.0)
        if candidate_front_edges and not has_north_wall_bed_row:
            target_back = min(candidate_front_edges) - clearance
        else:
            target_back = float(room.get("length", 0.0) or 0.0) - FLOOR_WALL_AGAINST_GAP
        target_y = target_back - bed_length / 2.0
        old_y = float(bed.get("y", target_y) or target_y)
        target_y = _clamp(
            target_y,
            bed_length / 2.0 + FLOOR_WALL_AGAINST_GAP,
            float(room.get("length", 0.0) or 0.0) - bed_length / 2.0 - FLOOR_WALL_AGAINST_GAP,
        )
        if abs(target_y - old_y) >= 0.08:
            bed["y"] = target_y
        _clamp_object_to_room(bed, room)
        moved_children = _move_direct_supported_children(
            objects,
            str(bed.get("id")),
            float(bed.get("x", old_x) or old_x) - old_x,
            float(bed.get("y", old_y) or old_y) - old_y,
            room,
        )
        after = _plan_object_snapshot(bed)
        if before != after:
            report["fixes"].append(
                {
                    "stage": report.get("stage"),
                    "type": "bed_back_wall_pose_and_clearance",
                    "id": bed.get("id"),
                    "before": before,
                    "after": after,
                    "target_back_y": round(float(target_back), 6),
                    "used_rear_anchor_front_edges": [round(float(value), 6) for value in candidate_front_edges],
                    "moved_children": moved_children,
                    "evidence": "Bed has a north-wall headboard; if no rear floor anchor exists, its headboard/back edge must be explicitly grounded against wall_north.",
                }
            )


def _same_side_wall_depth_order_fix(
    plan: dict[str, Any],
    scene_graph: dict[str, Any],
    cross_constraints: list[dict[str, Any]],
    parent: dict[str, str],
    report: dict[str, Any],
) -> None:
    room = plan.get("room") if isinstance(plan.get("room"), dict) else {}
    if not room:
        return
    objects = {str(obj.get("id")): obj for obj in plan.get("objects", []) if isinstance(obj, dict) and obj.get("id")}
    ref_depths = _reference_depths_by_object(scene_graph)
    ref_bboxes = _reference_bboxes_by_object(scene_graph)
    if not ref_depths and not ref_bboxes:
        return

    def depth_frontness(object_id: str) -> tuple[float, float] | None:
        item = ref_depths.get(object_id)
        if isinstance(item, dict):
            confidence = _safe_float(item.get("confidence"), 0.0)
            if confidence >= 0.48:
                return _safe_float(item.get("frontness"), 0.0), confidence
        bbox = ref_bboxes.get(object_id)
        if bbox:
            # In oblique bedroom references, the bbox bottom is a weak but useful
            # tangent-depth cue: visually lower objects are usually closer/front.
            return _clamp(float(bbox[3]), 0.0, 1.0), 0.42
        return None

    floor_by_wall: dict[str, list[str]] = {}
    wall_attached_by_wall: dict[str, list[str]] = {}
    for object_id, obj in objects.items():
        placement = str(obj.get("placement_type") or "")
        support_id = str(obj.get("support_id") or "")
        if placement == "attached_to_wall" and support_id in {"wall_east", "wall_west"}:
            wall_attached_by_wall.setdefault(support_id, []).append(object_id)
            continue
        if placement == "floor" and _is_floor_storage_or_table_branch_object(obj) and not _is_bedside_table_object(obj):
            wall_id = _wall_relation_for_object(object_id, cross_constraints, parent)
            if wall_id in {"wall_east", "wall_west"}:
                floor_by_wall.setdefault(wall_id, []).append(object_id)

    clearance = 0.06
    for wall_id, wall_ids in sorted(wall_attached_by_wall.items()):
        for wall_object_id in wall_ids:
            wall_obj = objects.get(wall_object_id)
            wall_depth = depth_frontness(wall_object_id)
            if not wall_obj or not wall_depth:
                continue
            for floor_id in floor_by_wall.get(wall_id, []):
                floor_obj = objects.get(floor_id)
                floor_depth = depth_frontness(floor_id)
                if not floor_obj or not floor_depth:
                    continue
                frontness_gap = wall_depth[0] - floor_depth[0]
                if abs(frontness_gap) < 0.12:
                    continue
                wall_width, wall_length = _rotated_footprint(wall_obj)
                floor_width, floor_length = _rotated_footprint(floor_obj)
                floor_min_y = float(floor_obj.get("y", 0.0) or 0.0) - floor_length / 2.0
                floor_max_y = float(floor_obj.get("y", 0.0) or 0.0) + floor_length / 2.0
                wall_min_y = float(wall_obj.get("y", 0.0) or 0.0) - wall_length / 2.0
                wall_max_y = float(wall_obj.get("y", 0.0) or 0.0) + wall_length / 2.0
                current_gap = max(floor_min_y - wall_max_y, wall_min_y - floor_max_y, 0.0)
                if current_gap > 0.18:
                    already_front = wall_max_y <= floor_min_y + 0.03
                    already_back = wall_min_y >= floor_max_y - 0.03
                    if frontness_gap > 0.0 and already_front:
                        continue
                    if frontness_gap < 0.0 and already_back:
                        continue
                old_y = float(wall_obj.get("y", 0.0) or 0.0)
                if frontness_gap > 0.0:
                    target_y = floor_min_y - clearance - wall_length / 2.0
                    relation = "in_front_of"
                else:
                    target_y = floor_max_y + clearance + wall_length / 2.0
                    relation = "behind"
                target_y = _clamp(
                    target_y,
                    wall_length / 2.0 + FLOOR_WALL_AGAINST_GAP,
                    float(room.get("length", 0.0) or 0.0) - wall_length / 2.0 - FLOOR_WALL_AGAINST_GAP,
                )
                if abs(target_y - old_y) < 0.08:
                    continue
                before = _plan_object_snapshot(wall_obj)
                wall_obj["y"] = target_y
                _clamp_wall_attached_object(wall_obj, room, wall_id)
                after = _plan_object_snapshot(wall_obj)
                if before != after:
                    report["fixes"].append(
                        {
                            "stage": report.get("stage"),
                            "type": "same_side_wall_reference_depth_order",
                            "id": wall_object_id,
                            "wall_id": wall_id,
                            "relative_to": floor_id,
                            "relation": relation,
                            "before": before,
                            "after": after,
                            "reference_frontness": {
                                wall_object_id: round(wall_depth[0], 6),
                                floor_id: round(floor_depth[0], 6),
                            },
                            "confidence": round(min(wall_depth[1], floor_depth[1]), 6),
                            "evidence": (
                                "Same side-wall wall-attached objects and floor storage need tangent-depth ordering "
                                "when reference depth shows one is clearly closer to the viewer."
                            ),
                        }
                    )


def _side_wall_storage_bed_front_depth_fix(
    plan: dict[str, Any],
    scene_graph: dict[str, Any],
    cross_constraints: list[dict[str, Any]],
    parent: dict[str, str],
    report: dict[str, Any],
) -> None:
    room = plan.get("room") if isinstance(plan.get("room"), dict) else {}
    if not room:
        return
    objects = {str(obj.get("id")): obj for obj in plan.get("objects", []) if isinstance(obj, dict) and obj.get("id")}
    beds = [obj for obj in objects.values() if _is_bed_or_sofa_object(obj)]
    if not beds:
        return
    if len(beds) != 1:
        # This reference-bias rule was learned for single-bed visual branches.
        # Multi-bed rows must stay governed by the row-packing/reference-order
        # modules; moving one bed branch independently breaks the shared
        # nightstand/rug structure.
        return
    consistency = scene_graph.get("_reference_consistency_refiner") if isinstance(scene_graph.get("_reference_consistency_refiner"), dict) else {}
    side_wall_cluster_ids = {
        str(object_id)
        for branch in consistency.get("side_wall_branches", [])
        if isinstance(branch, dict)
        for object_id in branch.get("object_ids", [])
    }
    ref_bboxes = _reference_bboxes_by_object(scene_graph)
    ref_depths = _reference_depths_by_object(scene_graph)
    clearance = 0.08
    room_length = float(room.get("length", 0.0) or 0.0)

    def side_wall_window_anchor(object_id: str, obj: dict[str, Any], wall_id: str) -> dict[str, Any] | None:
        obj_bbox = ref_bboxes.get(object_id)
        if not obj_bbox:
            return None
        obj_cx = (float(obj_bbox[0]) + float(obj_bbox[2])) / 2.0
        candidates: list[tuple[float, float, str, dict[str, Any]]] = []
        for other_id, other in objects.items():
            if other_id == object_id:
                continue
            if not _functional_cluster_is_window_object(other):
                continue
            other_wall = _object_wall_id_for_same_wall_separation(other_id, other, cross_constraints, parent)
            if other_wall != wall_id:
                continue
            other_bbox = ref_bboxes.get(other_id)
            if not other_bbox:
                continue
            other_cx = (float(other_bbox[0]) + float(other_bbox[2])) / 2.0
            overlap_x = max(0.0, min(float(obj_bbox[2]), float(other_bbox[2])) - max(float(obj_bbox[0]), float(other_bbox[0])))
            min_width = max(1e-6, min(float(obj_bbox[2]) - float(obj_bbox[0]), float(other_bbox[2]) - float(other_bbox[0])))
            overlap_ratio = overlap_x / min_width
            if abs(obj_cx - other_cx) > 0.16 and overlap_ratio < 0.18:
                continue
            candidates.append((abs(obj_cx - other_cx), float(other.get("y", 0.0) or 0.0), other_id, other))
        if not candidates:
            return None
        candidates.sort(key=lambda item: item[0])
        return {"y": float(candidates[0][1]), "id": candidates[0][2], "object": candidates[0][3]}

    for bed in beds:
        bed_id = str(bed.get("id") or "")
        bed_bbox = ref_bboxes.get(bed_id)
        bed_depth = ref_depths.get(bed_id, {})
        if not bed_bbox or not isinstance(bed_depth, dict):
            continue
        bed_w, bed_l = _rotated_footprint(bed)
        bed_front_y = float(bed.get("y", 0.0) or 0.0) - bed_l / 2.0
        bed_image_bottom = float(bed_bbox[3])
        bed_frontness = _safe_float(bed_depth.get("frontness"), 0.0)
        for obj in objects.values():
            object_id = str(obj.get("id") or "")
            if object_id == bed_id or _is_bedside_table_object(obj):
                continue
            if object_id in side_wall_cluster_ids:
                continue
            if str(obj.get("placement_type") or "") != "floor":
                continue
            if not _is_floor_storage_or_table_branch_object(obj):
                continue
            wall_id = _wall_relation_for_object(object_id, cross_constraints, parent)
            if wall_id not in {"wall_west", "wall_east"}:
                continue
            bbox = ref_bboxes.get(object_id)
            depth = ref_depths.get(object_id, {})
            if not bbox or not isinstance(depth, dict):
                continue
            window_anchor = side_wall_window_anchor(object_id, obj, wall_id)
            if window_anchor is not None:
                window_anchor_y = float(window_anchor.get("y", 0.0) or 0.0)
                window_anchor_id = str(window_anchor.get("id") or "")
                window_depth = ref_depths.get(window_anchor_id, {})
                window_bbox = ref_bboxes.get(window_anchor_id)
                depth_confidence = min(
                    _safe_float(depth.get("confidence"), 0.0),
                    _safe_float(window_depth.get("confidence"), 0.0) if isinstance(window_depth, dict) else 0.0,
                )
                depth_contradicts_window_alignment = False
                if window_bbox and isinstance(window_depth, dict) and depth_confidence >= 0.48:
                    storage_frontness = _safe_float(depth.get("frontness"), 0.0)
                    window_frontness = _safe_float(window_depth.get("frontness"), 0.0)
                    storage_lower_than_window = float(bbox[3]) - float(window_bbox[3])
                    depth_contradicts_window_alignment = (
                        storage_frontness - window_frontness >= 0.30
                        and storage_lower_than_window >= 0.16
                    )
                if depth_contradicts_window_alignment:
                    report.setdefault("warnings", []).append(
                        {
                            "stage": report.get("stage"),
                            "type": "side_wall_storage_window_alignment_skipped_reference_depth_contradiction",
                            "id": object_id,
                            "wall_id": wall_id,
                            "window_id": window_anchor_id,
                            "storage_frontness": round(float(_safe_float(depth.get("frontness"), 0.0)), 6),
                            "window_frontness": round(
                                float(_safe_float(window_depth.get("frontness"), 0.0))
                                if isinstance(window_depth, dict)
                                else 0.0,
                                6,
                            ),
                            "storage_bbox_bottom": round(float(bbox[3]), 6),
                            "window_bbox_bottom": round(float(window_bbox[3]) if window_bbox else 0.0, 6),
                            "evidence": (
                                "A same-wall storage/window visual stack is not enough to force identical wall-tangent "
                                "depth when reference depth and bbox bottom both show the storage is substantially closer "
                                "to the camera than the window."
                            ),
                        }
                    )
                else:
                    obj_w, obj_l = _rotated_footprint(obj)
                    target_y = _clamp(
                        float(window_anchor_y),
                        obj_l / 2.0 + FLOOR_WALL_AGAINST_GAP,
                        room_length - obj_l / 2.0 - FLOOR_WALL_AGAINST_GAP,
                    )
                    if abs(float(obj.get("y", 0.0) or 0.0) - target_y) > 0.12:
                        before = _plan_object_snapshot(obj)
                        obj["y"] = target_y
                        _clamp_object_to_room_rotated(obj, room, margin=0.0)
                        after = _plan_object_snapshot(obj)
                        if before != after:
                            report["fixes"].append(
                                {
                                    "stage": report.get("stage"),
                                    "type": "side_wall_storage_window_cluster_alignment",
                                    "id": object_id,
                                    "wall_id": wall_id,
                                    "target_window_y": round(float(window_anchor_y), 6),
                                    "window_id": window_anchor_id,
                                    "before": before,
                                    "after": after,
                                    "evidence": (
                                        "Side-wall storage directly under a same-wall window should align to the window/curtain wall segment; "
                                        "bed-front depth alignment is too coarse for this stacked wall cluster."
                                    ),
                                }
                            )
                    continue
            confidence = min(_safe_float(depth.get("confidence"), 0.0), _safe_float(bed_depth.get("confidence"), 0.0))
            if confidence < 0.55:
                continue
            image_bottom_gap = bed_image_bottom - float(bbox[3])
            frontness_gap = bed_frontness - _safe_float(depth.get("frontness"), 0.0)
            if image_bottom_gap < 0.04 and frontness_gap < 0.24:
                continue
            obj_w, obj_l = _rotated_footprint(obj)
            obj_front_y = float(obj.get("y", 0.0) or 0.0) - obj_l / 2.0
            target_front_y = bed_front_y + clearance
            if obj_front_y >= target_front_y - 0.03:
                continue
            before = _plan_object_snapshot(obj)
            target_y = target_front_y + obj_l / 2.0
            target_y = _clamp(target_y, obj_l / 2.0 + FLOOR_WALL_AGAINST_GAP, room_length - obj_l / 2.0 - FLOOR_WALL_AGAINST_GAP)
            old_y = float(obj.get("y", 0.0) or 0.0)
            obj["y"] = target_y
            _clamp_object_to_room_rotated(obj, room, margin=0.0)
            after = _plan_object_snapshot(obj)
            if before != after:
                report["fixes"].append(
                    {
                        "stage": report.get("stage"),
                        "type": "side_wall_storage_bed_front_depth_alignment",
                        "id": object_id,
                        "bed_id": bed_id,
                        "wall_id": wall_id,
                        "before": before,
                        "after": after,
                        "old_front_y": round(float(obj_front_y), 6),
                        "target_front_y": round(float(target_front_y), 6),
                        "reference_image_bottom_gap": round(float(image_bottom_gap), 6),
                        "reference_frontness_gap": round(float(frontness_gap), 6),
                        "confidence": round(float(confidence), 6),
                        "evidence": "Side-wall dresser/cabinet appears behind the bed foot in the reference; compare against the bed front/foot boundary instead of the whole-bed depth median.",
                    }
                )


def _is_bedside_table_object(obj: dict[str, Any]) -> bool:
    semantic = _semantic_class(obj)
    role = _semantic_layout_role(obj)
    category = str(obj.get("category") or "").strip().lower().replace("_", " ")
    object_id = str(obj.get("id") or "").strip().lower().replace("_", " ")
    identity = f"{object_id} {category}"
    if str(obj.get("placement_type") or "floor") not in {"", "floor"}:
        return False
    if semantic in {
        "plant",
        "lighting",
        "tabletop_small",
        "tabletop_flat",
        "floor_covering",
        "soft_bedding",
        "wall_attached",
    }:
        return False
    if any(
        keyword in identity
        for keyword in (
            "lamp",
            "plant",
            "pillow",
            "cushion",
            "blanket",
            "throw",
            "duvet",
            "rug",
            "carpet",
            "clock",
            "book",
            "photo",
            "picture",
            "frame",
            "tray",
            "vase",
            "mirror",
            "window",
            "curtain",
            "door",
        )
    ):
        return False
    has_bedside_identity = any(
        keyword in identity
        for keyword in (
            "nightstand",
            "bedside table",
            "bed side table",
            "bedside cabinet",
            "bed side cabinet",
            "side table",
        )
    )
    if not has_bedside_identity:
        return False
    if semantic and semantic not in {"table_anchor", "floor_furniture", "storage_anchor", "unknown", "other"}:
        return False
    if role and role not in {"floor_branch_anchor", "table_anchor", "storage_anchor", "unknown", "other"}:
        return False
    return True


def _right_side_branch_floor_layout_ids(plan_objects: dict[str, dict[str, Any]], branch_ids: list[str]) -> list[str]:
    ids: list[str] = []
    for object_id in branch_ids:
        obj = plan_objects.get(object_id)
        if not obj or str(obj.get("placement_type", "floor")) != "floor":
            continue
        if _is_bedside_table_object(obj):
            continue
        if (
            _is_floor_storage_or_table_branch_object(obj)
            or _is_seating_object(obj)
            or ("lamp" in _category_text(obj) and _is_branch_lighting_or_decor(obj))
        ):
            ids.append(object_id)
    return ids


def _nearest_floor_anchor_for_wall_object(
    wall_obj: dict[str, Any],
    floor_ids: list[str],
    plan_objects: dict[str, dict[str, Any]],
    scene_graph: dict[str, Any],
) -> dict[str, Any] | None:
    wall_object_id = str(wall_obj.get("id") or "")
    relation_targets: list[str] = []
    for rel in scene_graph.get("relations", []) if isinstance(scene_graph.get("relations"), list) else []:
        if not isinstance(rel, dict):
            continue
        subject = str(rel.get("subject") or "")
        target = str(rel.get("object") or "")
        if subject == wall_object_id and target in floor_ids:
            relation_targets.append(target)
        elif target == wall_object_id and subject in floor_ids:
            relation_targets.append(subject)
    if relation_targets:
        return plan_objects.get(relation_targets[0])
    bbox = _wall_affinity_bbox_for_object(wall_obj)
    if not bbox:
        return plan_objects.get(floor_ids[0]) if floor_ids else None
    cx = (bbox[0] + bbox[2]) / 2.0
    best: tuple[float, dict[str, Any]] | None = None
    for object_id in floor_ids:
        obj = plan_objects.get(object_id)
        if not obj:
            continue
        other_bbox = _wall_affinity_bbox_for_object(obj)
        if other_bbox:
            other_cx = (other_bbox[0] + other_bbox[2]) / 2.0
            score = abs(cx - other_cx)
        else:
            score = abs(float(obj.get("y", 0.0) or 0.0) - float(wall_obj.get("y", 0.0) or 0.0))
        if best is None or score < best[0]:
            best = (score, obj)
    return best[1] if best else None


def _pack_side_wall_branch(
    plan: dict[str, Any],
    scene_graph: dict[str, Any],
    branch: dict[str, Any],
    report: dict[str, Any],
) -> None:
    wall_id = str(branch.get("wall_id") or "")
    if wall_id not in {"wall_east", "wall_west"}:
        return
    room = plan.get("room") if isinstance(plan.get("room"), dict) else {}
    if not room:
        return
    plan_objects = {str(obj.get("id")): obj for obj in plan.get("objects", []) if isinstance(obj, dict) and obj.get("id")}
    branch_ids = [str(object_id) for object_id in branch.get("object_ids", []) if str(object_id) in plan_objects]
    floor_ids = _right_side_branch_floor_layout_ids(plan_objects, branch_ids)
    if len(floor_ids) < 2:
        return
    if str(branch.get("layout_mode") or "") in {"same_depth_lateral", "mixed_depth_lateral"}:
        _pack_side_wall_same_depth_lateral_branch(plan, scene_graph, branch, report, plan_objects, branch_ids, floor_ids)
        return
    order = _front_to_back_order_for_branch(scene_graph, plan_objects, floor_ids)
    if not order:
        return

    clearance = 0.08
    gap = FLOOR_WALL_AGAINST_GAP
    current_back_limit = float(room.get("length", 0.0) or 0.0) - gap
    placed_wall_anchors: list[dict[str, Any]] = []
    for object_id in reversed(order):
        obj = plan_objects[object_id]
        before = _plan_object_snapshot(obj)
        is_wall_anchor = _is_floor_storage_or_table_branch_object(obj)
        is_seat = _is_seating_object(obj) and not is_wall_anchor
        if is_wall_anchor:
            _orient_side_wall_floor_anchor(obj, wall_id)
        obj["placement_type"] = "floor"
        width, length = _rotated_footprint(obj)
        floor_lamp_inset = 0.20 if ("floor lamp" in _object_identity_text(obj) or ("floor" in _object_identity_text(obj) and "lamp" in _object_identity_text(obj))) else 0.0
        obj["support_id"] = wall_id if is_wall_anchor and floor_lamp_inset <= 0.0 else None
        if is_seat and placed_wall_anchors:
            anchor = min(placed_wall_anchors, key=lambda item: abs(float(item.get("y", 0.0) or 0.0) - float(obj.get("y", 0.0) or 0.0)))
            obj["x"] = float(anchor.get("x", obj.get("x", 0.0)) or obj.get("x", 0.0))
        elif wall_id == "wall_east":
            obj["x"] = float(room["width"]) - width / 2.0 - gap - floor_lamp_inset
        else:
            obj["x"] = width / 2.0 + gap + floor_lamp_inset
        obj["y"] = current_back_limit - length / 2.0
        current_back_limit = float(obj["y"]) - length / 2.0 - clearance
        _clamp_object_to_room(obj, room)
        if is_wall_anchor:
            placed_wall_anchors.append(obj)
        after = _plan_object_snapshot(obj)
        if before != after:
            report["fixes"].append(
                {
                    "stage": report.get("stage"),
                    "type": "side_wall_branch_depth_pack",
                    "id": object_id,
                    "wall_id": wall_id,
                    "front_to_back_order": order,
                    "before": before,
                    "after": after,
                }
            )

    for object_id in branch_ids:
        obj = plan_objects.get(object_id)
        if not obj or not _is_wall_attached_object(obj):
            continue
        before = _plan_object_snapshot(obj)
        support = _nearest_floor_anchor_for_wall_object(obj, floor_ids, plan_objects, scene_graph)
        obj["placement_type"] = "attached_to_wall"
        obj["support_id"] = wall_id
        obj["yaw"] = _wall_semantic_yaw(wall_id)
        obj["footprint_yaw_offset_degrees"] = _wall_footprint_offset_for_object(wall_id, obj)
        obj["dimensions"]["length"] = min(float(obj["dimensions"]["length"]), WALL_ASSET_AXIS_REPAIR_MAX_DEPTH)
        if support:
            obj["y"] = _clamp(
                float(support.get("y", 0.0) or 0.0) + 0.25,
                0.2,
                float(room.get("length", 0.0) or 0.0) - 0.2,
            )
        _clamp_wall_attached_object(obj, room, wall_id)
        after = _plan_object_snapshot(obj)
        if before != after:
            report["fixes"].append(
                {
                    "stage": report.get("stage"),
                    "type": "side_wall_attached_object_alignment",
                    "id": object_id,
                    "wall_id": wall_id,
                    "support_anchor": support.get("id") if support else None,
                    "before": before,
                    "after": after,
                }
            )


def _bed_lateral_shift_cluster_ids(
    objects: dict[str, dict[str, Any]],
    scene_graph: dict[str, Any],
    bed_id: str,
) -> set[str]:
    cluster_ids: set[str] = {str(bed_id)}
    related_ids: set[str] = set()
    relations = scene_graph.get("relations", []) if isinstance(scene_graph.get("relations"), list) else []
    for rel in relations:
        if not isinstance(rel, dict):
            continue
        subject = str(rel.get("subject") or "")
        target = str(rel.get("object") or "")
        rel_type = str(rel.get("type") or "")
        if subject == bed_id and target in objects:
            other_id = target
        elif target == bed_id and subject in objects:
            other_id = subject
        else:
            continue
        other = objects.get(other_id)
        if not other:
            continue
        if _is_bedside_table_object(other) or _is_floor_covering(other):
            related_ids.add(other_id)
            continue
        if (
            (str(other.get("placement_type") or "") == "attached_to_wall" or _is_wall_attached_object(other) or _is_hanging_object(other))
            and any(keyword in _object_identity_text(other) for keyword in ("art", "picture", "painting", "poster", "frame", "mirror"))
            and rel_type in {"near", "above", "behind", "attached_to", "against_wall"}
        ):
            related_ids.add(other_id)
    cluster_ids.update(related_ids)

    changed = True
    while changed:
        changed = False
        for object_id, obj in objects.items():
            if object_id in cluster_ids:
                continue
            support_id = str(obj.get("support_id") or "")
            if support_id in cluster_ids:
                cluster_ids.add(object_id)
                changed = True
    return cluster_ids


def _shift_cluster_x(
    objects: dict[str, dict[str, Any]],
    cluster_ids: set[str],
    dx: float,
    room: dict[str, Any],
) -> dict[str, dict[str, Any]]:
    changed: dict[str, dict[str, Any]] = {}
    if abs(dx) < 1e-6:
        return changed
    for object_id in sorted(cluster_ids):
        obj = objects.get(object_id)
        if not obj:
            continue
        before = _plan_object_snapshot(obj)
        obj["x"] = float(obj.get("x", 0.0) or 0.0) + dx
        support_id = str(obj.get("support_id") or "")
        placement = str(obj.get("placement_type") or "")
        if placement == "attached_to_wall" and support_id in VIRTUAL_WALLS:
            _clamp_wall_attached_object(obj, room, support_id)
        elif placement in {"floor", "hanging", "on_top", "inside", ""}:
            _clamp_object_to_room_rotated(obj, room)
        after = _plan_object_snapshot(obj)
        if before != after:
            changed[object_id] = {"before": before, "after": after}
    return changed


def _shift_bed_left_if_right_branch_too_close(
    plan: dict[str, Any],
    scene_graph: dict[str, Any],
    parent: dict[str, str],
    report: dict[str, Any],
) -> None:
    room = plan.get("room") if isinstance(plan.get("room"), dict) else {}
    if not room:
        return
    objects = {str(obj.get("id")): obj for obj in plan.get("objects", []) if isinstance(obj, dict) and obj.get("id")}
    beds = [obj for obj in objects.values() if _is_bed_or_sofa_object(obj)]
    east_branch = [
        obj
        for obj in objects.values()
        if str(obj.get("support_id") or "") == "wall_east"
        and str(obj.get("placement_type", "floor")) == "floor"
        and (_is_floor_storage_or_table_branch_object(obj) or _is_branch_lighting_or_decor(obj))
    ]
    if not beds:
        return
    if len(beds) != 1:
        # This reference-bias rule was learned for single-bed visual branches.
        # Multi-bed rows must stay governed by row-packing/reference-order
        # modules; moving one bed branch independently breaks shared
        # nightstand/rug structure.
        return
    ref_bboxes = _reference_bboxes_by_object(scene_graph)
    for bed in beds:
        bed_id = str(bed.get("id") or "")
        bed_w, _bed_l = _rotated_footprint(bed)
        bed_right = float(bed.get("x", 0.0) or 0.0) + bed_w / 2.0
        current_x = float(bed.get("x", 0.0) or 0.0)
        target_x = min(current_x, float(room.get("width", 0.0) or 0.0) * 0.48)
        dx_candidates: list[tuple[float, str, dict[str, Any]]] = []
        if east_branch:
            min_branch_left = min(float(obj.get("x", 0.0) or 0.0) - _rotated_footprint(obj)[0] / 2.0 for obj in east_branch)
            gap = min_branch_left - bed_right
            if gap < 0.24:
                dx_candidates.append(
                    (
                        -min(0.18, 0.24 - gap),
                        "right_branch_clearance",
                        {"right_branch_gap_before": round(float(gap), 6)},
                    )
                )
        if current_x - target_x >= 0.08:
            dx_candidates.append(
                (
                    target_x - current_x,
                    "central_bed_reference_center_bias",
                    {"target_x": round(float(target_x), 6), "current_x": round(float(current_x), 6)},
                )
            )

        bed_bbox = ref_bboxes.get(bed_id)
        left_bedside_candidates: list[tuple[float, str, dict[str, Any], list[float]]] = []
        left_storage_candidates: list[tuple[float, str, dict[str, Any], list[float]]] = []
        if bed_bbox:
            bed_cx = (float(bed_bbox[0]) + float(bed_bbox[2])) / 2.0
            for object_id, obj in objects.items():
                bbox = ref_bboxes.get(object_id)
                if not bbox:
                    continue
                cx = (float(bbox[0]) + float(bbox[2])) / 2.0
                if cx >= bed_cx:
                    continue
                if _is_bedside_table_object(obj) and object_id in _bed_lateral_shift_cluster_ids(objects, scene_graph, bed_id):
                    left_bedside_candidates.append((cx, object_id, obj, bbox))
                elif (
                    str(obj.get("placement_type", "floor")) == "floor"
                    and _is_floor_storage_or_table_branch_object(obj)
                    and not _is_bedside_table_object(obj)
                ):
                    wall_id = _wall_relation_for_object(object_id, [], parent) or _wall_id(_semantic_wall_relation(obj).get("wall_id"))
                    if wall_id in {"wall_west", "wall_north", None} or cx < bed_cx - 0.08:
                        left_storage_candidates.append((cx, object_id, obj, bbox))
        if left_bedside_candidates and left_storage_candidates:
            left_bedside_candidates.sort(key=lambda item: (-item[0], item[1]))
            left_storage_candidates.sort(key=lambda item: (abs(item[0] - left_bedside_candidates[0][0]), item[1]))
            bedside_cx, bedside_id, bedside_obj, _bedside_bbox = left_bedside_candidates[0]
            storage_cx, storage_id, storage_obj, _storage_bbox = left_storage_candidates[0]
            ref_gap_x = max(0.0, bedside_cx - storage_cx)
            scene_gap_x = float(bedside_obj.get("x", 0.0) or 0.0) - float(storage_obj.get("x", 0.0) or 0.0)
            desired_gap_x = _clamp(ref_gap_x * float(room.get("width", 0.0) or 0.0) * 0.95, 0.28, 1.15)
            delta_x = desired_gap_x - scene_gap_x
            if abs(delta_x) > 0.12:
                dx_candidates.append(
                    (
                        _clamp(delta_x, -0.30, 0.70),
                        "left_storage_to_bedside_reference_gap",
                        {
                            "bedside_id": bedside_id,
                            "storage_id": storage_id,
                            "reference_gap_x": round(float(ref_gap_x), 6),
                            "scene_gap_x": round(float(scene_gap_x), 6),
                            "desired_scene_gap_x": round(float(desired_gap_x), 6),
                        },
                    )
                )

        if not dx_candidates:
            continue
        dx, reason, evidence = min(dx_candidates, key=lambda item: item[0])
        cluster_ids = _bed_lateral_shift_cluster_ids(objects, scene_graph, bed_id)
        changed = _shift_cluster_x(objects, cluster_ids, dx, room)
        if changed:
            report["fixes"].append(
                {
                    "stage": report.get("stage"),
                    "type": "bed_visual_cluster_lateral_reference_alignment",
                    "id": bed_id,
                    "reason": reason,
                    "requested_delta_x": round(float(dx), 6),
                    "cluster_ids": sorted(cluster_ids),
                    "changed": changed,
                    **evidence,
                    "evidence": (
                        "Bed, bedside tables, their tabletop children, underlay rug, and bed-wall art form one visual bed branch. "
                        "When reference bbox spacing shows the bed branch shifted relative to nearby storage, move the cluster as a unit."
                    ),
                }
            )


def _side_wall_floor_storage_ids_for_bed_cluster(
    objects: dict[str, dict[str, Any]],
    cluster_ids: set[str],
) -> dict[str, list[str]]:
    by_wall = {"wall_west": [], "wall_east": []}
    for object_id, obj in objects.items():
        if object_id in cluster_ids:
            continue
        if str(obj.get("placement_type") or "floor") != "floor":
            continue
        if _is_floor_covering(obj) or _is_hanging_object(obj) or _is_bedside_table_object(obj):
            continue
        if not (_is_floor_storage_or_table_branch_object(obj) or _is_book_storage(obj)):
            continue
        wall_id = str(obj.get("support_id") or "")
        if wall_id in by_wall:
            by_wall[wall_id].append(object_id)
    return by_wall


def _cluster_vs_storage_overlap_score(
    objects: dict[str, dict[str, Any]],
    cluster_ids: set[str],
    storage_ids: list[str],
    margin: float = 0.02,
) -> tuple[float, float, list[dict[str, Any]]]:
    volume = 0.0
    max_x_overlap = 0.0
    pairs: list[dict[str, Any]] = []
    for cluster_id in sorted(cluster_ids):
        cluster_obj = objects.get(cluster_id)
        if not cluster_obj:
            continue
        if _is_floor_covering(cluster_obj) or _is_hanging_object(cluster_obj):
            continue
        for storage_id in sorted(storage_ids):
            storage_obj = objects.get(storage_id)
            if not storage_obj:
                continue
            dx, dy, dz = _bbox_overlap_3d(_bbox_for_object(cluster_obj), _bbox_for_object(storage_obj), margin=margin)
            if not _has_meaningful_3d_overlap(dx, dy, dz):
                continue
            overlap_volume = max(0.0, dx) * max(0.0, dy) * max(0.0, dz)
            volume += overlap_volume
            max_x_overlap = max(max_x_overlap, max(0.0, dx))
            pairs.append(
                {
                    "cluster_object": cluster_id,
                    "storage_object": storage_id,
                    "overlap_xyz": [round(dx, 6), round(dy, 6), round(dz, 6)],
                    "overlap_volume": round(overlap_volume, 9),
                }
            )
    return round(volume, 9), round(max_x_overlap, 6), pairs


def _repair_bed_cluster_side_wall_storage_collision(
    plan: dict[str, Any],
    scene_graph: dict[str, Any],
    report: dict[str, Any],
) -> None:
    room = plan.get("room") if isinstance(plan.get("room"), dict) else {}
    if not room:
        return
    objects = {str(obj.get("id")): obj for obj in plan.get("objects", []) if isinstance(obj, dict) and obj.get("id")}
    beds = [obj for obj in objects.values() if _is_bed_or_sofa_object(obj)]
    if len(beds) != 1:
        return
    bed = beds[0]
    bed_id = str(bed.get("id") or "")
    cluster_ids = _bed_lateral_shift_cluster_ids(objects, scene_graph, bed_id)
    by_wall = _side_wall_floor_storage_ids_for_bed_cluster(objects, cluster_ids)
    wall_scores: list[tuple[float, float, str, list[dict[str, Any]]]] = []
    for wall_id, storage_ids in by_wall.items():
        score, max_x_overlap, pairs = _cluster_vs_storage_overlap_score(objects, cluster_ids, storage_ids)
        if score > 0.0 and pairs:
            wall_scores.append((score, max_x_overlap, wall_id, pairs))
    if not wall_scores:
        return
    current_score, max_x_overlap, wall_id, pairs = max(wall_scores, key=lambda item: (item[0], item[1]))
    direction = -1.0 if wall_id == "wall_east" else 1.0
    requested_dx = direction * _clamp(max(0.12, max_x_overlap + 0.08), 0.0, 0.45)
    candidate_objects = json.loads(json.dumps(objects))
    candidate_changed = _shift_cluster_x(candidate_objects, cluster_ids, requested_dx, room)
    if not candidate_changed:
        return
    candidate_by_wall = _side_wall_floor_storage_ids_for_bed_cluster(candidate_objects, cluster_ids)
    candidate_score, _candidate_x_overlap, candidate_pairs = _cluster_vs_storage_overlap_score(
        candidate_objects,
        cluster_ids,
        candidate_by_wall.get(wall_id, []),
    )
    if candidate_score >= current_score - 1e-6:
        return
    changed = _shift_cluster_x(objects, cluster_ids, requested_dx, room)
    if not changed:
        return
    report["fixes"].append(
        {
            "stage": report.get("stage"),
            "type": "bed_cluster_side_wall_storage_collision_shift",
            "bed_id": bed_id,
            "wall_id": wall_id,
            "requested_delta_x": round(float(requested_dx), 6),
            "collision_score_before": current_score,
            "collision_score_after": candidate_score,
            "offending_pairs_before": pairs,
            "offending_pairs_after": candidate_pairs,
            "cluster_ids": sorted(cluster_ids),
            "changed": changed,
            "evidence": (
                "Side-wall storage is still in the physical floor collision domain. "
                "When a bedside/bed visual cluster penetrates against-wall storage, move the whole bed cluster away from that wall."
            ),
        }
    )


def _is_wall_door_object(obj: dict[str, Any]) -> bool:
    text = _object_identity_text(obj)
    if any(keyword in text for keyword in ("window", "curtain", "mirror", "art", "picture", "painting", "poster")):
        return False
    identity = _functional_cluster_primary_identity_text(obj)
    object_id = _functional_cluster_id_text(obj)
    category = str(obj.get("category") or "").strip().lower().replace("_", " ")
    storage_terms = ("wardrobe", "dresser", "cabinet", "chest", "nightstand", "bookcase", "bookshelf", "shelving")
    if any(term in identity for term in storage_terms) or any(term in category for term in storage_terms):
        explicit_room_door = (
            re.search(r"\b(entry|interior|room|closet|sliding|double)\s+door\b", identity) is not None
            or re.search(r"\bdoor\b", object_id) is not None
            or category in {"door", "interior door", "entry door", "closet door", "double closet door"}
        )
        if not explicit_room_door:
            return False
    if "closet door" in text or "closet_door" in text or ("closet" in text and "door" in text):
        return True
    if "closet" in text:
        return False
    return any(keyword in text for keyword in ("door", "closet door", "entry door"))


def _object_wall_id_for_same_wall_separation(
    object_id: str,
    obj: dict[str, Any],
    cross_constraints: list[dict[str, Any]],
    parent: dict[str, str],
) -> str | None:
    support_id = str(obj.get("support_id") or "")
    if support_id in VIRTUAL_WALLS:
        return support_id
    wall_id = _hard_wall_relation_for_object(object_id, cross_constraints, parent)
    if wall_id in VIRTUAL_WALLS:
        return wall_id
    wall_id = _wall_relation_for_object(object_id, cross_constraints, parent)
    if wall_id in VIRTUAL_WALLS:
        return wall_id
    relation = _semantic_wall_relation(obj)
    mode = str(relation.get("mode") or "").strip().lower()
    semantic_wall = _wall_id(relation.get("wall_id"))
    if mode in {"against", "attached", "mounted", "wall_flush", "near"} and semantic_wall in VIRTUAL_WALLS:
        return semantic_wall
    return None


def _same_wall_tangent_span(obj: dict[str, Any], tangent_axis: int) -> tuple[float, float, float]:
    min_v, max_v = _bbox_for_object(obj)
    low = float(min_v[tangent_axis])
    high = float(max_v[tangent_axis])
    return low, high, max(0.0, high - low)


def _per_wall_relation_member_role(obj: dict[str, Any]) -> str | None:
    if _is_floor_covering(obj):
        return None
    if _is_wall_door_object(obj):
        return "room_door"
    if _functional_cluster_is_window_object(obj):
        return "window"
    if _is_curtain_rod_object(obj):
        return "curtain_rod"
    if _functional_cluster_is_curtain_object(obj):
        return "curtain"
    if _is_hanging_object(obj):
        return None
    if _is_wall_attached_object(obj):
        return "wall_attached"
    if _is_floor_storage_or_table_branch_object(obj):
        return "wall_storage"
    return None


def _same_wall_pair_allows_tangent_overlap(role_a: str | None, role_b: str | None) -> bool:
    roles = {role_a, role_b}
    if "room_door" in roles and "wall_storage" in roles:
        return False
    if "wall_storage" in roles and ("curtain" in roles or "window" in roles or "wall_attached" in roles):
        return True
    if "curtain_rod" in roles and roles <= {"curtain_rod", "curtain", "window", "wall_attached"}:
        return True
    if roles == {"window", "curtain"}:
        return True
    if "curtain" in roles:
        return False
    if roles == {"window", "wall_attached"}:
        return False
    if role_a == "wall_attached" and role_b == "wall_attached":
        return True
    if "wall_attached" in roles and "wall_storage" in roles:
        return True
    return True


def _object_reference_center_for_axis(
    object_id: str,
    ref_bboxes: dict[str, list[float]],
    axis: int,
) -> float | None:
    bbox = ref_bboxes.get(object_id)
    if not bbox:
        return None
    if axis == 1:
        return (float(bbox[1]) + float(bbox[3])) / 2.0
    return (float(bbox[0]) + float(bbox[2])) / 2.0


def _same_wall_pair_reference_relation(scene_graph: dict[str, Any], a_id: str, b_id: str) -> list[dict[str, Any]]:
    relations: list[dict[str, Any]] = []
    for rel in scene_graph.get("relations", []) if isinstance(scene_graph.get("relations"), list) else []:
        if not isinstance(rel, dict):
            continue
        subject = str(rel.get("subject") or "")
        target = str(rel.get("object") or "")
        if {subject, target} != {a_id, b_id}:
            continue
        relations.append(
            {
                "subject": subject,
                "type": str(rel.get("type") or ""),
                "object": target,
                "confidence": rel.get("confidence"),
            }
        )
    return relations


def _reference_overlap_ratio_for_wall_tangent_closeness(
    ref_bboxes: dict[str, list[float]],
    wall_id: str,
    a_id: str,
    b_id: str,
) -> float | None:
    a_bbox = ref_bboxes.get(a_id)
    b_bbox = ref_bboxes.get(b_id)
    if not a_bbox or not b_bbox:
        return None
    axis = 1 if wall_id in {"wall_east", "wall_west"} else 0
    a_low = float(a_bbox[axis])
    a_high = float(a_bbox[axis + 2])
    b_low = float(b_bbox[axis])
    b_high = float(b_bbox[axis + 2])
    a_span = max(1e-6, a_high - a_low)
    b_span = max(1e-6, b_high - b_low)
    overlap = max(0.0, min(a_high, b_high) - max(a_low, b_low))
    return overlap / max(1e-6, min(a_span, b_span))


def _same_wall_door_storage_reference_close(
    ref_bboxes: dict[str, list[float]],
    wall_id: str,
    door_id: str,
    storage_id: str,
) -> bool:
    overlap_ratio = _reference_overlap_ratio_for_wall_tangent_closeness(ref_bboxes, wall_id, door_id, storage_id)
    if overlap_ratio is None:
        return False
    return overlap_ratio >= 0.45


def _scene_graph_wall_id_for_object(
    object_id: str,
    obj: dict[str, Any],
    relations: list[dict[str, Any]],
) -> str | None:
    support_hint = str(obj.get("support_hint") or obj.get("support_id") or "").strip()
    if support_hint in VIRTUAL_WALLS:
        return support_hint
    semantic_wall = _wall_id(_semantic_wall_relation(obj).get("wall_id"))
    if semantic_wall in VIRTUAL_WALLS:
        return semantic_wall
    functional_wall = _functional_cluster_wall_id(obj)
    if functional_wall in VIRTUAL_WALLS:
        return functional_wall
    for rel in relations:
        if str(rel.get("subject") or "") != object_id:
            continue
        target = str(rel.get("object") or "")
        if target not in VIRTUAL_WALLS:
            continue
        if str(rel.get("type") or "") in WALL_RELATIONS | {"against_wall", "attached_to", "mounted_on"}:
            return target
    return None


def _wall_corner_id_for_tangent_end(wall_id: str, end: str) -> str | None:
    if wall_id == "wall_east":
        return "northeast" if end == "high" else "southeast"
    if wall_id == "wall_west":
        return "northwest" if end == "high" else "southwest"
    if wall_id == "wall_north":
        return "northeast" if end == "high" else "northwest"
    if wall_id == "wall_south":
        return "southeast" if end == "high" else "southwest"
    return None


def _corner_tangent_end(corner_id: str, wall_id: str) -> str | None:
    corner = str(corner_id or "").lower()
    if wall_id in {"wall_east", "wall_west"}:
        if "north" in corner:
            return "high"
        if "south" in corner:
            return "low"
    if wall_id in {"wall_north", "wall_south"}:
        if "east" in corner:
            return "high"
        if "west" in corner:
            return "low"
    return None


def build_wall_local_layout_plan(scene_graph: dict[str, Any]) -> dict[str, Any]:
    report: dict[str, Any] = {
        "schema": "tree_sage_wall_local_layout_plan_v1",
        "enabled": True,
        "walls": {},
        "pair_orders": [],
        "corner_affinities": [],
        "warnings": [],
        "ok": True,
    }
    objects = {
        str(obj.get("id")): obj
        for obj in scene_graph.get("objects", [])
        if isinstance(obj, dict) and obj.get("id")
    } if isinstance(scene_graph.get("objects"), list) else {}
    if not objects:
        report["reason"] = "missing_objects"
        return report
    relations = [rel for rel in scene_graph.get("relations", []) if isinstance(rel, dict)] if isinstance(scene_graph.get("relations"), list) else []
    ref_bboxes = _reference_bboxes_by_object(scene_graph)
    ref_depths = _reference_depths_by_object(scene_graph)
    wall_members: dict[str, list[dict[str, Any]]] = {wall_id: [] for wall_id in sorted(VIRTUAL_WALLS)}
    for object_id, obj in objects.items():
        role = _per_wall_relation_member_role(obj)
        if not role:
            continue
        wall_id = _scene_graph_wall_id_for_object(object_id, obj, relations)
        if wall_id not in VIRTUAL_WALLS:
            continue
        bbox = ref_bboxes.get(object_id)
        depth = _reference_depth_for_profile(ref_depths, object_id, min_confidence=0.35)
        center_x = ((float(bbox[0]) + float(bbox[2])) / 2.0) if bbox else None
        center_y = ((float(bbox[1]) + float(bbox[3])) / 2.0) if bbox else None
        member = {
            "id": object_id,
            "role": role,
            "wall_id": wall_id,
            "bbox": bbox,
            "bbox_center": [
                round(float(center_x), 6) if center_x is not None else None,
                round(float(center_y), 6) if center_y is not None else None,
            ],
            "reference_frontness": round(float(depth["frontness"]), 6) if depth else None,
            "reference_depth_confidence": round(float(depth.get("confidence", 0.0)), 6) if depth else None,
        }
        wall_members[wall_id].append(member)

    for wall_id, members in wall_members.items():
        if not members:
            continue
        tangent_axis = _wall_tangent_axis(wall_id)
        axis_name = "y" if tangent_axis == 1 else "x"
        wall_report = {
            "wall_id": wall_id,
            "tangent_axis": axis_name,
            "members": members,
            "tangent_order": [],
            "order_source": None,
        }
        pair_order_keys: set[tuple[str, str]] = set()

        def add_wall_pair_order(
            low_id: str,
            high_id: str,
            *,
            source: str,
            confidence: float,
            evidence: str,
            extra: dict[str, Any] | None = None,
        ) -> None:
            if not low_id or not high_id or low_id == high_id:
                return
            key = (str(low_id), str(high_id))
            reverse_key = (str(high_id), str(low_id))
            if key in pair_order_keys or reverse_key in pair_order_keys:
                return
            item = {
                "wall_id": wall_id,
                "axis": axis_name,
                "front_id": low_id,
                "back_id": high_id,
                "expected_low_tangent_id": low_id,
                "expected_high_tangent_id": high_id,
                "source": source,
                "confidence": round(float(_clamp(confidence, 0.0, 1.0)), 6),
                "evidence": evidence,
            }
            if extra:
                item.update(extra)
            report["pair_orders"].append(item)
            pair_order_keys.add(key)

        if wall_id in {"wall_east", "wall_west"}:
            depth_members = [m for m in members if m.get("reference_frontness") is not None]
            if len(depth_members) >= 2:
                wall_report["tangent_order"] = [
                    str(m["id"]) for m in sorted(depth_members, key=lambda item: (-float(item["reference_frontness"]), str(item["id"])))
                ]
                wall_report["order_source"] = "reference_depth_frontness_front_to_back"
                for index, front_member in enumerate(wall_report["tangent_order"]):
                    for back_member in wall_report["tangent_order"][index + 1 :]:
                        frontness_a = next(float(m["reference_frontness"]) for m in depth_members if m["id"] == front_member)
                        frontness_b = next(float(m["reference_frontness"]) for m in depth_members if m["id"] == back_member)
                        gap = abs(frontness_a - frontness_b)
                        if gap < 0.055:
                            continue
                        add_wall_pair_order(
                            str(front_member),
                            str(back_member),
                            source="reference_depth_frontness",
                            confidence=min(0.95, 0.45 + gap),
                            evidence="For side-wall objects, higher reference frontness means closer to the viewer and lower room-y tangent placement.",
                            extra={"frontness_gap": round(float(gap), 6)},
                        )
            edge_members = [m for m in members if m.get("bbox_center", [None, None])[0] is not None]
            if len(edge_members) >= 2:
                edge_order = [
                    str(m["id"])
                    for m in sorted(
                        edge_members,
                        key=lambda item: (float(item["bbox_center"][0]), str(item["id"])),
                        reverse=(wall_id == "wall_east"),
                    )
                ]
                if not wall_report["tangent_order"]:
                    wall_report["tangent_order"] = edge_order
                    wall_report["order_source"] = "side_wall_image_edge_order"
                for index, low_member in enumerate(edge_order):
                    low_x = next(float(m["bbox_center"][0]) for m in edge_members if m["id"] == low_member)
                    for high_member in edge_order[index + 1 :]:
                        high_x = next(float(m["bbox_center"][0]) for m in edge_members if m["id"] == high_member)
                        gap_x = abs(low_x - high_x)
                        if gap_x < 0.035:
                            continue
                        low_role = next(str(m.get("role") or "") for m in edge_members if m["id"] == low_member)
                        high_role = next(str(m.get("role") or "") for m in edge_members if m["id"] == high_member)
                        if (
                            "curtain" not in {low_role, high_role}
                            and "curtain_rod" not in {low_role, high_role}
                            and "window" not in {low_role, high_role}
                            and "wall_attached" not in {low_role, high_role}
                        ):
                            continue
                        add_wall_pair_order(
                            str(low_member),
                            str(high_member),
                            source="side_wall_image_edge_order",
                            confidence=min(0.82, 0.50 + gap_x * 1.8),
                            evidence=(
                                "For side-wall wall-mounted/window/curtain objects, the image edge side disambiguates along-wall "
                                "front/back when depth samples are missing or too sparse: west wall uses smaller image-x as the "
                                "front/outside low tangent; east wall uses larger image-x as the front/outside low tangent."
                            ),
                            extra={"image_x_gap": round(float(gap_x), 6)},
                        )
        else:
            bbox_members = [m for m in members if m.get("bbox_center", [None, None])[0] is not None]
            wall_report["tangent_order"] = [
                str(m["id"]) for m in sorted(bbox_members, key=lambda item: (float(item["bbox_center"][0]), str(item["id"])))
            ]
            wall_report["order_source"] = "reference_bbox_x_left_to_right"

        for member in members:
            if member.get("role") != "wall_storage":
                continue
            bbox = member.get("bbox")
            frontness = member.get("reference_frontness")
            backness = (1.0 - float(frontness)) if frontness is not None else None
            if wall_id in {"wall_east", "wall_west"} and bbox:
                bbox_top = float(bbox[1])
                bbox_bottom = float(bbox[3])
                bbox_height = max(0.0, bbox_bottom - bbox_top)
                if bbox_top <= 0.23 and bbox_height >= 0.42 and (backness is None or backness >= 0.52):
                    corner_id = _wall_corner_id_for_tangent_end(wall_id, "high")
                    if corner_id:
                        affinity = {
                            "id": member["id"],
                            "wall_id": wall_id,
                            "corner_id": corner_id,
                            "tangent_end": "high",
                            "source": "reference_bbox_top_edge_and_depth",
                            "confidence": round(float(min(0.92, 0.58 + (backness or 0.0) * 0.35)), 6),
                            "evidence": "Tall side-wall storage reaches high in the reference crop and has rear/deeper depth evidence, so it should occupy the rear side-wall corner.",
                        }
                        report["corner_affinities"].append(affinity)
                elif bbox_bottom >= 0.88 and bbox_height >= 0.35 and frontness is not None and float(frontness) >= 0.56:
                    corner_id = _wall_corner_id_for_tangent_end(wall_id, "low")
                    if corner_id:
                        report["corner_affinities"].append(
                            {
                                "id": member["id"],
                                "wall_id": wall_id,
                                "corner_id": corner_id,
                                "tangent_end": "low",
                                "source": "reference_bbox_bottom_edge_and_depth",
                                "confidence": 0.74,
                                "evidence": "Side-wall storage reaches the lower/front edge of the reference and has foreground depth evidence.",
                            }
                        )
        report["walls"][wall_id] = wall_report
    report["pair_order_count"] = len(report["pair_orders"])
    report["corner_affinity_count"] = len(report["corner_affinities"])
    scene_graph["_wall_local_layout_plan"] = report
    return report


def _wall_local_pair_order(scene_graph: dict[str, Any], wall_id: str, a_id: str, b_id: str) -> dict[str, Any] | None:
    plan = scene_graph.get("_wall_local_layout_plan") if isinstance(scene_graph.get("_wall_local_layout_plan"), dict) else {}
    for item in plan.get("pair_orders", []) if isinstance(plan.get("pair_orders"), list) else []:
        if not isinstance(item, dict) or str(item.get("wall_id") or "") != wall_id:
            continue
        low_id = str(item.get("expected_low_tangent_id") or "")
        high_id = str(item.get("expected_high_tangent_id") or "")
        if {low_id, high_id} == {str(a_id), str(b_id)}:
            return item
    return None


def _wall_corner_affinity_for_object(scene_graph: dict[str, Any], object_id: str, wall_id: str) -> dict[str, Any] | None:
    plan = scene_graph.get("_wall_local_layout_plan") if isinstance(scene_graph.get("_wall_local_layout_plan"), dict) else {}
    for item in plan.get("corner_affinities", []) if isinstance(plan.get("corner_affinities"), list) else []:
        if not isinstance(item, dict):
            continue
        if str(item.get("id") or "") == str(object_id) and str(item.get("wall_id") or "") == str(wall_id):
            return item
    return None


def _corner_target_tangent_center(
    obj: dict[str, Any],
    room: dict[str, Any],
    wall_id: str,
    corner_id: str,
    tangent_axis: int,
) -> float | None:
    end = _corner_tangent_end(corner_id, wall_id)
    if end not in {"low", "high"}:
        return None
    _low, _high, span = _same_wall_tangent_span(obj, tangent_axis)
    room_extent = float(room.get("length" if tangent_axis == 1 else "width", 0.0) or 0.0)
    if room_extent <= 0.0 or span <= 0.0:
        return None
    if end == "high":
        return room_extent - span / 2.0 - FLOOR_WALL_AGAINST_GAP
    return span / 2.0 + FLOOR_WALL_AGAINST_GAP


def _move_same_wall_object_along_tangent(
    obj: dict[str, Any],
    object_id: str,
    target_center: float,
    wall_id: str,
    tangent_axis: int,
    room: dict[str, Any],
    objects: dict[str, dict[str, Any]],
) -> dict[str, Any]:
    before = _plan_object_snapshot(obj)
    old_x = float(obj.get("x", 0.0) or 0.0)
    old_y = float(obj.get("y", 0.0) or 0.0)
    axis_key = "y" if tangent_axis == 1 else "x"
    obj[axis_key] = float(target_center)
    placement = str(obj.get("placement_type") or "floor")
    support_id = str(obj.get("support_id") or "")
    if placement == "attached_to_wall" or support_id in VIRTUAL_WALLS:
        obj["placement_type"] = "attached_to_wall" if placement == "attached_to_wall" else placement
        obj["support_id"] = wall_id if placement == "attached_to_wall" else obj.get("support_id")
        if placement == "attached_to_wall":
            obj["yaw"] = _wall_semantic_yaw(wall_id)
            obj["footprint_yaw_offset_degrees"] = _wall_footprint_offset_for_object(wall_id, obj)
            _clamp_wall_attached_object(obj, room, wall_id)
        else:
            _clamp_floor_object_against_wall(obj, room, wall_id)
    else:
        _clamp_floor_object_against_wall(obj, room, wall_id)
    dx = float(obj.get("x", old_x) or old_x) - old_x
    dy = float(obj.get("y", old_y) or old_y) - old_y
    moved_children = _move_direct_supported_children(objects, object_id, dx, dy, room)
    return {
        "before": before,
        "after": _plan_object_snapshot(obj),
        "delta": [round(float(dx), 6), round(float(dy), 6)],
        "moved_children": moved_children,
    }


def _repair_same_wall_door_storage_tangent_pair(
    plan: dict[str, Any],
    objects: dict[str, dict[str, Any]],
    wall_id: str,
    door_id: str,
    storage_id: str,
    tangent_axis: int,
    min_clearance: float,
    *,
    expected_low_tangent_id: str | None = None,
    storage_corner_id: str | None = None,
    max_gap: float | None = None,
) -> dict[str, Any] | None:
    room = plan.get("room") if isinstance(plan.get("room"), dict) else {}
    door = objects.get(door_id)
    storage = objects.get(storage_id)
    if not door or not storage:
        return None
    door_low, door_high, door_span = _same_wall_tangent_span(door, tangent_axis)
    storage_low, storage_high, storage_span = _same_wall_tangent_span(storage, tangent_axis)
    if door_span <= 0.0 or storage_span <= 0.0:
        return None
    room_extent = float(room.get("length" if tangent_axis == 1 else "width", 0.0) or 0.0)
    if room_extent <= 0.0:
        return None
    current_gap = max(storage_low - door_high, door_low - storage_high, 0.0)
    overlap = max(0.0, min(door_high, storage_high) - max(door_low, storage_low))
    door_center = (door_low + door_high) / 2.0
    storage_center = (storage_low + storage_high) / 2.0
    expected_low = str(expected_low_tangent_id or "").strip()
    order_ok = True
    if expected_low == door_id:
        order_ok = door_center < storage_center - 1e-6
    elif expected_low == storage_id:
        order_ok = storage_center < door_center - 1e-6
    storage_corner_target = (
        _corner_target_tangent_center(storage, room, wall_id, storage_corner_id, tangent_axis)
        if storage_corner_id
        else None
    )
    corner_ok = True
    if storage_corner_target is not None:
        corner_tolerance = max(0.14, room_extent * 0.035)
        corner_ok = abs(float(storage_corner_target) - storage_center) <= corner_tolerance
    max_gap_ok = max_gap is None or current_gap <= float(max_gap)
    if overlap <= 1e-6 and current_gap >= min_clearance and order_ok and corner_ok and max_gap_ok:
        return None
    moves: list[dict[str, Any]] = []

    if storage_corner_target is not None:
        storage_center = (storage_low + storage_high) / 2.0
        if abs(float(storage_corner_target) - storage_center) >= 0.06:
            corner_move = _move_same_wall_object_along_tangent(
                storage,
                storage_id,
                float(storage_corner_target),
                wall_id,
                tangent_axis,
                room,
                objects,
            )
            if corner_move["before"] != corner_move["after"]:
                moves.append({"id": storage_id, "reason": "storage_corner_affinity", **corner_move})
        door_low, door_high, door_span = _same_wall_tangent_span(door, tangent_axis)
        storage_low, storage_high, storage_span = _same_wall_tangent_span(storage, tangent_axis)

    low_bound = door_span / 2.0 + FLOOR_WALL_AGAINST_GAP
    high_bound = room_extent - door_span / 2.0 - FLOOR_WALL_AGAINST_GAP
    storage_low_bound = storage_span / 2.0 + FLOOR_WALL_AGAINST_GAP
    storage_high_bound = room_extent - storage_span / 2.0 - FLOOR_WALL_AGAINST_GAP
    if expected_low == door_id:
        desired_door_center = storage_low - min_clearance - door_span / 2.0
        desired_door_center = _clamp(desired_door_center, low_bound, high_bound)
        if desired_door_center > storage_low - min_clearance - door_span / 2.0 + 1e-6:
            desired_storage_center = door_high + min_clearance + storage_span / 2.0
            desired_storage_center = _clamp(desired_storage_center, storage_low_bound, storage_high_bound)
            storage_move = _move_same_wall_object_along_tangent(
                storage,
                storage_id,
                desired_storage_center,
                wall_id,
                tangent_axis,
                room,
                objects,
            )
            if storage_move["before"] != storage_move["after"]:
                moves.append({"id": storage_id, "reason": "wall_local_order_storage_after_door", **storage_move})
            door_low, door_high, door_span = _same_wall_tangent_span(door, tangent_axis)
            storage_low, storage_high, storage_span = _same_wall_tangent_span(storage, tangent_axis)
            desired_door_center = _clamp(storage_low - min_clearance - door_span / 2.0, low_bound, high_bound)
        door_move = _move_same_wall_object_along_tangent(
            door,
            door_id,
            desired_door_center,
            wall_id,
            tangent_axis,
            room,
            objects,
        )
        if door_move["before"] != door_move["after"]:
            moves.append({"id": door_id, "reason": "wall_local_order_door_before_storage", **door_move})
    elif expected_low == storage_id:
        desired_storage_center = door_low - min_clearance - storage_span / 2.0
        desired_storage_center = _clamp(desired_storage_center, storage_low_bound, storage_high_bound)
        storage_move = _move_same_wall_object_along_tangent(
            storage,
            storage_id,
            desired_storage_center,
            wall_id,
            tangent_axis,
            room,
            objects,
        )
        if storage_move["before"] != storage_move["after"]:
            moves.append({"id": storage_id, "reason": "wall_local_order_storage_before_door", **storage_move})
    else:
        storage_center = (storage_low + storage_high) / 2.0
        door_center = (door_low + door_high) / 2.0
        storage_before_door = storage_center <= door_center
        if storage_before_door:
            desired_storage_center = door_low - min_clearance - storage_span / 2.0
        else:
            desired_storage_center = door_high + min_clearance + storage_span / 2.0
        desired_storage_center = _clamp(desired_storage_center, storage_low_bound, storage_high_bound)
        storage_move = _move_same_wall_object_along_tangent(
            storage,
            storage_id,
            desired_storage_center,
            wall_id,
            tangent_axis,
            room,
            objects,
        )
        if storage_move["before"] != storage_move["after"]:
            moves.append({"id": storage_id, "reason": "preserve_current_order_tangent_separation", **storage_move})

    new_door_low, new_door_high, _ = _same_wall_tangent_span(door, tangent_axis)
    new_storage_low, new_storage_high, _ = _same_wall_tangent_span(storage, tangent_axis)
    new_gap = max(new_storage_low - new_door_high, new_door_low - new_storage_high, 0.0)
    new_overlap = max(0.0, min(new_door_high, new_storage_high) - max(new_door_low, new_storage_low))
    if not moves and new_overlap > 1e-6:
        return None
    max_gap_ok_after = max_gap is None or new_gap <= float(max_gap) + 1e-6
    final_door_center = (new_door_low + new_door_high) / 2.0
    final_storage_center = (new_storage_low + new_storage_high) / 2.0
    return {
        "type": "per_wall_room_door_storage_tangent_separation",
        "wall_id": wall_id,
        "door_id": door_id,
        "storage_id": storage_id,
        "axis": "y" if tangent_axis == 1 else "x",
        "moves": moves,
        "gap_before": round(float(current_gap), 6),
        "overlap_before": round(float(overlap), 6),
        "gap_after": round(float(new_gap), 6),
        "overlap_after": round(float(new_overlap), 6),
        "max_gap_ok_after": bool(max_gap_ok_after),
        "min_clearance": round(float(min_clearance), 6),
        "max_gap": round(float(max_gap), 6) if max_gap is not None else None,
        "expected_low_tangent_id": expected_low_tangent_id,
        "storage_corner_id": storage_corner_id,
        "final_tangent_centers": {
            door_id: round(float(final_door_center), 6),
            storage_id: round(float(final_storage_center), 6),
        },
        "evidence": (
            "Objects sharing the same wall need a wall-local tangent audit. "
            "A room door and wall storage can be globally ordered in image space while still overlapping along the actual wall."
        ),
    }


def _repair_same_wall_generic_tangent_pair(
    plan: dict[str, Any],
    objects: dict[str, dict[str, Any]],
    wall_id: str,
    a_id: str,
    b_id: str,
    tangent_axis: int,
    min_clearance: float,
    *,
    expected_low_tangent_id: str | None = None,
) -> dict[str, Any] | None:
    room = plan.get("room") if isinstance(plan.get("room"), dict) else {}
    a_obj = objects.get(a_id)
    b_obj = objects.get(b_id)
    if not room or not a_obj or not b_obj:
        return None
    room_extent = float(room.get("length" if tangent_axis == 1 else "width", 0.0) or 0.0)
    if room_extent <= 0.0:
        return None
    a_low, a_high, a_span = _same_wall_tangent_span(a_obj, tangent_axis)
    b_low, b_high, b_span = _same_wall_tangent_span(b_obj, tangent_axis)
    if min(a_span, b_span) <= 0.0:
        return None
    expected_low = str(expected_low_tangent_id or "").strip()
    if expected_low == a_id:
        low_id, high_id = a_id, b_id
    elif expected_low == b_id:
        low_id, high_id = b_id, a_id
    else:
        a_center = (a_low + a_high) / 2.0
        b_center = (b_low + b_high) / 2.0
        low_id, high_id = (a_id, b_id) if a_center <= b_center else (b_id, a_id)
    low_obj = objects[low_id]
    high_obj = objects[high_id]
    low_low, low_high, low_span = _same_wall_tangent_span(low_obj, tangent_axis)
    high_low, high_high, high_span = _same_wall_tangent_span(high_obj, tangent_axis)
    current_gap = max(high_low - low_high, low_low - high_high, 0.0)
    current_overlap = max(0.0, min(low_high, high_high) - max(low_low, high_low))
    order_ok = (low_low + low_high) / 2.0 < (high_low + high_high) / 2.0 - 1e-6
    if current_overlap <= 1e-6 and current_gap >= min_clearance and order_ok:
        return None

    moves: list[dict[str, Any]] = []

    def bounds_for_span(span: float) -> tuple[float, float]:
        return span / 2.0 + FLOOR_WALL_AGAINST_GAP, room_extent - span / 2.0 - FLOOR_WALL_AGAINST_GAP

    low_bound, high_bound = bounds_for_span(low_span)
    desired_low_center = high_low - min_clearance - low_span / 2.0
    desired_low_center = _clamp(desired_low_center, low_bound, high_bound)
    low_move = _move_same_wall_object_along_tangent(
        low_obj,
        low_id,
        desired_low_center,
        wall_id,
        tangent_axis,
        room,
        objects,
    )
    if low_move["before"] != low_move["after"]:
        moves.append({"id": low_id, "reason": "wall_local_order_low_before_high", **low_move})

    low_low, low_high, low_span = _same_wall_tangent_span(low_obj, tangent_axis)
    high_low, high_high, high_span = _same_wall_tangent_span(high_obj, tangent_axis)
    overlap = max(0.0, min(low_high, high_high) - max(low_low, high_low))
    gap = max(high_low - low_high, low_low - high_high, 0.0)
    order_ok = (low_low + low_high) / 2.0 < (high_low + high_high) / 2.0 - 1e-6
    if overlap > 1e-6 or gap < min_clearance or not order_ok:
        high_bound_low, high_bound_high = bounds_for_span(high_span)
        desired_high_center = low_high + min_clearance + high_span / 2.0
        desired_high_center = _clamp(desired_high_center, high_bound_low, high_bound_high)
        high_move = _move_same_wall_object_along_tangent(
            high_obj,
            high_id,
            desired_high_center,
            wall_id,
            tangent_axis,
            room,
            objects,
        )
        if high_move["before"] != high_move["after"]:
            moves.append({"id": high_id, "reason": "wall_local_order_high_after_low", **high_move})

    final_a_low, final_a_high, _ = _same_wall_tangent_span(a_obj, tangent_axis)
    final_b_low, final_b_high, _ = _same_wall_tangent_span(b_obj, tangent_axis)
    final_gap = max(final_b_low - final_a_high, final_a_low - final_b_high, 0.0)
    final_overlap = max(0.0, min(final_a_high, final_b_high) - max(final_a_low, final_b_low))
    final_low_low, final_low_high, _ = _same_wall_tangent_span(low_obj, tangent_axis)
    final_high_low, final_high_high, _ = _same_wall_tangent_span(high_obj, tangent_axis)
    final_order_ok = (final_low_low + final_low_high) / 2.0 < (final_high_low + final_high_high) / 2.0 - 1e-6
    if not moves:
        return None
    return {
        "type": "per_wall_generic_tangent_separation",
        "wall_id": wall_id,
        "a_id": a_id,
        "b_id": b_id,
        "low_id": low_id,
        "high_id": high_id,
        "axis": "y" if tangent_axis == 1 else "x",
        "moves": moves,
        "gap_before": round(float(current_gap), 6),
        "overlap_before": round(float(current_overlap), 6),
        "gap_after": round(float(final_gap), 6),
        "overlap_after": round(float(final_overlap), 6),
        "order_ok_after": bool(final_order_ok),
        "min_clearance": round(float(min_clearance), 6),
        "expected_low_tangent_id": expected_low_tangent_id,
        "evidence": (
            "Same-wall wall-mounted objects such as curtains, windows, and wall art need an explicit tangent-order "
            "repair; aggregate collision repair alone cannot decide which wall item should move outward or inward."
        ),
    }


def audit_and_repair_per_wall_object_relations(
    plan: dict[str, Any],
    scene_graph: dict[str, Any],
    cross_constraints: list[dict[str, Any]],
    parent: dict[str, str],
    *,
    enabled: bool = True,
    repair: bool = True,
    stage: str = "reference_consistency",
) -> dict[str, Any]:
    report: dict[str, Any] = {
        "schema": "tree_sage_per_wall_object_relation_audit_v1",
        "enabled": bool(enabled),
        "stage": stage,
        "repair": bool(repair),
        "checks": [],
        "fixes": [],
        "warnings": [],
        "ok": True,
    }
    if not enabled:
        report["reason"] = "disabled"
        return report
    room = plan.get("room") if isinstance(plan.get("room"), dict) else {}
    if not room:
        report["reason"] = "missing_room"
        report["ok"] = False
        return report
    objects = {str(obj.get("id")): obj for obj in plan.get("objects", []) if isinstance(obj, dict) and obj.get("id")}
    if not objects:
        report["reason"] = "missing_objects"
        return report
    # Scene graph relations and object membership can change after the initial
    # wall-local plan is built, e.g. bedside false positives are removed or
    # wall semantics are materialized. Rebuild here so the audit never consumes
    # stale same-wall ordering.
    build_wall_local_layout_plan(scene_graph)
    ref_bboxes = _reference_bboxes_by_object(scene_graph)

    wall_members: dict[str, list[dict[str, Any]]] = {wall_id: [] for wall_id in sorted(VIRTUAL_WALLS)}
    for object_id, obj in objects.items():
        role = _per_wall_relation_member_role(obj)
        if not role:
            continue
        wall_id = _object_wall_id_for_same_wall_separation(object_id, obj, cross_constraints, parent)
        if wall_id not in VIRTUAL_WALLS:
            continue
        wall_members[wall_id].append({"id": object_id, "obj": obj, "role": role})

    for wall_id, members in wall_members.items():
        if len(members) < 2:
            continue
        tangent_axis = _wall_tangent_axis(wall_id)
        axis_name = "y" if tangent_axis == 1 else "x"
        room_extent = float(room.get("length" if tangent_axis == 1 else "width", 0.0) or 0.0)
        min_clearance = _clamp(room_extent * 0.025, 0.06, 0.16) if room_extent > 0.0 else 0.08
        for index, member_a in enumerate(members):
            a_id = str(member_a["id"])
            a_obj = member_a["obj"]
            role_a = str(member_a["role"])
            for member_b in members[index + 1 :]:
                b_id = str(member_b["id"])
                b_obj = member_b["obj"]
                role_b = str(member_b["role"])
                a_low, a_high, a_span = _same_wall_tangent_span(a_obj, tangent_axis)
                b_low, b_high, b_span = _same_wall_tangent_span(b_obj, tangent_axis)
                overlap = max(0.0, min(a_high, b_high) - max(a_low, b_low))
                gap = max(b_low - a_high, a_low - b_high, 0.0)
                relations = _same_wall_pair_reference_relation(scene_graph, a_id, b_id)
                ref_a = _object_reference_center_for_axis(a_id, ref_bboxes, tangent_axis)
                ref_b = _object_reference_center_for_axis(b_id, ref_bboxes, tangent_axis)
                order_plan = _wall_local_pair_order(scene_graph, wall_id, a_id, b_id)
                expected_low_id = str(order_plan.get("expected_low_tangent_id") or "") if order_plan else ""
                expected_high_id = str(order_plan.get("expected_high_tangent_id") or "") if order_plan else ""
                center_by_id = {
                    a_id: (a_low + a_high) / 2.0,
                    b_id: (b_low + b_high) / 2.0,
                }
                order_violation = False
                if expected_low_id in center_by_id and expected_high_id in center_by_id:
                    order_violation = center_by_id[expected_low_id] > center_by_id[expected_high_id] - 1e-6
                corner_affinity_a = _wall_corner_affinity_for_object(scene_graph, a_id, wall_id)
                corner_affinity_b = _wall_corner_affinity_for_object(scene_graph, b_id, wall_id)
                reference_close_door_storage = False
                max_gap: float | None = None
                if {role_a, role_b} == {"room_door", "wall_storage"}:
                    door_id_for_close = a_id if role_a == "room_door" else b_id
                    storage_id_for_close = a_id if role_a == "wall_storage" else b_id
                    reference_close_door_storage = _same_wall_door_storage_reference_close(
                        ref_bboxes,
                        wall_id,
                        door_id_for_close,
                        storage_id_for_close,
                    )
                    if reference_close_door_storage:
                        max_gap = max(min_clearance * 1.5, min(0.42, room_extent * 0.08))
                corner_violations: list[dict[str, Any]] = []
                for corner_affinity, object_id, obj in (
                    (corner_affinity_a, a_id, a_obj),
                    (corner_affinity_b, b_id, b_obj),
                ):
                    if not corner_affinity:
                        continue
                    target_center = _corner_target_tangent_center(
                        obj,
                        room,
                        wall_id,
                        str(corner_affinity.get("corner_id") or ""),
                        tangent_axis,
                    )
                    if target_center is None:
                        continue
                    current_center = center_by_id[object_id]
                    delta = abs(float(target_center) - float(current_center))
                    tolerance = max(0.14, room_extent * 0.035)
                    if delta > tolerance:
                        corner_violations.append(
                            {
                                "id": object_id,
                                "corner_id": corner_affinity.get("corner_id"),
                                "target_center": round(float(target_center), 6),
                                "current_center": round(float(current_center), 6),
                                "delta": round(float(delta), 6),
                                "tolerance": round(float(tolerance), 6),
                            }
                        )
                requires_separation = not _same_wall_pair_allows_tangent_overlap(role_a, role_b)
                status = "ok"
                if requires_separation and overlap > 1e-6:
                    status = "tangent_overlap"
                elif requires_separation and gap < min_clearance:
                    status = "gap_too_small"
                elif requires_separation and max_gap is not None and gap > max_gap:
                    status = "gap_too_large"
                elif requires_separation and order_violation:
                    status = "tangent_order_violation"
                elif requires_separation and corner_violations:
                    status = "corner_affinity_violation"
                check = {
                    "wall_id": wall_id,
                    "axis": axis_name,
                    "a_id": a_id,
                    "b_id": b_id,
                    "a_role": role_a,
                    "b_role": role_b,
                    "a_span": [round(float(a_low), 6), round(float(a_high), 6)],
                    "b_span": [round(float(b_low), 6), round(float(b_high), 6)],
                    "tangent_overlap": round(float(overlap), 6),
                    "tangent_gap": round(float(gap), 6),
                    "min_clearance": round(float(min_clearance), 6),
                    "requires_separation": bool(requires_separation),
                    "reference_centers": {
                        a_id: round(float(ref_a), 6) if ref_a is not None else None,
                        b_id: round(float(ref_b), 6) if ref_b is not None else None,
                    },
                    "relations": relations,
                    "wall_local_order": order_plan,
                    "order_violation": bool(order_violation),
                    "corner_violations": corner_violations,
                    "reference_close_door_storage": bool(reference_close_door_storage),
                    "max_gap": round(float(max_gap), 6) if max_gap is not None else None,
                    "status": status,
                }
                report["checks"].append(check)
                if (
                    requires_separation
                    and status in {"tangent_overlap", "gap_too_small", "gap_too_large", "tangent_order_violation"}
                    and not any(str(rel.get("type") or "") in {"in_front_of", "behind"} for rel in relations)
                    and not order_plan
                    and wall_id in {"wall_east", "wall_west"}
                ):
                    report["warnings"].append(
                        {
                            "type": "missing_side_wall_tangent_relation",
                            "wall_id": wall_id,
                            "a_id": a_id,
                            "b_id": b_id,
                            "status": status,
                            "evidence": (
                                "For side-wall objects, image left/right is not enough to recover along-wall depth. "
                                "Planner should emit a wall-local tangent order or same-wall adjacency relation."
                            ),
                        }
                    )
                if not repair or not requires_separation or status == "ok":
                    continue
                storage_corner_id = None
                if role_a == "wall_storage" and corner_affinity_a:
                    storage_corner_id = str(corner_affinity_a.get("corner_id") or "")
                if role_b == "wall_storage" and corner_affinity_b:
                    storage_corner_id = str(corner_affinity_b.get("corner_id") or "")
                if role_a == "room_door" and role_b == "wall_storage":
                    fix = _repair_same_wall_door_storage_tangent_pair(
                        plan,
                        objects,
                        wall_id,
                        a_id,
                        b_id,
                        tangent_axis,
                        min_clearance,
                        expected_low_tangent_id=expected_low_id or None,
                        storage_corner_id=storage_corner_id,
                        max_gap=max_gap,
                    )
                elif role_b == "room_door" and role_a == "wall_storage":
                    fix = _repair_same_wall_door_storage_tangent_pair(
                        plan,
                        objects,
                        wall_id,
                        b_id,
                        a_id,
                        tangent_axis,
                        min_clearance,
                        expected_low_tangent_id=expected_low_id or None,
                        storage_corner_id=storage_corner_id,
                        max_gap=max_gap,
                    )
                else:
                    fix = _repair_same_wall_generic_tangent_pair(
                        plan,
                        objects,
                        wall_id,
                        a_id,
                        b_id,
                        tangent_axis,
                        min_clearance,
                        expected_low_tangent_id=expected_low_id or None,
                    )
                if fix:
                    fix["stage"] = stage
                    report["fixes"].append(fix)
                    post_a_low, post_a_high, _ = _same_wall_tangent_span(a_obj, tangent_axis)
                    post_b_low, post_b_high, _ = _same_wall_tangent_span(b_obj, tangent_axis)
                    post_overlap = max(0.0, min(post_a_high, post_b_high) - max(post_a_low, post_b_low))
                    post_gap = max(post_b_low - post_a_high, post_a_low - post_b_high, 0.0)
                    check["post_a_span"] = [round(float(post_a_low), 6), round(float(post_a_high), 6)]
                    check["post_b_span"] = [round(float(post_b_low), 6), round(float(post_b_high), 6)]
                    check["post_tangent_overlap"] = round(float(post_overlap), 6)
                    check["post_tangent_gap"] = round(float(post_gap), 6)
                    post_centers = {
                        a_id: (post_a_low + post_a_high) / 2.0,
                        b_id: (post_b_low + post_b_high) / 2.0,
                    }
                    post_order_violation = False
                    if expected_low_id in post_centers and expected_high_id in post_centers:
                        post_order_violation = post_centers[expected_low_id] > post_centers[expected_high_id] - 1e-6
                    check["post_order_violation"] = bool(post_order_violation)
                    check["status"] = (
                        "repaired"
                        if (
                            post_overlap <= 1e-6
                            and post_gap + 1e-6 >= min_clearance
                            and (max_gap is None or post_gap <= max_gap + 1e-6)
                            and not post_order_violation
                        )
                        else "repair_incomplete"
                    )
    report["fix_count"] = len(report["fixes"])
    report["warning_count"] = len(report["warnings"])
    report["ok"] = not any(
        check.get("requires_separation")
        and check.get("status") in {
            "tangent_overlap",
            "gap_too_small",
            "gap_too_large",
            "tangent_order_violation",
            "corner_affinity_violation",
            "repair_incomplete",
        }
        for check in report.get("checks", [])
    )
    return report


def _separate_same_wall_doors_from_storage_along_tangent(
    plan: dict[str, Any],
    scene_graph: dict[str, Any],
    cross_constraints: list[dict[str, Any]],
    parent: dict[str, str],
    report: dict[str, Any],
) -> None:
    report.setdefault("warnings", []).append(
        {
            "stage": report.get("stage"),
            "type": "same_wall_door_storage_separator_superseded",
            "evidence": (
                "Legacy door/storage separator is disabled because it used ambiguous image-center fallback on side walls. "
                "Per-wall relation audit now owns same-wall tangent overlap, wall-local order, and corner repair."
            ),
        }
    )
    return
    room = plan.get("room") if isinstance(plan.get("room"), dict) else {}
    if not room:
        return
    objects = {str(obj.get("id")): obj for obj in plan.get("objects", []) if isinstance(obj, dict) and obj.get("id")}
    if not objects:
        return
    ref_bboxes = _reference_bboxes_by_object(scene_graph)
    door_ids = [object_id for object_id, obj in objects.items() if _is_wall_door_object(obj)]
    storage_ids = [
        object_id
        for object_id, obj in objects.items()
        if object_id not in door_ids
        and str(obj.get("placement_type", "floor")) == "floor"
        and _is_floor_storage_or_table_branch_object(obj)
        and not _is_bedside_table_object(obj)
    ]
    if not door_ids or not storage_ids:
        return
    room_extent_by_axis = {
        0: float(room.get("width", 0.0) or 0.0),
        1: float(room.get("length", 0.0) or 0.0),
    }
    for door_id in door_ids:
        door = objects.get(door_id)
        if not door:
            continue
        wall_id = _object_wall_id_for_same_wall_separation(door_id, door, cross_constraints, parent)
        if wall_id not in VIRTUAL_WALLS:
            continue
        tangent_axis = _wall_tangent_axis(wall_id)
        axis_key = "y" if tangent_axis == 1 else "x"
        room_extent = room_extent_by_axis[tangent_axis]
        if room_extent <= 0.0:
            continue
        door_low, door_high, door_span = _same_wall_tangent_span(door, tangent_axis)
        if door_span <= 0.0:
            continue
        door_center = float(door.get(axis_key, 0.0) or 0.0)
        door_ref = ref_bboxes.get(door_id)
        door_ref_center = ((float(door_ref[1]) + float(door_ref[3])) / 2.0) if door_ref and tangent_axis == 1 else (
            ((float(door_ref[0]) + float(door_ref[2])) / 2.0) if door_ref else None
        )
        for storage_id in storage_ids:
            storage = objects.get(storage_id)
            if not storage:
                continue
            storage_wall = _object_wall_id_for_same_wall_separation(storage_id, storage, cross_constraints, parent)
            if storage_wall != wall_id:
                continue
            storage_low, storage_high, storage_span = _same_wall_tangent_span(storage, tangent_axis)
            if storage_span <= 0.0:
                continue
            storage_center = float(storage.get(axis_key, 0.0) or 0.0)
            current_gap = max(storage_low - door_high, door_low - storage_high, 0.0)
            min_clearance = _clamp(room_extent * 0.105, 0.34, 0.55)
            if current_gap >= min_clearance:
                continue
            storage_ref = ref_bboxes.get(storage_id)
            storage_ref_center = ((float(storage_ref[1]) + float(storage_ref[3])) / 2.0) if storage_ref and tangent_axis == 1 else (
                ((float(storage_ref[0]) + float(storage_ref[2])) / 2.0) if storage_ref else None
            )
            if door_ref_center is not None and storage_ref_center is not None and abs(door_ref_center - storage_ref_center) >= 0.05:
                door_before_storage = door_ref_center > storage_ref_center if wall_id in {"wall_north", "wall_south"} else door_ref_center > storage_ref_center
                # In image coordinates, larger vertical bbox centers are visually closer/front.
                if tangent_axis == 1:
                    door_before_storage = door_ref_center > storage_ref_center
            else:
                door_before_storage = door_center <= storage_center
            if door_before_storage:
                target_center = storage_low - min_clearance - door_span / 2.0
            else:
                target_center = storage_high + min_clearance + door_span / 2.0
            target_center = _clamp(target_center, door_span / 2.0 + FLOOR_WALL_AGAINST_GAP, room_extent - door_span / 2.0 - FLOOR_WALL_AGAINST_GAP)
            if abs(target_center - door_center) < 0.06:
                continue
            before = _plan_object_snapshot(door)
            old_x = float(door.get("x", 0.0) or 0.0)
            old_y = float(door.get("y", 0.0) or 0.0)
            door[axis_key] = target_center
            if str(door.get("placement_type") or "") == "attached_to_wall" or str(door.get("support_id") or "") in VIRTUAL_WALLS:
                door["placement_type"] = "attached_to_wall"
                door["support_id"] = wall_id
                door["yaw"] = _wall_semantic_yaw(wall_id)
                door["footprint_yaw_offset_degrees"] = _wall_footprint_offset_for_object(wall_id, door)
                _clamp_wall_attached_object(door, room, wall_id)
            else:
                _clamp_floor_object_against_wall(door, room, wall_id)
            after = _plan_object_snapshot(door)
            if before != after:
                report.setdefault("fixes", []).append(
                    {
                        "stage": report.get("stage"),
                        "type": "same_wall_door_storage_tangent_separation",
                        "id": door_id,
                        "storage_id": storage_id,
                        "wall_id": wall_id,
                        "axis": axis_key,
                        "before": before,
                        "after": after,
                        "current_gap_before": round(float(current_gap), 6),
                        "min_clearance": round(float(min_clearance), 6),
                        "door_before_storage": bool(door_before_storage),
                        "door_ref_center": round(float(door_ref_center), 6) if door_ref_center is not None else None,
                        "storage_ref_center": round(float(storage_ref_center), 6) if storage_ref_center is not None else None,
                        "delta": [round(float(door.get("x", old_x) or old_x) - old_x, 6), round(float(door.get("y", old_y) or old_y) - old_y, 6)],
                        "evidence": "Doors and storage/cabinets sharing one wall need clear non-overlap along the wall-tangent coordinate; collision-only repair can miss visually merged same-wall spans.",
                    }
                )
                door_low, door_high, door_span = _same_wall_tangent_span(door, tangent_axis)


def _align_bedside_tables_with_bed(
    plan: dict[str, Any],
    scene_graph: dict[str, Any],
    report: dict[str, Any],
) -> None:
    room = plan.get("room") if isinstance(plan.get("room"), dict) else {}
    if not room:
        return
    objects = {str(obj.get("id")): obj for obj in plan.get("objects", []) if isinstance(obj, dict) and obj.get("id")}
    beds = [obj for obj in objects.values() if _is_bed_or_sofa_object(obj)]
    if not beds:
        return
    bed = beds[0]
    bed_y = float(bed.get("y", 0.0) or 0.0)
    relation_by_subject: dict[str, set[str]] = {}
    relation_by_target: dict[str, set[str]] = {}
    for rel in scene_graph.get("relations", []) if isinstance(scene_graph.get("relations"), list) else []:
        if not isinstance(rel, dict):
            continue
        subject = str(rel.get("subject") or "")
        target = str(rel.get("object") or "")
        rel_type = str(rel.get("type") or "")
        relation_by_subject.setdefault(subject, set()).add(f"{rel_type}:{target}")
        relation_by_target.setdefault(target, set()).add(f"{rel_type}:{subject}")

    for obj in objects.values():
        text = _category_text(obj)
        object_id = str(obj.get("id") or "")
        if not any(keyword in text for keyword in ("nightstand", "bedside", "side table")):
            continue
        related_beds = _bed_ids_related_to_object(scene_graph, object_id, beds)
        if len(related_beds) >= 2:
            related = [objects[bed_id] for bed_id in related_beds if bed_id in objects]
            if related:
                before = _plan_object_snapshot(obj)
                old_x = float(obj.get("x", 0.0) or 0.0)
                old_y = float(obj.get("y", 0.0) or 0.0)
                target_y = _clamp(
                    sum(float(item.get("y", 0.0) or 0.0) for item in related) / float(len(related)) + 0.10,
                    0.2,
                    float(room.get("length", 0.0) or 0.0) - 0.2,
                )
                if abs(target_y - old_y) < 0.08 and str(obj.get("support_id") or "") not in VIRTUAL_WALLS:
                    continue
                obj["y"] = target_y
                if str(obj.get("support_id") or "") in VIRTUAL_WALLS:
                    obj["support_id"] = None
                    obj["placement_type"] = "floor"
                _clamp_object_to_room(obj, room)
                actual_dx = float(obj.get("x", old_x) or old_x) - old_x
                actual_dy = float(obj.get("y", old_y) or old_y) - old_y
                moved_children = _move_direct_supported_children(objects, object_id, actual_dx, actual_dy, room)
                after = _plan_object_snapshot(obj)
                if before != after:
                    report["fixes"].append(
                        {
                            "stage": report.get("stage"),
                            "type": "shared_bedside_table_depth_alignment",
                            "id": object_id,
                            "bed_ids": sorted(related_beds),
                            "moved_children": moved_children,
                            "before": before,
                            "after": after,
                            "evidence": "A nightstand shared by multiple beds belongs between the bed pair; align its depth with the bed row without pushing it outside either bed.",
                        }
                    )
                continue
        relation_tokens = relation_by_subject.get(object_id, set()) | relation_by_target.get(object_id, set())
        if not any("queen_bed" in token or str(bed.get("id")) in token for token in relation_tokens):
            continue
        before = _plan_object_snapshot(obj)
        old_x = float(obj.get("x", 0.0) or 0.0)
        old_y = float(obj.get("y", 0.0) or 0.0)
        target_y = _clamp(bed_y + 0.10, 0.2, float(room.get("length", 0.0) or 0.0) - 0.2)
        dy = target_y - old_y
        if abs(dy) < 0.08:
            if str(obj.get("support_id") or "") not in VIRTUAL_WALLS:
                continue
        obj["y"] = target_y
        if str(obj.get("support_id") or "") in VIRTUAL_WALLS:
            obj["support_id"] = None
            obj["placement_type"] = "floor"
        _clamp_object_to_room(obj, room)
        actual_dx = float(obj.get("x", old_x) or old_x) - old_x
        actual_dy = float(obj.get("y", old_y) or old_y) - old_y
        moved_children = _move_direct_supported_children(objects, object_id, actual_dx, actual_dy, room)
        after = _plan_object_snapshot(obj)
        if before != after:
            report["fixes"].append(
                {
                    "stage": report.get("stage"),
                    "type": "bedside_table_depth_alignment",
                    "id": object_id,
                    "bed_id": bed.get("id"),
                    "moved_children": moved_children,
                    "before": before,
                    "after": after,
                    "evidence": "Bedside table belongs to the bed branch; keep its depth close to the bed instead of global foreground ordering.",
                }
            )


def _bed_ids_related_to_object(scene_graph: dict[str, Any], object_id: str, beds: list[dict[str, Any]]) -> set[str]:
    bed_ids = {str(bed.get("id") or "") for bed in beds if bed.get("id")}
    related: set[str] = set()
    for rel in scene_graph.get("relations", []) if isinstance(scene_graph.get("relations"), list) else []:
        if not isinstance(rel, dict):
            continue
        subject = str(rel.get("subject") or "")
        target = str(rel.get("object") or "")
        if subject == object_id and target in bed_ids:
            related.add(target)
        elif target == object_id and subject in bed_ids:
            related.add(subject)
    return related


def _is_shared_between_multiple_beds(
    obj: dict[str, Any],
    scene_graph: dict[str, Any],
    beds: list[dict[str, Any]],
) -> bool:
    object_id = str(obj.get("id") or "")
    if len(_bed_ids_related_to_object(scene_graph, object_id, beds)) >= 2:
        return True
    text = _category_text(obj)
    return len(beds) >= 2 and "between" in text and "bed" in text


def _align_multi_bed_wall_rows(
    plan: dict[str, Any],
    scene_graph: dict[str, Any],
    cross_constraints: list[dict[str, Any]],
    parent: dict[str, str],
    report: dict[str, Any],
) -> None:
    room = plan.get("room") if isinstance(plan.get("room"), dict) else {}
    if not room:
        return
    objects = {str(obj.get("id")): obj for obj in plan.get("objects", []) if isinstance(obj, dict) and obj.get("id")}
    groups = list(scene_graph.get("_reference_spatial_order_groups") if isinstance(scene_graph.get("_reference_spatial_order_groups"), list) else [])
    beds_by_wall: dict[str, list[str]] = {}
    for object_id, obj in objects.items():
        if not _is_bed_or_sofa_object(obj):
            continue
        wall = _back_to_wall_target_wall(obj, cross_constraints, parent) or _wall_id(_semantic_wall_relation(obj).get("wall_id"))
        if wall in VIRTUAL_WALLS:
            beds_by_wall.setdefault(wall, []).append(object_id)
    for wall_id, wall_bed_ids in sorted(beds_by_wall.items()):
        if len(wall_bed_ids) < 2:
            continue
        wall_beds = [objects[bed_id] for bed_id in wall_bed_ids if bed_id in objects]
        shared_bedside_ids = [
            object_id
            for object_id, obj in objects.items()
            if _is_bedside_table_object(obj)
            and _is_shared_between_multiple_beds(obj, scene_graph, wall_beds)
        ]

        def bed_ref_order_key(object_id: str) -> float:
            bbox = _reference_bbox_from_sources(objects[object_id])
            if bbox:
                if wall_id in {"wall_north", "wall_south"}:
                    return (float(bbox[0]) + float(bbox[2])) / 2.0
                    return (float(bbox[1]) + float(bbox[3])) / 2.0
            return float(objects[object_id].get("x" if wall_id in {"wall_north", "wall_south"} else "y", 0.0) or 0.0)

        fallback_order = sorted([*wall_bed_ids, *shared_bedside_ids], key=bed_ref_order_key)
        groups.append(
            {
                "group_id": f"fallback_same_wall_bed_row_{wall_id}",
                "left_to_right": fallback_order,
                "evidence": "Rule fallback: multiple beds/sofas share the same wall and must keep a common wall-contact line even if the spatial-order agent omits the row group; shared bedside tables stay between the related beds.",
            }
        )
    if not groups:
        return

    for group in groups:
        if not isinstance(group, dict):
            continue
        raw_order = [str(item) for item in group.get("left_to_right", []) if str(item) in objects]
        bed_ids = [object_id for object_id in raw_order if _is_bed_or_sofa_object(objects[object_id])]
        if len(bed_ids) < 2:
            continue
        walls = {
            _back_to_wall_target_wall(objects[bed_id], cross_constraints, parent)
            or _wall_id(_semantic_wall_relation(objects[bed_id]).get("wall_id"))
            for bed_id in bed_ids
        }
        walls = {wall for wall in walls if wall in VIRTUAL_WALLS}
        if len(walls) != 1:
            continue
        wall_id = next(iter(walls))
        if wall_id in {"wall_north", "wall_south"}:
            axis = "x"
            room_extent = float(room.get("width", 0.0) or 0.0)
            normalized_center = lambda bbox: (float(bbox[0]) + float(bbox[2])) / 2.0
        elif wall_id in {"wall_east", "wall_west"}:
            axis = "y"
            room_extent = float(room.get("length", 0.0) or 0.0)
            normalized_center = lambda bbox: 1.0 - (float(bbox[1]) + float(bbox[3])) / 2.0
        else:
            continue
        if room_extent <= 0.0:
            continue

        order = [
            object_id
            for object_id in raw_order
            if _is_bed_or_sofa_object(objects[object_id])
            or (
                _is_bedside_table_object(objects[object_id])
                and _is_shared_between_multiple_beds(objects[object_id], scene_graph, [objects[bed_id] for bed_id in bed_ids])
            )
        ]
        if len(order) < 2:
            continue

        values: list[float] = []
        extents: list[float] = []
        for object_id in order:
            obj = objects[object_id]
            bbox = _reference_bbox_from_sources(obj)
            if bbox:
                values.append(_clamp(normalized_center(bbox) * room_extent, 0.0, room_extent))
            else:
                values.append(float(obj.get(axis, 0.0) or 0.0))
            width, length = _rotated_footprint(obj)
            extents.append(float(width if axis == "x" else length))

        gap = 0.08
        for index in range(1, len(values)):
            required = values[index - 1] + (extents[index - 1] + extents[index]) / 2.0 + gap
            if values[index] < required:
                values[index] = required
        margin = FLOOR_WALL_AGAINST_GAP
        left_edge = values[0] - extents[0] / 2.0
        right_edge = values[-1] + extents[-1] / 2.0
        if left_edge < margin:
            shift = margin - left_edge
            values = [value + shift for value in values]
            right_edge += shift
        if right_edge > room_extent - margin:
            shift = right_edge - (room_extent - margin)
            values = [value - shift for value in values]
        for index, object_id in enumerate(order):
            obj = objects[object_id]
            old_x = float(obj.get("x", 0.0) or 0.0)
            old_y = float(obj.get("y", 0.0) or 0.0)
            before = _plan_object_snapshot(obj)
            obj[axis] = values[index]
            if _is_bed_or_sofa_object(obj):
                _apply_bed_or_sofa_wall_pose_constraint(obj, wall_id)
                obj_w, obj_l = _rotated_footprint(obj)
                if wall_id == "wall_north":
                    obj["y"] = float(room.get("length", 0.0) or 0.0) - obj_l / 2.0 - FLOOR_WALL_AGAINST_GAP
                elif wall_id == "wall_south":
                    obj["y"] = obj_l / 2.0 + FLOOR_WALL_AGAINST_GAP
                elif wall_id == "wall_east":
                    obj["x"] = float(room.get("width", 0.0) or 0.0) - obj_w / 2.0 - FLOOR_WALL_AGAINST_GAP
                elif wall_id == "wall_west":
                    obj["x"] = obj_w / 2.0 + FLOOR_WALL_AGAINST_GAP
            else:
                # Shared bedside tables reserve lateral space in a multi-bed row,
                # but their depth belongs to the bedside-table module. Forcing
                # them onto the same wall-contact line as beds makes later depth
                # repairs fight this row alignment pass.
                pass
            _clamp_object_to_room(obj, room)
            actual_dx = float(obj.get("x", old_x) or old_x) - old_x
            actual_dy = float(obj.get("y", old_y) or old_y) - old_y
            moved_children = _move_direct_supported_children(objects, object_id, actual_dx, actual_dy, room)
            after = _plan_object_snapshot(obj)
            if before != after:
                report["fixes"].append(
                    {
                        "stage": report.get("stage"),
                        "type": "multi_bed_wall_row_alignment",
                        "id": object_id,
                        "group_id": group.get("group_id"),
                        "wall_id": wall_id,
                        "axis": axis,
                        "before": before,
                        "after": after,
                        "moved_children": moved_children,
                        "evidence": "Multiple beds against the same wall should be packed as a row using the reference left-to-right group; shared nightstands remain between beds instead of being pushed outside one bed.",
                    }
                )


def _bedside_table_related_to_bed(
    obj: dict[str, Any],
    bed: dict[str, Any],
    scene_graph: dict[str, Any],
) -> bool:
    object_id = str(obj.get("id") or "")
    bed_id = str(bed.get("id") or "")
    if not object_id or not bed_id:
        return False
    for rel in scene_graph.get("relations", []) if isinstance(scene_graph.get("relations"), list) else []:
        if not isinstance(rel, dict):
            continue
        subject = str(rel.get("subject") or "")
        target = str(rel.get("object") or "")
        if {subject, target} == {object_id, bed_id}:
            return True
    bed_w, bed_l = _rotated_footprint(bed)
    dx = abs(float(obj.get("x", 0.0) or 0.0) - float(bed.get("x", 0.0) or 0.0))
    dy = abs(float(obj.get("y", 0.0) or 0.0) - float(bed.get("y", 0.0) or 0.0))
    return dx >= bed_w * 0.32 and dx <= bed_w * 0.95 and dy <= max(0.85, bed_l * 0.55)


def _bed_front_wall_for_bedside_table(
    bed: dict[str, Any],
    room: dict[str, Any],
    cross_constraints: list[dict[str, Any]],
    parent: dict[str, str],
) -> str | None:
    wall_id = _back_to_wall_target_wall(bed, cross_constraints, parent)
    if wall_id in VIRTUAL_WALLS:
        return wall_id
    relation = _semantic_wall_relation(bed)
    mode = str(relation.get("mode") or "").strip().lower()
    semantic_wall = _wall_id(relation.get("wall_id"))
    if mode in {"against", "attached", "wall_flush", "near"} and semantic_wall in VIRTUAL_WALLS:
        return semantic_wall
    room_width = float(room.get("width", 0.0) or 0.0)
    room_length = float(room.get("length", 0.0) or 0.0)
    x = float(bed.get("x", 0.0) or 0.0)
    y = float(bed.get("y", 0.0) or 0.0)
    distances = {
        "wall_west": x,
        "wall_east": max(0.0, room_width - x),
        "wall_south": y,
        "wall_north": max(0.0, room_length - y),
    }
    return min(distances, key=distances.get) if distances else None


def _merge_bedside_front_pose_report(
    report: dict[str, Any],
    pass_report: dict[str, Any],
) -> dict[str, Any]:
    if not report:
        report = {
            "schema": "tree_sage_bedside_table_front_to_room_repair_v1",
            "enabled": False,
            "passes": [],
            "fixes": [],
            "checks": [],
            "fix_count": 0,
            "ok": True,
        }
    report["enabled"] = bool(report.get("enabled")) or bool(pass_report.get("enabled"))
    report.setdefault("passes", []).append(
        {
            "stage": pass_report.get("stage"),
            "fix_count": int(pass_report.get("fix_count", 0) or 0),
            "check_count": len(pass_report.get("checks", []) if isinstance(pass_report.get("checks"), list) else []),
            "ok": bool(pass_report.get("ok", True)),
        }
    )
    report.setdefault("fixes", []).extend(pass_report.get("fixes", []) if isinstance(pass_report.get("fixes"), list) else [])
    report.setdefault("checks", []).extend(pass_report.get("checks", []) if isinstance(pass_report.get("checks"), list) else [])
    report["fix_count"] = len(report.get("fixes", []))
    report["ok"] = bool(report.get("ok", True)) and bool(pass_report.get("ok", True))
    return report


def repair_bedside_table_fronts_to_room(
    plan: dict[str, Any],
    scene_graph: dict[str, Any],
    cross_constraints: list[dict[str, Any]],
    parent: dict[str, str],
    *,
    stage: str,
    enabled: bool = True,
) -> dict[str, Any]:
    report: dict[str, Any] = {
        "schema": "tree_sage_bedside_table_front_to_room_repair_v1",
        "enabled": bool(enabled),
        "stage": stage,
        "fixes": [],
        "checks": [],
        "fix_count": 0,
        "ok": True,
    }
    if not enabled:
        report["reason"] = "disabled"
        return report
    room = plan.get("room") if isinstance(plan.get("room"), dict) else {}
    if not room:
        report["reason"] = "missing_room"
        report["ok"] = False
        return report
    objects = {str(obj.get("id")): obj for obj in plan.get("objects", []) if isinstance(obj, dict) and obj.get("id")}
    beds = [obj for obj in objects.values() if _is_bed_or_sofa_object(obj)]
    if not beds:
        report["reason"] = "no_bed_or_sofa_anchor"
        return report

    for obj in objects.values():
        if not _is_bedside_table_object(obj):
            continue
        bed = min(
            beds,
            key=lambda item: (
                abs(float(item.get("x", 0.0) or 0.0) - float(obj.get("x", 0.0) or 0.0))
                + abs(float(item.get("y", 0.0) or 0.0) - float(obj.get("y", 0.0) or 0.0))
            ),
        )
        if not _bedside_table_related_to_bed(obj, bed, scene_graph):
            report["checks"].append(
                {
                    "id": obj.get("id"),
                    "status": "skipped_not_bed_branch",
                    "nearest_bed": bed.get("id"),
                }
            )
            continue
        wall_id = _bed_front_wall_for_bedside_table(bed, room, cross_constraints, parent)
        if wall_id not in VIRTUAL_WALLS:
            report["checks"].append(
                {
                    "id": obj.get("id"),
                    "status": "skipped_no_bed_wall",
                    "nearest_bed": bed.get("id"),
                    "wall_id": wall_id,
                }
            )
            continue
        desired_effective_yaw = _wall_semantic_yaw(wall_id)
        before_effective = _effective_yaw(obj)
        delta = abs(((before_effective - desired_effective_yaw + 180.0) % 360.0) - 180.0)
        check = {
            "id": obj.get("id"),
            "bed_id": bed.get("id"),
            "wall_id": wall_id,
            "current_effective_yaw": before_effective,
            "desired_effective_yaw": desired_effective_yaw,
            "status": "ok" if delta <= 1e-4 else "needs_fix",
        }
        report["checks"].append(check)
        if delta <= 1e-4:
            continue
        before = _plan_object_snapshot(obj)
        old_x = float(obj.get("x", 0.0) or 0.0)
        old_y = float(obj.get("y", 0.0) or 0.0)
        _set_effective_yaw(obj, desired_effective_yaw)
        _clamp_object_to_room_rotated(obj, room, margin=0.0)
        dx = float(obj.get("x", old_x) or old_x) - old_x
        dy = float(obj.get("y", old_y) or old_y) - old_y
        moved_children = _move_direct_supported_children(objects, str(obj.get("id")), dx, dy, room)
        after = _plan_object_snapshot(obj)
        report["fixes"].append(
            {
                "stage": stage,
                "type": "bedside_table_front_to_room",
                "id": obj.get("id"),
                "bed_id": bed.get("id"),
                "wall_id": wall_id,
                "before": before,
                "after": after,
                "desired_effective_yaw": desired_effective_yaw,
                "moved_children": moved_children,
                "evidence": "Bedside table belongs to the bed branch; drawer/door front should face into the room from the bed headboard wall, independent of side-wall storage rules.",
            }
        )
    report["fix_count"] = len(report["fixes"])
    return report


def _prune_support_tree_ids(node: dict[str, Any], removed_ids: set[str]) -> dict[str, Any] | None:
    if str(node.get("id") or "") in removed_ids:
        return None
    children = []
    for child in node.get("children", []) if isinstance(node.get("children"), list) else []:
        if not isinstance(child, dict):
            continue
        pruned = _prune_support_tree_ids(child, removed_ids)
        if pruned is not None:
            children.append(pruned)
    node["children"] = children
    return node


def remove_redundant_integrated_bed_bedding(
    plan: dict[str, Any],
    support_tree: dict[str, Any],
    cross_constraints: list[dict[str, Any]],
    parent: dict[str, str],
    relation_to_parent: dict[str, str],
) -> dict[str, Any]:
    report: dict[str, Any] = {
        "schema": "tree_sage_integrated_bed_bedding_dedupe_v1",
        "enabled": True,
        "removed": [],
        "removed_count": 0,
        "ok": True,
    }
    objects = {str(obj.get("id")): obj for obj in plan.get("objects", []) if isinstance(obj, dict) and obj.get("id")}
    removed_ids: set[str] = set()
    for obj in list(objects.values()):
        object_id = str(obj.get("id") or "")
        parent_id = str(obj.get("support_id") or parent.get(object_id) or "")
        bed = objects.get(parent_id)
        if not bed or not _is_bed_or_sofa_object(bed):
            continue
        child_text = _category_text(obj)
        child_category = str(obj.get("category") or "").lower()
        child_id = object_id.lower()
        is_removable_bedding = any(keyword in child_category for keyword in ("blanket", "bedspread", "quilt")) or any(
            keyword in child_id for keyword in ("bed_throw", "blanket", "bedspread", "quilt")
        )
        if not is_removable_bedding:
            continue
        explicitly_independent = any(
            keyword in child_text
            for keyword in (
                "separate freestanding",
                "beside bed",
                "storage blanket",
            )
        )
        if explicitly_independent:
            continue
        removed_ids.add(object_id)
        report["removed"].append(
            {
                "id": object_id,
                "parent_id": parent_id,
                "category": obj.get("category"),
                "description": obj.get("description"),
                "reason": "standalone blanket/throw/quilt supported by a generated bed is usually already represented in the integrated bed asset and frequently becomes a flat board-like duplicate",
            }
        )
    if not removed_ids:
        return report
    plan["objects"] = [obj for obj in plan.get("objects", []) if str(obj.get("id") or "") not in removed_ids]
    cross_constraints[:] = [
        rel
        for rel in cross_constraints
        if str(rel.get("subject") or "") not in removed_ids
        and str(rel.get("object") or "") not in removed_ids
        and str(rel.get("target") or "") not in removed_ids
    ]
    for object_id in removed_ids:
        parent.pop(object_id, None)
        relation_to_parent.pop(object_id, None)
    if isinstance(support_tree, dict):
        _prune_support_tree_ids(support_tree, removed_ids)
    report["removed_count"] = len(report["removed"])
    plan["_integrated_bed_bedding_dedupe"] = report
    return report


def repair_pose_edited_storage_local_collisions(
    plan: dict[str, Any],
    support_tree: dict[str, Any],
    parent: dict[str, str],
    relation_to_parent: dict[str, str],
    cross_constraints: list[dict[str, Any]],
    asset_registry: dict[str, Any],
    applied_items: list[dict[str, Any]],
    *,
    margin: float,
) -> dict[str, Any]:
    report: dict[str, Any] = {
        "schema": "tree_sage_pose_edited_storage_local_collision_repair_v1",
        "enabled": True,
        "attempts": [],
        "accepted": [],
        "accepted_count": 0,
        "ok": True,
    }
    current_registry = build_support_surface_registry(plan, asset_registry)
    current_report = build_aggregate_collision_report(
        plan,
        support_tree,
        parent,
        relation_to_parent,
        current_registry,
        margin=margin,
    )
    if int(current_report.get("conflict_count", 0) or 0) <= 0:
        report["reason"] = "no_aggregate_collision_after_pose_edits"
        return report
    objects = {str(obj.get("id")): obj for obj in plan.get("objects", []) if isinstance(obj, dict) and obj.get("id")}
    room = plan.get("room") if isinstance(plan.get("room"), dict) else {}
    room_width = float(room.get("width", 0.0) or 0.0)
    room_length = float(room.get("length", 0.0) or 0.0)
    if room_width <= 0.0 or room_length <= 0.0:
        report["reason"] = "missing_room_dimensions"
        return report

    def candidate_positions(obj: dict[str, Any]) -> list[tuple[float, float, str]]:
        object_id = str(obj.get("id") or "")
        obj_w, obj_l = _rotated_footprint(obj)
        x0 = float(obj.get("x", 0.0) or 0.0)
        y0 = float(obj.get("y", 0.0) or 0.0)
        candidates = [(x0, y0, "current")]
        beds = [bed for bed in objects.values() if _is_bed_or_sofa_object(bed)]
        if _is_bedside_table_object(obj) and beds:
            bed = min(beds, key=lambda item: abs(float(item.get("x", 0.0) or 0.0) - x0))
            bed_w, bed_l = _rotated_footprint(bed)
            bed_x = float(bed.get("x", 0.0) or 0.0)
            bed_y = float(bed.get("y", 0.0) or 0.0)
            side = -1.0 if x0 <= bed_x else 1.0
            side_x = bed_x + side * (bed_w / 2.0 + obj_w / 2.0 + 0.08)
            y_values = [
                y0,
                bed_y + min(0.28, bed_l * 0.12),
                bed_y + min(0.42, bed_l * 0.18),
                bed_y - min(0.10, bed_l * 0.05),
            ]
            for y in y_values:
                candidates.append((side_x, y, "bedside_outside_bed_footprint"))
                candidates.append((x0, y, "bedside_depth_only"))
        wall_id = _wall_relation_for_object(object_id, cross_constraints, parent)
        if _is_floor_storage_or_table_branch_object(obj) and wall_id in {"wall_west", "wall_east"}:
            wall_x = obj_w / 2.0 + FLOOR_WALL_AGAINST_GAP if wall_id == "wall_west" else room_width - obj_w / 2.0 - FLOOR_WALL_AGAINST_GAP
            for y in (y0, max(obj_l / 2.0 + 0.05, y0 - 0.18), min(room_length - obj_l / 2.0 - 0.05, y0 + 0.18)):
                candidates.append((wall_x, y, "wall_tangent_storage_clearance"))
        unique: list[tuple[float, float, str]] = []
        seen: set[tuple[float, float]] = set()
        for x, y, reason in candidates:
            x = _clamp(x, obj_w / 2.0 + 0.025, room_width - obj_w / 2.0 - 0.025)
            y = _clamp(y, obj_l / 2.0 + 0.025, room_length - obj_l / 2.0 - 0.025)
            key = (round(x, 4), round(y, 4))
            if key in seen:
                continue
            seen.add(key)
            unique.append((x, y, reason))
        return unique

    best_plan = None
    best_report = current_report
    best_score = _aggregate_collision_score(current_report)
    for item in applied_items:
        if not isinstance(item, dict) or not item.get("changed") or item.get("rolled_back"):
            continue
        object_id = str(item.get("object_id") or "")
        obj = objects.get(object_id)
        if not obj:
            continue
        if not (_is_bedside_table_object(obj) or _is_floor_storage_or_table_branch_object(obj)):
            continue
        for x, y, reason in candidate_positions(obj):
            candidate_plan = deepcopy(plan)
            candidate_objects = {
                str(candidate.get("id")): candidate
                for candidate in candidate_plan.get("objects", [])
                if isinstance(candidate, dict) and candidate.get("id")
            }
            candidate_obj = candidate_objects.get(object_id)
            if not candidate_obj:
                continue
            old_x = float(candidate_obj.get("x", 0.0) or 0.0)
            old_y = float(candidate_obj.get("y", 0.0) or 0.0)
            candidate_obj["x"] = x
            candidate_obj["y"] = y
            _clamp_object_to_room_rotated(candidate_obj, candidate_plan.get("room", {}), margin=0.0)
            dx = float(candidate_obj.get("x", x) or x) - old_x
            dy = float(candidate_obj.get("y", y) or y) - old_y
            _move_direct_supported_children(candidate_objects, object_id, dx, dy, candidate_plan.get("room", {}))
            candidate_registry = build_support_surface_registry(candidate_plan, asset_registry)
            candidate_report = build_aggregate_collision_report(
                candidate_plan,
                support_tree,
                parent,
                relation_to_parent,
                candidate_registry,
                margin=margin,
            )
            candidate_score = _aggregate_collision_score(candidate_report)
            report["attempts"].append(
                {
                    "object_id": object_id,
                    "reason": reason,
                    "x": round(float(candidate_obj.get("x", 0.0) or 0.0), 6),
                    "y": round(float(candidate_obj.get("y", 0.0) or 0.0), 6),
                    "conflict_count": int(candidate_report.get("conflict_count", 0) or 0),
                    "score": list(candidate_score),
                }
            )
            if candidate_score < best_score:
                best_score = candidate_score
                best_plan = candidate_plan
                best_report = candidate_report
                if int(candidate_report.get("conflict_count", 0) or 0) == 0:
                    break
        if int(best_report.get("conflict_count", 0) or 0) == 0:
            break
    if best_plan is not None and best_score < _aggregate_collision_score(current_report):
        plan["objects"] = best_plan.get("objects", plan.get("objects", []))
        report["accepted"].append(
            {
                "previous_conflict_count": int(current_report.get("conflict_count", 0) or 0),
                "new_conflict_count": int(best_report.get("conflict_count", 0) or 0),
                "score": list(best_score),
                "reason": "accepted lower-collision local placement while preserving final pose edit",
            }
        )
        report["accepted_count"] = len(report["accepted"])
    else:
        report["ok"] = False
        report["reason"] = "no candidate reduced pose-edit collisions"
    return report


def _window_curtain_reference_tightness(
    window_id: str,
    low_curtain_id: str,
    high_curtain_id: str,
    ref_bboxes: dict[str, list[float]],
) -> dict[str, Any]:
    window_bbox = ref_bboxes.get(str(window_id))
    low_bbox = ref_bboxes.get(str(low_curtain_id))
    high_bbox = ref_bboxes.get(str(high_curtain_id))
    default_gap = max(0.0, float(WINDOW_CURTAIN_CLUSTER_MEDIUM_GAP))
    if not window_bbox or not low_bbox or not high_bbox:
        return {
            "tier": "medium",
            "reference_gap_ratio": None,
            "scene_gap": default_gap,
            "evidence": "missing_reference_bbox",
        }
    window_width = max(1e-6, float(window_bbox[2]) - float(window_bbox[0]))
    low_gap = max(0.0, float(window_bbox[0]) - float(low_bbox[2]))
    high_gap = max(0.0, float(high_bbox[0]) - float(window_bbox[2]))
    reference_gap_ratio = ((low_gap + high_gap) / 2.0) / window_width
    if reference_gap_ratio <= float(WINDOW_CURTAIN_CLUSTER_TIGHT_REF_GAP_RATIO):
        tier = "tight"
        scene_gap = max(0.0, float(WINDOW_CURTAIN_CLUSTER_TIGHT_GAP))
    elif reference_gap_ratio <= float(WINDOW_CURTAIN_CLUSTER_MEDIUM_REF_GAP_RATIO):
        tier = "medium"
        scene_gap = max(0.0, float(WINDOW_CURTAIN_CLUSTER_MEDIUM_GAP))
    else:
        tier = "loose"
        scene_gap = max(0.0, float(WINDOW_CURTAIN_CLUSTER_LOOSE_GAP))
    return {
        "tier": tier,
        "reference_left_gap": round(float(low_gap), 6),
        "reference_right_gap": round(float(high_gap), 6),
        "reference_gap_ratio": round(float(reference_gap_ratio), 6),
        "scene_gap": round(float(scene_gap), 6),
        "evidence": "reference_bbox_adjacent_gap",
    }


def _window_curtain_tangent_span(obj: dict[str, Any], tangent_axis: int) -> float:
    dims = obj.setdefault("dimensions", {})
    if (
        _functional_cluster_is_window_object(obj)
        or _is_curtain_panel_object(obj)
        or _is_curtain_rod_object(obj)
    ):
        span = _safe_float(dims.get("width"), 0.0)
        if span > 1e-6:
            return float(span)
    low, high, span = _same_wall_tangent_span(obj, tangent_axis)
    del low, high
    return max(float(span), 1e-6)


def _separate_window_curtain_panels(
    plan: dict[str, Any],
    scene_graph: dict[str, Any],
    report: dict[str, Any],
) -> None:
    room = plan.get("room") if isinstance(plan.get("room"), dict) else {}
    if not room:
        return
    objects = {str(obj.get("id")): obj for obj in plan.get("objects", []) if isinstance(obj, dict) and obj.get("id")}
    windows = []
    for obj in objects.values():
        identity = _object_identity_text(obj)
        if (
            "window" in identity
            and "curtain" not in identity
            and "rod" not in identity
            and str(obj.get("placement_type") or "") == "attached_to_wall"
            and str(obj.get("support_id") or "") in VIRTUAL_WALLS
        ):
            windows.append(obj)
    if not windows:
        return
    ref_bboxes = _reference_bboxes_by_object(scene_graph)
    for window in windows:
        wall_id = str(window.get("support_id") or "")
        if wall_id not in VIRTUAL_WALLS:
            continue
        same_wall_curtains: list[dict[str, Any]] = []
        fallback_curtains: list[dict[str, Any]] = []
        window_bbox = ref_bboxes.get(str(window.get("id") or ""))

        def is_near_window_curtain(obj: dict[str, Any]) -> bool:
            curtain_bbox = ref_bboxes.get(str(obj.get("id") or ""))
            if not window_bbox or not curtain_bbox:
                return len(windows) == 1
            wx = (float(window_bbox[0]) + float(window_bbox[2])) / 2.0
            wy = (float(window_bbox[1]) + float(window_bbox[3])) / 2.0
            cx = (float(curtain_bbox[0]) + float(curtain_bbox[2])) / 2.0
            cy = (float(curtain_bbox[1]) + float(curtain_bbox[3])) / 2.0
            return abs(cx - wx) <= 0.45 and abs(cy - wy) <= 0.45

        for obj in objects.values():
            if obj is window:
                continue
            identity = _object_identity_text(obj)
            if "curtain" not in identity or "rod" in identity:
                continue
            if str(obj.get("placement_type") or "") not in {"attached_to_wall", "hanging"}:
                continue
            current_wall = str(obj.get("support_id") or "")
            if current_wall == wall_id:
                same_wall_curtains.append(obj)
            elif current_wall in VIRTUAL_WALLS and is_near_window_curtain(obj):
                fallback_curtains.append(obj)
            elif current_wall not in VIRTUAL_WALLS and is_near_window_curtain(obj):
                fallback_curtains.append(obj)
        curtains = same_wall_curtains if len(same_wall_curtains) >= 2 else same_wall_curtains + fallback_curtains
        if len(curtains) < 2:
            continue
        rods: list[dict[str, Any]] = []
        for obj in objects.values():
            if obj is window:
                continue
            if not _is_curtain_rod_object(obj):
                continue
            current_wall = str(obj.get("support_id") or "")
            if current_wall == wall_id or is_near_window_curtain(obj):
                rods.append(obj)
        along_axis = "y" if wall_id in {"wall_east", "wall_west"} else "x"
        tangent_axis = 1 if along_axis == "y" else 0
        room_extent = float(room.get("length" if along_axis == "y" else "width", 0.0) or 0.0)
        if room_extent <= 0.0:
            continue

        def curtain_sort_key(obj: dict[str, Any]) -> tuple[float, str]:
            bbox = ref_bboxes.get(str(obj.get("id") or ""))
            if bbox:
                return ((float(bbox[0]) + float(bbox[2])) / 2.0, str(obj.get("id") or ""))
            text = str(obj.get("id") or "").lower()
            if "left" in text:
                return (-1.0, text)
            if "right" in text:
                return (2.0, text)
            return (0.5, text)

        ordered = sorted(curtains, key=curtain_sort_key)
        selected = [ordered[0], ordered[-1]]
        members_to_lock = [window, *selected, *rods]
        before_by_id = {str(member.get("id") or ""): _plan_object_snapshot(member) for member in members_to_lock}
        for member in members_to_lock:
            member["placement_type"] = "attached_to_wall"
            member["support_id"] = wall_id
            member["yaw"] = _wall_semantic_yaw(wall_id)
            member["footprint_yaw_offset_degrees"] = _wall_footprint_offset_for_object(wall_id, member)
            if _is_wall_flat_visual_asset(member):
                _set_wall_flat_visual_yaw(member, wall_id)
            dims = member.setdefault("dimensions", {})
            dims["length"] = min(
                float(dims.get("length", WINDOW_CURTAIN_CLUSTER_PANEL_THICKNESS) or WINDOW_CURTAIN_CLUSTER_PANEL_THICKNESS),
                float(WINDOW_CURTAIN_CLUSTER_PANEL_THICKNESS),
            )

        low_curtain, high_curtain = selected
        window_span = _window_curtain_tangent_span(window, tangent_axis)

        def ref_width(object_id: str) -> float | None:
            bbox = ref_bboxes.get(str(object_id))
            if not bbox or len(bbox) < 4:
                return None
            width = max(0.0, float(bbox[2]) - float(bbox[0]))
            return width if width > 1e-6 else None

        window_ref_width = ref_width(str(window.get("id") or ""))
        panel_ratios: list[float] = []
        if window_ref_width:
            for curtain in selected:
                curtain_ref_width = ref_width(str(curtain.get("id") or ""))
                if curtain_ref_width:
                    panel_ratios.append(curtain_ref_width / window_ref_width)
        panel_ratio = (
            sum(panel_ratios) / len(panel_ratios)
            if panel_ratios
            else float(WINDOW_CURTAIN_CLUSTER_PANEL_MIN_RATIO)
        )
        panel_ratio = _clamp(
            float(panel_ratio),
            float(WINDOW_CURTAIN_CLUSTER_PANEL_MIN_RATIO),
            float(WINDOW_CURTAIN_CLUSTER_PANEL_MAX_RATIO),
        )
        target_panel_span = _clamp(
            window_span * panel_ratio,
            float(WINDOW_CURTAIN_CLUSTER_PANEL_MIN_SPAN),
            float(WINDOW_CURTAIN_CLUSTER_PANEL_MAX_SPAN),
        )
        for curtain in selected:
            dims = curtain.setdefault("dimensions", {})
            # For wall-mounted curtain panels in this pipeline, width is the wall-tangent span.
            dims["width"] = float(target_panel_span)
            dims["length"] = min(
                float(dims.get("length", WINDOW_CURTAIN_CLUSTER_PANEL_THICKNESS) or WINDOW_CURTAIN_CLUSTER_PANEL_THICKNESS),
                float(WINDOW_CURTAIN_CLUSTER_PANEL_THICKNESS),
            )
            curtain["dimensions"] = dims

        low_span = _window_curtain_tangent_span(low_curtain, tangent_axis)
        high_span = _window_curtain_tangent_span(high_curtain, tangent_axis)
        tightness = _window_curtain_reference_tightness(
            str(window.get("id") or ""),
            str(low_curtain.get("id") or ""),
            str(high_curtain.get("id") or ""),
            ref_bboxes,
        )
        gap = _clamp(
            _safe_float(tightness.get("scene_gap"), WINDOW_CURTAIN_CLUSTER_MEDIUM_GAP),
            0.0,
            max(0.0, room_extent * 0.06),
        )
        total_span = low_span + gap + window_span + gap + high_span
        if total_span > room_extent - 0.08:
            gap = min(gap, 0.012)
            total_span = low_span + gap + window_span + gap + high_span
        if total_span > room_extent - 0.08:
            available_panel_span = max(0.0, (room_extent - 0.08 - window_span - 2.0 * gap) / 2.0)
            if available_panel_span > 1e-6:
                target_panel_span = min(target_panel_span, available_panel_span)
                for curtain in selected:
                    curtain.setdefault("dimensions", {})["width"] = float(target_panel_span)
                low_span = _window_curtain_tangent_span(low_curtain, tangent_axis)
                high_span = _window_curtain_tangent_span(high_curtain, tangent_axis)
                total_span = low_span + gap + window_span + gap + high_span
        requested_window_center = float(window.get(along_axis, 0.0) or 0.0)
        min_center = low_span + gap + window_span / 2.0 + 0.02
        max_center = room_extent - high_span - gap - window_span / 2.0 - 0.02
        if min_center <= max_center:
            window_center = _clamp(requested_window_center, min_center, max_center)
        else:
            window_center = room_extent / 2.0
        low_center = window_center - window_span / 2.0 - gap - low_span / 2.0
        high_center = window_center + window_span / 2.0 + gap + high_span / 2.0

        low_curtain[along_axis] = float(low_center)
        window[along_axis] = float(window_center)
        high_curtain[along_axis] = float(high_center)
        for curtain in selected:
            _clamp_wall_attached_object(curtain, room, wall_id)
        _clamp_wall_attached_object(window, room, wall_id)

        rod_ids: list[str] = []
        group_low = min(
            low_center - low_span / 2.0,
            window_center - window_span / 2.0,
            high_center - high_span / 2.0,
        )
        group_high = max(
            low_center + low_span / 2.0,
            window_center + window_span / 2.0,
            high_center + high_span / 2.0,
        )
        group_center = (group_low + group_high) / 2.0
        group_span = group_high - group_low
        top_z = max(
            float(window.get("z", 0.0) or 0.0) + float(window.get("dimensions", {}).get("height", 0.0) or 0.0),
            *(float(c.get("z", 0.0) or 0.0) + float(c.get("dimensions", {}).get("height", 0.0) or 0.0) for c in selected),
        )
        for rod in rods:
            rod_ids.append(str(rod.get("id") or ""))
            dims = rod.setdefault("dimensions", {})
            # With the wall footprint offset, width is the tangent span for
            # side-wall rods and also the tangent span for back/front-wall rods.
            rod_overhang = max(0.0, float(WINDOW_CURTAIN_CLUSTER_ROD_OVERHANG))
            dims["width"] = _clamp(group_span + rod_overhang, 0.35, room_extent - 0.04)
            dims["length"] = min(float(dims.get("length", 0.045) or 0.045), 0.06)
            dims["height"] = _clamp(float(dims.get("height", 0.045) or 0.045), 0.025, 0.08)
            rod[along_axis] = float(group_center)
            rod["z"] = min(float(room.get("height", 2.7) or 2.7) - float(dims["height"]) - 0.04, top_z + 0.035)
            _clamp_wall_attached_object(rod, room, wall_id)

        after_by_id = {str(member.get("id") or ""): _plan_object_snapshot(member) for member in members_to_lock}
        changed = {
            object_id: {"before": before_by_id[object_id], "after": after}
            for object_id, after in after_by_id.items()
            if object_id and before_by_id.get(object_id) != after
        }
        if changed:
            report.setdefault("fixes", []).append(
                {
                    "stage": report.get("stage"),
                    "type": "window_curtain_assembly_lock",
                    "window_id": window.get("id"),
                    "curtain_ids": [str(curtain.get("id") or "") for curtain in selected],
                    "rod_ids": rod_ids,
                    "wall_id": wall_id,
                    "along_axis": along_axis,
                    "window_center": round(float(window.get(along_axis, 0.0) or 0.0), 6),
                    "target_panel_span": round(float(target_panel_span), 6),
                    "reference_panel_ratio": round(float(panel_ratio), 6),
                    "tightness": tightness,
                    "target_gap": round(float(gap), 6),
                    "left_gap": round(float((window_center - window_span / 2.0) - (low_center + low_span / 2.0)), 6),
                    "right_gap": round(float((high_center - high_span / 2.0) - (window_center + window_span / 2.0)), 6),
                    "group_span": round(float(group_span), 6),
                    "ordered_ids": [
                        str(low_curtain.get("id") or ""),
                        str(window.get("id") or ""),
                        str(high_curtain.get("id") or ""),
                    ],
                    "changed": changed,
                    "evidence": (
                        "A window, its two curtain panels, and curtain rod form one wall fixture assembly: "
                        "the window must stay between the two panels and the rod should span the whole group."
                    ),
                }
            )


def _is_curtain_panel_object(obj: dict[str, Any]) -> bool:
    text = _object_identity_text(obj)
    return any(keyword in text for keyword in ("curtain", "drape", "drapery")) and "rod" not in text


def _is_curtain_rod_object(obj: dict[str, Any]) -> bool:
    text = _object_identity_text(obj)
    return any(keyword in text for keyword in ("curtain rod", "drape rod", "drapery rod"))


def _fit_curtain_panels_to_reference_vertical_extent(
    plan: dict[str, Any],
    scene_graph: dict[str, Any],
    report: dict[str, Any],
) -> None:
    room = plan.get("room") if isinstance(plan.get("room"), dict) else {}
    if not room:
        return
    room_height = float(room.get("height", 0.0) or 0.0)
    if room_height <= 0.0:
        return
    objects = {str(obj.get("id")): obj for obj in plan.get("objects", []) if isinstance(obj, dict) and obj.get("id")}
    ref_bboxes = _reference_bboxes_by_object(scene_graph)
    for curtain in objects.values():
        if not _is_curtain_panel_object(curtain):
            continue
        wall_id = str(curtain.get("support_id") or "")
        if wall_id not in VIRTUAL_WALLS:
            support = objects.get(wall_id)
            wall_id = str(support.get("support_id") or "") if support else ""
        if wall_id not in VIRTUAL_WALLS:
            relation = _semantic_wall_relation(curtain)
            wall_id = _wall_id(relation.get("wall_id")) if isinstance(relation, dict) else ""
        if wall_id not in VIRTUAL_WALLS:
            continue
        bbox = ref_bboxes.get(str(curtain.get("id") or ""))
        if not bbox:
            continue
        y1 = _clamp(float(bbox[1]), 0.0, 1.0)
        y2 = _clamp(float(bbox[3]), 0.0, 1.0)
        if y2 <= y1:
            continue
        bbox_span = y2 - y1
        if bbox_span < 0.12:
            continue
        dims = curtain.setdefault("dimensions", {})
        current_height = float(dims.get("height", 0.45) or 0.45)
        # The visible bbox is perspective-compressed on oblique side walls. Use it as a
        # lower-bound signal and keep curtains long enough to read as panels.
        target_height = _clamp(
            room_height * bbox_span * 1.16,
            max(current_height, room_height * 0.42, 1.05),
            min(room_height - 0.10, 2.60),
        )
        top_z = _clamp(room_height * (1.0 - y1) - 0.02, target_height + 0.04, room_height - 0.08)
        bottom_z = _clamp(top_z - target_height, 0.04, max(0.04, room_height - target_height - 0.04))
        before = _plan_object_snapshot(curtain)
        dims["height"] = float(target_height)
        dims["length"] = min(
            float(dims.get("length", WINDOW_CURTAIN_CLUSTER_PANEL_THICKNESS) or WINDOW_CURTAIN_CLUSTER_PANEL_THICKNESS),
            float(WINDOW_CURTAIN_CLUSTER_PANEL_THICKNESS),
        )
        curtain["z"] = float(bottom_z)
        curtain["placement_type"] = "attached_to_wall"
        curtain["support_id"] = wall_id
        curtain["yaw"] = _wall_semantic_yaw(wall_id)
        curtain["footprint_yaw_offset_degrees"] = _wall_footprint_offset_for_object(wall_id, curtain)
        _clamp_wall_attached_object(curtain, room, wall_id)
        after = _plan_object_snapshot(curtain)
        if before != after:
            report.setdefault("fixes", []).append(
                {
                    "stage": report.get("stage"),
                    "type": "curtain_reference_vertical_fit",
                    "id": curtain.get("id"),
                    "wall_id": wall_id,
                    "reference_bbox": [round(float(value), 6) for value in bbox],
                    "target_height": round(float(target_height), 6),
                    "target_bottom_z": round(float(bottom_z), 6),
                    "before": before,
                    "after": after,
                    "evidence": "Curtain panels should use the reference bbox vertical extent; generic wall/hanging defaults make them too short.",
                }
            )


def _align_floor_covering_underlay_supports(
    plan: dict[str, Any],
    parent: dict[str, str],
    report: dict[str, Any],
    scene_graph: dict[str, Any] | None = None,
    cross_constraints: list[dict[str, Any]] | None = None,
) -> None:
    room = plan.get("room") if isinstance(plan.get("room"), dict) else {}
    if not room:
        return
    objects = {str(obj.get("id")): obj for obj in plan.get("objects", []) if isinstance(obj, dict) and obj.get("id")}
    children_by_rug: dict[str, dict[str, dict[str, Any]]] = {}

    def add_visual_underlay(child_id: str, rug_id: str) -> None:
        rug = objects.get(str(rug_id))
        child = objects.get(str(child_id))
        if not rug or not child or not _is_floor_covering(rug):
            return
        if not _is_floor_covering_underlay_target(child):
            return
        children_by_rug.setdefault(str(rug_id), {})[str(child_id)] = child

    for child_id, parent_id in parent.items():
        add_visual_underlay(str(child_id), str(parent_id))

    relation_sources: list[dict[str, Any]] = []
    if isinstance(scene_graph, dict) and isinstance(scene_graph.get("relations"), list):
        relation_sources.extend(rel for rel in scene_graph.get("relations", []) if isinstance(rel, dict))
    if isinstance(cross_constraints, list):
        relation_sources.extend(rel for rel in cross_constraints if isinstance(rel, dict))
    for rel in relation_sources:
        rel_type = str(rel.get("type") or "")
        if rel_type.startswith("secondary_"):
            rel_type = rel_type[len("secondary_") :]
        subject_id = str(rel.get("subject") or "")
        object_id = str(rel.get("object") or "")
        if subject_id not in objects or object_id not in objects:
            continue
        subject = objects[subject_id]
        target = objects[object_id]
        relation_is_visual_layer = bool(rel.get("_floor_covering_visual_layer")) or rel_type in SUPPORT_RELATIONS or _is_floor_covering_underlay_evidence(rel)
        if not relation_is_visual_layer:
            continue
        if _is_floor_covering(subject):
            add_visual_underlay(object_id, subject_id)
        elif _is_floor_covering(target):
            add_visual_underlay(subject_id, object_id)

    for rug_id, children_by_id in children_by_rug.items():
        children = list(children_by_id.values())
        rug = objects.get(rug_id)
        if not rug or not children:
            continue
        anchor = max(children, key=lambda item: _bbox_area(_reference_bbox_from_sources(item)) or 0.0)
        child_boxes: list[tuple[float, float, float, float]] = []
        for child in children:
            child_w, child_l = _rotated_footprint(child)
            child_x = float(child.get("x", 0.0) or 0.0)
            child_y = float(child.get("y", 0.0) or 0.0)
            min_x = child_x - child_w / 2.0
            max_x = child_x + child_w / 2.0
            min_y = child_y - child_l / 2.0
            max_y = child_y + child_l / 2.0
            if _is_bed_or_sofa_object(child):
                relation = _semantic_wall_relation(child)
                mode = str(relation.get("mode") or "").strip().lower()
                wall_id = _wall_id(relation.get("wall_id")) if mode in {"against", "near", "attached", "wall_flush"} else ""
                # Rugs under beds usually cover the foot/front portion, not the full headboard-to-wall footprint.
                if wall_id == "wall_north":
                    max_y = min(max_y, child_y + child_l * 0.12)
                elif wall_id == "wall_south":
                    min_y = max(min_y, child_y - child_l * 0.12)
                elif wall_id == "wall_east":
                    max_x = min(max_x, child_x + child_w * 0.12)
                elif wall_id == "wall_west":
                    min_x = max(min_x, child_x - child_w * 0.12)
            child_boxes.append((min_x, max_x, min_y, max_y))
        if not child_boxes:
            continue
        union_min_x = min(box[0] for box in child_boxes)
        union_max_x = max(box[1] for box in child_boxes)
        union_min_y = min(box[2] for box in child_boxes)
        union_max_y = max(box[3] for box in child_boxes)
        union_width = union_max_x - union_min_x
        union_length = union_max_y - union_min_y
        has_bed_underlay = any(_is_bed_or_sofa_object(child) for child in children)
        before = _plan_object_snapshot(rug)
        anchor_w, anchor_l = _rotated_footprint(anchor)
        rug_dims = _validated_dimension_triplet(rug.get("dimensions")) or dict(rug.get("dimensions", {}))
        if not rug_dims:
            continue
        if has_bed_underlay:
            target_width = _clamp(
                max(union_width + 0.55, anchor_w * 1.06),
                max(union_width + 0.22, anchor_w * 0.92),
                float(room.get("width", anchor_w)) - 0.10,
            )
            target_length = _clamp(
                max(union_length + 0.52, anchor_l * 0.86),
                max(union_length + 0.22, anchor_l * 0.50),
                float(room.get("length", anchor_l)) - 0.16,
            )
            rug_dims["width"] = target_width
            rug_dims["length"] = target_length
        else:
            target_width = _clamp(
                max(anchor_w * 1.28, union_width + 0.45),
                max(anchor_w + 0.35, union_width + 0.20),
                float(room.get("width", anchor_w)) - 0.10,
            )
            target_length = _clamp(
                max(anchor_l * 1.52, union_length + 0.70),
                max(anchor_l + 0.55, union_length + 0.25),
                float(room.get("length", anchor_l)) - 0.16,
            )
            rug_dims["width"] = max(float(rug_dims.get("width", 0.0) or 0.0), target_width)
            rug_dims["length"] = max(float(rug_dims.get("length", 0.0) or 0.0), target_length)
        rug_dims["height"] = min(max(float(rug_dims.get("height", 0.035) or 0.035), 0.018), 0.055)
        rug["dimensions"] = rug_dims
        rug["yaw"] = 0.0
        rug["footprint_yaw_offset_degrees"] = 0.0
        rug_w, rug_l = _rotated_footprint(rug)
        rug["x"] = _clamp(
            (union_min_x + union_max_x) / 2.0,
            rug_w / 2.0 + FLOOR_WALL_AGAINST_GAP,
            float(room.get("width", 0.0) or 0.0) - rug_w / 2.0 - FLOOR_WALL_AGAINST_GAP,
        )
        if has_bed_underlay:
            target_back = min(float(room.get("length", 0.0) or 0.0) - 0.10, union_max_y + 0.10)
            rug["y"] = target_back - rug_l / 2.0
        else:
            target_back = min(float(room.get("length", 0.0) or 0.0) - 0.10, union_max_y - 0.04)
            target_front = max(0.10, union_min_y - anchor_l * 0.58)
            if target_back - target_front > rug_l * 0.72:
                rug["y"] = (target_front + target_back) / 2.0
                if target_back - target_front > rug_l:
                    rug_dims["length"] = min(float(room.get("length", rug_l) or rug_l) - 0.16, target_back - target_front)
                    rug["dimensions"] = rug_dims
                    rug_w, rug_l = _rotated_footprint(rug)
                    rug["y"] = (target_front + target_back) / 2.0
            else:
                rug["y"] = (union_min_y + union_max_y) / 2.0 - anchor_l * 0.20
        rug["y"] = _clamp(
            float(rug.get("y", 0.0) or 0.0),
            rug_l / 2.0 + FLOOR_WALL_AGAINST_GAP,
            float(room.get("length", 0.0) or 0.0) - rug_l / 2.0 - FLOOR_WALL_AGAINST_GAP,
        )
        rug["z"] = 0.0
        rug["placement_type"] = "floor"
        rug["support_id"] = None
        after = _plan_object_snapshot(rug)
        if before != after:
            report["fixes"].append(
                {
                    "stage": report.get("stage"),
                    "type": "floor_covering_visual_underlay_alignment",
                    "id": rug_id,
                    "underlay_object_ids": sorted(str(child.get("id") or "") for child in children),
                    "anchor_object": anchor.get("id"),
                    "rug_before": before,
                    "rug_after": after,
                    "evidence": "Floor covering is a thin visual floor layer: align it under related furniture without making it the support parent or moving supported objects.",
                }
            )


def _place_left_rear_plants_behind_bedside(
    plan: dict[str, Any],
    scene_graph: dict[str, Any],
    report: dict[str, Any],
) -> None:
    room = plan.get("room") if isinstance(plan.get("room"), dict) else {}
    if not room:
        return
    objects = {str(obj.get("id")): obj for obj in plan.get("objects", []) if isinstance(obj, dict) and obj.get("id")}
    relation_pairs: list[tuple[str, str]] = []
    for rel in scene_graph.get("relations", []) if isinstance(scene_graph.get("relations"), list) else []:
        if not isinstance(rel, dict) or str(rel.get("type") or "") != "in_front_of":
            continue
        subject_id = str(rel.get("subject") or "")
        target_id = str(rel.get("object") or "")
        subject = objects.get(subject_id)
        target = objects.get(target_id)
        if not subject or not target:
            continue
        subject_kind = f"{_category_text(subject)} {subject_id.lower()}"
        target_text = _object_identity_text(target)
        if (
            "plant" not in _category_text(subject)
            and any(keyword in subject_kind for keyword in ("nightstand", "bedside", "side table"))
            and "plant" in target_text
            and "top" not in target_text
            and float(subject.get("x", 0.0) or 0.0) <= float(room.get("width", 0.0) or 0.0) * 0.35
            and float(target.get("x", 0.0) or 0.0) <= float(room.get("width", 0.0) or 0.0) * 0.35
        ):
            relation_pairs.append((subject_id, target_id))
    if not relation_pairs:
        return

    bed_candidates = [obj for obj in objects.values() if _is_bed_or_sofa_object(obj)]
    bed = bed_candidates[0] if bed_candidates else None
    bed_left_limit: float | None = None
    if bed:
        bed_w, _bed_l = _rotated_footprint(bed)
        bed_left_limit = float(bed.get("x", 0.0) or 0.0) - bed_w / 2.0

    for table_id, plant_id in relation_pairs:
        table = objects.get(table_id)
        plant = objects.get(plant_id)
        if not table or not plant:
            continue
        before = _plan_object_snapshot(plant)
        table_w, table_l = _rotated_footprint(table)
        plant_w, plant_l = _rotated_footprint(plant)
        clearance = 0.10
        target_y = float(table.get("y", 0.0) or 0.0) + table_l / 2.0 + plant_l / 2.0 + clearance
        max_y = float(room.get("length", 0.0) or 0.0) - plant_l / 2.0 - FLOOR_WALL_AGAINST_GAP
        for anchor in objects.values():
            if anchor is table or anchor is plant or _is_bed_or_sofa_object(anchor):
                continue
            if not _is_floor_storage_or_table_branch_object(anchor):
                continue
            anchor_y = float(anchor.get("y", 0.0) or 0.0)
            if anchor_y < float(room.get("length", 0.0) or 0.0) * 0.70:
                continue
            anchor_w, anchor_l = _rotated_footprint(anchor)
            anchor_left = float(anchor.get("x", 0.0) or 0.0) - anchor_w / 2.0
            anchor_right = float(anchor.get("x", 0.0) or 0.0) + anchor_w / 2.0
            plant_left = float(plant.get("x", 0.0) or 0.0) - plant_w / 2.0
            plant_right = float(plant.get("x", 0.0) or 0.0) + plant_w / 2.0
            if min(anchor_right, plant_right) - max(anchor_left, plant_left) <= 0.0:
                continue
            anchor_front = anchor_y - anchor_l / 2.0
            max_y = min(max_y, anchor_front - plant_l / 2.0 - clearance)
        plant["y"] = _clamp(target_y, plant_l / 2.0 + FLOOR_WALL_AGAINST_GAP, max_y)
        if bed_left_limit is not None:
            max_x = bed_left_limit - plant_w / 2.0 - 0.06
            if max_x > plant_w / 2.0 + FLOOR_WALL_AGAINST_GAP:
                plant["x"] = min(float(plant.get("x", 0.0) or 0.0), max_x)
        _clamp_object_to_room(plant, room)
        after = _plan_object_snapshot(plant)
        if before != after:
            report["fixes"].append(
                {
                    "stage": report.get("stage"),
                    "type": "left_bedside_plant_depth_alignment",
                    "id": plant_id,
                    "front_anchor": table_id,
                    "before": before,
                    "after": after,
                    "evidence": "Left floor plant belongs behind the left bedside table in the reference, not in the foreground.",
                }
            )


def _is_rear_storage_between_anchor(obj: dict[str, Any], room: dict[str, Any]) -> bool:
    text = _object_identity_text(obj)
    if not any(keyword in text for keyword in ("wardrobe", "closet", "armoire", "cabinet")):
        return False
    relation = _semantic_wall_relation(obj)
    wall_id = _wall_id(relation.get("wall_id")) if isinstance(relation, dict) else None
    if wall_id == "wall_north":
        return True
    room_length = float(room.get("length", 0.0) or 0.0)
    return room_length > 0.0 and float(obj.get("y", 0.0) or 0.0) >= room_length * 0.68


def _place_rear_between_storage_plants(
    plan: dict[str, Any],
    scene_graph: dict[str, Any],
    report: dict[str, Any],
) -> None:
    room = plan.get("room") if isinstance(plan.get("room"), dict) else {}
    if not room:
        return
    objects = {str(obj.get("id")): obj for obj in plan.get("objects", []) if isinstance(obj, dict) and obj.get("id")}
    if not objects:
        return
    relations = scene_graph.get("relations") if isinstance(scene_graph.get("relations"), list) else []
    related_by_object: dict[str, set[str]] = {}
    for rel in relations:
        if not isinstance(rel, dict):
            continue
        rel_type = str(rel.get("type") or "")
        if rel_type not in {"near", "left_of", "right_of", "in_front_of", "behind"}:
            continue
        subject = str(rel.get("subject") or "")
        target = str(rel.get("object") or "")
        if not subject or not target:
            continue
        related_by_object.setdefault(subject, set()).add(target)
        related_by_object.setdefault(target, set()).add(subject)

    for plant in objects.values():
        plant_id = str(plant.get("id") or "")
        if str(plant.get("placement_type", "floor")) != "floor" or str(plant.get("support_id") or ""):
            continue
        if _semantic_class(plant) != "plant" and "plant" not in _object_identity_text(plant):
            continue
        semantics = plant.get("agent_semantics") if isinstance(plant.get("agent_semantics"), dict) else {}
        combined = " ".join(
            [
                plant_id,
                str(plant.get("category") or ""),
                str(plant.get("description") or ""),
                str(semantics.get("reference_evidence") or ""),
            ]
        ).lower()
        if "between" not in combined:
            continue
        if not any(keyword in combined for keyword in ("wardrobe", "closet", "armoire", "cabinet")):
            continue
        if not any(keyword in combined for keyword in ("rear wall", "back wall", "north wall", "behind the bed", "behind bed")):
            continue

        related_anchor_ids = related_by_object.get(plant_id, set())
        anchors = [
            objects[anchor_id]
            for anchor_id in related_anchor_ids
            if anchor_id in objects and _is_rear_storage_between_anchor(objects[anchor_id], room)
        ]
        plant_bbox = _reference_bbox_from_sources(plant)
        plant_cx = ((float(plant_bbox[0]) + float(plant_bbox[2])) / 2.0) if plant_bbox else None
        if len(anchors) < 2 and plant_cx is not None:
            bbox_anchors: list[dict[str, Any]] = []
            for candidate in objects.values():
                if candidate is plant or not _is_rear_storage_between_anchor(candidate, room):
                    continue
                candidate_bbox = _reference_bbox_from_sources(candidate)
                if not candidate_bbox:
                    continue
                cx = (float(candidate_bbox[0]) + float(candidate_bbox[2])) / 2.0
                if abs(cx - plant_cx) <= 0.28:
                    bbox_anchors.append(candidate)
            anchors = bbox_anchors
        if len(anchors) < 2:
            continue

        before = _plan_object_snapshot(plant)
        plant_w, plant_l = _rotated_footprint(plant)
        anchor_centers_x = [float(anchor.get("x", 0.0) or 0.0) for anchor in anchors]
        anchor_front_edges: list[float] = []
        for anchor in anchors:
            _anchor_w, anchor_l = _rotated_footprint(anchor)
            anchor_front_edges.append(float(anchor.get("y", 0.0) or 0.0) - anchor_l / 2.0)
        if not anchor_front_edges:
            continue
        room_width = float(room.get("width", 0.0) or 0.0)
        room_length = float(room.get("length", 0.0) or 0.0)
        target_x = sum(anchor_centers_x) / max(1, len(anchor_centers_x))
        target_y = min(anchor_front_edges) - plant_l / 2.0 - 0.06
        target_y = max(target_y, room_length * 0.72)
        plant["x"] = _clamp(target_x, plant_w / 2.0 + FLOOR_WALL_AGAINST_GAP, room_width - plant_w / 2.0 - FLOOR_WALL_AGAINST_GAP)
        plant["y"] = _clamp(target_y, plant_l / 2.0 + FLOOR_WALL_AGAINST_GAP, room_length - plant_l / 2.0 - FLOOR_WALL_AGAINST_GAP)
        _clamp_object_to_room(plant, room)
        after = _plan_object_snapshot(plant)
        if before != after:
            report["fixes"].append(
                {
                    "stage": report.get("stage"),
                    "type": "rear_between_storage_plant_alignment",
                    "id": plant_id,
                    "anchor_ids": [str(anchor.get("id") or "") for anchor in anchors],
                    "before": before,
                    "after": after,
                    "evidence": "Plant described as between rear storage units should stay in the rear storage branch instead of being pulled into the foreground by a generic in-front-of relation.",
                }
            )

        plant_x = float(plant.get("x", 0.0) or 0.0)
        plant_y = float(plant.get("y", 0.0) or 0.0)
        plant_left = plant_x - plant_w / 2.0
        plant_right = plant_x + plant_w / 2.0
        plant_front = plant_y - plant_l / 2.0
        for bed in objects.values():
            if not _is_bed_or_sofa_object(bed):
                continue
            bed_id = str(bed.get("id") or "")
            bed_w, bed_l = _rotated_footprint(bed)
            if bed_w <= 0.0 or bed_l <= 0.0:
                continue
            bed_x = float(bed.get("x", 0.0) or 0.0)
            bed_y = float(bed.get("y", 0.0) or 0.0)
            bed_left = bed_x - bed_w / 2.0
            bed_right = bed_x + bed_w / 2.0
            bed_front = bed_y - bed_l / 2.0
            bed_back = bed_y + bed_l / 2.0
            overlap_x = min(bed_right, plant_right) - max(bed_left, plant_left)
            overlap_y = min(bed_back, plant_y + plant_l / 2.0) - max(bed_front, plant_front)
            if overlap_x <= min(bed_w, plant_w) * 0.12 or overlap_y <= 0.0:
                continue
            bed_before = _plan_object_snapshot(bed)
            old_x = float(bed.get("x", 0.0) or 0.0)
            old_y = bed_y
            clearance = max(0.04, FLOOR_WALL_AGAINST_GAP)
            target_bed_back = plant_front - clearance
            target_bed_y = target_bed_back - bed_l / 2.0
            target_bed_y = _clamp(
                target_bed_y,
                bed_l / 2.0 + FLOOR_WALL_AGAINST_GAP,
                room_length - bed_l / 2.0 - FLOOR_WALL_AGAINST_GAP,
            )
            # A rear-between-storage plant is a background cue. Move the bed
            # forward only enough to reveal that rear branch instead of
            # letting the bed footprint consume the plant.
            target_bed_y = max(target_bed_y, old_y - 0.65)
            if old_y - target_bed_y < 0.05:
                continue
            bed["y"] = target_bed_y
            _clamp_object_to_room_rotated(bed, room)
            moved_children = _move_direct_supported_children(
                objects,
                bed_id,
                float(bed.get("x", old_x) or old_x) - old_x,
                float(bed.get("y", old_y) or old_y) - old_y,
                room,
            )
            bed_after = _plan_object_snapshot(bed)
            if bed_before != bed_after:
                report["fixes"].append(
                    {
                        "stage": report.get("stage"),
                        "type": "bed_forward_for_rear_between_storage_plant_clearance",
                        "id": bed_id,
                        "plant_id": plant_id,
                        "anchor_ids": [str(anchor.get("id") or "") for anchor in anchors],
                        "before": bed_before,
                        "after": bed_after,
                        "target_bed_back_y": round(float(target_bed_back), 6),
                        "plant_front_y": round(float(plant_front), 6),
                        "overlap_x": round(float(overlap_x), 6),
                        "overlap_y": round(float(overlap_y), 6),
                        "moved_children": moved_children,
                        "evidence": "A small plant explicitly behind the headboard and between rear storage should occupy the rear visual branch; if the bed footprint covers it, shift the bed forward to preserve the reference depth layer.",
                    }
                )


def _bed_side_hint_from_reference(
    scene_graph: dict[str, Any],
    object_id: str,
    bed_id: str,
    obj: dict[str, Any],
) -> str | None:
    texts: list[str] = [
        object_id,
        str(obj.get("category") or ""),
        str(obj.get("description") or ""),
    ]
    semantics = obj.get("agent_semantics") if isinstance(obj.get("agent_semantics"), dict) else {}
    texts.extend(
        str(value)
        for value in (
            semantics.get("reference_evidence"),
            semantics.get("support_evidence"),
            semantics.get("expected_pose"),
        )
        if value is not None
    )
    for rel in scene_graph.get("relations", []) if isinstance(scene_graph.get("relations"), list) else []:
        if not isinstance(rel, dict):
            continue
        subject = str(rel.get("subject") or "")
        target = str(rel.get("object") or "")
        if {subject, target} != {object_id, bed_id}:
            continue
        texts.append(str(rel.get("evidence") or ""))
        rel_type = str(rel.get("type") or "")
        if subject == object_id and rel_type == "right_of":
            return "right"
        if subject == object_id and rel_type == "left_of":
            return "left"
        if target == object_id and rel_type == "right_of":
            return "left"
        if target == object_id and rel_type == "left_of":
            return "right"
    combined = " ".join(texts).lower()
    right_phrases = (
        "right side of bed",
        "right side of the bed",
        "right edge of bed",
        "right edge of the bed",
        "beside right side",
        "beside the right side",
        "to the right of the bed",
        "right of the bed",
    )
    left_phrases = (
        "left side of bed",
        "left side of the bed",
        "left edge of bed",
        "left edge of the bed",
        "beside left side",
        "beside the left side",
        "to the left of the bed",
        "left of the bed",
    )
    if any(phrase in combined for phrase in right_phrases):
        return "right"
    if any(phrase in combined for phrase in left_phrases):
        return "left"
    return None


def _is_bed_side_lateral_clearance_candidate(obj: dict[str, Any]) -> bool:
    text = _category_text(obj)
    semantic = _semantic_class(obj)
    if any(keyword in text for keyword in ("nightstand", "bedside", "side table")):
        return True
    hard_storage_keywords = (
        "wardrobe",
        "closet",
        "dresser",
        "chest",
        "cabinet",
        "bookcase",
        "bookshelf",
        "shelving",
        "drawer unit",
    )
    if semantic in {"floor_furniture", "book_storage", "table_anchor"} or any(keyword in text for keyword in hard_storage_keywords):
        return False
    if semantic in {"plant", "lighting", "decor"}:
        return True
    return any(keyword in text for keyword in ("plant", "lamp", "decor", "vase", "basket"))


def _bed_side_depth_alignment_candidate(scene_graph: dict[str, Any], object_id: str, bed_id: str, obj: dict[str, Any]) -> bool:
    texts: list[str] = [
        object_id,
        str(obj.get("category") or ""),
        str(obj.get("description") or ""),
    ]
    semantics = obj.get("agent_semantics") if isinstance(obj.get("agent_semantics"), dict) else {}
    for key in ("reference_evidence", "support_evidence", "expected_pose"):
        value = semantics.get(key)
        if value is not None:
            texts.append(str(value))
    for rel in scene_graph.get("relations", []) if isinstance(scene_graph.get("relations"), list) else []:
        if not isinstance(rel, dict):
            continue
        subject = str(rel.get("subject") or "")
        target = str(rel.get("object") or "")
        if object_id not in {subject, target}:
            continue
        if bed_id in {subject, target}:
            texts.append(str(rel.get("evidence") or ""))
            continue
        rel_text = " ".join([subject, target, str(rel.get("type") or ""), str(rel.get("evidence") or "")]).lower()
        if any(keyword in rel_text for keyword in ("window", "curtain", "door", "closet", "wardrobe", "dresser", "cabinet")):
            texts.append(rel_text)
    combined = " ".join(texts).lower()
    explicit_bedside_phrases = (
        "beside the bed",
        "beside bed",
        "bedside",
        "side of the bed",
        "side of bed",
        "right of the bed",
        "left of the bed",
        "to the right of the bed",
        "to the left of the bed",
        "bed right",
        "bed left",
        "headboard",
        "near the bed",
    )
    if any(phrase in combined for phrase in explicit_bedside_phrases):
        return True
    non_bed_branch_phrases = (
        "window",
        "curtain",
        "door",
        "closet",
        "wardrobe",
        "dresser",
        "cabinet",
    )
    if any(phrase in combined for phrase in non_bed_branch_phrases):
        return False
    return False


def _place_bed_side_floor_objects_outside_bed_footprint(
    plan: dict[str, Any],
    scene_graph: dict[str, Any],
    report: dict[str, Any],
) -> None:
    room = plan.get("room") if isinstance(plan.get("room"), dict) else {}
    if not room:
        return
    objects = {str(obj.get("id")): obj for obj in plan.get("objects", []) if isinstance(obj, dict) and obj.get("id")}
    beds = [obj for obj in objects.values() if _is_bed_or_sofa_object(obj)]
    if not beds:
        return
    for bed in beds:
        bed_id = str(bed.get("id") or "")
        bed_w, bed_l = _rotated_footprint(bed)
        bed_x = float(bed.get("x", 0.0) or 0.0)
        bed_y = float(bed.get("y", 0.0) or 0.0)
        bed_left = bed_x - bed_w / 2.0
        bed_right = bed_x + bed_w / 2.0
        for obj in objects.values():
            object_id = str(obj.get("id") or "")
            if object_id == bed_id:
                continue
            if str(obj.get("placement_type", "floor")) != "floor":
                continue
            if str(obj.get("support_id") or "") in VIRTUAL_WALLS:
                continue
            if _is_floor_covering(obj) or _is_hanging_object(obj):
                continue
            if not _is_bed_side_lateral_clearance_candidate(obj):
                continue
            if _is_shared_between_multiple_beds(obj, scene_graph, beds):
                continue
            side = _bed_side_hint_from_reference(scene_graph, object_id, bed_id, obj)
            if side not in {"left", "right"}:
                continue
            obj_w, obj_l = _rotated_footprint(obj)
            obj_x = float(obj.get("x", 0.0) or 0.0)
            obj_y = float(obj.get("y", 0.0) or 0.0)
            obj_left = obj_x - obj_w / 2.0
            obj_right = obj_x + obj_w / 2.0
            overlap_x = min(bed_right, obj_right) - max(bed_left, obj_left)
            clearance = 0.08
            target_x = obj_x
            lateral_needs_fix = False
            if side == "right":
                required_x = bed_right + obj_w / 2.0 + clearance
                if overlap_x > 0.0 or obj_x < required_x - 0.03:
                    target_x = max(obj_x, required_x)
                    lateral_needs_fix = True
            else:
                required_x = bed_left - obj_w / 2.0 - clearance
                if overlap_x > 0.0 or obj_x > required_x + 0.03:
                    target_x = min(obj_x, required_x)
                    lateral_needs_fix = True
            decor_text = _category_text(obj)
            is_bedside_floor_decor = (
                _semantic_class(obj) in {"plant", "lighting", "decor", "floor_lamp"}
                or any(keyword in decor_text for keyword in ("plant", "floor lamp", "lamp", "vase", "decor"))
            )
            # Bedside floor decor in these bedroom references belongs around the headboard/rear half, not near the foot.
            depth_alignment_allowed = True
            if is_bedside_floor_decor:
                depth_alignment_allowed = _bed_side_depth_alignment_candidate(scene_graph, object_id, bed_id, obj)
            target_y = bed_y + (bed_l * 0.18 if is_bedside_floor_decor else 0.06)
            depth_needs_fix = depth_alignment_allowed and obj_y < target_y - 0.08
            if not lateral_needs_fix and not depth_needs_fix:
                continue
            before = _plan_object_snapshot(obj)
            old_x = obj_x
            old_y = obj_y
            obj["x"] = _clamp(target_x, obj_w / 2.0 + FLOOR_WALL_AGAINST_GAP, float(room.get("width", 0.0) or 0.0) - obj_w / 2.0 - FLOOR_WALL_AGAINST_GAP)
            if depth_needs_fix:
                obj["y"] = _clamp(
                    target_y,
                    obj_l / 2.0 + FLOOR_WALL_AGAINST_GAP,
                    float(room.get("length", 0.0) or 0.0) - obj_l / 2.0 - FLOOR_WALL_AGAINST_GAP,
                )
            _clamp_object_to_room(obj, room)
            moved_children = _move_direct_supported_children(
                objects,
                object_id,
                float(obj.get("x", old_x) or old_x) - old_x,
                float(obj.get("y", old_y) or old_y) - old_y,
                room,
            )
            after = _plan_object_snapshot(obj)
            if before != after:
                report["fixes"].append(
                    {
                        "stage": report.get("stage"),
                        "type": "bed_side_object_lateral_clearance",
                        "id": object_id,
                        "bed_id": bed_id,
                        "side": side,
                        "bed_footprint_x": [round(float(bed_left), 6), round(float(bed_right), 6)],
                        "overlap_x_before": round(float(overlap_x), 6),
                        "bed_y": round(float(bed_y), 6),
                        "target_y": round(float(target_y), 6),
                        "depth_alignment_allowed": bool(depth_alignment_allowed),
                        "depth_needs_fix": bool(depth_needs_fix),
                        "lateral_needs_fix": bool(lateral_needs_fix),
                        "before": before,
                        "after": after,
                        "moved_children": moved_children,
                        "evidence": "Object is described as belonging beside the bed; keep it outside the bed footprint and, for bedside decor, in the bed headboard/rear-half depth band.",
                    }
                )


def apply_reference_consistency_layout_refinements(
    plan: dict[str, Any],
    scene_graph: dict[str, Any],
    cross_constraints: list[dict[str, Any]],
    parent: dict[str, str],
    enabled: bool,
    stage: str,
) -> dict[str, Any]:
    report: dict[str, Any] = {
        "schema": "tree_sage_reference_consistency_layout_refiner_pass_v1",
        "enabled": bool(enabled),
        "stage": stage,
        "ok": True,
        "fixes": [],
        "warnings": [],
    }
    if not enabled:
        report["reason"] = "disabled"
        return report
    consistency = scene_graph.get("_reference_consistency_refiner") if isinstance(scene_graph.get("_reference_consistency_refiner"), dict) else {}
    branches = consistency.get("side_wall_branches") if isinstance(consistency.get("side_wall_branches"), list) else []
    _reference_consistency_fix_bed_against_back_wall(plan, cross_constraints, parent, report)
    _align_multi_bed_wall_rows(plan, scene_graph, cross_constraints, parent, report)
    for branch in branches:
        if isinstance(branch, dict):
            _pack_side_wall_branch(plan, scene_graph, branch, report)
    _reference_depth_slice_fix_large_object_rear_contact(plan, scene_graph, cross_constraints, parent, report)
    _place_bed_side_floor_objects_outside_bed_footprint(plan, scene_graph, report)
    _align_bedside_tables_with_bed(plan, scene_graph, report)
    _shift_bed_left_if_right_branch_too_close(plan, scene_graph, parent, report)
    _repair_bed_cluster_side_wall_storage_collision(plan, scene_graph, report)
    _align_floor_covering_underlay_supports(plan, parent, report, scene_graph, cross_constraints)
    _same_side_wall_depth_order_fix(plan, scene_graph, cross_constraints, parent, report)
    _separate_same_wall_doors_from_storage_along_tangent(plan, scene_graph, cross_constraints, parent, report)
    _side_wall_storage_bed_front_depth_fix(plan, scene_graph, cross_constraints, parent, report)
    _separate_window_curtain_panels(plan, scene_graph, report)
    _fit_curtain_panels_to_reference_vertical_extent(plan, scene_graph, report)
    _place_left_rear_plants_behind_bedside(plan, scene_graph, report)
    _place_rear_between_storage_plants(plan, scene_graph, report)
    per_wall_relation_report = audit_and_repair_per_wall_object_relations(
        plan,
        scene_graph,
        cross_constraints,
        parent,
        enabled=True,
        repair=True,
        stage=stage,
    )
    report["per_wall_relation_audit"] = per_wall_relation_report
    report["fixes"].extend(per_wall_relation_report.get("fixes", []))
    report["warnings"].extend(per_wall_relation_report.get("warnings", []))
    post_per_wall_curtain_report: dict[str, Any] = {
        "schema": "tree_sage_window_curtain_assembly_post_per_wall_v1",
        "enabled": True,
        "stage": f"{stage}_post_per_wall",
        "fixes": [],
        "warnings": [],
    }
    _separate_window_curtain_panels(plan, scene_graph, post_per_wall_curtain_report)
    _fit_curtain_panels_to_reference_vertical_extent(plan, scene_graph, post_per_wall_curtain_report)
    post_per_wall_curtain_report["fix_count"] = len(post_per_wall_curtain_report.get("fixes", []))
    report["post_per_wall_window_curtain_assembly"] = post_per_wall_curtain_report
    report["fixes"].extend(post_per_wall_curtain_report.get("fixes", []))
    report["warnings"].extend(post_per_wall_curtain_report.get("warnings", []))
    report["fix_count"] = len(report["fixes"])
    plan["_reference_consistency_layout_refiner_last_pass"] = report
    return report


def _rebuild_flow2_validation_state(
    plan: dict[str, Any],
    scene_graph: dict[str, Any],
    support_tree: dict[str, Any],
    parent: dict[str, str],
    relation_to_parent: dict[str, str],
    cross_constraints: list[dict[str, Any]],
    asset_registry: dict[str, Any],
    branch_candidate_k: int,
    margin: float,
) -> dict[str, Any]:
    support_surface_registry = build_support_surface_registry(plan, asset_registry)
    branch_summaries = build_branch_summaries(plan, support_tree, parent, relation_to_parent)
    reference_alignment_report = build_reference_alignment_report(scene_graph, plan, support_tree, cross_constraints, parent)
    branch_candidates = build_branch_candidates(
        plan,
        support_tree,
        parent,
        relation_to_parent,
        cross_constraints,
        support_surface_registry,
        k=branch_candidate_k,
    )
    aggregate_collision_report = build_aggregate_collision_report(
        plan,
        support_tree,
        parent,
        relation_to_parent,
        support_surface_registry,
        margin=margin,
    )
    scene_hypergraph = build_scene_hypergraph(
        plan,
        support_tree,
        parent,
        relation_to_parent,
        cross_constraints,
        scene_graph=scene_graph,
    )
    scene_hypergraph_validation_report = validate_scene_hypergraph_constraints(plan, scene_hypergraph, parent)
    spatial_order_repair_report = audit_and_repair_reference_spatial_order(
        deepcopy(plan),
        scene_graph,
        support_tree,
        parent,
        cross_constraints,
        repair=False,
    )
    return {
        "support_surface_registry": support_surface_registry,
        "branch_summaries": branch_summaries,
        "reference_alignment_report": reference_alignment_report,
        "branch_candidates": branch_candidates,
        "aggregate_collision_report": aggregate_collision_report,
        "scene_hypergraph": scene_hypergraph,
        "scene_hypergraph_validation_report": scene_hypergraph_validation_report,
        "spatial_order_repair_report": spatial_order_repair_report,
    }


def _apply_reference_consistency_guard_pass(
    plan: dict[str, Any],
    scene_graph: dict[str, Any],
    support_tree: dict[str, Any],
    parent: dict[str, str],
    relation_to_parent: dict[str, str],
    cross_constraints: list[dict[str, Any]],
    asset_registry: dict[str, Any],
    reference_consistency_layout_report: dict[str, Any],
    enabled: bool,
    stage: str,
    branch_candidate_k: int,
    margin: float,
) -> tuple[dict[str, Any], dict[str, Any]]:
    pass_report = apply_reference_consistency_layout_refinements(
        plan,
        scene_graph,
        cross_constraints,
        parent,
        enabled=enabled,
        stage=stage,
    )
    merge_reference_consistency_layout_report(reference_consistency_layout_report, pass_report)
    if not pass_report.get("fixes"):
        return pass_report, {}
    _clamp_layout_objects_to_room(plan, cross_constraints, parent)
    state = _rebuild_flow2_validation_state(
        plan,
        scene_graph,
        support_tree,
        parent,
        relation_to_parent,
        cross_constraints,
        asset_registry,
        branch_candidate_k,
        margin,
    )
    return pass_report, state


def _should_hard_clamp_floor_object_to_wall(obj: dict[str, Any]) -> bool:
    if _is_bed_or_sofa_object(obj):
        return False
    if _is_branch_lighting_or_decor(obj) and not _is_floor_storage_or_table_branch_object(obj):
        return False
    return True


def _clamp_layout_objects_to_room(
    plan: dict[str, Any],
    cross_constraints: list[dict[str, Any]] | None = None,
    parent: dict[str, str] | None = None,
) -> None:
    room = plan.get("room") if isinstance(plan.get("room"), dict) else {}
    if not room:
        return
    for obj in plan.get("objects", []):
        placement = str(obj.get("placement_type", "floor"))
        support_id = str(obj.get("support_id") or "")
        if placement == "attached_to_wall" and support_id in VIRTUAL_WALLS:
            _clamp_wall_attached_object(obj, room, support_id)
        elif placement in {"floor", "hanging", "on_top", "inside"}:
            wall_id = _hard_wall_relation_for_object(str(obj.get("id") or ""), cross_constraints or [], parent or {})
            if wall_id not in VIRTUAL_WALLS and support_id in VIRTUAL_WALLS:
                wall_id = support_id
            if wall_id in VIRTUAL_WALLS and placement == "floor" and _should_hard_clamp_floor_object_to_wall(obj):
                _clamp_floor_object_against_wall(obj, room, wall_id)
            else:
                _clamp_object_to_room_rotated(obj, room)


def _reference_bbox_for_object(obj: dict[str, Any]) -> list[float] | None:
    bbox = obj.get("image_bbox")
    if not isinstance(bbox, list) or len(bbox) != 4:
        ref = obj.get("reference_instance") if isinstance(obj.get("reference_instance"), dict) else {}
        bbox = ref.get("bbox")
    if not isinstance(bbox, list) or len(bbox) != 4:
        return None
    try:
        values = [float(value) for value in bbox]
    except (TypeError, ValueError):
        return None
    if values[2] <= values[0] or values[3] <= values[1]:
        return None
    return values


def _view_conditioned_primary_anchor_candidate(obj: dict[str, Any]) -> bool:
    if str(obj.get("placement_type", "floor")) != "floor":
        return False
    if _is_floor_covering(obj) or _is_hanging_object(obj):
        return False
    text = _category_text(obj)
    if _is_bed_or_sofa_object(obj) or "dining table" in text:
        return True
    if "table" in text and not any(keyword in text for keyword in ("lamp", "side", "nightstand", "bedside")):
        return True
    return False


def stabilize_view_conditioned_primary_anchors(
    plan: dict[str, Any],
    scene_graph: dict[str, Any],
    support_tree: dict[str, Any],
    parent: dict[str, str],
    relation_to_parent: dict[str, str],
    cross_constraints: list[dict[str, Any]],
    support_surface_registry: dict[str, Any],
    margin: float = 0.02,
) -> dict[str, Any]:
    view_condition = scene_graph.get("_view_condition_report") if isinstance(scene_graph.get("_view_condition_report"), dict) else {}
    report: dict[str, Any] = {
        "schema": "tree_sage_view_conditioned_primary_anchor_stabilization_v1",
        "enabled": bool(view_condition.get("branch_relation_mode_enabled")),
        "strategy": "for oblique/reference-depth-ambiguous scenes, keep large central floor anchors close to their reference bbox center before final collision validation",
        "fixes": [],
        "fix_count": 0,
        "ok": True,
    }
    if not report["enabled"]:
        report["reason"] = "view_conditioned_branch_mode_disabled"
        return report

    room = plan.get("room") if isinstance(plan.get("room"), dict) else {}
    if not room:
        report["reason"] = "missing_room"
        return report
    room_width = float(room.get("width", 0.0) or 0.0)
    if room_width <= 0.0:
        report["reason"] = "invalid_room_width"
        return report

    descendants = _descendant_map(support_tree)
    objects = _copy_object_map(plan)
    current_report = build_aggregate_collision_report(
        plan,
        support_tree,
        parent,
        relation_to_parent,
        support_surface_registry,
        margin=margin,
    )
    current_score = _aggregate_collision_score(current_report)
    center_x = room_width / 2.0
    min_improvement_score = current_score

    candidates: list[tuple[float, str, dict[str, Any], list[float]]] = []
    for obj_id, obj in objects.items():
        if parent.get(obj_id) not in {None, "", "floor"}:
            continue
        if not _view_conditioned_primary_anchor_candidate(obj):
            continue
        bbox = _reference_bbox_for_object(obj)
        if not bbox:
            continue
        bbox_width = bbox[2] - bbox[0]
        bbox_center_x = (bbox[0] + bbox[2]) / 2.0
        if bbox_width < 0.42 or not (0.34 <= bbox_center_x <= 0.66):
            continue
        scene_offset = abs(float(obj.get("x", center_x)) - center_x)
        ref_weight = bbox_width * (1.0 - min(1.0, abs(bbox_center_x - 0.5) * 2.0))
        candidates.append((scene_offset + ref_weight, obj_id, obj, bbox))
    candidates.sort(reverse=True)

    for _score, obj_id, obj, bbox in candidates[:3]:
        bbox_center_x = (bbox[0] + bbox[2]) / 2.0
        bbox_target_x = bbox_center_x * room_width
        # Perspective can make the visible bed/table bbox asymmetric. Blend with room center
        # for anchors that occupy the central field of view.
        target_x = 0.65 * center_x + 0.35 * bbox_target_x
        current_x = float(obj.get("x", target_x))
        delta_x = target_x - current_x
        if abs(delta_x) < max(0.18, room_width * 0.06):
            continue

        candidate_objects = json.loads(json.dumps(objects))
        _move_branch_objects(candidate_objects, descendants, obj_id, (delta_x, 0.0, 0.0))
        for node_id in descendants.get(obj_id, [obj_id]):
            moved = candidate_objects.get(node_id)
            if moved and str(moved.get("placement_type", "floor")) in {"floor", "hanging", "on_top", "inside"}:
                _clamp_object_to_room(moved, room)
        candidate_plan = {**plan, "objects": list(candidate_objects.values())}
        candidate_surface_registry = build_support_surface_registry(candidate_plan, None)
        candidate_report = build_aggregate_collision_report(
            candidate_plan,
            support_tree,
            parent,
            relation_to_parent,
            candidate_surface_registry,
            margin=margin,
        )
        candidate_score = _aggregate_collision_score(candidate_report)
        center_error_before = abs(current_x - target_x)
        moved_obj = candidate_objects.get(obj_id, {})
        center_error_after = abs(float(moved_obj.get("x", target_x)) - target_x)
        anchor_restore_required = center_error_before >= max(0.55, room_width * 0.18)
        accept = candidate_score < min_improvement_score or (
            candidate_score <= current_score and center_error_after + 0.05 < center_error_before
        ) or (
            anchor_restore_required
            and center_error_after + 0.05 < center_error_before
            and int(candidate_score[0]) <= int(current_score[0]) + 3
        )
        action = {
            "object": obj_id,
            "reference_bbox": [round(value, 6) for value in bbox],
            "bbox_target_x": round(float(bbox_target_x), 6),
            "blended_target_x": round(float(target_x), 6),
            "delta_x": round(float(delta_x), 6),
            "collision_score_before": list(current_score),
            "collision_score_after": list(candidate_score),
            "center_error_before": round(float(center_error_before), 6),
            "center_error_after": round(float(center_error_after), 6),
            "anchor_restore_required": bool(anchor_restore_required),
            "accepted": bool(accept),
        }
        if accept:
            objects = candidate_objects
            plan["objects"] = list(objects.values())
            current_report = candidate_report
            current_score = candidate_score
            min_improvement_score = candidate_score
            report["fixes"].append(action)
        else:
            report.setdefault("rejected", []).append(action)

    report["fix_count"] = len(report["fixes"])
    report["final_conflict_count"] = int(current_report.get("conflict_count", 0) or 0)
    report["ok"] = True
    return report


def merge_scene_hypergraph_repair_report(
    primary: dict[str, Any],
    extra: dict[str, Any],
    stage: str,
) -> dict[str, Any]:
    if not extra.get("enabled") and not extra.get("fixes"):
        return primary
    primary["enabled"] = bool(primary.get("enabled")) or bool(extra.get("enabled"))
    primary.setdefault("passes", []).append(
        {
            "stage": stage,
            "ok": bool(extra.get("ok")),
            "fix_count": int(extra.get("fix_count", 0) or 0),
            "before_warning_count": int(extra.get("before_warning_count", 0) or 0),
            "after_warning_count": int(extra.get("after_warning_count", 0) or 0),
            "remaining_violation_count": len(extra.get("remaining_violations", [])),
        }
    )
    primary.setdefault("fixes", []).extend(extra.get("fixes", []))
    primary.setdefault("iterations", []).extend(extra.get("iterations", []))
    primary["warnings"] = list(extra.get("warnings", []))
    primary["soft_warnings"] = list(extra.get("soft_warnings", []))
    primary["remaining_violations"] = extra.get("remaining_violations", [])
    if "after_validation" in extra:
        primary["after_validation"] = extra.get("after_validation")
    primary["after_warning_count"] = int(extra.get("after_warning_count", len(primary.get("warnings", []))) or 0)
    primary["fix_count"] = len(primary.get("fixes", []))
    primary["ok"] = bool(extra.get("ok"))
    return primary


def _merge_collision_repair_report(primary: dict[str, Any], extra: dict[str, Any], stage: str) -> dict[str, Any]:
    if not extra.get("enabled") and not extra.get("actions"):
        return primary
    primary["enabled"] = bool(primary.get("enabled")) or bool(extra.get("enabled"))
    primary.setdefault("passes", []).append(
        {
            "stage": stage,
            "ok": bool(extra.get("ok")),
            "action_count": len(extra.get("actions", [])),
            "final_conflict_count": int(extra.get("final_conflict_count", 0) or 0),
        }
    )
    primary.setdefault("actions", []).extend(extra.get("actions", []))
    primary["final_conflict_count"] = int(extra.get("final_conflict_count", primary.get("final_conflict_count", 0)) or 0)
    primary["final_conflicts"] = extra.get("final_conflicts", primary.get("final_conflicts", []))
    primary["ok"] = bool(extra.get("ok"))
    return primary


def _merge_same_wall_collision_repair_report(primary: dict[str, Any], extra: dict[str, Any], stage: str) -> dict[str, Any]:
    if not extra.get("enabled") and not extra.get("fixes"):
        return primary
    primary["enabled"] = bool(primary.get("enabled")) or bool(extra.get("enabled"))
    primary.setdefault("passes", []).append(
        {
            "stage": stage,
            "ok": bool(extra.get("ok")),
            "fix_count": int(extra.get("fix_count", 0) or 0),
            "final_conflict_count": int(extra.get("final_conflict_count", 0) or 0),
        }
    )
    primary.setdefault("fixes", []).extend(extra.get("fixes", []))
    primary.setdefault("iterations", []).extend(extra.get("iterations", []))
    primary["fix_count"] = len(primary.get("fixes", []))
    primary["final_conflict_count"] = int(extra.get("final_conflict_count", primary.get("final_conflict_count", 0)) or 0)
    primary["final_conflicts"] = extra.get("final_conflicts", primary.get("final_conflicts", []))
    primary["ok"] = bool(extra.get("ok"))
    return primary


def _scene_hypergraph_protected_spatial_objects(scene_hypergraph: dict[str, Any]) -> set[str]:
    protected: set[str] = set()
    for factor in scene_hypergraph.get("factors", []) if isinstance(scene_hypergraph.get("factors"), list) else []:
        if not isinstance(factor, dict):
            continue
        confidence = _safe_float(factor.get("confidence"), 0.0)
        if confidence < SPATIAL_ORDER_HARD_CONFIDENCE:
            continue
        factor_type = str(factor.get("type") or "")
        if factor_type == "reference_axis_pair_constraints":
            for constraint in factor.get("pair_constraints", []) if isinstance(factor.get("pair_constraints"), list) else []:
                if not isinstance(constraint, dict):
                    continue
                if str(constraint.get("relation") or "") in {"same_depth", "same_column"}:
                    protected.add(str(constraint.get("subject") or ""))
                    protected.add(str(constraint.get("object") or ""))
        elif factor_type == "reference_axis_gap_affinity":
            for constraint in factor.get("gap_affinity_constraints", []) if isinstance(factor.get("gap_affinity_constraints"), list) else []:
                if not isinstance(constraint, dict):
                    continue
                protected.add(str(constraint.get("subject") or ""))
                protected.add(str(constraint.get("near_object") or ""))
                protected.add(str(constraint.get("far_object") or ""))
        elif factor_type == "reference_cluster_anchor_affinity":
            for constraint in factor.get("cluster_constraints", []) if isinstance(factor.get("cluster_constraints"), list) else []:
                if not isinstance(constraint, dict):
                    continue
                protected.add(str(constraint.get("anchor_object") or ""))
                for object_id in constraint.get("members", []) if isinstance(constraint.get("members"), list) else []:
                    protected.add(str(object_id))
        elif factor_type == "reference_order_group" and str(factor.get("priority") or "") == "high":
            for object_id in factor.get("objects", []) if isinstance(factor.get("objects"), list) else []:
                protected.add(str(object_id))
    protected.discard("")
    return protected


def repair_hypergraph_preserving_floor_collisions(
    plan: dict[str, Any],
    scene_graph: dict[str, Any],
    support_tree: dict[str, Any],
    parent: dict[str, str],
    relation_to_parent: dict[str, str],
    cross_constraints: list[dict[str, Any]],
    asset_registry: dict[str, Any] | None,
    margin: float,
    branch_candidate_k: int,
    state: dict[str, Any],
    max_actions: int = 4,
) -> tuple[dict[str, Any], dict[str, Any]]:
    report: dict[str, Any] = {
        "schema": "tree_sage_hypergraph_preserving_collision_repair_v1",
        "enabled": True,
        "strategy": "resolve floor collisions by moving non-protected branches first, accepting only candidates that preserve reference and hypergraph validation",
        "actions": [],
        "ok": bool(state["aggregate_collision_report"].get("ok")),
    }
    protected = _scene_hypergraph_protected_spatial_objects(state["scene_hypergraph"])
    if not protected:
        report["reason"] = "no_high_confidence_hypergraph_protected_objects"
        return state, report

    descendants = _descendant_map(support_tree)
    current_state = state
    for _action_index in range(max(0, int(max_actions))):
        current_conflicts = int(current_state["aggregate_collision_report"].get("conflict_count", 0) or 0)
        if current_conflicts <= 0:
            break
        current_hg_warnings = len(current_state["scene_hypergraph_validation_report"].get("warnings", []))
        current_ref_warnings = len(current_state["reference_alignment_report"].get("warnings", []))
        best: tuple[tuple[int, int, int, float, float], str, str, tuple[float, float, float], dict[str, Any], dict[str, Any]] | None = None
        for conflict in current_state["aggregate_collision_report"].get("conflicts", []):
            if conflict.get("type") != "branch_collision" or str(conflict.get("level_parent")) != "floor":
                continue
            branch_a = str(conflict.get("branch_a") or "")
            branch_b = str(conflict.get("branch_b") or "")
            if not branch_a or not branch_b:
                continue
            broad = conflict.get("broad_overlap_xyz") if isinstance(conflict.get("broad_overlap_xyz"), list) else [0.0, 0.0, 0.0]
            x_overlap = max(0.0, _safe_float(broad[0] if len(broad) > 0 else 0.0, 0.0))
            y_overlap = max(0.0, _safe_float(broad[1] if len(broad) > 1 else 0.0, 0.0))
            move_order: list[tuple[str, str]] = []
            a_protected = branch_a in protected
            b_protected = branch_b in protected
            if a_protected and not b_protected:
                move_order.append((branch_b, branch_a))
            elif b_protected and not a_protected:
                move_order.append((branch_a, branch_b))
            else:
                move_order.extend([(branch_a, branch_b), (branch_b, branch_a)])

            base_objects = _copy_object_map(plan)
            for movable_id, anchor_id in move_order:
                movable = base_objects.get(movable_id)
                anchor = base_objects.get(anchor_id)
                if not movable or not anchor or not _hypergraph_object_movable(movable):
                    continue
                x_sign = 1.0 if float(movable.get("x", 0.0)) >= float(anchor.get("x", 0.0)) else -1.0
                y_sign = 1.0 if float(movable.get("y", 0.0)) >= float(anchor.get("y", 0.0)) else -1.0
                shifts = [
                    (x_sign * (x_overlap + margin + 0.06), 0.0, 0.0),
                    (-x_sign * (x_overlap + margin + 0.06), 0.0, 0.0),
                    (0.0, y_sign * (y_overlap + margin + 0.06), 0.0),
                    (0.0, -y_sign * (y_overlap + margin + 0.06), 0.0),
                    (x_sign * 0.42, 0.0, 0.0),
                    (-x_sign * 0.42, 0.0, 0.0),
                    (0.0, y_sign * 0.42, 0.0),
                    (0.0, -y_sign * 0.42, 0.0),
                    (x_sign * 0.72, 0.0, 0.0),
                    (-x_sign * 0.72, 0.0, 0.0),
                ]
                seen_shifts: set[tuple[float, float, float]] = set()
                for delta in shifts:
                    rounded_delta = (round(float(delta[0]), 6), round(float(delta[1]), 6), 0.0)
                    if rounded_delta in seen_shifts or (abs(rounded_delta[0]) <= 1e-6 and abs(rounded_delta[1]) <= 1e-6):
                        continue
                    seen_shifts.add(rounded_delta)
                    candidate_plan = deepcopy(plan)
                    candidate_objects = {str(obj.get("id")): obj for obj in candidate_plan.get("objects", []) if isinstance(obj, dict)}
                    _move_spatial_relation_unit(candidate_objects, descendants, movable_id, rounded_delta, candidate_plan["room"])
                    candidate_state = _layout_state_after_changes(
                        candidate_plan,
                        scene_graph,
                        support_tree,
                        parent,
                        relation_to_parent,
                        cross_constraints,
                        asset_registry,
                        margin,
                        branch_candidate_k,
                    )
                    candidate_conflicts = int(candidate_state["aggregate_collision_report"].get("conflict_count", 0) or 0)
                    candidate_hg_warnings = len(candidate_state["scene_hypergraph_validation_report"].get("warnings", []))
                    candidate_ref_warnings = len(candidate_state["reference_alignment_report"].get("warnings", []))
                    if candidate_conflicts >= current_conflicts:
                        continue
                    if candidate_hg_warnings > current_hg_warnings or candidate_ref_warnings > current_ref_warnings:
                        continue
                    distance = abs(rounded_delta[0]) + abs(rounded_delta[1])
                    score_tuple = (
                        candidate_conflicts,
                        candidate_hg_warnings,
                        candidate_ref_warnings,
                        float(candidate_state["score"]),
                        distance,
                    )
                    if best is None or score_tuple < best[0]:
                        best = (score_tuple, movable_id, anchor_id, rounded_delta, candidate_plan, candidate_state)
        if best is None:
            break
        _, movable_id, anchor_id, delta, best_plan, best_state = best
        plan["objects"] = best_plan.get("objects", plan.get("objects", []))
        action = {
            "type": "hypergraph_preserving_floor_collision_shift",
            "moved_root": movable_id,
            "anchor": anchor_id,
            "delta": [round(float(value), 6) for value in delta],
            "conflict_count_after": int(best_state["aggregate_collision_report"].get("conflict_count", 0) or 0),
            "reference_warning_count_after": len(best_state["reference_alignment_report"].get("warnings", [])),
            "hypergraph_warning_count_after": len(best_state["scene_hypergraph_validation_report"].get("warnings", [])),
        }
        report["actions"].append(action)
        current_state = best_state
    report["final_conflict_count"] = int(current_state["aggregate_collision_report"].get("conflict_count", 0) or 0)
    report["ok"] = report["final_conflict_count"] == 0
    return current_state, report


def _run_hypergraph_collision_stabilization(
    candidate_plan: dict[str, Any],
    scene_graph: dict[str, Any],
    support_tree: dict[str, Any],
    parent: dict[str, str],
    relation_to_parent: dict[str, str],
    cross_constraints: list[dict[str, Any]],
    asset_registry: dict[str, Any] | None,
    margin: float,
    branch_candidate_k: int,
    hypergraph_repair_report: dict[str, Any],
    collision_repair_report: dict[str, Any],
    same_wall_report: dict[str, Any],
    initial_state: dict[str, Any] | None = None,
    max_cycles: int = 4,
    branch_execution_plan: dict[str, Any] | None = None,
) -> tuple[dict[str, Any], list[dict[str, Any]], dict[str, Any], dict[str, Any], dict[str, Any]]:
    cycles: list[dict[str, Any]] = []
    state = initial_state or _layout_state_after_changes(
        candidate_plan,
        scene_graph,
        support_tree,
        parent,
        relation_to_parent,
        cross_constraints,
        asset_registry,
        margin,
        branch_candidate_k,
        branch_execution_plan=branch_execution_plan,
    )
    for cycle_index in range(max(0, int(max_cycles))):
        before_conflicts = int(state["aggregate_collision_report"].get("conflict_count", 0) or 0)
        before_hg_warnings = len(state["scene_hypergraph_validation_report"].get("warnings", []))
        changed = False
        cycle: dict[str, Any] = {
            "cycle": cycle_index + 1,
            "before_conflict_count": before_conflicts,
            "before_hypergraph_warning_count": before_hg_warnings,
        }

        if not state["scene_hypergraph_validation_report"].get("ok"):
            extra_hypergraph_report = repair_scene_hypergraph_spatial_constraints(
                candidate_plan,
                state["scene_hypergraph"],
                support_tree,
                parent,
            )
            hypergraph_repair_report = merge_scene_hypergraph_repair_report(
                hypergraph_repair_report,
                extra_hypergraph_report,
                f"stabilization_cycle_{cycle_index + 1}",
            )
            changed = changed or bool(extra_hypergraph_report.get("fix_count", 0))
            cycle["hypergraph_fix_count"] = int(extra_hypergraph_report.get("fix_count", 0) or 0)
            _clamp_layout_objects_to_room(candidate_plan, cross_constraints, parent)
            state = _layout_state_after_changes(
                candidate_plan,
                scene_graph,
                support_tree,
                parent,
                relation_to_parent,
                cross_constraints,
                asset_registry,
                margin,
                branch_candidate_k,
                branch_execution_plan=branch_execution_plan,
            )

        if not state["aggregate_collision_report"].get("ok"):
            preserving_collision_report: dict[str, Any] = {"enabled": False, "actions": [], "ok": False}
            if state["scene_hypergraph_validation_report"].get("ok"):
                state, preserving_collision_report = repair_hypergraph_preserving_floor_collisions(
                    candidate_plan,
                    scene_graph,
                    support_tree,
                    parent,
                    relation_to_parent,
                    cross_constraints,
                    asset_registry,
                    margin,
                    branch_candidate_k,
                    state,
                )
                if preserving_collision_report.get("actions"):
                    collision_repair_report = _merge_collision_repair_report(
                        collision_repair_report,
                        preserving_collision_report,
                        f"stabilization_cycle_{cycle_index + 1}_hypergraph_preserving",
                    )
                    changed = True
                    cycle["hypergraph_preserving_collision_action_count"] = len(preserving_collision_report.get("actions", []))
                    state = _layout_state_after_changes(
                        candidate_plan,
                        scene_graph,
                        support_tree,
                        parent,
                        relation_to_parent,
                        cross_constraints,
                        asset_registry,
                        margin,
                        branch_candidate_k,
                        branch_execution_plan=branch_execution_plan,
                    )

        if not state["aggregate_collision_report"].get("ok"):
            extra_collision_report = run_repair_agent(
                candidate_plan,
                support_tree,
                parent,
                relation_to_parent,
                state["support_surface_registry"],
                state["aggregate_collision_report"],
                max_iterations=6,
                cross_constraints=cross_constraints,
                scene_graph=scene_graph,
                margin=margin,
            )
            collision_repair_report = _merge_collision_repair_report(
                collision_repair_report,
                extra_collision_report,
                f"stabilization_cycle_{cycle_index + 1}",
            )
            changed = changed or bool(extra_collision_report.get("actions"))
            cycle["collision_action_count"] = len(extra_collision_report.get("actions", []))
            _clamp_layout_objects_to_room(candidate_plan, cross_constraints, parent)
            state = _layout_state_after_changes(
                candidate_plan,
                scene_graph,
                support_tree,
                parent,
                relation_to_parent,
                cross_constraints,
                asset_registry,
                margin,
                branch_candidate_k,
                branch_execution_plan=branch_execution_plan,
            )

        if not state["aggregate_collision_report"].get("ok"):
            extra_same_wall_report = repair_same_wall_floor_branch_collisions(
                candidate_plan,
                support_tree,
                parent,
                relation_to_parent,
                cross_constraints,
                state["support_surface_registry"],
                margin=margin,
            )
            same_wall_report = _merge_same_wall_collision_repair_report(
                same_wall_report,
                extra_same_wall_report,
                f"stabilization_cycle_{cycle_index + 1}",
            )
            changed = changed or bool(extra_same_wall_report.get("fix_count", 0))
            cycle["same_wall_fix_count"] = int(extra_same_wall_report.get("fix_count", 0) or 0)
            _clamp_layout_objects_to_room(candidate_plan, cross_constraints, parent)
            state = _layout_state_after_changes(
                candidate_plan,
                scene_graph,
                support_tree,
                parent,
                relation_to_parent,
                cross_constraints,
                asset_registry,
                margin,
                branch_candidate_k,
                branch_execution_plan=branch_execution_plan,
            )

        cycle["after_conflict_count"] = int(state["aggregate_collision_report"].get("conflict_count", 0) or 0)
        cycle["after_hypergraph_warning_count"] = len(state["scene_hypergraph_validation_report"].get("warnings", []))
        cycle["after_reference_warning_count"] = len(state["reference_alignment_report"].get("warnings", []))
        cycle["score"] = float(state["score"])
        cycles.append(cycle)
        if state["aggregate_collision_report"].get("ok") and state["scene_hypergraph_validation_report"].get("ok"):
            break
        if not changed:
            break
    return state, cycles, hypergraph_repair_report, collision_repair_report, same_wall_report


def run_final_layout_polish(
    plan: dict[str, Any],
    scene_graph: dict[str, Any],
    support_tree: dict[str, Any],
    parent: dict[str, str],
    relation_to_parent: dict[str, str],
    cross_constraints: list[dict[str, Any]],
    asset_registry: dict[str, Any] | None,
    margin: float,
    branch_candidate_k: int,
    branch_execution_plan: dict[str, Any] | None = None,
    max_iterations: int = 5,
) -> tuple[dict[str, Any], dict[str, Any], dict[str, Any], dict[str, Any]]:
    report: dict[str, Any] = {
        "schema": "tree_sage_final_layout_polish_v1",
        "enabled": True,
        "strategy": "repair order/relation/hypergraph constraints on a candidate, run relation-aware collision repair, accept only non-colliding non-worse layouts",
        "attempts": [],
        "scene_hypergraph_repair_passes": [],
        "ok": True,
    }
    objects_for_guard = [obj for obj in plan.get("objects", []) if isinstance(obj, dict)]
    object_count = len(objects_for_guard)
    floor_root_count = sum(
        1
        for obj in objects_for_guard
        if str(obj.get("placement_type", "floor")) == "floor"
        and str(parent.get(str(obj.get("id") or "")) or obj.get("support_id") or "floor") == "floor"
    )
    large_scene_guard = object_count >= 22 or (object_count >= 18 and floor_root_count >= 10)
    if large_scene_guard:
        max_iterations = min(max(1, int(max_iterations)), 1)
        branch_execution_plan = None
        report["large_scene_guard"] = {
            "enabled": True,
            "object_count": object_count,
            "floor_root_count": floor_root_count,
            "max_iterations": int(max_iterations),
            "branch_execution_audit_disabled": True,
            "collision_repair_max_iterations": 1,
            "stabilization_max_cycles": 0,
            "reason": "avoid expensive repair oscillation on complex many-object bedroom scenes; keep validation and one conservative repair pass",
        }
    else:
        report["large_scene_guard"] = {"enabled": False, "object_count": object_count, "floor_root_count": floor_root_count}
    collision_repair_max_iterations = 1 if large_scene_guard else 6
    stabilization_max_cycles = 0 if large_scene_guard else 4
    fallback_order_report: dict[str, Any] = {"enabled": False, "ok": True, "fix_count": 0}
    fallback_relation_report: dict[str, Any] = {
        "schema": "tree_sage_spatial_relation_repair_v1",
        "enabled": False,
        "reason": "not_run",
        "fixes": [],
        "fix_count": 0,
        "warnings": [],
        "soft_warnings": [],
        "remaining_violations": [],
        "ok": True,
    }
    base_state = _layout_state_after_changes(
        plan,
        scene_graph,
        support_tree,
        parent,
        relation_to_parent,
        cross_constraints,
        asset_registry,
        margin,
        branch_candidate_k,
        branch_execution_plan=branch_execution_plan,
    )
    base_score = float(base_state["score"])
    best_score = base_score
    best_plan: dict[str, Any] | None = None
    best_state: dict[str, Any] | None = None
    best_order_report: dict[str, Any] | None = None
    best_relation_report: dict[str, Any] | None = None
    candidate_plan = deepcopy(plan)

    for iteration in range(max(1, int(max_iterations))):
        _clamp_layout_objects_to_room(candidate_plan, cross_constraints, parent)
        order_report = audit_and_repair_reference_spatial_order(
            candidate_plan,
            scene_graph,
            support_tree,
            parent,
            cross_constraints,
        )
        initial_order_fix_count = int(order_report.get("fix_count", 0))
        relation_report = repair_spatial_relation_constraints(candidate_plan, cross_constraints, support_tree, parent, scene_graph=scene_graph)
        post_relation_order_report = audit_and_repair_reference_spatial_order(
            candidate_plan,
            scene_graph,
            support_tree,
            parent,
            cross_constraints,
        )
        post_order_relation_report = repair_spatial_relation_constraints(candidate_plan, cross_constraints, support_tree, parent, scene_graph=scene_graph)
        relation_report = merge_spatial_relation_repair_report(
            relation_report,
            post_order_relation_report,
            "post_order_status_refresh",
        )
        if int(post_relation_order_report.get("fix_count", 0)) or post_relation_order_report.get("warnings"):
            order_report = post_relation_order_report
        scene_hypergraph = build_scene_hypergraph(
            candidate_plan,
            support_tree,
            parent,
            relation_to_parent,
            cross_constraints,
            scene_graph=scene_graph,
        )
        hypergraph_repair_report = repair_scene_hypergraph_spatial_constraints(
            candidate_plan,
            scene_hypergraph,
            support_tree,
            parent,
        )
        if hypergraph_repair_report.get("fixes"):
            post_hypergraph_relation_report = repair_spatial_relation_constraints(candidate_plan, cross_constraints, support_tree, parent, scene_graph=scene_graph)
            relation_report = merge_spatial_relation_repair_report(
                relation_report,
                post_hypergraph_relation_report,
                "post_hypergraph_repair",
            )
            post_hypergraph_order_report = audit_and_repair_reference_spatial_order(
                candidate_plan,
                scene_graph,
                support_tree,
                parent,
                cross_constraints,
            )
            if int(post_hypergraph_order_report.get("fix_count", 0)) or post_hypergraph_order_report.get("warnings"):
                order_report = post_hypergraph_order_report
        _clamp_layout_objects_to_room(candidate_plan, cross_constraints, parent)
        state = _layout_state_after_changes(
            candidate_plan,
            scene_graph,
            support_tree,
            parent,
            relation_to_parent,
            cross_constraints,
            asset_registry,
            margin,
            branch_candidate_k,
            branch_execution_plan=branch_execution_plan,
        )
        collision_repair_report: dict[str, Any] = {"enabled": False, "reason": "aggregate_already_ok", "actions": [], "ok": True}
        same_wall_report: dict[str, Any] = {"enabled": False, "reason": "not_needed", "fix_count": 0, "ok": True}
        if not state["aggregate_collision_report"].get("ok"):
            collision_repair_report = run_repair_agent(
                candidate_plan,
                support_tree,
                parent,
                relation_to_parent,
                state["support_surface_registry"],
                state["aggregate_collision_report"],
                max_iterations=collision_repair_max_iterations,
                cross_constraints=cross_constraints,
                scene_graph=scene_graph,
                margin=margin,
            )
            _clamp_layout_objects_to_room(candidate_plan, cross_constraints, parent)
            order_report = audit_and_repair_reference_spatial_order(
                candidate_plan,
                scene_graph,
                support_tree,
                parent,
                cross_constraints,
            )
            relation_report = repair_spatial_relation_constraints(candidate_plan, cross_constraints, support_tree, parent, scene_graph=scene_graph)
            post_relation_order_report = audit_and_repair_reference_spatial_order(
                candidate_plan,
                scene_graph,
                support_tree,
                parent,
                cross_constraints,
            )
            if int(post_relation_order_report.get("fix_count", 0)) or post_relation_order_report.get("warnings"):
                order_report = post_relation_order_report
            scene_hypergraph = build_scene_hypergraph(
                candidate_plan,
                support_tree,
                parent,
                relation_to_parent,
                cross_constraints,
                scene_graph=scene_graph,
            )
            post_collision_hypergraph_repair_report = repair_scene_hypergraph_spatial_constraints(
                candidate_plan,
                scene_hypergraph,
                support_tree,
                parent,
            )
            if post_collision_hypergraph_repair_report.get("fixes"):
                hypergraph_repair_report = merge_scene_hypergraph_repair_report(
                    hypergraph_repair_report,
                    post_collision_hypergraph_repair_report,
                    "post_collision_repair",
                )
                post_hypergraph_relation_report = repair_spatial_relation_constraints(candidate_plan, cross_constraints, support_tree, parent, scene_graph=scene_graph)
                relation_report = merge_spatial_relation_repair_report(
                    relation_report,
                    post_hypergraph_relation_report,
                    "post_collision_hypergraph_repair",
                )
            _clamp_layout_objects_to_room(candidate_plan, cross_constraints, parent)
            state = _layout_state_after_changes(
                candidate_plan,
                scene_graph,
                support_tree,
                parent,
                relation_to_parent,
                cross_constraints,
                asset_registry,
                margin,
                branch_candidate_k,
                branch_execution_plan=branch_execution_plan,
            )
        if not state["aggregate_collision_report"].get("ok"):
            same_wall_report = repair_same_wall_floor_branch_collisions(
                candidate_plan,
                support_tree,
                parent,
                relation_to_parent,
                cross_constraints,
                state["support_surface_registry"],
                margin=margin,
            )
            _clamp_layout_objects_to_room(candidate_plan, cross_constraints, parent)
            state = _layout_state_after_changes(
                candidate_plan,
                scene_graph,
                support_tree,
                parent,
                relation_to_parent,
                cross_constraints,
                asset_registry,
                margin,
                branch_candidate_k,
                branch_execution_plan=branch_execution_plan,
            )
        stabilization_cycles: list[dict[str, Any]] = []
        if (not state["aggregate_collision_report"].get("ok")) or (not state["scene_hypergraph_validation_report"].get("ok")):
            state, stabilization_cycles, hypergraph_repair_report, collision_repair_report, same_wall_report = (
                _run_hypergraph_collision_stabilization(
                    candidate_plan,
                    scene_graph,
                    support_tree,
                    parent,
                    relation_to_parent,
                    cross_constraints,
                    asset_registry,
                    margin,
                    branch_candidate_k,
                    hypergraph_repair_report,
                    collision_repair_report,
                    same_wall_report,
                    initial_state=state,
                    max_cycles=stabilization_max_cycles,
                    branch_execution_plan=branch_execution_plan,
                )
            )
        attempt = {
            "iteration": iteration + 1,
            "spatial_order_fix_count": initial_order_fix_count + int(post_relation_order_report.get("fix_count", 0)),
            "spatial_order_ok": bool(order_report.get("ok")) and bool(post_relation_order_report.get("ok")),
            "spatial_relation_fix_count": int(relation_report.get("fix_count", 0)),
            "spatial_relation_ok": bool(relation_report.get("ok")),
            "scene_hypergraph_repair_fix_count": int(hypergraph_repair_report.get("fix_count", 0) or 0),
            "scene_hypergraph_repair_ok": bool(state["scene_hypergraph_validation_report"].get("ok")),
            "collision_repair_action_count": len(collision_repair_report.get("actions", [])),
            "collision_repair_ok": bool(state["aggregate_collision_report"].get("ok")),
            "same_wall_fix_count": int(same_wall_report.get("fix_count", 0) or 0),
            "stabilization_cycle_count": len(stabilization_cycles),
            "stabilization_cycles": stabilization_cycles,
            "aggregate_conflict_count": int(state["aggregate_collision_report"].get("conflict_count", 0) or 0),
            "reference_warning_count": len(state["reference_alignment_report"].get("warnings", [])),
            "scene_hypergraph_warning_count": len(state["scene_hypergraph_validation_report"].get("warnings", [])),
            "branch_failed_count": int(state.get("branch_audit_report", {}).get("failed_branch_count", 0) or 0),
            "score": float(state["score"]),
            "accepted_candidate": False,
        }
        report["scene_hypergraph_repair_passes"].append(
            {
                "iteration": iteration + 1,
                "fix_count": int(hypergraph_repair_report.get("fix_count", 0) or 0),
                "before_warning_count": int(hypergraph_repair_report.get("before_warning_count", 0) or 0),
                "after_warning_count": int(hypergraph_repair_report.get("after_warning_count", 0) or 0),
                "final_warning_count": len(state["scene_hypergraph_validation_report"].get("warnings", [])),
                "final_ok": bool(state["scene_hypergraph_validation_report"].get("ok")),
                "remaining_violation_count": len(hypergraph_repair_report.get("remaining_violations", [])),
                "fixes": hypergraph_repair_report.get("fixes", [])[:40],
            }
        )
        report["attempts"].append(attempt)
        candidate_ok = (
            state["aggregate_collision_report"].get("ok")
            and state["reference_alignment_report"].get("ok")
            and order_report.get("ok")
            and relation_report.get("ok")
            and state["scene_hypergraph_validation_report"].get("ok")
            and state.get("branch_audit_report", {}).get("ok", True)
        )
        if state["aggregate_collision_report"].get("ok") and state.get("branch_audit_report", {}).get("ok", True) and float(state["score"]) <= best_score:
            best_score = float(state["score"])
            best_plan = deepcopy(candidate_plan)
            best_state = state
            best_order_report = deepcopy(order_report)
            best_relation_report = deepcopy(relation_report)
            attempt["accepted_candidate"] = True
        if candidate_ok:
            break
        if (
            int(order_report.get("fix_count", 0)) == 0
            and int(post_relation_order_report.get("fix_count", 0)) == 0
            and int(relation_report.get("fix_count", 0)) == 0
            and int(hypergraph_repair_report.get("fix_count", 0) or 0) == 0
            and len(collision_repair_report.get("actions", [])) == 0
            and int(same_wall_report.get("fix_count", 0) or 0) == 0
        ):
            break

    if best_plan is not None and best_state is not None:
        plan["objects"] = best_plan.get("objects", plan.get("objects", []))
        report["accepted"] = True
        report["accepted_score"] = best_score
        report["final_conflict_count"] = int(best_state["aggregate_collision_report"].get("conflict_count", 0) or 0)
        report["final_reference_warning_count"] = len(best_state["reference_alignment_report"].get("warnings", []))
        report["final_hypergraph_warning_count"] = len(best_state["scene_hypergraph_validation_report"].get("warnings", []))
        report["final_branch_failed_count"] = int(best_state["branch_audit_report"].get("failed_branch_count", 0) or 0)
        report["final_score"] = float(best_state["score"])
        report["ok"] = (
            bool(best_state["aggregate_collision_report"].get("ok"))
            and bool(best_state["reference_alignment_report"].get("ok"))
            and bool(best_state["scene_hypergraph_validation_report"].get("ok"))
            and bool(best_state["branch_audit_report"].get("ok"))
        )
        return report, best_order_report or fallback_order_report, best_relation_report or fallback_relation_report, best_state

    report["accepted"] = False
    report["accepted_score"] = base_score
    report["final_conflict_count"] = int(base_state["aggregate_collision_report"].get("conflict_count", 0) or 0)
    report["final_reference_warning_count"] = len(base_state["reference_alignment_report"].get("warnings", []))
    report["final_hypergraph_warning_count"] = len(base_state["scene_hypergraph_validation_report"].get("warnings", []))
    report["final_branch_failed_count"] = int(base_state.get("branch_audit_report", {}).get("failed_branch_count", 0) or 0)
    report["final_score"] = float(base_state["score"])
    final_order_report = audit_and_repair_reference_spatial_order(
        deepcopy(plan),
        scene_graph,
        support_tree,
        parent,
        cross_constraints,
        repair=False,
    )
    report["final_spatial_order_warning_count"] = len(final_order_report.get("warnings", []))
    report["ok"] = (
        bool(base_state["aggregate_collision_report"].get("ok"))
        and bool(base_state["reference_alignment_report"].get("ok"))
        and bool(final_order_report.get("ok"))
        and bool(base_state["scene_hypergraph_validation_report"].get("ok"))
        and bool(base_state.get("branch_audit_report", {}).get("ok", True))
    )
    return report, final_order_report, fallback_relation_report, base_state


def build_global_validator_report(
    aggregate_collision_report: dict[str, Any],
    reference_alignment_report: dict[str, Any],
    pose_review_report: dict[str, Any],
    incremental_branch_report: dict[str, Any],
    spatial_order_repair_report: dict[str, Any] | None = None,
    spatial_relation_repair_report: dict[str, Any] | None = None,
    scene_hypergraph_validation_report: dict[str, Any] | None = None,
    mujoco_report: dict[str, Any] | None = None,
) -> dict[str, Any]:
    checks = [
        {
            "type": "aggregate_collision",
            "ok": bool(aggregate_collision_report.get("ok")),
            "conflict_count": int(aggregate_collision_report.get("conflict_count", 0)),
        },
        {
            "type": "reference_alignment",
            "ok": bool(reference_alignment_report.get("ok")),
            "warning_count": len(reference_alignment_report.get("warnings", [])),
        },
        {
            "type": "pose_review",
            "ok": bool(pose_review_report.get("ok", True)),
            "fix_count": len(pose_review_report.get("fixes", [])) if isinstance(pose_review_report, dict) else 0,
        },
    ]
    if spatial_order_repair_report and spatial_order_repair_report.get("enabled"):
        checks.append(
            {
                "type": "reference_spatial_order",
                "ok": bool(spatial_order_repair_report.get("ok")),
                "fix_count": int(spatial_order_repair_report.get("fix_count", 0)),
            }
        )
    if spatial_relation_repair_report and spatial_relation_repair_report.get("enabled"):
        checks.append(
            {
                "type": "spatial_relation_repair",
                "ok": bool(spatial_relation_repair_report.get("ok")),
                "fix_count": int(spatial_relation_repair_report.get("fix_count", 0)),
                "remaining_violation_count": len(spatial_relation_repair_report.get("remaining_violations", [])),
            }
        )
    if scene_hypergraph_validation_report and scene_hypergraph_validation_report.get("enabled"):
        checks.append(
            {
                "type": "scene_hypergraph",
                "ok": bool(scene_hypergraph_validation_report.get("ok")),
                "check_count": int(scene_hypergraph_validation_report.get("check_count", 0)),
                "warning_count": len(scene_hypergraph_validation_report.get("warnings", [])),
                "soft_warning_count": len(scene_hypergraph_validation_report.get("soft_warnings", [])),
            }
        )
    branch_conflicts: list[dict[str, Any]] = []
    stale_branch_conflicts: list[dict[str, Any]] = []
    if incremental_branch_report.get("enabled") and not incremental_branch_report.get("ok"):
        for branch_result in incremental_branch_report.get("branch_results", []):
            if branch_result.get("ok"):
                continue
            validation = branch_result.get("validation") if isinstance(branch_result.get("validation"), dict) else {}
            validation_conflicts = validation.get("conflicts", []) if isinstance(validation.get("conflicts"), list) else []
            conflict_types = {str(conflict.get("type", "")) for conflict in validation_conflicts if isinstance(conflict, dict)}
            branch_conflict = {
                "source": "incremental_branch_execution",
                "type": "branch_commit_failed",
                "branch": branch_result.get("branch"),
                "root_object": branch_result.get("root_object"),
                "conflict_count": int(validation.get("conflict_count", 0)),
                "conflicts": validation_conflicts,
                "suggested_action": "rerun_branch_executor_with_error_feedback",
            }
            collision_only = bool(conflict_types) and all("collision" in conflict_type for conflict_type in conflict_types)
            if aggregate_collision_report.get("ok") and collision_only:
                branch_conflict["stale_after_final_aggregate_repair"] = True
                stale_branch_conflicts.append(branch_conflict)
            else:
                branch_conflicts.append(branch_conflict)
    if incremental_branch_report.get("enabled"):
        checks.append(
            {
                "type": "incremental_branch_execution",
                "ok": not branch_conflicts,
                "failed_branch_count": int(incremental_branch_report.get("failed_branch_count", 0)),
                "active_failed_branch_count": len(branch_conflicts),
                "stale_failed_branch_count": len(stale_branch_conflicts),
            }
        )
    if mujoco_report and mujoco_report.get("enabled"):
        checks.append(
            {
                "type": "mujoco_simulation",
                "ok": bool(mujoco_report.get("ok")),
                "max_displacement": float(mujoco_report.get("max_displacement", 0.0) or 0.0),
                "unstable_object_count": len(mujoco_report.get("unstable_objects", [])),
            }
        )
    conflicts: list[dict[str, Any]] = []
    if not aggregate_collision_report.get("ok"):
        for conflict in aggregate_collision_report.get("conflicts", []):
            conflicts.append({"source": "aggregate_collision", **conflict})
    if not reference_alignment_report.get("ok"):
        for warning in reference_alignment_report.get("warnings", []):
            conflicts.append({"source": "reference_alignment", "type": "reference_alignment_warning", "detail": warning})
    if spatial_order_repair_report and spatial_order_repair_report.get("enabled") and not spatial_order_repair_report.get("ok"):
        for warning in spatial_order_repair_report.get("warnings", []):
            conflicts.append({"source": "reference_spatial_order", "type": "spatial_order_warning", "detail": warning})
    if spatial_relation_repair_report and spatial_relation_repair_report.get("enabled") and not spatial_relation_repair_report.get("ok"):
        for warning in spatial_relation_repair_report.get("warnings", []):
            conflicts.append({"source": "spatial_relation_repair", "type": "spatial_relation_warning", "detail": warning})
    if (
        scene_hypergraph_validation_report
        and scene_hypergraph_validation_report.get("enabled")
        and not scene_hypergraph_validation_report.get("ok")
    ):
        for warning in scene_hypergraph_validation_report.get("warnings", []):
            conflicts.append({"source": "scene_hypergraph", "type": "hypergraph_constraint_warning", "detail": warning})
    conflicts.extend(branch_conflicts)
    if mujoco_report and mujoco_report.get("enabled") and not mujoco_report.get("ok"):
        conflicts.append(
            {
                "source": "mujoco_simulation",
                "type": "mujoco_instability",
                "max_displacement": mujoco_report.get("max_displacement"),
                "threshold": mujoco_report.get("max_displacement_threshold"),
                "unstable_objects": mujoco_report.get("unstable_objects", []),
                "returncode": mujoco_report.get("returncode"),
            }
        )
    return {
        "schema": "tree_sage_global_validator_v1",
        "checks": checks,
        "conflict_count": len(conflicts),
        "conflicts": conflicts,
        "diagnostics": {
            "stale_incremental_branch_conflicts": stale_branch_conflicts,
        },
        "ok": all(check["ok"] for check in checks),
    }


def build_plan_from_scene_graph(
    scene_graph: dict[str, Any],
    support_tree: dict[str, Any],
    cross_constraints: list[dict[str, Any]],
    parent: dict[str, str],
    relation_to_parent: dict[str, str],
) -> dict[str, Any]:
    room = dict(scene_graph["room"])
    plan: dict[str, Any] = {
        "scene_id": scene_graph["scene_id"],
        "room_type": scene_graph["room_type"],
        "building_style": scene_graph.get("style", "image-guided generated scene"),
        "description": scene_graph.get("description", ""),
        "room": room,
        "objects": [],
        "_planner": "tree_sage_flow2_image_scene_graph",
        "_coordinate_frame": "corner_origin",
        "_functional_spatial_clusters": deepcopy(scene_graph.get("_functional_spatial_clusters", [])),
    }
    metas = {obj["id"]: obj for obj in scene_graph["objects"]}
    placed: dict[str, dict[str, Any]] = {}

    for index, meta in enumerate(scene_graph["objects"]):
        dims = _default_dimensions(meta)
        x, y = _image_reference_position(meta, room, index)
        obj = {
            "id": meta["id"],
            "category": meta["category"],
            "description": meta.get("description", meta["category"]),
            "asset_prompt": meta["asset_prompt"],
            "image_bbox": meta.get("image_bbox"),
            "agent_semantics": dict(meta.get("agent_semantics") if isinstance(meta.get("agent_semantics"), dict) else {}),
            "asset_generation": dict(meta.get("asset_generation") if isinstance(meta.get("asset_generation"), dict) else {}),
            "x": x,
            "y": y,
            "z": 0.0,
            "yaw": 0.0,
            "dimensions": dims,
            "placement_type": "floor",
            "asset_axis_to_z": 2,
            "asset_local_yaw_offset_degrees": 0.0,
            "front_yaw_offset_degrees": 0.0,
            "footprint_yaw_offset_degrees": 0.0,
        }
        if parent.get(meta["id"]) in VIRTUAL_WALLS:
            wall_ref = dict(meta)
            wall_ref["dimensions"] = obj["dimensions"]
            obj["x"], obj["y"], obj["z"], obj["yaw"] = _wall_pose(parent[meta["id"]], room, wall_ref)
            obj["placement_type"] = "attached_to_wall"
            obj["support_id"] = parent[meta["id"]]
            obj["dimensions"]["length"] = min(float(obj["dimensions"]["length"]), 0.08)
        elif _is_hanging_object(obj):
            obj["z"] = _clamp(float(room["height"]) - float(obj["dimensions"]["height"]) - 0.22, 1.15, float(room["height"]) - 0.25)
            obj["placement_type"] = "hanging"
        plan["objects"].append(obj)
        placed[obj["id"]] = obj

    # Stabilize floor roots before placing support children; otherwise later root moves orphan tabletop objects.
    _apply_spatial_constraints(plan, scene_graph, cross_constraints)

    # Support children are placed after image-guided floor positions so parent bboxes are available.
    for obj in plan["objects"]:
        parent_id = parent.get(obj["id"], "floor")
        if parent_id in {"floor"} | VIRTUAL_WALLS:
            continue
        support = placed.get(parent_id)
        if support:
            _place_supported_child(obj, support, relation_to_parent.get(obj["id"], "on"), metas[obj["id"]], metas[parent_id])
    hanging_wall_normalization_fixes = _normalize_hanging_children_to_wall(plan)

    _normalize_flow2_object_dimensions(plan)
    apply_asset_pose_defaults(plan)
    ceiling_hanging_normalization_fixes = _normalize_ceiling_hanging_objects(plan)
    for obj in plan["objects"]:
        if str(obj.get("placement_type", "floor")) == "floor":
            obj["z"] = 0.0
            _clamp_object_to_room(obj, room)
        elif str(obj.get("placement_type")) == "hanging":
            _clamp_object_to_room(obj, room)
        obj["yaw"] = _round_yaw_90(float(obj.get("yaw", 0.0)))

    layout_fixes = repair_floor_branch_collisions(plan, support_tree, parent, relation_to_parent)
    spatial_order_repair_report = audit_and_repair_reference_spatial_order(plan, scene_graph, support_tree, parent, cross_constraints)
    spatial_relation_repair_report = repair_spatial_relation_constraints(plan, cross_constraints, support_tree, parent, scene_graph=scene_graph)
    scene_hypergraph = build_scene_hypergraph(plan, support_tree, parent, relation_to_parent, cross_constraints, scene_graph=scene_graph)
    group_pose_repair_report = apply_scene_hypergraph_pose_constraints(plan, scene_hypergraph)
    pose_review_report = audit_and_repair_object_poses(plan, parent, cross_constraints)
    post_pose_group_repair_report = apply_scene_hypergraph_pose_constraints(plan, scene_hypergraph)
    if post_pose_group_repair_report.get("fixes"):
        group_pose_repair_report.setdefault("fixes", []).extend(post_pose_group_repair_report.get("fixes", []))
        group_pose_repair_report.setdefault("checks", []).extend(post_pose_group_repair_report.get("checks", []))
        group_pose_repair_report["fix_count"] = len(group_pose_repair_report.get("fixes", []))
    post_pose_collision_fixes = repair_floor_branch_collisions(plan, support_tree, parent, relation_to_parent)
    if post_pose_collision_fixes:
        pose_review_report["fixes"].extend(post_pose_collision_fixes)
    plan["_flow2"] = {
        "input_mode": "prompt_plus_flux_image_scene_graph",
        "layout_reference": "Flux reference image bboxes + support-tree relations",
        "room_size_grounding": scene_graph.get("_room_size_grounding"),
        "room_axis_grounding": scene_graph.get("_room_axis_grounding"),
        "branch_collision_fixes": layout_fixes,
        "hanging_wall_normalization_fixes": hanging_wall_normalization_fixes,
        "ceiling_hanging_normalization_fixes": ceiling_hanging_normalization_fixes,
        "post_pose_branch_collision_fixes": post_pose_collision_fixes,
    }
    plan["_scene_hypergraph"] = scene_hypergraph
    plan["_group_pose_repair"] = group_pose_repair_report
    plan["_spatial_order_repair"] = spatial_order_repair_report
    plan["_spatial_relation_repair"] = spatial_relation_repair_report
    plan["_pose_review"] = pose_review_report
    return plan


