def _generic_parametric_color(mesh: trimesh.Trimesh, rgba: tuple[int, int, int, int]) -> trimesh.Trimesh:
    mesh.visual = trimesh.visual.TextureVisuals(
        material=trimesh.visual.material.PBRMaterial(
            baseColorFactor=[float(channel) / 255.0 for channel in rgba],
            metallicFactor=0.0,
            roughnessFactor=0.68,
        )
    )
    mesh.visual.vertex_colors = rgba
    return mesh


def _generic_parametric_add_box(
    scene: trimesh.Scene,
    name: str,
    extents: tuple[float, float, float],
    center: tuple[float, float, float],
    rgba: tuple[int, int, int, int],
) -> None:
    mesh = trimesh.creation.box(extents=extents)
    mesh.apply_translation(center)
    scene.add_geometry(_generic_parametric_color(mesh, rgba), geom_name=name)


def _generic_parametric_add_cylinder(
    scene: trimesh.Scene,
    name: str,
    radius: float,
    height: float,
    center: tuple[float, float, float],
    rgba: tuple[int, int, int, int],
    sections: int = 24,
) -> None:
    mesh = trimesh.creation.cylinder(radius=radius, height=height, sections=sections)
    mesh.apply_translation(center)
    scene.add_geometry(_generic_parametric_color(mesh, rgba), geom_name=name)


def _is_generic_parametric_tabletop_decor(obj: dict[str, Any]) -> bool:
    text = (
        f"{obj.get('id', '')} {obj.get('category', '')} {obj.get('description', '')} "
        f"{obj.get('asset_prompt', '')}"
    ).lower().replace("_", " ")
    if any(keyword in text for keyword in GENERIC_TABLETOP_DECOR_DENY_KEYWORDS):
        return False
    semantic = _semantic_class(obj)
    role = _semantic_layout_role(obj)
    scale_kind = _scale_kind(obj)
    is_tabletop = (
        role == "tabletop_child"
        or semantic in {"decor", "tabletop_small", "tabletop_upright", "tabletop_flat"}
        or scale_kind == "tabletop_small"
        or str(obj.get("placement_type") or "") in {"on_top", "on_top_of", "supported_by"}
        or bool(obj.get("support_parent_id"))
    )
    if not is_tabletop:
        return False
    if any(keyword in text for keyword in GENERIC_TABLETOP_DECOR_KEYWORDS):
        return True
    return semantic == "decor" and scale_kind in {"tabletop_small", "generic"}


def _is_generic_parametric_window(obj: dict[str, Any]) -> bool:
    identity = f"{obj.get('id', '')} {obj.get('category', '')}".lower().replace("_", " ")
    text = (
        f"{obj.get('id', '')} {obj.get('category', '')} {obj.get('description', '')} "
        f"{obj.get('asset_prompt', '')}"
    ).lower().replace("_", " ")
    if "window" not in text and _scale_kind(obj) != "window":
        return False
    if any(keyword in identity for keyword in ("curtain", "drape", "plant", "sill plant", "window sill", "lamp", "wall art")):
        return False
    semantic = _semantic_class(obj)
    role = _semantic_layout_role(obj)
    return (
        semantic in {"window", "wall_attached", "wall_fixture"}
        or role in {"window", "wall_window", "wall_branch"}
        or _is_wall_attached_object(obj)
    )


def _make_generic_tabletop_decor_asset(obj: dict[str, Any]) -> trimesh.Scene:
    dimensions = obj.get("dimensions") if isinstance(obj.get("dimensions"), dict) else {}
    width = _clamp(float(dimensions.get("width", 0.16) or 0.16), 0.08, 0.28)
    length = _clamp(float(dimensions.get("length", 0.12) or 0.12), 0.06, 0.24)
    height = _clamp(float(dimensions.get("height", 0.18) or 0.18), 0.08, 0.32)
    scene = trimesh.Scene()
    base_height = max(0.018, height * 0.12)
    body_height = max(0.04, height * 0.64)
    cap_height = max(0.018, height - base_height - body_height)
    _generic_parametric_add_box(
        scene,
        "low_base",
        (width, length, base_height),
        (0.0, 0.0, base_height * 0.5),
        (172, 132, 86, 255),
    )
    _generic_parametric_add_cylinder(
        scene,
        "upright_body",
        min(width, length) * 0.28,
        body_height,
        (0.0, 0.0, base_height + body_height * 0.5),
        (217, 198, 154, 255),
        sections=18,
    )
    _generic_parametric_add_box(
        scene,
        "front_mark",
        (width * 0.34, length * 0.08, body_height * 0.42),
        (0.0, -length * 0.18, base_height + body_height * 0.56),
        (91, 116, 126, 255),
    )
    _generic_parametric_add_cylinder(
        scene,
        "top_cap",
        min(width, length) * 0.2,
        cap_height,
        (0.0, 0.0, base_height + body_height + cap_height * 0.5),
        (146, 93, 78, 255),
        sections=16,
    )
    return scene


def route_asset_fixed_policy(obj: dict[str, Any]) -> dict[str, Any]:
    object_id = str(obj.get("id") or "")
    text = _category_text(obj)
    has_factory = object_id in PARAMETRIC_ASSET_FACTORIES or _is_generic_parametric_window(obj)
    if not has_factory:
        return {
            "object_id": object_id,
            "route": "trellis2",
            "confidence": 1.0,
            "reason": "no local procedural fallback factory; use Trellis2 as the primary asset generator",
            "allowed_generators": ["trellis2"],
            "forbidden_generators": [],
        }
    if any(keyword in text for keyword in PARAMETRIC_ASSET_DENY_KEYWORDS):
        return {
            "object_id": object_id,
            "route": "trellis2",
            "confidence": 0.92,
            "reason": "soft/organic/complex object should stay on Trellis2 unless explicitly regenerated by another high-fidelity model",
            "allowed_generators": ["trellis2"],
            "forbidden_generators": ["parametric"],
        }
    return {
        "object_id": object_id,
        "route": "trellis2",
        "confidence": 0.9,
        "reason": "Trellis2 is primary; local procedural factory is reserved as a QA fallback",
        "allowed_generators": ["trellis2"],
        "fallback_generators": ["parametric"],
        "forbidden_generators": [],
    }


def _backup_router_original_asset(obj: dict[str, Any], asset_dir: Path, output_dir: Path) -> dict[str, Any]:
    object_id = str(obj.get("id") or "")
    backup_dir = output_dir / "_asset_router_originals"
    backup_dir.mkdir(parents=True, exist_ok=True)
    backup: dict[str, Any] = {"object_id": object_id, "backup_dir": str(backup_dir), "copied": []}
    for suffix in (".glb", ".json"):
        src = asset_dir / f"{object_id}{suffix}"
        if not src.exists():
            continue
        dst = backup_dir / src.name
        shutil.copy2(src, dst)
        backup["copied"].append(str(dst))
        if suffix == ".glb":
            backup["glb"] = str(dst)
        elif suffix == ".json":
            backup["json"] = str(dst)
    obj.setdefault("asset_generation", {})["router_original_backup"] = backup
    return backup


def write_parametric_asset(obj: dict[str, Any], asset_dir: Path) -> dict[str, Any]:
    object_id = str(obj.get("id") or "")
    factory = PARAMETRIC_ASSET_FACTORIES.get(object_id)
    if factory is None:
        if _is_generic_parametric_window(obj):
            scene = make_parametric_window_asset()
            source = "tree_sage_generic_window_parametric_v1"
        elif _is_generic_parametric_tabletop_decor(obj):
            scene = _make_generic_tabletop_decor_asset(obj)
            source = "tree_sage_generic_tabletop_parametric_v1"
        else:
            raise KeyError(f"no parametric asset factory for {object_id}")
    else:
        scene = factory()
        source = "tree_sage_asset_router_parametric_v1"
    # Local procedural factories in create_tree_sage_fallback_assets.py are authored z-up.
    # Reset any Trellis-derived axis metadata before the new GLB is analyzed/rendered.
    obj["asset_axis_to_z"] = 2
    obj.pop("asset_axis_to_z_sign", None)
    obj.setdefault("asset_generation", {})["raw_coordinate_frame"] = {
        "source": source,
        "vertical_axis": "z",
        "width_axis": "x",
        "depth_axis": "y",
    }
    asset_dir.mkdir(parents=True, exist_ok=True)
    path = asset_dir / f"{object_id}.glb"
    scene.export(path)
    meta = {
        "object_id": object_id,
        "asset_path": str(path),
        "content_type": "model/gltf-binary",
        "source": source,
        "route": "parametric",
    }
    (asset_dir / f"{object_id}.json").write_text(json.dumps(meta, indent=2), encoding="utf-8")
    return {"object_id": object_id, "asset_path": str(path), "source": meta["source"]}


def _forced_regeneration_can_use_parametric(obj: dict[str, Any]) -> bool:
    object_id = str(obj.get("id") or "")
    identity_without_id = (
        f"{obj.get('category', '')} {obj.get('description', '')} {obj.get('asset_prompt', '')}"
    ).lower().replace("_", " ")
    semantic = _semantic_class(obj)
    role = _semantic_layout_role(obj)
    if object_id not in PARAMETRIC_ASSET_FACTORIES:
        return _is_generic_parametric_window(obj) or _is_generic_parametric_tabletop_decor(obj)
    is_tabletop_photo = (
        ("framed photo" in identity_without_id or "photo frame" in identity_without_id or "framed picture" in identity_without_id)
        and (role == "tabletop_child" or semantic in {"decor", "tabletop_upright"})
    )
    return bool(is_tabletop_photo or _is_generic_parametric_tabletop_decor(obj))


def write_articraft_asset(args: argparse.Namespace, obj: dict[str, Any], asset_dir: Path, output_dir: Path) -> dict[str, Any]:
    object_id = str(obj.get("id") or "")
    asset_dir.mkdir(parents=True, exist_ok=True)
    object_json = output_dir / "_articraft_requests" / f"{object_id}.json"
    object_json.parent.mkdir(parents=True, exist_ok=True)
    object_json.write_text(json.dumps(obj, indent=2, ensure_ascii=False), encoding="utf-8")
    report_path = output_dir / "_articraft_reports" / f"{object_id}.json"
    work_dir = output_dir / "_articraft_work" / object_id
    output_glb = asset_dir / f"{object_id}.glb"
    script_path = Path(__file__).with_name("run_articraft_asset_worker.py")
    cmd = [
        sys.executable,
        str(script_path),
        "--object-json",
        str(object_json),
        "--output-glb",
        str(output_glb),
        "--report",
        str(report_path),
        "--work-dir",
        str(work_dir),
        "--articraft-repo",
        str(args.articraft_repo),
        "--articraft-provider",
        str(args.articraft_provider),
        "--articraft-model",
        str(args.articraft_model),
        "--max-cost-usd",
        str(args.articraft_max_cost_usd),
        "--timeout",
        str(args.articraft_timeout),
    ]
    if args.articraft_python:
        cmd.extend(["--articraft-python", str(args.articraft_python)])
    if args.articraft_reference_image_mode == "flux" and args.flux_image and args.flux_image.exists():
        cmd.extend(["--reference-image", str(args.flux_image)])
    proc = subprocess.run(
        cmd,
        cwd=str(Path.cwd()),
        text=True,
        stdout=subprocess.PIPE,
        stderr=subprocess.PIPE,
        timeout=float(args.articraft_timeout) + 30.0,
        check=False,
    )
    report_path.parent.mkdir(parents=True, exist_ok=True)
    stdout_path = report_path.with_suffix(".stdout.txt")
    stderr_path = report_path.with_suffix(".stderr.txt")
    stdout_path.write_text(proc.stdout, encoding="utf-8")
    stderr_path.write_text(proc.stderr, encoding="utf-8")
    worker_report = extract_json(report_path.read_text(encoding="utf-8")) if report_path.exists() else {}
    if proc.returncode != 0 or not worker_report.get("ok"):
        raise RuntimeError(
            f"Articraft worker failed for {object_id}: returncode={proc.returncode}; "
            f"{worker_report.get('error') or proc.stderr[-500:]}"
        )
    obj["asset_axis_to_z"] = 1
    obj["asset_axis_to_z_sign"] = -1.0
    obj.setdefault("asset_generation", {})["raw_coordinate_frame"] = {
        "source": "articraft_prompt_contract",
        "blender_import_vertical_axis": "-y",
        "width_axis": "x",
        "depth_axis_after_axis_repair": "y",
    }
    meta = {
        "object_id": object_id,
        "asset_path": str(output_glb),
        "content_type": "model/gltf-binary",
        "source": "tree_sage_asset_router_articraft_v1",
        "route": "articraft",
        "worker_report": str(report_path),
    }
    (asset_dir / f"{object_id}.json").write_text(json.dumps(meta, indent=2), encoding="utf-8")
    return {"object_id": object_id, "asset_path": str(output_glb), "source": meta["source"], "worker_report": str(report_path)}


def apply_asset_router(args: argparse.Namespace, plan: dict[str, Any], asset_dir: Path, output_dir: Path) -> dict[str, Any]:
    report: dict[str, Any] = {
        "schema": "tree_sage_asset_router_v1",
        "enabled": bool(args.asset_router),
        "asset_dir": str(asset_dir),
        "routes": [],
        "parametric_written": [],
        "articraft_written": [],
        "parametric_count": 0,
        "articraft_count": 0,
        "ok": True,
    }
    if not args.asset_router:
        report["reason"] = "disabled"
        write_json(output_dir / "asset_router_report.json", report)
        return report
    for obj in plan.get("objects", []):
        if not isinstance(obj, dict) or not obj.get("id"):
            continue
        route = route_asset_fixed_policy(obj)
        if route.get("route") == "articraft" and not args.articraft_assets:
            route = {
                **route,
                "route": "trellis2",
                "fallback_reason": "articraft asset generation disabled",
                "allowed_generators": ["trellis2"],
            }
        obj.setdefault("asset_generation", {})["router"] = route
        report["routes"].append(route)
        if route.get("route") not in {"parametric", "articraft"}:
            continue
        try:
            _backup_router_original_asset(obj, asset_dir, output_dir)
            if route.get("route") == "parametric":
                written = write_parametric_asset(obj, asset_dir)
                report["parametric_written"].append({**written, "reason": route.get("reason")})
                print(f"[asset-router] parametric {obj['id']}: {written['asset_path']}", flush=True)
            else:
                written = write_articraft_asset(args, obj, asset_dir, output_dir)
                report["articraft_written"].append({**written, "reason": route.get("reason")})
                print(f"[asset-router] articraft {obj['id']}: {written['asset_path']}", flush=True)
        except Exception as exc:
            route["route"] = "trellis2"
            route["fallback_reason"] = f"router generation failed: {type(exc).__name__}: {exc}"
            backup = obj.get("asset_generation", {}).get("router_original_backup")
            if isinstance(backup, dict):
                backup_glb = Path(str(backup.get("glb") or ""))
                backup_json = Path(str(backup.get("json") or ""))
                if backup_glb.exists():
                    shutil.copy2(backup_glb, asset_dir / f"{obj['id']}.glb")
                if backup_json.exists():
                    shutil.copy2(backup_json, asset_dir / f"{obj['id']}.json")
            report.setdefault("warnings", []).append(f"{obj.get('id')} router generation failed; kept Trellis/reused asset: {exc}")
            print(f"[asset-router] {obj.get('id')} generation failed; kept Trellis/reused asset: {exc}", flush=True)
    report["parametric_count"] = len(report["parametric_written"])
    report["articraft_count"] = len(report["articraft_written"])
    write_json(output_dir / "asset_router_report.json", report)
    return report


def restore_router_fallback_assets(
    plan: dict[str, Any],
    asset_dir: Path,
    asset_registry: dict[str, Any],
    output_dir: Path,
) -> dict[str, Any]:
    report: dict[str, Any] = {
        "schema": "tree_sage_asset_router_qa_fallback_v1",
        "enabled": True,
        "asset_dir": str(asset_dir),
        "restored": [],
        "restore_count": 0,
        "ok": True,
    }
    registry_objects = asset_registry.get("objects", {}) if isinstance(asset_registry.get("objects"), dict) else {}
    for obj in plan.get("objects", []):
        if not isinstance(obj, dict) or not obj.get("id"):
            continue
        generation = obj.get("asset_generation") if isinstance(obj.get("asset_generation"), dict) else {}
        route = generation.get("router") if isinstance(generation.get("router"), dict) else {}
        if route.get("route") not in {"parametric", "articraft"}:
            continue
        entry = registry_objects.get(str(obj.get("id")), {})
        warnings = [str(item) for item in entry.get("warnings", [])] if isinstance(entry, dict) else []
        quality = str(entry.get("quality") or "missing") if isinstance(entry, dict) else "missing"
        blocking_warnings = [
            warning
            for warning in warnings
            if (
                warning.startswith("component policy violation:")
                or "wall-attached object does not have a thin footprint axis" in warning
                or "requires extreme axis compression" in warning
                or "lacks a clear broad top surface" in warning
            )
        ]
        if quality == "ok" and not blocking_warnings:
            continue
        backup = generation.get("router_original_backup") if isinstance(generation.get("router_original_backup"), dict) else {}
        backup_glb = Path(str(backup.get("glb") or ""))
        backup_json = Path(str(backup.get("json") or ""))
        if not backup_glb.exists():
            report.setdefault("warnings", []).append(f"{obj.get('id')} failed router QA but no backup asset exists")
            report["ok"] = False
            continue
        shutil.copy2(backup_glb, asset_dir / f"{obj['id']}.glb")
        if backup_json.exists():
            shutil.copy2(backup_json, asset_dir / f"{obj['id']}.json")
        route["route"] = "trellis2"
        route["fallback_reason"] = f"router asset failed QA: quality={quality}; warnings={blocking_warnings}"
        restored = {
            "object_id": obj.get("id"),
            "quality": quality,
            "blocking_warnings": blocking_warnings,
            "restored_from": str(backup_glb),
            "restored_to": str(asset_dir / f"{obj['id']}.glb"),
        }
        report["restored"].append(restored)
        print(f"[asset-router-qa] restored {obj['id']} to Trellis/reused asset", flush=True)
    report["restore_count"] = len(report["restored"])
    write_json(output_dir / "asset_router_qa_fallback_report.json", report)
    return report


def _parametric_fallback_blocking_warnings(entry: dict[str, Any]) -> list[str]:
    warnings = [str(item) for item in entry.get("warnings", [])] if isinstance(entry, dict) else []
    return [
        warning
        for warning in warnings
        if (
            warning.startswith("component policy violation:")
            or "wall-attached object does not have a thin footprint axis" in warning
            or "requires extreme axis compression" in warning
            or "window asset has low pedestal/sill-like geometry" in warning
            or "window asset has excessive disconnected fragments" in warning
            or "lacks a clear broad top surface" in warning
        )
    ]


def _is_only_wall_thinness_or_axis_warning(warnings: list[str]) -> bool:
    if not warnings:
        return False
    allowed_fragments = (
        "wall-attached object does not have a thin footprint axis",
        "requires extreme axis compression",
    )
    return all(any(fragment in warning for fragment in allowed_fragments) for warning in warnings)


def _is_only_window_tolerated_parametric_fallback_warning(warnings: list[str]) -> bool:
    if not warnings:
        return False
    allowed_fragments = (
        "wall-attached object does not have a thin footprint axis",
        "requires extreme axis compression",
        "window asset has low pedestal/sill-like geometry",
    )
    return all(any(fragment in warning for fragment in allowed_fragments) for warning in warnings)


def fallback_failed_trellis_assets_to_parametric(
    plan: dict[str, Any],
    asset_dir: Path,
    asset_registry: dict[str, Any],
    output_dir: Path,
    enabled: bool,
) -> dict[str, Any]:
    report: dict[str, Any] = {
        "schema": "tree_sage_parametric_fallback_v1",
        "enabled": bool(enabled),
        "asset_dir": str(asset_dir),
        "fallbacks": [],
        "skipped": [],
        "fallback_count": 0,
        "ok": True,
    }
    if not enabled:
        report["reason"] = "disabled"
        write_json(output_dir / "parametric_fallback_report.json", report)
        return report
    registry_objects = asset_registry.get("objects", {}) if isinstance(asset_registry.get("objects"), dict) else {}
    backup_dir = output_dir / "_parametric_fallback_originals"
    objects = [obj for obj in plan.get("objects", []) if isinstance(obj, dict) and obj.get("id")]
    for obj in objects:
        object_id = str(obj.get("id"))
        if object_id not in PARAMETRIC_ASSET_FACTORIES and not _is_generic_parametric_window(obj):
            continue
        text = _category_text(obj)
        simple_wall_door = (
            any(keyword in text for keyword in ("door", "closet"))
            and str(obj.get("placement_type") or "") == "attached_to_wall"
        )
        if any(keyword in text for keyword in PARAMETRIC_ASSET_DENY_KEYWORDS) and not simple_wall_door:
            continue
        entry = registry_objects.get(object_id, {})
        quality = str(entry.get("quality") or "missing") if isinstance(entry, dict) else "missing"
        blocking_warnings = _parametric_fallback_blocking_warnings(entry if isinstance(entry, dict) else {})
        if quality == "ok" and not blocking_warnings:
            continue
        if "window" in text and not blocking_warnings:
            report["skipped"].append(
                {
                    "object_id": object_id,
                    "quality": quality,
                    "blocking_warnings": [],
                    "reason": "kept Trellis/reused window asset because QA warnings are non-blocking for window fallback",
                }
            )
            continue
        if "window" in text and _is_only_window_tolerated_parametric_fallback_warning(blocking_warnings):
            report["skipped"].append(
                {
                    "object_id": object_id,
                    "quality": quality,
                    "blocking_warnings": blocking_warnings,
                    "reason": (
                        "kept Trellis/reused window asset because the only QA issues are expected wall-thickness "
                        "or sill-like geometry; procedural fallback is less faithful for reference-specific windows."
                    ),
                }
            )
            continue
        if simple_wall_door and _is_only_wall_thinness_or_axis_warning(blocking_warnings):
            report["skipped"].append(
                {
                    "object_id": object_id,
                    "quality": quality,
                    "blocking_warnings": blocking_warnings,
                    "reason": (
                        "kept Trellis/reused door asset because the only QA issue is wall-thinness/axis compression; "
                        "parametric fallback makes these doors less faithful to the reference."
                    ),
                }
            )
            continue
        backup_dir.mkdir(parents=True, exist_ok=True)
        for suffix in (".glb", ".json"):
            src = asset_dir / f"{object_id}{suffix}"
            if src.exists():
                shutil.copy2(src, backup_dir / src.name)
        try:
            written = write_parametric_asset(obj, asset_dir)
        except Exception as exc:
            warning = f"{object_id} parametric fallback failed; kept existing asset: {type(exc).__name__}: {exc}"
            report.setdefault("warnings", []).append(warning)
            report["ok"] = False
            print(f"[parametric-fallback] {warning}", flush=True)
            continue
        obj.setdefault("asset_generation", {})["parametric_fallback"] = {
            "applied": True,
            "source": "tree_sage_parametric_fallback_v1",
            "reason": (
                "wall-mounted door uses procedural thin-panel fallback only because Trellis/reused asset failed QA: "
                f"quality={quality}; warnings={blocking_warnings}"
                if simple_wall_door
                else f"Trellis2 asset failed QA after available retries: quality={quality}; warnings={blocking_warnings}"
            ),
            "backup_dir": str(backup_dir),
        }
        fallback = {
            **written,
            "previous_quality": quality,
            "blocking_warnings": blocking_warnings,
            "backup_dir": str(backup_dir),
        }
        report["fallbacks"].append(fallback)
        print(f"[parametric-fallback] {object_id}: {written['asset_path']}", flush=True)
    report["fallback_count"] = len(report["fallbacks"])
    report["skipped_count"] = len(report["skipped"])
    write_json(output_dir / "parametric_fallback_report.json", report)
    return report


def _asset_generation_object_for_trellis(obj: dict[str, Any]) -> dict[str, Any]:
    """Return a generation-only object with prompts adjusted for known fragile asset classes."""
    generated = json.loads(json.dumps(obj))
    object_id = str(generated.get("id") or "")
    text = _category_text(generated)
    base_prompt = str(generated.get("asset_prompt") or generated.get("description") or generated.get("category") or object_id)
    prompt_notes: list[str] = []

    wall_generation_subject = (
        _is_wall_attached_object(generated)
        or str(generated.get("placement_type") or "") == "attached_to_wall"
        or str(generated.get("support_id") or "").startswith("wall_")
    )
    if wall_generation_subject:
        if any(keyword in text for keyword in ("door", "closet")):
            generated["asset_prompt"] = (
                f"{base_prompt}, flat wall-mounted double closet door panel only, very thin slab, "
                "front-facing paneled door surface with knobs and hinges, no cabinet body, no wardrobe box, "
                "no side walls, no freestanding furniture, no thickness except a thin wall panel, "
                "clean smooth painted door finish, no mottled noise texture, no chipped speckled surface"
            )
            prompt_notes.append("wall_attached_door_flat_panel_prompt")
        elif "window" in text:
            generated["asset_prompt"] = (
                f"{base_prompt}, thin wall-mounted residential window frame assembly, continuous outer frame and muntins, "
                "clear or very pale lightly tinted glass panes, readable front surface, very shallow depth, "
                "no opaque backing plane, no black solid backplate, no wall slab behind it, no freestanding body, "
                "no saturated background color visible inside the panes"
            )
            prompt_notes.append("wall_attached_window_frame_prompt")
        if not prompt_notes:
            identity_text = f"{generated.get('id', '')} {generated.get('category', '')}".lower().replace("_", " ")
            category_text = str(generated.get("category", "")).lower().replace("_", " ")
            explicit_curtain_panel_prompt = (
                any(phrase in identity_text for phrase in ("curtain panel", "drape panel", "drapery panel"))
                or (
                    any(keyword in identity_text for keyword in ("curtain", "drape", "drapery"))
                    and "panel" in identity_text
                )
                or (
                    any(keyword in category_text for keyword in ("curtain", "drape", "drapery"))
                    and not any(keyword in category_text for keyword in ("curtain rod", "drape rod", "drapery rod"))
                )
            )
            explicit_curtain_rod_prompt = any(keyword in identity_text for keyword in ("curtain rod", "drape rod", "drapery rod"))
            if explicit_curtain_panel_prompt:
                generated["asset_prompt"] = (
                    f"{base_prompt}, single pleated fabric curtain panel, vertical hanging textile strip, "
                    "thin cloth sheet with visible folds, no window, no rod, no wall slab, no freestanding body"
                )
                prompt_notes.append("wall_attached_curtain_panel_prompt")
            elif explicit_curtain_rod_prompt or any(keyword in text for keyword in ("curtain rod", "drape rod", "drapery rod")):
                generated["asset_prompt"] = (
                    f"{base_prompt}, black metal curtain rod only, thin horizontal cylinder with small round finials, "
                    "very shallow wall-mounted fixture, no curtain panel, no flat board, no wall slab, no room"
                )
                prompt_notes.append("wall_attached_curtain_rod_prompt")
            elif any(keyword in text for keyword in ("curtain", "drape", "drapery")):
                generated["asset_prompt"] = (
                    f"{base_prompt}, single pleated fabric curtain panel, vertical hanging textile strip, "
                    "thin cloth sheet with visible folds, no window, no rod, no wall slab, no freestanding body"
                )
                prompt_notes.append("wall_attached_curtain_panel_prompt")
            elif any(keyword in text for keyword in ("wall art", "painting", "picture", "poster", "print")):
                generated["asset_prompt"] = (
                    f"{base_prompt}, flat framed wall art print with a visible colored landscape or botanical picture printed on the front, "
                    "thin wall-mounted panel with continuous backing and frame, readable decorative image surface, "
                    "not a blank white panel, not a grey empty board, no window frame, no glass-only pane, no wall slab behind it"
                )
                prompt_notes.append("wall_attached_visible_wall_art_prompt")
            elif "mirror" in text:
                generated["asset_prompt"] = (
                    f"{base_prompt}, flat wall-mounted panel asset, very thin depth, single integrated backing plane, "
                    "front surface readable, no freestanding body, no room, no wall slab behind it"
                )
                prompt_notes.append("wall_attached_flat_panel_prompt")

    if _is_soft_bedding_object(generated):
        if any(keyword in text for keyword in ("throw", "blanket", "quilt", "bedspread")):
            generated["asset_prompt"] = (
                f"{base_prompt}, thin flat soft fabric strip draped across the foot of a bed, very low thickness, "
                "wide and shallow rectangular textile, not a folded blanket stack, not a hard board, no rigid slab"
            )
            prompt_notes.append("thin_flat_bed_throw_prompt")
        elif any(keyword in text for keyword in ("pillow", "cushion")):
            generated["asset_prompt"] = (
                f"{base_prompt}, soft fabric pillow with rounded bulging edges, compressible cushion, "
                "not a rigid block, no hard rectangular board"
            )
            prompt_notes.append("soft_pillow_prompt")

    if prompt_notes:
        generated.setdefault("asset_generation", {})["prompt_rewrite"] = {
            "source": "tree_sage_asset_prompt_rewrite_v1",
            "notes": prompt_notes,
            "original_asset_prompt": base_prompt,
            "rewritten_asset_prompt": generated.get("asset_prompt"),
        }
    return generated


def _object_requires_asset_regeneration(obj: dict[str, Any]) -> bool:
    generation = obj.get("asset_generation") if isinstance(obj.get("asset_generation"), dict) else {}
    return bool(
        generation.get("force_regenerate")
        or generation.get("reference_tabletop_relabel")
        or generation.get("reference_tabletop_create")
    )


def _asset_source_image_path(args: argparse.Namespace, obj: dict[str, Any]) -> Path | None:
    source_dir = getattr(args, "asset_source_image_dir", None)
    if not source_dir:
        return None
    return Path(source_dir) / f"{obj['id']}.png"


def analyze_asset_source_image(path: Path) -> dict[str, Any]:
    report: dict[str, Any] = {
        "path": str(path),
        "exists": path.exists(),
        "ok": False,
        "warnings": [],
    }
    if not path.exists():
        report["warnings"].append("missing_source_image")
        return report
    with Image.open(path) as image:
        rgb = image.convert("RGB")
        arr = np.asarray(rgb, dtype=np.int16)
    h, w = arr.shape[:2]
    report["size"] = [int(w), int(h)]
    border_width = max(2, min(24, h // 12, w // 12))
    border = np.concatenate(
        [
            arr[:border_width].reshape(-1, 3),
            arr[-border_width:].reshape(-1, 3),
            arr[:, :border_width].reshape(-1, 3),
            arr[:, -border_width:].reshape(-1, 3),
        ],
        axis=0,
    )
    bg = np.median(border, axis=0)
    dist = np.abs(arr - bg).mean(axis=2)
    border_dist = np.abs(border - bg).mean(axis=1)
    subject = dist > 35.0
    ys, xs = np.where(subject)
    report["background_rgb_median"] = [int(round(float(v))) for v in bg]
    report["border_background_ratio_d25"] = round(float((border_dist < 25.0).mean()), 6)
    report["subject_ratio"] = round(float(subject.mean()), 6)
    if len(xs):
        bbox = [int(xs.min()), int(ys.min()), int(xs.max()), int(ys.max())]
        report["subject_bbox_xyxy"] = bbox
        report["subject_padding_ltrb"] = [bbox[0], bbox[1], w - 1 - bbox[2], h - 1 - bbox[3]]
    else:
        report["subject_bbox_xyxy"] = None
        report["subject_padding_ltrb"] = [0, 0, 0, 0]
        report["warnings"].append("no_foreground_detected_against_border_background")
    if w < 512 or h < 512:
        report["warnings"].append("source_image_resolution_below_512")
    if float(report["border_background_ratio_d25"]) < 0.72:
        report["warnings"].append("border_background_not_flat_or_object_touches_edges")
    subject_ratio = float(report["subject_ratio"])
    if subject_ratio < 0.025:
        report["warnings"].append("foreground_subject_too_small_or_missing")
    if subject_ratio > 0.88:
        report["warnings"].append("foreground_subject_too_large_or_background_not_separable")
    padding = report.get("subject_padding_ltrb") if isinstance(report.get("subject_padding_ltrb"), list) else []
    if padding and min(int(v) for v in padding) < 6:
        report["warnings"].append("foreground_touches_image_edge_or_has_too_little_padding")
    blocking = {
        "missing_source_image",
        "no_foreground_detected_against_border_background",
        "foreground_subject_too_small_or_missing",
        "foreground_subject_too_large_or_background_not_separable",
    }
    report["ok"] = not any(warning in blocking for warning in report["warnings"])
    return report


def generate_asset_from_source_image(
    trellis_url: str,
    obj: dict[str, Any],
    source_image: Path,
    asset_dir: Path,
    seed: int,
    timeout: float,
    steps: int,
    texture_size: int,
    decimation_target: int,
    pipeline_type: str,
    preprocess_image: bool,
    force: bool = False,
    qa_strict: bool = True,
) -> Path:
    asset_dir.mkdir(parents=True, exist_ok=True)
    out_path = asset_dir / f"{obj['id']}.glb"
    meta_path = asset_dir / f"{obj['id']}.json"
    if out_path.exists() and meta_path.exists() and not force:
        return out_path
    qa = analyze_asset_source_image(source_image)
    if qa_strict and not qa.get("ok"):
        write_json(
            meta_path,
            {
                "source": "trellis2_from_asset_source_image",
                "status": "pre_trellis_image_qa_failed",
                "object": obj,
                "asset_path": str(out_path),
                "asset_source_image": str(source_image),
                "pre_trellis_image_qa": qa,
            },
        )
        raise ValueError(f"pre-Trellis source-image QA failed for {obj['id']}: {qa.get('warnings')}")
    request_payload = {
        "input_text": obj["asset_prompt"],
        "reference_image_path": str(source_image.resolve()),
        "seed": seed,
        "pipeline_type": pipeline_type,
        "preprocess_image": preprocess_image,
        "sparse_steps": steps,
        "shape_steps": steps,
        "tex_steps": steps,
        "texture_size": texture_size,
        "decimation_target": decimation_target,
        "simplify_limit": 1048576,
    }
    deadline = time.time() + timeout
    while True:
        try:
            status, payload = trellis_post_json(trellis_url.rstrip("/") + "/generate", request_payload, timeout=30.0)
            break
        except RETRYABLE_JOB_POLL_ERRORS as exc:
            if time.time() >= deadline:
                raise RuntimeError(f"Trellis2 server did not accept image-source job for {obj['id']} before timeout: {exc}") from exc
            print(f"[trellis2-image-source] waiting for server to accept {obj['id']}: {exc}", flush=True)
            time.sleep(5.0)
    if status != 202:
        raise RuntimeError(f"Trellis2 server returned {status} for image-source asset {obj['id']}: {payload}")
    job_id = str(payload["job_id"])
    bridge_metadata = None
    while time.time() < deadline:
        try:
            status, body, content_type = trellis_get_job(trellis_url.rstrip("/") + f"/job/{job_id}", timeout=60.0)
        except RETRYABLE_JOB_POLL_ERRORS:
            time.sleep(2.0)
            continue
        if status == 200:
            out_path.write_bytes(body)
            try:
                metadata_status, metadata_body, _ = trellis_get_job(trellis_url.rstrip("/") + f"/job/{job_id}/metadata", timeout=60.0)
            except RETRYABLE_JOB_POLL_ERRORS:
                metadata_status, metadata_body = 0, b""
            if metadata_status == 200:
                try:
                    bridge_metadata = json.loads(metadata_body.decode("utf-8"))
                except Exception as exc:  # noqa: BLE001
                    bridge_metadata = {"metadata_parse_error": str(exc)}
            write_json(
                meta_path,
                {
                    "source": "trellis2_from_asset_source_image",
                    "job_id": job_id,
                    "object": obj,
                    "asset_path": str(out_path),
                    "content_type": content_type,
                    "asset_source_image": str(source_image),
                    "pre_trellis_image_qa": qa,
                    "trellis_request_payload": request_payload,
                    "bridge_metadata": bridge_metadata,
                },
            )
            return out_path
        if status == 500:
            write_json(
                meta_path,
                {
                    "source": "trellis2_from_asset_source_image",
                    "status": "failed",
                    "job_id": job_id,
                    "object": obj,
                    "asset_path": str(out_path),
                    "asset_source_image": str(source_image),
                    "pre_trellis_image_qa": qa,
                    "server_error": body.decode("utf-8", errors="replace"),
                    "bridge_metadata": bridge_metadata,
                },
            )
            raise RuntimeError(body.decode("utf-8", errors="replace"))
        if status in {404, 410}:
            remaining = deadline - time.time()
            if remaining <= 0:
                break
            time.sleep(5.0)
            return generate_asset_from_source_image(
                trellis_url,
                obj,
                source_image,
                asset_dir,
                seed=seed,
                timeout=remaining,
                steps=steps,
                texture_size=texture_size,
                decimation_target=decimation_target,
                pipeline_type=pipeline_type,
                preprocess_image=preprocess_image,
                force=force,
                qa_strict=qa_strict,
            )
        if status != 202:
            raise RuntimeError(f"Trellis2 image-source job {job_id} for {obj['id']} returned {status}: {body[:200]!r}")
        time.sleep(3.0)
    write_json(
        meta_path,
        {
            "source": "trellis2_from_asset_source_image",
            "status": "timeout",
            "job_id": job_id,
            "object": obj,
            "asset_path": str(out_path),
            "asset_source_image": str(source_image),
            "pre_trellis_image_qa": qa,
            "bridge_metadata": bridge_metadata,
        },
    )
    raise TimeoutError(f"Trellis2 image-source job timed out for {obj['id']}")


def generate_tree_sage_asset(args: argparse.Namespace, obj: dict[str, Any], asset_dir: Path, *, seed: int, force: bool) -> Path:
    generation_obj = _asset_generation_object_for_trellis(obj)
    source_image = _asset_source_image_path(args, obj)
    if source_image and source_image.exists():
        return generate_asset_from_source_image(
            args.trellis_url,
            generation_obj,
            source_image,
            asset_dir,
            seed=seed,
            timeout=args.asset_timeout,
            steps=args.steps,
            texture_size=args.texture_size,
            decimation_target=args.decimation_target,
            pipeline_type=args.trellis_pipeline_type,
            preprocess_image=args.trellis_preprocess_image,
            force=force,
            qa_strict=bool(getattr(args, "asset_source_image_qa_strict", True)),
        )
    if source_image and getattr(args, "asset_source_image_required", False):
        raise FileNotFoundError(f"missing required asset source image for {obj['id']}: {source_image}")
    return generate_asset(
        args.trellis_url,
        generation_obj,
        asset_dir,
        seed=seed,
        timeout=args.asset_timeout,
        steps=args.steps,
        texture_size=args.texture_size,
        decimation_target=args.decimation_target,
        force=force,
    )


def _tree_sage_asset_cleanup_retry_object(obj: dict[str, Any]) -> dict[str, Any]:
    retry = json.loads(json.dumps(obj))
    prompt = str(retry.get("asset_prompt") or retry.get("category") or retry.get("id"))
    retry["asset_prompt"] = (
        f"{prompt}, isolated product cutout, object only, floating slightly above ground with visible underside, "
        "no floor, no ground plane, no wall, no room, no platform, no base slab, no pedestal, no plinth, "
        "no display stand, no contact shadow"
    )
    retry["_regeneration_reason"] = "integrated_broad_thin_artifact"
    return retry


def repair_tree_sage_assets_for_scene(
    args: argparse.Namespace,
    plan: dict[str, Any],
    source_dir: Path,
    output_dir: Path,
    *,
    force_clean: bool = False,
    regenerate_integrated: bool = True,
) -> list[dict[str, Any]]:
    reports: list[dict[str, Any]] = []
    regenerated_raw_dir = output_dir / "_regenerated_raw"
    for index, obj in enumerate(plan.get("objects", [])):
        object_id = str(obj.get("id"))
        src = source_dir / f"{object_id}.glb"
        dst = output_dir / f"{object_id}.glb"
        report = clean_asset_ground_artifacts(src, dst, obj, force=force_clean)
        if report.get("requires_regeneration") and regenerate_integrated:
            retry_obj = _tree_sage_asset_cleanup_retry_object(obj)
            regenerated_src = generate_tree_sage_asset(
                args,
                retry_obj,
                regenerated_raw_dir,
                seed=args.seed + 5000 + index,
                force=True,
            )
            retry_report = clean_asset_ground_artifacts(regenerated_src, dst, obj, force=True)
            report["regeneration"] = {
                "enabled": True,
                "route": "tree_sage_generate_asset",
                "uses_asset_source_image_dir": bool(getattr(args, "asset_source_image_dir", None)),
                "retry_asset_prompt": retry_obj["asset_prompt"],
                "raw_regenerated_asset": str(regenerated_src),
                "cleanup_report": retry_report,
            }
            report["artifact_action"] = (
                "regenerated_then_component_cleanup"
                if retry_report.get("changed")
                else "regenerated_still_requires_review"
                if retry_report.get("requires_regeneration")
                else "regenerated"
            )
        meta_src = source_dir / f"{object_id}.json"
        if meta_src.exists():
            shutil.copy2(meta_src, output_dir / meta_src.name)
        reports.append(report)
        gc.collect()
    return reports


def write_asset_source_image_qa_report(args: argparse.Namespace, plan: dict[str, Any], output_dir: Path) -> dict[str, Any]:
    source_dir = getattr(args, "asset_source_image_dir", None)
    report: dict[str, Any] = {
        "schema": "tree_sage_asset_source_image_qa_v1",
        "enabled": bool(source_dir),
        "source_dir": str(source_dir) if source_dir else None,
        "required": bool(getattr(args, "asset_source_image_required", False)),
        "qa_strict": bool(getattr(args, "asset_source_image_qa_strict", True)),
        "objects": [],
        "missing": [],
        "failed": [],
        "ok": True,
    }
    if not source_dir:
        write_json(output_dir / "asset_source_image_qa_report.json", report)
        return report
    for obj in plan.get("objects", []):
        if not isinstance(obj, dict) or not obj.get("id"):
            continue
        path = _asset_source_image_path(args, obj)
        qa = analyze_asset_source_image(path) if path else {"exists": False, "ok": False, "warnings": ["missing_source_image"]}
        item = {
            "id": str(obj.get("id")),
            "category": obj.get("category"),
            "source_image": str(path) if path else None,
            "qa": qa,
        }
        report["objects"].append(item)
        if not qa.get("exists"):
            report["missing"].append(str(obj.get("id")))
        elif not qa.get("ok"):
            report["failed"].append({"id": str(obj.get("id")), "warnings": qa.get("warnings", [])})
    required_missing = bool(report["missing"]) and bool(report["required"])
    strict_failed = bool(report["failed"]) and bool(report["qa_strict"])
    report["ok"] = not required_missing and not strict_failed
    if required_missing:
        report["reason"] = "missing_required_asset_source_images"
    elif strict_failed:
        report["reason"] = "asset_source_image_qa_failed"
    write_json(output_dir / "asset_source_image_qa_report.json", report)
    if required_missing:
        raise FileNotFoundError(f"missing required asset source images: {', '.join(report['missing'])}")
    if strict_failed:
        failed_ids = ", ".join(str(item.get("id")) for item in report["failed"])
        raise ValueError(f"asset source image QA failed for: {failed_ids}")
    return report


def prepare_assets(args: argparse.Namespace, plan: dict[str, Any], output_asset_dir: Path) -> Path:
    reuse_source_already_cleaned = False
    force_regenerate_ids: set[str] = {
        str(obj.get("id"))
        for obj in plan.get("objects", [])
        if isinstance(obj, dict) and obj.get("id") and _object_requires_asset_regeneration(obj)
    }
    write_asset_source_image_qa_report(args, plan, output_asset_dir.parent)
    if args.reuse_asset_dir:
        source_dir = Path(args.reuse_asset_dir)
        reuse_source_already_cleaned = source_dir.name.endswith("_cleaned")
        reuse_aliases = read_reuse_asset_aliases(getattr(args, "reuse_asset_alias_file", None))
        alias_report: dict[str, Any] = {
            "schema": "tree_sage_asset_reuse_alias_v1",
            "enabled": bool(reuse_aliases),
            "alias_file": str(getattr(args, "reuse_asset_alias_file", "")) if getattr(args, "reuse_asset_alias_file", None) else None,
            "source_dir": str(source_dir),
            "target_dir": str(output_asset_dir),
            "aliases": reuse_aliases,
            "uses": [],
            "missing": [],
            "regenerated": [],
            "rejected": [],
            "ok": True,
        }
        missing = [
            str(obj["id"])
            for obj in plan["objects"]
            if str(obj["id"]) not in force_regenerate_ids
            and not _resolve_reused_asset_source_id(source_dir, str(obj["id"]), reuse_aliases)
        ]
        alias_report["missing"] = missing
        if missing and not args.partial_reuse_assets:
            raise FileNotFoundError(f"Missing reused assets for: {', '.join(missing)}")
        local_copy_required = bool(
            args.copy_reused_assets
            or args.partial_reuse_assets
            or args.asset_router
            or reuse_aliases
            or args.parametric_fallback_assets
            or args.component_policy_regenerate_reused_assets
            or force_regenerate_ids
        )
        if local_copy_required:
            output_asset_dir.mkdir(parents=True, exist_ok=True)
            for obj in plan["objects"]:
                object_id = str(obj["id"])
                source_object_id = _resolve_reused_asset_source_id(source_dir, object_id, reuse_aliases)
                rejection_reason = ""
                reject_reused_asset = bool(
                    source_object_id
                    and (
                        object_id in force_regenerate_ids
                        or (args.partial_reuse_assets and _is_known_bad_reused_asset(source_dir, source_object_id))
                        or _is_parametric_reused_asset(source_dir, source_object_id)
                    )
                )
                if source_object_id:
                    if object_id in force_regenerate_ids:
                        rejection_reason = "object_metadata_requires_asset_regeneration"
                    elif args.partial_reuse_assets and _is_known_bad_reused_asset(source_dir, source_object_id):
                        rejection_reason = "known_bad_reused_fallback_asset"
                    elif _is_parametric_reused_asset(source_dir, source_object_id):
                        rejection_reason = "parametric_reuse_rejected_trellis2_is_primary"
                if reject_reused_asset:
                    alias_report["rejected"].append(
                        {
                            "target_object_id": object_id,
                            "source_object_id": source_object_id,
                            "reason": rejection_reason,
                        }
                    )
                    print(
                        f"[asset-reuse] regenerating rejected reused asset {object_id} from {source_object_id} "
                        f"in {source_dir}: {rejection_reason}",
                        flush=True,
                    )
                if source_object_id and not reject_reused_asset:
                    copied = _copy_reused_asset(source_dir, output_asset_dir, object_id, source_object_id)
                    if source_object_id != object_id:
                        alias_report["uses"].append(
                            {
                                "target_object_id": object_id,
                                "source_object_id": source_object_id,
                                "copied": copied,
                            }
                        )
                if (
                    args.partial_reuse_assets
                    or object_id in force_regenerate_ids
                    or reject_reused_asset
                ) and not (output_asset_dir / f"{object_id}.glb").exists():
                    if _forced_regeneration_can_use_parametric(obj):
                        written = write_parametric_asset(obj, output_asset_dir)
                        asset_path = Path(written["asset_path"])
                        obj.setdefault("asset_generation", {})["forced_parametric_regeneration"] = {
                            "source": "tree_sage_forced_regeneration_parametric_v1",
                            "reason": "small tabletop framed photo was relabelled from reference; local rigid parametric asset is sufficient",
                        }
                        print(f"parametric regenerated missing partial-reuse asset {object_id}: {asset_path}", flush=True)
                        alias_report["regenerated"].append({**written, "route": "parametric"})
                    else:
                        asset_path = generate_tree_sage_asset(
                            args,
                            obj,
                            output_asset_dir,
                            seed=args.seed + plan["objects"].index(obj),
                            force=True,
                        )
                        print(f"generated missing partial-reuse asset {object_id}: {asset_path}", flush=True)
                        alias_report["regenerated"].append({"object_id": object_id, "asset_path": str(asset_path)})
            if reuse_aliases:
                write_json(output_asset_dir.parent / "asset_reuse_alias_report.json", alias_report)
            source_dir = output_asset_dir
        asset_dir = source_dir
    else:
        output_asset_dir.mkdir(parents=True, exist_ok=True)
        for index, obj in enumerate(plan["objects"]):
            existing_asset = (output_asset_dir / f"{obj['id']}.glb").exists() and not args.force_assets
            asset_path = generate_tree_sage_asset(
                args,
                obj,
                output_asset_dir,
                seed=args.seed + index,
                force=args.force_assets,
            )
            action = "reused" if existing_asset else "generated"
            print(f"{action} {obj['id']}: {asset_path}", flush=True)
        asset_dir = output_asset_dir

    apply_asset_router(args, plan, asset_dir, output_asset_dir.parent)
    if not args.clean_assets:
        return asset_dir
    if (
        args.reuse_asset_dir
        and reuse_source_already_cleaned
        and not args.force_clean_assets
        and not args.partial_reuse_assets
        and not args.asset_router
        and not args.articraft_assets
        and not args.parametric_fallback_assets
        and not args.component_policy_regenerate_reused_assets
        and not force_regenerate_ids
    ):
        write_json(
            output_asset_dir.parent / "asset_cleanup_report.json",
            {
                "schema": "tree_sage_asset_cleanup_report_v1",
                "enabled": False,
                "skipped": True,
                "reason": "reuse_asset_dir_already_cleaned",
                "source_dir": str(Path(args.reuse_asset_dir)),
                "asset_dir": str(asset_dir),
                "ok": True,
            },
        )
        return asset_dir
    cleaned_dir = output_asset_dir.parent / f"{output_asset_dir.name}_cleaned"
    reports = repair_tree_sage_assets_for_scene(
        args,
        plan,
        asset_dir,
        cleaned_dir,
        force_clean=args.force_clean_assets,
        regenerate_integrated=args.regenerate_integrated_artifacts,
    )
    write_json(output_asset_dir.parent / "asset_cleanup_report.json", reports)
    return cleaned_dir


def _component_policy_retry_object(obj: dict[str, Any], policy: dict[str, Any], reason: str) -> dict[str, Any]:
    retry = json.loads(json.dumps(obj))
    base_prompt = str(retry.get("asset_prompt") or retry.get("category") or retry.get("id"))
    component_policy = str(policy.get("component_policy") or "unknown")
    hint = str(policy.get("regeneration_hint") or "").strip()
    if component_policy == "single_integrated_panel":
        default_hint = (
            "one continuous thin solid backing board, single integrated object, flat printed surface detail, "
            "no individual tiles, no separate pieces, no cutouts, no floating fragments"
        )
    elif component_policy == "many_details_on_base":
        default_hint = (
            "one coherent asset with a clear main base, frame, pot, shelf, or backing that holds all details, "
            "no detached floating fragments, no duplicate separate objects"
        )
    elif component_policy == "soft_or_irregular_integrated":
        default_hint = "one continuous integrated soft object, no detached fragments, no duplicate objects"
    else:
        default_hint = "one coherent complete object, no floating detached fragments, no duplicate objects, object only"
    retry["asset_prompt"] = (
        f"{base_prompt}, {hint or default_hint}, isolated product cutout, object only, "
        "no room, no wall, no floor, no platform, no pedestal, no display stand"
    )
    retry["_regeneration_reason"] = reason
    retry["_component_policy_retry"] = policy
    return retry


def regenerate_component_policy_failed_assets(
    plan: dict[str, Any],
    asset_dir: Path,
    asset_registry: dict[str, Any],
    args: argparse.Namespace,
) -> dict[str, Any]:
    failed_ids = [
        object_id
        for object_id in asset_registry.get("component_policy_failed_ids", [])
        if isinstance(object_id, str) and (asset_dir / f"{object_id}.glb").exists()
    ]
    report: dict[str, Any] = {
        "schema": "tree_sage_component_policy_regeneration_v1",
        "enabled": bool(args.component_policy_regenerate),
        "asset_dir": str(asset_dir),
        "failed_ids": failed_ids,
        "attempts": [],
        "regenerated_count": 0,
        "ok": True,
    }
    if not args.component_policy_regenerate:
        report["reason"] = "disabled"
        return report
    reuse_only_mode = bool(
        getattr(args, "reuse_asset_dir", None)
        and not getattr(args, "partial_reuse_assets", False)
        and not getattr(args, "component_policy_regenerate_reused_assets", False)
    )
    if reuse_only_mode:
        report["enabled"] = False
        report["reason"] = "skipped_for_reuse_asset_dir"
        report["skipped_failed_ids"] = failed_ids
        return report
    if not failed_ids:
        report["reason"] = "no_component_policy_failures"
        return report
    objects = {str(obj.get("id")): obj for obj in plan.get("objects", [])}
    raw_dir = asset_dir / "_component_policy_regenerated_raw"
    max_passes = max(0, int(args.component_policy_regenerate_max_passes))
    remaining_failed_ids = list(failed_ids)
    for pass_index in range(max_passes):
        if not remaining_failed_ids:
            break
        regenerated_this_pass: list[str] = []
        attempted_this_pass = list(remaining_failed_ids)
        failed_attempt_ids: set[str] = set()
        for offset, object_id in enumerate(attempted_this_pass):
            obj = objects.get(object_id)
            entry = asset_registry.get("objects", {}).get(object_id, {})
            if not obj:
                continue
            policy = entry.get("asset_component_policy") if isinstance(entry.get("asset_component_policy"), dict) else _component_policy_for_asset(obj)
            retry_obj = _component_policy_retry_object(
                obj,
                policy,
                "; ".join(str(w) for w in entry.get("warnings", []) if str(w).startswith("component policy violation:")) or "component_policy_violation",
            )
            try:
                regenerated_src = generate_tree_sage_asset(
                    args,
                    retry_obj,
                    raw_dir,
                    seed=args.seed + 9000 + pass_index * 1000 + offset,
                    force=True,
                )
                cleanup_report = clean_asset_ground_artifacts(regenerated_src, asset_dir / f"{object_id}.glb", obj, force=True)
                meta_src = raw_dir / f"{object_id}.json"
                if meta_src.exists():
                    shutil.copy2(meta_src, asset_dir / meta_src.name)
                regenerated_this_pass.append(object_id)
                report["attempts"].append(
                    {
                        "pass": pass_index + 1,
                        "id": object_id,
                        "component_policy": policy,
                        "retry_asset_prompt": retry_obj["asset_prompt"],
                        "raw_regenerated_asset": str(regenerated_src),
                        "cleanup_report": cleanup_report,
                    }
                )
                print(f"[component-policy] regenerated {object_id}: {regenerated_src}", flush=True)
            except Exception as exc:
                failed_attempt_ids.add(object_id)
                warning = f"{object_id} component-policy regeneration failed; kept existing asset: {type(exc).__name__}: {exc}"
                report.setdefault("warnings", []).append(warning)
                report["attempts"].append(
                    {
                        "pass": pass_index + 1,
                        "id": object_id,
                        "component_policy": policy,
                        "retry_asset_prompt": retry_obj["asset_prompt"],
                        "error": warning,
                        "kept_existing_asset": str(asset_dir / f"{object_id}.glb"),
                    }
                )
                print(f"[component-policy] {warning}", flush=True)
        report["regenerated_count"] += len(regenerated_this_pass)
        asset_registry = build_asset_registry(plan, asset_dir)
        still_policy_failed = {
            object_id
            for object_id in asset_registry.get("component_policy_failed_ids", [])
            if isinstance(object_id, str)
        }
        remaining_failed_ids = [
            object_id
            for object_id in attempted_this_pass
            if object_id in failed_attempt_ids or object_id in still_policy_failed
        ]
    report["remaining_failed_ids"] = remaining_failed_ids
    report["ok"] = not remaining_failed_ids
    return report


def selected_flow2_scene_prompt(args: argparse.Namespace) -> str:
    if args.prompt:
        return args.prompt
    if args.prompt_file:
        return Path(args.prompt_file).read_text(encoding="utf-8").strip()
    if args.prompt_preset:
        return OFFICIAL_PROMPTS[args.prompt_preset]
    return IMAGE_ONLY_SCENE_PROMPT


